import ACTION from '../actionTypes';
import * as Logic from '../../components/omok/omokLogic';

export function remove_mark(mark_x, mark_y, lboard2) {
  return {
    type: ACTION.REMOVE_OMOK_MARK,
    mark_x,
    mark_y,
    lboard2
  }
}

export function add_mark(mark_x, mark_y, mark_type, lboard2, mark_text) {
  return {
    type: ACTION.ADD_OMOK_MARK,
    mark_x,
    mark_y,
    mark_type,
    mark_text: !mark_text? "" : mark_text,
    lboard2
  }
}

export function remove_all_marks(what) {
  return {
    type: ACTION.REMOVE_OMOK_ALL_MARKS,
    what
  }
}

export function show_hints(hint_x, hint_y) {
  return {
    type: ACTION.SHOW_OMOK_HINTS,
    hint_x,
    hint_y
  }
}

export function hide_hints() {
  return {
    type: ACTION.HIDE_OMOK_HINTS,
  }
}

export function update_edit_mode(mode) {
  return {
    type: ACTION.UPDATE_OMOK_EDIT_MODE,
    mode
  }
}

export function set_edit_stone(x, y, color) {
  // Logic.theLogicBoard.set_edit_stone(x, y, color);
  return {
    type: ACTION.UPDATED_OMOK_BOARD,
  }
}

export function set_edit_stones(black_stones, white_stones) {
  return {
    type: ACTION.SET_EDIT_OMOK_STONES,
    black_stones,
    white_stones,
  }
}

export function update_board(board) {
  return ({type: ACTION.INIT_OMOK_BOARD, board});
}

export function update_board_size(board_size) {
  return ({type: ACTION.UPDATE_BOARD_SIZE, board_size});
}