import React from 'react';
import {bindActionCreators} from "redux";
import {connect} from 'react-redux';
import * as ModalAction from '../../store/actions/toast.action';

import {
  Button,
  DialogActions,
  DialogContent,
} from "@material-ui/core";

import { makeStyles } from '@material-ui/core/styles';
const useStyles = makeStyles(theme => ({
  commonModalStyle: { /* Hidden by default */
    display: 'block',
    position: 'fixed', /* Stay in place */
    zIndex: 1115, /* Sit on top */
    paddingTop: '100px', /* Location of the box */
    left: 0,
    top: 0,
    width: '100%', /* Full width */
    height: '100%', /* Full height */
    overflow: 'auto', /* Enable scroll if needed */
    backgroundColor: 'rgb(0,0,0)', /* Fallback color */
    backgroundColor: 'rgba(0,0,0,0.4)', /* Black w/ opacity */
  },  
  // showStyle: {
  //   display: 'block',
  // },
  // hiddenStyle: {
  //   display: 'none',
  // },
  modalContentStyle: {
    backgroundColor: '#fefefe',
    margin: 'auto',
    padding: "20px",
    border: "1px solid #888",
    width: '30%',
    content: {
      padding: "20px 0",
    }
  },
  // closeStyle: {
  //   color: '#aaaaaa',
  //   float: 'right',
  //   fontSize: '28px',
  //   fontWeight: 'bold',
  // },
  // // closeHoverStyle,
  // closeFocusStyle: {
  //   color: '#000',
  //   textDecoration: 'none',
  //   cursor: 'pointer',
  // }
}));

const Modal = ({modal_content, modal, hiddenModal})=> {
  const classes = useStyles();

  const onSubmit = () => {
    modal_content.clickOK();
    hiddenModal();
  };

  const onClose = () => {
    modal_content.clickCancel();
    hiddenModal();
  };
  return (
    <>
      {
        modal && (
          <div id="myModal" className={classes.commonModalStyle}>
            <div className={classes.modalContentStyle}>
              <DialogContent>
                <h5>{modal_content.content}</h5>
              </DialogContent>
              {
                modal_content.type==='query' && (
                  <DialogActions>
                    <Button onClick={()=>onSubmit()} color="primary">{window.i18n.t("modal.yes")}</Button>
                    <Button onClick={()=>onClose()} color="primary">{window.i18n.t("modal.no")}</Button>
                  </DialogActions>
                )
              }
              {
                modal_content.type==='notice' && (
                  <DialogActions>
                    <Button onClick={()=>onClose()} color="primary">{window.i18n.t("modal.ok")}</Button>
                  </DialogActions>
                )
              }
            </div>
          </div>
        )
      }
    </>
  )
};

function mapStateToProps(store) {
  return {
    modal: store.toastReducer.modal,
    modal_content: store.toastReducer.modal_content,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      hiddenModal: ModalAction.hiddenModal,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(Modal);