import ACTION from '../actionTypes';

const initialState = {
  problem_index: 0,
  solve_result: '',
  problem: {
    _id: '',
    description: '',
    first_color: '',
    cur_turn: 0,
    history_length: 0,
    h_index: 0,
    train_mode: false,
    solved: false,
    retried: 0,
    solved_time: 0,
    answer: [[]],
    answer_index: 0,
    varied: false,
  }, 
};

export default function goProblemReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_GO_PROBLEM:
      return {
        ...state,
        problem: {
          ...state.problem,
          description: action.problem.description,
          first_color: action.problem.first_color,
          h_index: 0,
          varied: true,
        }
      };
    case ACTION.DELETE_HISTORY_ON_PROBLEM:
      return {
        ...state,
        problem: {
          ...state.problem,
          answer: [[]],
          answer_index: 0,
          history_length: 0,
          h_index: 0,
          varied: true,
        }
      };
    case ACTION.ADD_MOVE_ON_PROBLEM_ANSWER:
      return {
        ...state,
        problem: {
          ...state.problem,
          answer: state.problem.answer.map((answer, index) => {
            if (index !== state.problem.answer_index)
              return answer;
            return answer.slice(0, action.grcounter-1).concat(action.pos);
          }),
          history_length: action.grcounter,
          h_index: action.grcounter,
          varied: true, 
        }
      };
    case ACTION.UPDATE_GO_PROBLEM_ANSWER_HISTORY_INDEX:
      return {
        ...state,
        problem: {
          ...state.problem,
          h_index: action.h_index,
        }
      };
    case ACTION.ADD_ANSWER_ON_PROBLEM:
      return {
        ...state,
        problem: {
          ...state.problem,
          answer_index: state.problem.answer.length,
          answer: state.problem.answer.concat([[]]),
          history_length: 0,
          h_index: 0,
        }
      };
    case ACTION.REMOVE_ANSWER_ON_PROBLEM:
      return {
        ...state,
        problem: {
          ...state.problem,
          answer_index: action.index,
          answer: state.problem.answer.filter((answer, i) => (i !== action.index) && answer),
          history_length: action.length,
          h_index: action.length,
          varied: true,
        }
      };
    case ACTION.SELECT_ANSWER_ON_PROBLEM:
      return {
        ...state,
        problem: {
          ...state.problem,
          answer_index: action.answer_index,
          history_length: action.length,
          h_index: action.length,
        }
      };
    case ACTION.LOAD_GO_PROBLEM:
      return {
        ...state,
        problem_index: action.problem_index,
        solve_result: '',
        problem: {
          ...state.problem,
          _id: action.problem._id,
          type: action.problem.type,
          description: action.problem.description,
          first_color: action.problem.first_color,
          difficulty: action.problem.difficulty,
          answer: action.problem.answer,
          answer_index: 0,
          history_length: action.grcounter,
          h_index: 0,
          varied: false,
        }
      };
    case ACTION.DO_GO_PROBLEM_MOVE:
      return {
        ...state,
        solve_result: action.result,
        problem: {
          ...state.problem,
          cur_turn: action.next_turn,
          history_length: state.problem.history_length + 1,
          h_index: state.problem.h_index + 1,
          solved: (state.problem.solved || action.result === 'correct')? true : false,
          retried: (!state.problem.solved && action.result === 'incorrect')? state.problem.retried + 1 : state.problem.retried,
        }
      };
    case ACTION.UPDATE_SOLVE_TIME:
      return {
        ...state,
        problem: {
          ...state.problem,
          solved_time: action.time,
        }
      };
    case ACTION.SWITCH_GO_SOLVE_PROBLEM_MODE:
      return {
        ...state,
        problem: {
          ...state.problem,
          train_mode: action.train_mode
        }
      };
    case ACTION.RESOLVE_GO_PROBLEM:
      return {
        ...state,
        solve_result: '',
        problem: {
          ...state.problem,
          history_length: 0,
          h_index: 0,
          solved: action.solved,
          retried: action.retried,
          solved_time: action.time,
        }
      };
    case ACTION.UPDATE_GO_PROBLEM_HISTORY_INDEX:
      return {
        ...state,
        problem: {
          ...state.problem,
          h_index: action.h_index,
        }
      };
    case ACTION.EXIT_GO_PROBLEM:
      return {
        ...state,
        solve_result: '',
        problem: {
          ...state.problem,
          solved_time: 0,
        },
      };
    case ACTION.CLEAR_PROBLEM_BOARD:
      return {
        ...state,
        solve_result: '',
        problem: {
          ...state.problem,
          answer: [[]],
          answer_index: 0,
          history_length: 0,
          h_index: 0,
          varied: true,
        },
      };
    case ACTION.CHANGED_GO_PROBLEM:
      return {
        ...state,
        problem: {
          ...state.problem,
          varied: true,
        }
      };
    default: return state;
  }
}
