import React, {useState,useEffect, useRef} from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { PNG } from 'pngjs/browser';
import { Image } from '@material-ui/icons';
import {Button} from '@material-ui/core';

import * as Logic from './pdesignLogic';
import PieceBoard from './pdesignLogic';

import * as PDesignBoardAction from '../../store/actions/pdesign_board.action';
import * as PDesignTaskAction from '../../store/actions/pdesign_task.action';
import PROTOCOL from '../../helper/protocol';

function CColor(r, g, b, a) {
  this.r = r;
  this.g = g;
  this.b = b;
  this.a = typeof a === 'undefined' ? 255 : a;
}

CColor.prototype.ToString = function() {
  return 'rgba(' + this.r + ',' + this.g + ',' + this.b + ',' + this.a / 255 + ')';
};

var board = [];
var drag_state = false;
var piece_kind, piece_index, tool, tool_property, pen_thick;
var diam, rad;
var s_x, s_y, e_x, e_y;
var shift_press = false, ctrl_press = false, ctrl_z_press = false, ctrl_y_press = false;
var temp_boards = [];

var imageData = {
  W: 0,
  H: 0,
  StoneDiam: 0,
  ShadowOff: 0,
  Board: null,
  Lines: null,
};
var htmlElement = {
  Board: null,
  Lines: null,
  Pieces: null,
  Preview: null,
  Shadow: null,
}

var coeffOffsetY = 0;
var coeffOffsetX = 0;
var coeffCellW = 0;
var coeffCellH = 0;
var coeffDiam = 0;
var g_dBoardCellW = 23.61;
var g_dBoardHorOffset = 17.51;
var inited = false;
const kind_array = [[0, 29], [1, 28], [2, 28], [4, 10], [7, 29], [8, 20], [9, 20]];
var temp_boards = [], board_index = 0;

function PDesignBoard(props) {
  const [width, setWidth] = useState(100); 
  const [height, setHeight] = useState(100);
  const [show_grid, setShowGrid] = useState(true);
  const [board_back, setBoardBack] = useState(0);
  const [png_result, setPngResult] = useState(new PNG());
  var viewPort = { X0: 0, Y0: 0, X1: PieceBoard.board_size, Y1: PieceBoard.board_size };

  useEffect(() => {
    piece_kind = props.piece_kind;
    piece_index = props.piece_index;
    tool = props.tool;
    tool_property = props.tool_property;
    pen_thick = props.pen_thick;
    if (tool == Logic.TOOL_ERASER && tool_property == 1) {
      empty_board();
      _drawPieces();
    }
  }, [props.piece_kind, props.piece_index, props.tool, props.tool_property, props.pen_thick]);
  
  useEffect(() => {
    const {user, socketRoom, room_id} = props;
    if (!props.complete_draw) return;
    if (props.complete_draw) {
      // var zip_array = ArrayZip.encode(PieceBoard.board);
      var pakp = require('pakp');
      // var array = String(PieceBoard.board);
      var obj = {board: PieceBoard.board};
      var zip_array = pakp.deflate(JSON.stringify(obj), { to: 'string'});
      var move = {board_data: zip_array};
      if (!!socketRoom) {
        socketRoom.emit('cs_message', PROTOCOL.CS_GAME_MOVE,  {token: !!user? user.token : null, room_id, move});
        
      }
      console.log('move', move, JSON.parse(pakp.inflate(zip_array, { to: 'string' })));
    }
  }, [props.complete_draw]);

  var canvas_ref = useRef("canvas");

  useEffect(() => {
    init("PDesignBoard");
    onResize(true);
    PieceBoard.set_board_size(props.size);
  }, [props.size, props.isShowGrid, props.board_back]);
    
  useEffect(() => {
    init("PDesignBoard");
    init_imageLibrary(kind_array);
    onResize(true);
    window.addEventListener("resize", ()=>{
      onResize();
    });
    window.addEventListener("keydown", (e)=>{
      onKeyPress(e);
    });
    window.addEventListener("keyup", (e)=>{
      onKeyUp(e);
    });
    board_array_init();
    return () => {
      window.onkeypress = null;
    }
  }, []);

  const board_array_init = () => {
    PieceBoard.initialize(Logic.MN_BOARD_SIZE);
    update_board();
  };

  const empty_board = () => {
    PieceBoard.empty_board();
    update_board();
  };

  const update_board = () => {
    props.update_board(PieceBoard.board, props.board_updated);
    PieceBoard.update_temp_boards();
  };

  const init = (name) => {
    var boardElem = document.getElementById(name);
    boardElem.innerHTML = null;
    boardElem.onmousemove = onMouseMove;
    boardElem.onmousedown = onMouseDown;
    boardElem.onmouseup = onMouseUp;

    imageData.Board = document.getElementById("board_back");
    var boardName = name + "_BoardCanvas";
    var linesName = name + "_LinesCanvas";
    var shadowsName = name + '_ShadowsCanvas';
    var piecesName = name + "_PiecesCanvas";
    var previewName = name + "_PreviewCanvas"
    htmlElement.Board = createCanvasElem(boardElem, boardName);
    htmlElement.Lines = createCanvasElem(boardElem, linesName);
    htmlElement.Shadow = createCanvasElem(boardElem, shadowsName);
    htmlElement.Pieces = createCanvasElem(boardElem, piecesName);
    htmlElement.Preview = createCanvasElem(boardElem, previewName);

    inited = true;

    imageData.W = htmlElement.Board.width;
    imageData.H = htmlElement.Board.height;
  };

  const init_imageLibrary = (array) => {
    var div = document.getElementById("items");
    array.map((item, index) => {
      for (let i = 0; i < item[1]; i ++) {
        var image = document.createElement("img");
        image.setAttribute("id", "piece_"+`${item[0]}_${i}`);
        image.setAttribute("src", `/assets/img/cell/${item[0]}/${i}.png`);
        div.appendChild(image);
      }
    });
  }

  const createCanvasElem = (parentElem, name) => {
    var elem = document.createElement("canvas");
    elem.setAttribute("id", name);
    elem.setAttribute("style", "position:absolute;padding:0;margin:0;");
    elem.setAttribute("oncontextmenu", "return false;");
    elem.setAttribute("width", parentElem.clientWidth);
    elem.setAttribute("height", parentElem.clientHeight);
    parentElem.appendChild(elem);
    return elem;
  };
  const _getBoardPosXY = (_X, _Y) => {
    var W = imageData.W;
    var H = imageData.H;

    var dCellH = coeffCellH * H;
    var dCellW = coeffCellW * W;
    var dHorOff = coeffOffsetX * W - dCellH * viewPort.X0;
    var dVerOff = coeffOffsetY * H - dCellW * viewPort.Y0;

    var Y = 0;
    var size = PieceBoard.board_size;

    var oSize = { X: size, Y: size };
    for (Y = 0; Y < oSize.Y - 1; Y++) {
        if (_Y > dVerOff + dCellH * Y + dCellH / 2)
            continue;
        else {
            break;
        }
    }

    var X = 0;
    for (X = 0; X < oSize.X - 1; X++) {
        if (_X > dHorOff + dCellW * X + dCellW / 2)
            continue;
        else {
            break;
        }
    }

    X = Math.max(viewPort.X0, Math.min(size, X));
    Y = Math.max(viewPort.Y0, Math.min(size, Y));

    return {X: X, Y: Y};
  };

  const poss_array = (pos) => {
    var poss = [];
    switch(tool) {
      case Logic.TOOL_PENCIL:
      case Logic.TOOL_ERASER:
        poss = PieceBoard.get_point_poss(pos.X, pos.Y, pen_thick);
        break;
      case Logic.TOOL_FIGURE:
        switch (tool_property) {
          case 0:
            poss = PieceBoard.get_line_poss(s_x, s_y, pos.X, pos.Y, pen_thick);
            break;
          case 1:
            poss = PieceBoard.get_rectangle_border_poss(s_x, s_y, pos.X, pos.Y, pen_thick, shift_press);
            break;
          case 2:
            poss = PieceBoard.get_ellipse_border_poss(s_x, s_y, pos.X, pos.Y, pen_thick, shift_press);
            break;
          case 3:
            poss = PieceBoard.get_rectangle_inside_poss(s_x, s_y, pos.X, pos.Y, shift_press);
            break;
          case 4:
            poss = PieceBoard.get_ellipse_inside_poss(s_x, s_y, pos.X, pos.Y, shift_press);
            break;
        }
        break;
      case Logic.TOOL_BUCKET:
        if (PieceBoard.get_piece(pos.X, pos.Y) == Logic.PIECE(piece_kind, piece_index)) return;
        poss = PieceBoard.get_same_piece_region_poss(Logic.APOS(pos.X, pos.Y), PieceBoard.board_size, PieceBoard.get_piece(pos.X, pos.Y));
        break;
      default: break;
    };
    return poss;
  }

  const _handleMouseDown = (pos, event) => {
    var poss = poss_array(pos);
    if (!!poss && poss.length > 0) {
      for (let i = 0; i < poss.length; i ++){
        if (tool == Logic.TOOL_PENCIL) {
          PieceBoard.board[poss[i]] = Logic.PIECE(piece_kind, piece_index);
          drawImg('piece', poss[i], PieceBoard.get_piece(pos.X, pos.Y));
        } else if (tool == Logic.TOOL_ERASER) {
          PieceBoard.board[poss[i]] = -1;
          drawImg('piece', poss[i], -1);
        }
      }
    }
    if (tool == Logic.TOOL_DIP) {
      var piece = PieceBoard.get_piece(pos.X, pos.Y);
      if (piece == -1) return;
      props.update_piece_kind(Logic.KIND(piece));
      props.update_piece_index(Logic.INDEX(piece));
    }
  }

  const _handleMouseMove = (pos, event) => {
    if (drag_state) {
      var poss = poss_array(pos);
      if (!!poss && poss.length > 0) {
        for (let i = 0; i < poss.length; i ++){
          if (poss[i] > 0) {
            if (tool == Logic.TOOL_ERASER) {
              PieceBoard.board[poss[i]] = -1;
              drawImg('piece', poss[i], -1);
            } else if (tool == Logic.TOOL_PENCIL) {
              PieceBoard.board[poss[i]] = Logic.PIECE(piece_kind, piece_index);
              drawImg('piece', poss[i], PieceBoard.get_piece(pos.X, pos.Y));
            } else if (tool == Logic.TOOL_FIGURE) {
              drawImg('preview', poss[i], Logic.PIECE(piece_kind, piece_index));
            }
          }
        }
      }
    };
  };

  const _handleMouseUp = (pos, e) => {
    if(props.replay) return;
    var poss = poss_array(pos);
    if (!!poss && poss.length > 0) {
      for (let i = 0; i < poss.length; i ++){
        if (tool == Logic.TOOL_FIGURE) {
          PieceBoard.board[poss[i]] = Logic.PIECE(piece_kind, piece_index);
        } else if (tool == Logic.TOOL_BUCKET){
          PieceBoard.board[poss[i]] = Logic.PIECE(piece_kind, piece_index);
          drawImg('piece', poss[i], PieceBoard.get_piece(pos.X, pos.Y));
        }
      }
    }
    update_board();
    _drawPieces();
  }

  const onMouseMove = (e) => {
    if(!inited || !drag_state || props.replay) return;
    var pos = _getBoardPosXY(e.offsetX, e.offsetY);
    var preview = htmlElement.Preview.getContext('2d');
    preview.clearRect(0, 0, imageData.W, imageData.H);
    _handleMouseMove(pos, e);
  };

  const onMouseDown = (e) => {
    if(!inited || props.replay) return;
    drag_state = true;
    var pos = _getBoardPosXY(e.offsetX, e.offsetY);
    s_x = pos.X;
    s_y = pos.Y;
    _handleMouseDown(pos, e);
  };

  const onMouseUp = (e) => {
    if(!inited) return;
    drag_state = false;
    var preview = htmlElement.Preview.getContext('2d');
    preview.clearRect(0, 0, imageData.W, imageData.H);
    var pos = _getBoardPosXY(e.offsetX, e.offsetY);
    _handleMouseUp(pos, e);
  };

  const onKeyUp = (e) => {
    if (e.keyCode == 0x10) shift_press = false;
    if (e.keyCode == 0x11) {
      ctrl_z_press = false;
      ctrl_y_press = false;
      ctrl_press = false;
    }
    if (e.keyCode == 0x5a && ctrl_z_press) {
      back_previous_board();
    }
    if (e.keyCode == 0x59 && ctrl_y_press) {
      back_next_board();
      _drawPieces();
    }
  };
  const onKeyPress = (e) => {
    if (e.keyCode == 0x10) shift_press = true;
    if (e.keyCode == 0x11) ctrl_press = true;
    if (ctrl_press == true && e.keyCode == 0x5a) ctrl_z_press = true;
    if (ctrl_press == true && e.keyCode == 0x59) ctrl_y_press = true;
  };

  const back_previous_board = () => {
    PieceBoard.back_previous_board();
    _drawPieces();
  }

  const back_next_board = () => {
    PieceBoard.back_next_board();
    _drawPieces();
  }

  const drawImg = (canvas, pos, piece) => {
    var _X = Logic.X(pos);
    var _Y = Logic.Y(pos);
    var kind = Logic.KIND(piece);
    var index = Logic.INDEX(piece);
    var size = PieceBoard.board_size;
    if (_X > size - 2) _X = size - 1;
    if (_Y > size - 1) _Y = size - 1;
    if (_X < 0) _X = 0;
    if (_Y < 0) _Y = 0;
    var x = imageData.Lines[_X].X - rad;
    var y = imageData.Lines[_Y].Y - rad;

    var Canvas = canvas == 'piece' ? htmlElement.Pieces.getContext("2d") : htmlElement.Preview.getContext("2d");
    Canvas.clearRect(x, y, diam, diam);
    if (piece == -1) return;
    var image = document.getElementById('piece_' + `${kind}_${index}`);
    if (!!image) Canvas.drawImage(image, x, y, diam, diam);
  }
  const _updateCoeffs = () => {
    var size = PieceBoard.board_size;
    var dAbsBoardW = (size - 1) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsBoardH = (size - 1) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsHorOff = g_dBoardHorOffset;
    var dAbsVerOff = g_dBoardHorOffset;

    coeffCellH = g_dBoardCellW / dAbsBoardH;
    coeffCellW = g_dBoardCellW / dAbsBoardW;
    coeffOffsetX = dAbsHorOff / dAbsBoardW;
    coeffOffsetY = dAbsVerOff / dAbsBoardH;
    coeffDiam = 4 / dAbsBoardW;
    diam = coeffCellW * imageData.W;
    rad  = diam / 2;
  };

  const onResize = (force) => {
    _updateCoeffs();

    if(!inited) return;

    var div = document.getElementById("PDesignBoard");

    if(!div)
      return;

    var W = parseInt(width * window.innerWidth / 100);
    var H = parseInt(height * window.innerHeight / 100);

    var _W = H;
    var _H = W;
    var marginLeft = 0;
    if (_W <= W) {
      marginLeft = (W - _W) / 2;
      W = _W;
    } 
    else H = _H;

    div.style.width = W + "px";
    div.style.height = H + "px";
    div.style.marginLeft = 0 + 'px';

    if (W !== imageData.W || H !== imageData.H || force) {
        imageData.W = W;
        imageData.H = H;

        var DWidth = Math.floor(imageData.W) - 1;

        var d = Math.floor(DWidth / 2) * 2 + 1;
        imageData.StoneDiam = d;

        _createLines();
    }
    drawBoard();
  };
  const _createLines = () => {
    var W = imageData.W;
    var H = imageData.H;
    var size = PieceBoard.board_size;

    if (0 === W || 0 === H)
        return;

    var dHorOff = coeffOffsetX * W;
    var dVerOff = coeffOffsetY * H;
    var dCellH = coeffCellH * H;
    var dCellW = coeffCellW * W;

    var Lines = new Array(size);

    var X_startoffset = dHorOff;
    var Y_startoffset = dVerOff;

    var X, Y, X_G, Y_G, X_L, Y_L, X_G2, Y_G2, X_L2, Y_L2;
    for (var Index = 0; Index < size; Index++) {
        X = X_startoffset + Index * dCellW;

        X_G = X_startoffset + Index * dCellW + 0.6 * dCellW;
        X_L = X_startoffset + Index * dCellW - 0.6 * dCellW;
        X_G2 = X_startoffset + Index * dCellW + 0.5 * dCellW;
        X_L2 = X_startoffset + Index * dCellW - 0.5 * dCellW;
        Y = Y_startoffset + Index * dCellH;
        Y_G = Y_startoffset + Index * dCellH + 0.6 * dCellH;
        Y_L = Y_startoffset + Index * dCellH - 0.6 * dCellH;
        Y_G2 = Y_startoffset + Index * dCellH + 0.5 * dCellH;
        Y_L2 = Y_startoffset + Index * dCellH - 0.5 * dCellH;

        Lines[Index] =
            {
                X: Math.floor(X + 0.5),
                X_G: Math.floor(X_G + 0.5),
                X_L: Math.floor(X_L + 0.5),
                X_G2: Math.floor(X_G2 + 0.5),
                X_L2: Math.floor(X_L2 + 0.5),
                Y: Math.floor(Y + 0.5),
                Y_G: Math.floor(Y_G + 0.5),
                Y_L: Math.floor(Y_L + 0.5),
                Y_G2: Math.floor(Y_G2 + 0.5),
                Y_L2: Math.floor(Y_L2 + 0.5)
            };
    }
    imageData.Lines = Lines;
  }

  const drawBoard = () => {
    if(!inited) return;

    _drawBoard();
    _drawPieces();
    _drawTrueColorLines();
  }
  const _drawBoard = () => {
    var BoardCanvas = htmlElement.Board.getContext("2d");
   
    var W = imageData.W; 
    var H = imageData.H;   
    var d = W / 64;

    var ShadowCanvas = htmlElement.Shadow.getContext("2d");
    ShadowCanvas.canvas.width = W + 2*d;
    ShadowCanvas.canvas.height = H + 2*d;
    ShadowCanvas.shadowBlur = d;
    ShadowCanvas.shadowOffsetX = d;
    ShadowCanvas.shadowOffsetY = d;
    ShadowCanvas.shadowColor = "black";
    ShadowCanvas.fillStyle = 'rgb(219,187,114,0.5)';
    ShadowCanvas.fillRect(0, 0, W, H);
    ShadowCanvas.clearRect(0, 0, W, H);
 
    BoardCanvas.canvas.width = W;
    BoardCanvas.canvas.height = H;
    switch (board_back) {
      case 0:
        BoardCanvas.drawImage(imageData.Board, 0, 0, W, H);
        break;
      case 1:
        BoardCanvas.fillStyle = 'rgb(220, 180, 120)';
        BoardCanvas.fillRect(0, 0, W, H);
        break;
      case 2:
        BoardCanvas.fillStyle = 'rgb(0, 0, 0)';
        BoardCanvas.fillRect(0, 0, W, H);
        break;
      case 3:
        BoardCanvas.fillStyle = 'rgb(255, 255, 255)';
        BoardCanvas.fillRect(0, 0, W, H);
        break;
    }
  }
  const _drawTrueColorLines = (Exclude) => {
    if (!imageData.Lines || !show_grid)
        return;

    var W = imageData.W;
    var H = imageData.H;

    var LinesCanvas = htmlElement.Lines.getContext("2d");
    var size = PieceBoard.board_size;
    LinesCanvas.canvas.width = W;
    LinesCanvas.canvas.height = H;

    var oSize = {X: size, Y: size};
    var Lines = imageData.Lines;

    LinesCanvas.clearRect(0, 0, W, H);

    var X_0 = Lines[0].X;
    var X_1 = Lines[oSize.X - 1].X;

    var Y_0 = Lines[0].Y;
    var Y_1 = Lines[oSize.Y - 1].Y;

    var VerLine = LinesCanvas.createImageData(1, H);
    var HorLine = LinesCanvas.createImageData(W, 1);

    var LineColor = new CColor(0, 0, 0, 255);
    for (var i = 0; i < H; i++) {
        var Index = i * 4;

        if (i >= Y_0 && i <= Y_1) {
            VerLine.data[Index + 0] = LineColor.r;
            VerLine.data[Index + 1] = LineColor.g;
            VerLine.data[Index + 2] = LineColor.b;
            VerLine.data[Index + 3] = LineColor.a;
        }
    }

    for (var i = 0; i < W; i++) {
        var Index = i * 4;

        if (X_0 <= i && i <= X_1) {
            HorLine.data[Index + 0] = LineColor.r;
            HorLine.data[Index + 1] = LineColor.g;
            HorLine.data[Index + 2] = LineColor.b;
            HorLine.data[Index + 3] = LineColor.a;
        }
    }

    for (var nX = 0; nX < oSize.X; nX++) {
        LinesCanvas.putImageData(VerLine, Lines[nX].X, 0);
    }

    for (var nY = 0; nY < oSize.Y; nY++) {
        LinesCanvas.putImageData(HorLine, 0, Lines[nY].Y);
    }

    if (undefined !== Exclude) {
        var clear_w = Lines[1].X - Lines[0].X + 2;
        var clear_h = Lines[1].Y - Lines[0].Y + 2;

        for (var Index = 0, Count = Exclude.length; Index < Count; Index++) {
            var X = Exclude[Index].X;
            var Y = Exclude[Index].Y;
        }
    }
  }

  const _drawPieces = () => {
    if(!inited) return;
    const {board} = props;
    var W = imageData.W; 
    var H = imageData.H; 

    var PiecesCanvas = htmlElement.Pieces.getContext("2d");
    var size = PieceBoard.board_size;
    PiecesCanvas.canvas.width = W;
    PiecesCanvas.canvas.height = H;
    PiecesCanvas.clearRect(0, 0, W, H);
    for (let y = 0; y < size; y ++){
      for (let x = 0; x < size; x ++) {
        if (PieceBoard.get_piece(x, y) !== -1) {
          drawImg('piece', Logic.APOS(x, y), PieceBoard.get_piece(x, y));
        }}
    }
  }

  const _draw_pngCanvas = (canvas) => {
    var W = imageData.W; 
    var H = imageData.H;
    var size = PieceBoard.board_size;
    switch (board_back) {
      case 0:
        canvas.drawImage(imageData.Board, 0, 0, W, H);
        break;
      case 1:
        canvas.fillStyle = 'rgb(220, 180, 120)';
        canvas.fillRect(0, 0, W, H);
        break;
      case 2:
        canvas.fillStyle = 'rgb(0, 0, 0)';
        canvas.fillRect(0, 0, W, H);
        break;
      case 3:
        canvas.fillStyle = 'rgb(255, 255, 255)';
        canvas.fillRect(0, 0, W, H);
        break;
    }
    
    if (show_grid) {

      var oSize = {X: size, Y: size};
      var Lines = imageData.Lines;

      var X_0 = Lines[0].X;
      var X_1 = Lines[oSize.X - 1].X;

      var Y_0 = Lines[0].Y;
      var Y_1 = Lines[oSize.Y - 1].Y;

      var VerLine = canvas.createImageData(1, Y_1 - Y_0 + 1);
      var HorLine = canvas.createImageData(X_1 - X_0 + 1, 1);

      var LineColor = new CColor(0, 0, 0, 255);
      for (var i = 0; i < H; i++) {
          var Index = i * 4;

          if (i >= Y_0 && i <= Y_1) {
              VerLine.data[Index + 0] = LineColor.r;
              VerLine.data[Index + 1] = LineColor.g;
              VerLine.data[Index + 2] = LineColor.b;
              VerLine.data[Index + 3] = LineColor.a;
          }
      }

      for (var i = 0; i < W; i++) {
          var Index = i * 4;

          if (X_0 <= i && i <= X_1) {
              HorLine.data[Index + 0] = LineColor.r;
              HorLine.data[Index + 1] = LineColor.g;
              HorLine.data[Index + 2] = LineColor.b;
              HorLine.data[Index + 3] = LineColor.a;
          }
      }

      for (var nX = 0; nX < oSize.X; nX++) {
          canvas.putImageData(VerLine, Lines[nX].X, Y_0);
      }

      for (var nY = 0; nY < oSize.Y; nY++) {
          canvas.putImageData(HorLine, X_0, Lines[nY].Y);
      }
    }
    const {board} = props;
    for (let y = 0; y < size; y ++){
      for (let x = 0; x < size; x ++) {
        var piece = PieceBoard.get_piece(x, y);
        if (board.length > 1 && piece !== -1) {
          var _x = imageData.Lines[x].X - rad;
          var _y = imageData.Lines[y].Y - rad;
          var kind = Logic.KIND(piece);
          var index = Logic.INDEX(piece);
          var image = document.getElementById('piece_' + `${kind}_${index}`);
          canvas.drawImage(image, _x, _y, diam, diam);
        }}
    }
  }

  const savePicture = () => {
    var _W = 653;
    var _H = 653;
    var result = document.getElementById('result_png');
    var pngCanvas = result.getContext("2d");
    pngCanvas.clearRect(0, 0, _W, _H);
    _draw_pngCanvas(pngCanvas);
    var png_result = pngCanvas.getImageData(0, 0, _W, _H);

    var png = new PNG({width: _W, height: _H});
    for (let i = 0; i < png.data.length; i ++) {
      png.data[i] = png_result.data[i];
    }

    png.pack();
  }

  var force_redraw = false;
  if (width !== props.width || height !== props.height) {
    force_redraw = true;
    setWidth(props.width);
    setHeight(props.height);
  }
  if (PieceBoard.board_size !== props.size || show_grid !== props.isShowGrid || board_back != props.board_back) {
    force_redraw = true;
    setShowGrid(props.isShowGrid);
    setBoardBack(props.board_back);
    PieceBoard.set_board_size(props.size);
  }
  if(!!inited) {
    force_redraw = true;
  }
  if (force_redraw) {
    onResize(true);
  }
  return (
    <div>
      <div style = {{position: 'fixed', right: '15vw', top: '3vh', zIndex: '1112'}} >
        <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {back_next_board}>
          <i class = "fa fa-share" style = {{fontSize: '2rem', color: 'white'}}/>
        </Button>
      </div>
      <div style = {{position: 'fixed', right: '20vw', top: '3vh', zIndex: '1112'}} >
        <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {back_previous_board}>
          <i class = "fa fa-reply" style = {{fontSize: '2rem', color: 'white'}}/>
        </Button>
      </div>
      <img id="board_back" src="/assets/img/board.jpg" alt="" style={{display: "none"}} onLoad={onResize}/>
      <div id="items" style={{display: "none"}}/>
      <div ref={canvas_ref} id="PDesignBoard"/>
      {/* <canvas id = 'result_png' width = {653} height = {653} style = {{display: 'none'}} /> */}
    </div>
  );
}

const mapStateToProps = (store) => {
  return {
    user: store.authReducer.user,
    size: store.pdesignBoardReducer.board_size,
    isShowGrid: store.pdesignBoardReducer.isShowGrid,
    board_back: store.pdesignBoardReducer.board_back,
    piece_kind: store.pdesignTaskReducer.piece_kind,
    piece_index: store.pdesignTaskReducer.piece_index,
    tool: store.pdesignTaskReducer.tool,
    pen_thick: store.pdesignTaskReducer.pen_thick,
    tool_property: store.pdesignTaskReducer.tool_property,
    board: store.pdesignBoardReducer.board,
    board_updated: store.pdesignBoardReducer.board_updated,
    complete_draw: store.pdesignTaskReducer.complete_draw,

    socketRoom: store.roomReducer.socketRoom,
		room_id: store.roomReducer.room.room_id,
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    update_board: PDesignBoardAction.update_board,
    update_piece_kind: PDesignTaskAction.updatePieceKind,
    update_piece_index: PDesignTaskAction.updatePieceIndex,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(PDesignBoard));
