import React, {useState,useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { makeStyles } from '@material-ui/core/styles';
import {bindActionCreators} from "redux";
import {  
  Button,    
} from '@material-ui/core';
import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import CD from "../../helper/const";

const useStyles = makeStyles(theme => ({
  navigationButtons: {
    position: 'relative',
    width: '21vw',
    height: '8vh',
    background: '#ffffff',
    fontSize: '2.5vh',
    display: 'flex',
    zIndex: '1200',
  },
  navigationButton1: {
    minWidth:'3.5vw',
    width:'3.5vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    color: "#404040",
  },
  navigationButton: {
    minWidth:'3.5vw',
    width:'3.5vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    borderLeft: 'none',
    color: "#404040",
  },
}));

function GrController(props) {
  const classes = useStyles();  
  const {game_type, update_go_gr_index, update_common_gr_index} = props;
  let update_gr_index = game_type === CD.GAME_TYPE.GO? update_go_gr_index : update_common_gr_index;

  const handleToFirst = () => {
    update_gr_index(0);
  }
  const handleToBack5 = () => {
    const {gr_index} = props;
    var gr_idx = gr_index - 5;
    if (gr_idx < 0)
      gr_idx = 0;
    update_gr_index(gr_idx);
  }
  const handleToBack = () => {
    const {gr_index} = props;
    var gr_idx = gr_index - 1;
    if (gr_idx < 0)
      gr_idx = 0;
    update_gr_index(gr_idx);
  }
  const handleToNext = () => {
    const {move_history, gr_index} = props;
    var gr_idx = gr_index + 1;
    if (gr_idx >= move_history.length)
      gr_idx = move_history.length;
    update_gr_index(gr_idx);
  }
  const handleToNext5 = () => {
    const {move_history, gr_index} = props;
    var gr_idx = gr_index + 5;
    if (gr_idx >= move_history.length)
      gr_idx = move_history.length;
    update_gr_index(gr_idx);
  }
  const handleToLast = () => {
    const {move_history} = props;
    var gr_idx = move_history.length;
    update_gr_index(gr_idx);
  }
  return(
    <div className={classes.navigationButtons}>
      <Button disabled = {props.gr_index == 0 ? true : false} className={classes.navigationButton1} style={{padding:'0px', fontSize: 'inherit'}}  onClick={handleToFirst}><i className="fa fa-fast-backward"/></Button>
      <Button disabled = {props.gr_index == 0 ? true : false} className={classes.navigationButton} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToBack5}><i className="fa fa-backward" /></Button>
      <Button disabled = {props.gr_index == 0 ? true : false} className={classes.navigationButton} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToBack}><i className="fa fa-step-backward" /></Button>
      <Button disabled = {props.gr_index == props.move_history.length ? true : false} className={classes.navigationButton} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToNext}><i className="fa fa-step-forward" /></Button>
      <Button disabled = {props.gr_index == props.move_history.length ? true : false} className={classes.navigationButton} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToNext5}><i className="fa fa-forward" /></Button>
      <Button disabled = {props.gr_index == props.move_history.length ? true : false} className={classes.navigationButton} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToLast}><i className="fa fa-fast-forward" /></Button>
    </div>
  )
}
const mapStateToProps = (store) => {
  let game_type = store.commonReducer.content;
  var gr_index, move_history;
  if (game_type === CD.GAME_TYPE.GO) {
    gr_index = store.goReducer.gr_index;
    move_history = store.goReducer.game.move_history;
  } else {
    gr_index = store.commonReducer.gr_index;
    move_history = store.roomReducer.room.move_history;
  }
  return {  
    gr_index,
    move_history,
    game_type,
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {    
    update_go_gr_index: GoAction.update_gr_index,
    update_common_gr_index: CommonAction.update_gr_index,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(GrController);
