import React, {useState,useEffect, useRef} from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { PNG } from 'pngjs/browser';
import { Image } from '@material-ui/icons';
import {Button} from '@material-ui/core';

import * as Logic from './omokLogic';
import OmokLogicBoard from './omokLogic';

import * as PDesignBoardAction from '../../store/actions/pdesign_board.action';
import * as PDesignTaskAction from '../../store/actions/pdesign_task.action';
import * as OmokBoardAction from '../../store/actions/omok_board.action';
import * as OmokAction from '../../store/actions/omok.action';

import PROTOCOL from '../../helper/protocol';

function CColor(r, g, b, a) {
  this.r = r;
  this.g = g;
  this.b = b;
  this.a = typeof a === 'undefined' ? 255 : a;
}

CColor.prototype.ToString = function() {
  return 'rgba(' + this.r + ',' + this.g + ',' + this.b + ',' + this.a / 255 + ')';
};

var board = [];
var drag_state = false;
var piece_kind, piece_index, tool, tool_property, pen_thick;
var diam, rad;
var s_x, s_y, e_x, e_y;
var shift_press = false, ctrl_press = false, ctrl_z_press = false, ctrl_y_press = false;
var temp_boards = [];

var imageData = {
  W: 0,
  H: 0,
  StoneDiam: 0,
  ShadowOff: 0,
  Board: null,
  Lines: null,
  BlackStone: null,
  WhiteStone: null,
};

var htmlElement = {
  Board: null,
  Lines: null,
  Preview: null,
  Shadow: null,
  Stones: null,
}

var coeffOffsetY = 0;
var coeffOffsetX = 0;
var coeffCellW = 0;
var coeffCellH = 0;
var coeffDiam = 0;
var g_dBoardCellW = 23.61;
var g_dBoardHorOffset = 17.51;
var inited = false;
var temp_boards = [], board_index = 0;

function OmokBoard(props) {
  const socketRoom_ref = useRef();

  const [width, setWidth] = useState(100); 
  const [height, setHeight] = useState(100);
  const [show_grid, setShowGrid] = useState(true);
  const [board_back, setBoardBack] = useState(0);
  const [png_result, setPngResult] = useState(new PNG());
  const [first_turn, setFirstTurn] = useState(0);
  const [move_history, setMoveHistory] = useState([]);
  var viewPort = { X0: 0, Y0: 0, X1: OmokLogicBoard.board_size, Y1: OmokBoard.board_size };

  var canvas_ref = useRef("canvas");

  useEffect(() => {
    board_array_init();
    init("OmokBoard");
    onResize(true);
  }, [props.size]);
    
  useEffect(() => {
    init("OmokBoard");
    board_array_init();
    // init_imageLibrary(kind_array);
    onResize(true);
    window.addEventListener("resize", ()=>{
      onResize();
    });
    window.addEventListener("keydown", (e)=>{
      onKeyPress(e);
    });
    window.addEventListener("keyup", (e)=>{
      onKeyUp(e);
    });
    return () => {
      window.onkeypress = null;
    }
  }, []);

  useEffect(() => {
    socketRoom_ref.current = props.socketRoom;
  }, [props.socketRoom]);

  useEffect(() => {
    _drawStones();
  }, [props.board_updated]);

  useEffect(() => {
    if (!props.replay) return;
    const {move_history} = props;
    // OmokLogicBoard.move_history = props.move_history;
    setMoveHistory(props.move_history);
    board_array_init();
  }, [props.move_history]);

  useEffect(() => {
    setFirstTurn(props.first_turn);
  }, [props.first_turn]);

  useEffect(() => {
    if (!props.replay) return;
    if (!!props.move_history && props.move_history.length > 0) {
      const {gr_index} = props;
      var index = gr_index;
      if (index < 0) index = 0;
      if (index > props.move_history.length - 1) index = props.move_history.length - 1;
      empty_board();
      _drawMoveHistory(index);
    } else return;
  }, [props.gr_index]);

  const board_array_init = () => {
    OmokLogicBoard.initialize(props.size);
    update_board();
  };

  const empty_board = () => {
    OmokLogicBoard.empty_board();
    update_board();
  };

  const update_board = () => {
    props.update_board(OmokLogicBoard.board, props.board_updated);
    OmokLogicBoard.update_temp_boards();
  };

  const init = (name) => {
    var boardElem = document.getElementById(name);
    boardElem.innerHTML = null;
    boardElem.onmousemove = onMouseMove;
    boardElem.onmousedown = onMouseDown;
    boardElem.onmouseup = onMouseUp;

    imageData.Board = document.getElementById("board_back");
    imageData.WhiteStone = document.getElementById("white_stone");
    imageData.BlackStone = document.getElementById("black_stone");
    
    var boardName = name + "_BoardCanvas";
    var linesName = name + "_LinesCanvas";
    var shadowsName = name + '_ShadowsCanvas';
    var previewName = name + "_PreviewCanvas";
    var stonesName = name + "_StonesCanvas";
    htmlElement.Board = createCanvasElem(boardElem, boardName);
    htmlElement.Lines = createCanvasElem(boardElem, linesName);
    htmlElement.Shadow = createCanvasElem(boardElem, shadowsName);
    htmlElement.Preview = createCanvasElem(boardElem, previewName);
    htmlElement.Stones = createCanvasElem(boardElem, stonesName);
    htmlElement.Preview.style.opacity = '0.5';
    inited = true;

    imageData.W = htmlElement.Board.width;
    imageData.H = htmlElement.Board.height;
  };

  const createCanvasElem = (parentElem, name) => {
    var elem = document.createElement("canvas");
    elem.setAttribute("id", name);
    elem.setAttribute("style", "position:absolute;padding:0;margin:0;");
    elem.setAttribute("oncontextmenu", "return false;");
    elem.setAttribute("width", parentElem.clientWidth);
    elem.setAttribute("height", parentElem.clientHeight);
    parentElem.appendChild(elem);
    return elem;
  };

  const _getBoardPosXY = (_X, _Y) => {
    var W = imageData.W;
    var H = imageData.H;

    var dCellH = coeffCellH * H;
    var dCellW = coeffCellW * W;
    var dHorOff = coeffOffsetX * W - dCellH * viewPort.X0;
    var dVerOff = coeffOffsetY * H - dCellW * viewPort.Y0;

    var Y = 0;
    var size = OmokLogicBoard.board_size;

    var oSize = { X: size, Y: size };
    for (Y = 0; Y < oSize.Y - 1; Y++) {
        if (_Y > dVerOff + dCellH * Y + dCellH / 2)
            continue;
        else {
            break;
        }
    }

    var X = 0;
    for (X = 0; X < oSize.X - 1; X++) {
        if (_X > dHorOff + dCellW * X + dCellW / 2)
            continue;
        else {
            break;
        }
    }

    X = Math.max(viewPort.X0, Math.min(size, X));
    Y = Math.max(viewPort.Y0, Math.min(size, Y));

    return {X: X, Y: Y};
  };

  const _handleMouseDown = (pos, event) => {
    const {socketRoom, user, room_id} = props;
    if (OmokLogicBoard.board[OmokLogicBoard.APOS(pos.X, pos.Y)] != Logic.EMPTY) return;
    // var color = shift_press ? Logic.WHITE : Logic.BLACK;
    if (OmokLogicBoard.putable) {
      // OmokLogicBoard.put_stone(pos.X, pos.Y, OmokLogicBoard.mine_color);
      // _putStone('put', OmokLogicBoard.APOS(pos.X, pos.Y), OmokLogicBoard.mine_color);
      let move = OmokLogicBoard.APOS(pos.X, pos.Y);
      if (!!socketRoom_ref.current){
        socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_GAME_MOVE, {token: !!user? user.token : null, room_id: room_id, move: move});
      }
    }
  }

  const _handleMouseMove = (pos, event) => {
    if (OmokLogicBoard.board[OmokLogicBoard.APOS(pos.X, pos.Y)] != Logic.EMPTY || !OmokLogicBoard.putable) return;
    // var color = shift_press ? Logic.WHITE : Logic.BLACK;
    _putStone('preview', OmokLogicBoard.APOS(pos.X, pos.Y), OmokLogicBoard.mine_color);
  };

  const _handleMouseUp = (pos, e) => {
    update_board();
    // _drawStones();
  }

  const onMouseMove = (e) => {
    if(!inited) return;
    var pos = _getBoardPosXY(e.offsetX, e.offsetY);
    var preview = htmlElement.Preview.getContext('2d');
    preview.clearRect(0, 0, imageData.W, imageData.H);
    _handleMouseMove(pos, e);
  };

  const onMouseDown = (e) => {
    if(!inited) return;
    drag_state = true;
    var pos = _getBoardPosXY(e.offsetX, e.offsetY);
    s_x = pos.X;
    s_y = pos.Y;
    _handleMouseDown(pos, e);
  };

  const onMouseUp = (e) => {
    if(!inited) return;
    drag_state = false;
    var preview = htmlElement.Preview.getContext('2d');
    preview.clearRect(0, 0, imageData.W, imageData.H);
    var pos = _getBoardPosXY(e.offsetX, e.offsetY);
    _handleMouseUp(pos, e);
  };

  const onKeyUp = (e) => {
    if (e.keyCode == 0x10) shift_press = false;
    if (e.keyCode == 0x11) {
      ctrl_z_press = false;
      ctrl_y_press = false;
      ctrl_press = false;
    }
    if (e.keyCode == 0x5a && ctrl_z_press) {
      back_previous_board();
    }
    if (e.keyCode == 0x59 && ctrl_y_press) {
      back_next_board();
      _drawStones();
    }
  };
  const onKeyPress = (e) => {
    if (e.keyCode == 0x10) shift_press = true;
    if (e.keyCode == 0x11) ctrl_press = true;
    if (ctrl_press == true && e.keyCode == 0x5a) ctrl_z_press = true;
    if (ctrl_press == true && e.keyCode == 0x59) ctrl_y_press = true;
  };

  const back_previous_board = () => {
    OmokLogicBoard.back_previous_board();
    _drawStones();
  }

  const back_next_board = () => {
    OmokLogicBoard.back_next_board();
    _drawStones();
  }

  const _putStone = (canvas, pos, color) => {
    var Canvas = canvas == 'put' ? htmlElement.Stones.getContext("2d") : htmlElement.Preview.getContext("2d");
    var image;
    var _X = OmokLogicBoard.X(pos);
    var _Y = OmokLogicBoard.Y(pos);
    var size = OmokLogicBoard.board_size;
    if (_X > size - 2) _X = size - 1;
    if (_Y > size - 1) _Y = size - 1;
    if (_X < 0) _X = 0;
    if (_Y < 0) _Y = 0;
    var x = imageData.Lines[_X].X - rad;
    var y = imageData.Lines[_Y].Y - rad;
    var num = OmokLogicBoard.numboard[pos];
    var fontFamily = "cursive";
    var fontSize = rad;
    var font = fontSize + "px " + fontFamily;
    var x_offset = (diam - Canvas.measureText(num).width) / 2;
    var y_offset = diam / 2 + fontSize / 3;
    Canvas.clearRect(x, y, diam, diam);
    Canvas.font = font;
    if (color == Logic.EMPTY) return;
    else if (color == Logic.WHITE) {
      image = imageData.WhiteStone;
      if (canvas == 'put') {
        Canvas.fillStyle = '#000';
        Canvas.strokeStyle = '#000';
      }
    } else {
      image = imageData.BlackStone;
      if (canvas == "put") {
        Canvas.fillStyle = '#FFF';
        Canvas.strokeStyle = '#FFF';
      }
    }
    if (!!image) {
      Canvas.drawImage(image, x, y, diam, diam);
      if (!!num) Canvas.fillText(num, x + x_offset, y + y_offset);
      if (OmokLogicBoard.last_move == pos) {
        Canvas.beginPath();
        Canvas.arc(x + rad, y + rad, rad / 2 + 2, 0, Math.PI * 2, false);
        Canvas.stroke();
      }
    }
  }

  const _updateCoeffs = () => {
    var size = OmokLogicBoard.board_size;
    var dAbsBoardW = (size - 1) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsBoardH = (size - 1) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsHorOff = g_dBoardHorOffset;
    var dAbsVerOff = g_dBoardHorOffset;

    coeffCellH = g_dBoardCellW / dAbsBoardH;
    coeffCellW = g_dBoardCellW / dAbsBoardW;
    coeffOffsetX = dAbsHorOff / dAbsBoardW;
    coeffOffsetY = dAbsVerOff / dAbsBoardH;
    coeffDiam = 4 / dAbsBoardW;
    diam = coeffCellW * imageData.W;
    rad  = diam / 2;
  };

  const onResize = (force) => {
    _updateCoeffs();

    if(!inited) return;

    var div = document.getElementById("OmokBoard");

    if(!div)
      return;

    var W = parseInt(width * window.innerWidth / 100);
    var H = parseInt(height * window.innerHeight / 100);

    var _W = H;
    var _H = W;
    var marginLeft = 0;
    if (_W <= W) {
      marginLeft = (W - _W) / 2;
      W = _W;
    } 
    else H = _H;

    div.style.width = W + "px";
    div.style.height = H + "px";
    div.style.marginLeft = 0 + 'px';

    if (W !== imageData.W || H !== imageData.H || force) {
        imageData.W = W;
        imageData.H = H;

        var DWidth = Math.floor(imageData.W) - 1;

        var d = Math.floor(DWidth / 2) * 2 + 1;
        imageData.StoneDiam = d;

        _createLines();
    }
    drawBoard();
  };
  const _createLines = () => {
    var W = imageData.W;
    var H = imageData.H;
    var size = OmokLogicBoard.board_size;

    if (0 === W || 0 === H)
        return;

    var dHorOff = coeffOffsetX * W;
    var dVerOff = coeffOffsetY * H;
    var dCellH = coeffCellH * H;
    var dCellW = coeffCellW * W;

    var Lines = new Array(size);

    var X_startoffset = dHorOff;
    var Y_startoffset = dVerOff;

    var X, Y, X_G, Y_G, X_L, Y_L, X_G2, Y_G2, X_L2, Y_L2;
    for (var Index = 0; Index < size; Index++) {
        X = X_startoffset + Index * dCellW;

        X_G = X_startoffset + Index * dCellW + 0.6 * dCellW;
        X_L = X_startoffset + Index * dCellW - 0.6 * dCellW;
        X_G2 = X_startoffset + Index * dCellW + 0.5 * dCellW;
        X_L2 = X_startoffset + Index * dCellW - 0.5 * dCellW;
        Y = Y_startoffset + Index * dCellH;
        Y_G = Y_startoffset + Index * dCellH + 0.6 * dCellH;
        Y_L = Y_startoffset + Index * dCellH - 0.6 * dCellH;
        Y_G2 = Y_startoffset + Index * dCellH + 0.5 * dCellH;
        Y_L2 = Y_startoffset + Index * dCellH - 0.5 * dCellH;

        Lines[Index] =
            {
                X: Math.floor(X + 0.5),
                X_G: Math.floor(X_G + 0.5),
                X_L: Math.floor(X_L + 0.5),
                X_G2: Math.floor(X_G2 + 0.5),
                X_L2: Math.floor(X_L2 + 0.5),
                Y: Math.floor(Y + 0.5),
                Y_G: Math.floor(Y_G + 0.5),
                Y_L: Math.floor(Y_L + 0.5),
                Y_G2: Math.floor(Y_G2 + 0.5),
                Y_L2: Math.floor(Y_L2 + 0.5)
            };
    }
    imageData.Lines = Lines;
  }

  const drawBoard = () => {
    if(!inited) return;

    _drawBoard();
    _drawStones();
    _drawTrueColorLines();
  }
  const _drawBoard = () => {
    var BoardCanvas = htmlElement.Board.getContext("2d");
   
    var W = imageData.W; 
    var H = imageData.H;   
    var d = W / 64;

    var ShadowCanvas = htmlElement.Shadow.getContext("2d");
    ShadowCanvas.canvas.width = W + 2*d;
    ShadowCanvas.canvas.height = H + 2*d;
    ShadowCanvas.shadowBlur = d;
    ShadowCanvas.shadowOffsetX = d;
    ShadowCanvas.shadowOffsetY = d;
    ShadowCanvas.shadowColor = "black";
    ShadowCanvas.fillStyle = 'rgb(219,187,114,0.5)';
    ShadowCanvas.fillRect(0, 0, W, H);
    ShadowCanvas.clearRect(0, 0, W, H);
 
    BoardCanvas.canvas.width = W;
    BoardCanvas.canvas.height = H;
    BoardCanvas.drawImage(imageData.Board, 0, 0, W, H);
  }
  const _drawTrueColorLines = (Exclude) => {
    if (!inited||!imageData.Lines) return;

    var W = imageData.W;
    var H = imageData.H;

    var LinesCanvas = htmlElement.Lines.getContext("2d");
    var size = OmokLogicBoard.board_size;
    LinesCanvas.canvas.width = W;
    LinesCanvas.canvas.height = H;

    var oSize = {X: size, Y: size};
    var Lines = imageData.Lines;

    LinesCanvas.clearRect(0, 0, W, H);

    var X_0 = Lines[0].X;
    var X_1 = Lines[oSize.X - 1].X;

    var Y_0 = Lines[0].Y;
    var Y_1 = Lines[oSize.Y - 1].Y;

    var VerLine = LinesCanvas.createImageData(1, H);
    var HorLine = LinesCanvas.createImageData(W, 1);

    var LineColor = new CColor(0, 0, 0, 255);
    for (var i = 0; i < H; i++) {
        var Index = i * 4;

        if (i >= Y_0 && i <= Y_1) {
            VerLine.data[Index + 0] = LineColor.r;
            VerLine.data[Index + 1] = LineColor.g;
            VerLine.data[Index + 2] = LineColor.b;
            VerLine.data[Index + 3] = LineColor.a;
        }
    }

    for (var i = 0; i < W; i++) {
        var Index = i * 4;

        if (X_0 <= i && i <= X_1) {
            HorLine.data[Index + 0] = LineColor.r;
            HorLine.data[Index + 1] = LineColor.g;
            HorLine.data[Index + 2] = LineColor.b;
            HorLine.data[Index + 3] = LineColor.a;
        }
    }

    for (var nX = 0; nX < oSize.X; nX++) {
        LinesCanvas.putImageData(VerLine, Lines[nX].X, 0);
    }

    for (var nY = 0; nY < oSize.Y; nY++) {
        LinesCanvas.putImageData(HorLine, 0, Lines[nY].Y);
    }

    if (undefined !== Exclude) {
        var clear_w = Lines[1].X - Lines[0].X + 2;
        var clear_h = Lines[1].Y - Lines[0].Y + 2;

        for (var Index = 0, Count = Exclude.length; Index < Count; Index++) {
            var X = Exclude[Index].X;
            var Y = Exclude[Index].Y;
        }
    }
  }

  const _drawMoveHistory = (gr_index) => {
    var W = imageData.W;
    var H = imageData.H;
    var PiecesCanvas = htmlElement.Stones.getContext('2d');
    var size = OmokLogicBoard.board_size;
    PiecesCanvas.canvas.width = W;
    PiecesCanvas.canvas.height = H;
    PiecesCanvas.clearRect(0, 0, W, H);
    var num = 0;
    for (let i = 0; i < gr_index; i ++) {
      var pos = move_history[i];
      if (pos == 100) continue;
      OmokLogicBoard.numboard[pos] = i + 1;
      props.do_move(pos, i % 2 + 1);
    }
  }

  const _drawStones = () => {
    if(!inited) return;
    const {board} = props;
    var W = imageData.W; 
    var H = imageData.H; 

    var PiecesCanvas = htmlElement.Stones.getContext("2d");
    var size = OmokLogicBoard.board_size;
    PiecesCanvas.canvas.width = W;
    PiecesCanvas.canvas.height = H;
    PiecesCanvas.clearRect(0, 0, W, H);
    var num = 0;
    if (!!OmokLogicBoard.move_history && OmokLogicBoard.move_history.length > 0) {
      for (let i = 0; i < OmokLogicBoard.move_history.length; i ++) {
        var pos = OmokLogicBoard.move_history[i];
        if (!!pos) {
          OmokLogicBoard.numboard[pos] = i + 1;
          _putStone('put', pos, board[pos]);
        }
      }
    }
  }

  var force_redraw = false;
  if (width !== props.width || height !== props.height) {
    force_redraw = true;
    setWidth(props.width);
    setHeight(props.height);
  }
  if (OmokLogicBoard.board_size !== props.size ) {
    force_redraw = true;
    // OmokLogicBoard.initialize(props.size);
    OmokLogicBoard.set_board_size(props.size);
  }
  if(!!inited) {
    force_redraw = true;
  }
  if (force_redraw) {
    onResize(true);
  }
  return (
    <div>
      <img id="board_back" src="/assets/img/board.jpg" alt="" style={{display: "none"}} onLoad={onResize}/>
      <div id="items" style={{display: "none"}}>
        <img id="white_stone" src="/assets/img/stone_w.png"/>
        <img id="black_stone" src="/assets/img/stone_b.png"/>
      </div>
      <div ref={canvas_ref} id="OmokBoard"/>
      {/* <canvas id = 'result_png' width = {653} height = {653} style = {{display: 'none'}} /> */}
    </div>
  );
}

const mapStateToProps = (store) => {
  return {
    user: store.authReducer.user,
    size: store.omokBoardReducer.board_size,
    piece_kind: store.pdesignTaskReducer.piece_kind,
    piece_index: store.pdesignTaskReducer.piece_index,
    tool: store.pdesignTaskReducer.tool,
    pen_thick: store.pdesignTaskReducer.pen_thick,
    tool_property: store.pdesignTaskReducer.tool_property,
    board: store.omokBoardReducer.board,
    board_updated: store.omokBoardReducer.board_updated,
    move_history: store.roomReducer.room.move_history,
    
    socketRoom: store.roomReducer.socketRoom,
		room_id: store.roomReducer.room.room_id,
    gr_index: store.commonReducer.gr_index,
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    update_board: OmokBoardAction.update_board,
    update_piece_kind: PDesignTaskAction.updatePieceKind,
    update_piece_index: PDesignTaskAction.updatePieceIndex,
    do_move: OmokAction.do_move,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(OmokBoard));
