import React, {useState,useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import {
  Button,
  Avatar
} from '@material-ui/core';
import CD, { GAME_TYPE } from "../../helper/const";
import * as Icon from "@material-ui/icons";
import { makeStyles } from '@material-ui/core/styles';
import * as AuthAction from '../../store/actions/auth.action';
import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import { bindActionCreators } from 'redux';
import {
  MDBRow, 
  MDBBtn,
} from "mdbreact";
import {notify_w} from "../../helper/alert";

const useStyles = makeStyles(theme => ({
  tabOtherStyle: {
    whiteSpace: 'nowrap',
    height: "5vh",
    color: "black",
    fontSize: "2vh",
    fontFamily: "Bell MT",
    borderRadius: '0',
    paddingTop: "1.3vh",
    paddingBottom: "1vw", 
    paddingLeft: "2vw",
    paddingRight: "2vw",
    backgroundColor: 'rgba(0, 0, 0, 0)',
  },
}));


function OtherGameBtn(props) {

  const classes = useStyles();

  const setGameType = (game_type) => {
    props.setGame(game_type);
  }

  useEffect(() => {
    var set_btn = document.getElementById(`button_${props.gameType - 3}`);
    for (let i = 0; i < 3; i ++) {
      var button = document.getElementById(`button_${i}`);
      button.style.border = 'none';
      button.style.borderBottom = 'dashed 1px rgb(0, 206, 209)';
      button.style.color = 'rgb(130, 130, 130)';
      button.style.fontWeight = '100';
    }
    set_btn.style.color = 'rgb(0, 0, 0)';
    set_btn.style.border = 'dashed 1px rgb(0, 206, 209)';
    set_btn.style.borderBottom = 'none';
    set_btn.style.fontWeight = 'bold';
  }, [props.gameType]);

  return (
    <div style = {{position: 'fixed', top: '10vh', left: '17vw', width: "80vw", marginBottom: '1vh'}}>
      <Button
        id = "button_0"
        onClick={setGameType.bind(this, CD.GAME_TYPE.FFA)}
        className={classes.tabOtherStyle}
      >
        {/* <img src={"/assets/img/FFA_Icon.svg"} className = {classes.svgIconStyle2} alt="icon" /> */}
        {window.i18n.t("gameType.FFA")}
      </Button>

      <Button
        id = "button_1"
        onClick={setGameType.bind(this, CD.GAME_TYPE.SKPNI)}
        className={classes.tabOtherStyle}
      >
        {/* <img src={"/assets/img/KPNI_Icon.svg"} className = {classes.svgIconStyle2} alt="icon" /> */}
        {window.i18n.t("gameType.star_kpni")}
      </Button>

      <Button
        id = "button_2"
        onClick={setGameType.bind(this, CD.GAME_TYPE.OMOK)}
        className={classes.tabOtherStyle}
      >
        {/* <img src={"/assets/img/KPNI_Icon.svg"} className = {classes.svgIconStyle2} alt="icon" /> */}
        {window.i18n.t("gameType.omok")}
      </Button>
      <div style = {{position: 'fixed', top: '10vh', left: '38vw', width: "65vw", height: '4.8vh', borderBottom: 'dashed 1px rgb(0, 206, 209)'}}></div>
    </div>
  );
}
function mapStateToProps(store) {
  return {
    gameType:store.commonReducer.content,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      setGame: CommonAction.setGame,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(OtherGameBtn));