import ACTION from '../actionTypes';

export const update_game_result = ( result, player1_update_coin, player2_update_coin) => dispatch => { 
  dispatch({
    type: ACTION.UPDATE_GAME_RESULT,
    result,
  });
  dispatch({
    type: ACTION.UPDATE_COIN_RESULT,
    player1_update_coin:player1_update_coin,
    player2_update_coin:player2_update_coin,
  });
}

export function set_open_multiple_dlg() {
  return {
    type: ACTION.SET_OPEN_MULTIPLE_DLG,
  }
}

export function update_game_start() {
  return {
    type: ACTION.UPDATE_GAME_START,
  }
}

export function set_mine_number(mineNumber) { 
  return {
    type: ACTION.SET_MINE_NUMBER,
    mineNumber:mineNumber,
  }
}

export function update_skpni_user_count(count) { 
  return {
    type: ACTION.UPDATE_SKPNI_USER_COUNT,
    count   
  }
}
