import React, { useEffect } from 'react';
import { useSnackbar } from 'notistack';
import {connect} from 'react-redux';
import { Link, withRouter} from "react-router-dom";
import { makeStyles } from '@material-ui/core/styles';
import Typography from '@material-ui/core/Typography';
import * as CommonAction from "../../store/actions/common.action";
import {
  MDBInput,
  MDBBtn,
  MDBSelectOption,
  MDBRow
} from 'mdbreact';
import {
  MenuItem,
  Select, 
} from "@material-ui/core";
import {registerUser} from '../../store/actions/auth.action';
import SparkLine from '../util/SparkLine';
const useStyles = makeStyles(theme => ({
  svgStyle: {
    position: 'fixed',
    top:'12vh',
    marginBottom: '6vw',
    marginLeft: '-1vw',
    width: '1000px',
    height: '600px',
    backgroundColor: 'none',
    transform: 'scale(1, 1)',
    background: "url(/assets/img/Mark_back.svg)",
    backgroundSize: 'cover'
  },
  fontStyle: {
    color: '#616b76',
    fontSize: 20,
    paddingTop: '2vh',
    paddingBottom: '3vh',
    marginLeft: '8px',
  },
  container: {
    display: 'inline-grid',
    marginTop:'4vh',
    position:'fixed',
    // boxShadow:'0px 0px 15px rgba(0, 0, 0, 0.7)',
    width: '40vw',
    left:'35vw',
    padding: '2vw',
    paddingTop: '0vw',
    backgroundSize: 'contain',  
    
    borderRadius:'40px',
    backgroundColor: 'rgba(0, 0, 0, 0.0)',
  },
}));


function Register(props) {
  // const [labelWidth, setLabelWidth] = React.useState(0);
  const {enqueueSnackbar} = useSnackbar();
  const showSnackbar = (msg, value) => {
    enqueueSnackbar(msg, { varient: value });
  }
  const [user_id, setUserid] = React.useState('');
  const [pwd, setPwd] = React.useState('');
  const [pwd_verify, setPwdVerify] = React.useState('');
  const [gender, setGender] = React.useState(0);
  const [name, setName] = React.useState('');
  const [birth, setBirth] = React.useState('');
  const [phone, setPhone] = React.useState(''); 
  const [certification, setCertification] = React.useState('');
  // const labelRef = React.useRef(null);
  const classes = useStyles();
  const submitHandler = event => {
    if(user_id != "" && pwd != "" && pwd_verify != "" && name != ""){ // && birth != "" && phone != "" && certification != ""){
      if (pwd.length < 6) {
        showSnackbar("The password must be longer than 6 letters!");
      } else if (pwd != pwd_verify) {
        showSnackbar("password is not match!");
      } else {
        event.preventDefault();
        const { history, registerUser } = props;
        registerUser({user_id, pwd, name, gender, birth, phone, certification}, history);   
        props.showHiddenSideBar("14.5vw", true);
      }
    } else {
      showSnackbar("Please enter your all information", "info");
    }
  };

  const changeHandler = event => {
    switch (event.target.name) {
      case 'user_id':
        setUserid(event.target.value);
        break;
      case 'pwd':
        setPwd(event.target.value);
        break;
      case 'pwd_verify':
        setPwdVerify(event.target.value);
        break;
      case 'gender':
        setGender(event.target.value);
        break;
      case 'name':
        setName(event.target.value);
        break;
      case 'birth':
        setBirth(event.target.value);
        break;
      case 'phone':
        setPhone(event.target.value);
        break;
        case 'certification':
          setCertification(event.target.value);
          break;
      default:
        break;
    }
    // React.useState({ ...state, [event.target.name]: event.target.value });
  };
  //
  useEffect(()=>{
    props.showHiddenSideBar("14.5vw", true);
  }, []);
  return (
    <React.Fragment>

        <svg className={classes.svgStyle}>
          {/* <path d="M 188 0 4 158 C 4 158 -10 180 12 186 L 12 186 274 240 C 274 240 310 246 320 224 L 320 224 390 120 310 192 C 310 192 292 212 268 206 L268 206 74 170 C 74 170 40 164 62 138 L62 138Z" stroke="#99ccff" strokeWidth="1" fill="#99ccff" />
          <path d="M 34 240 292 327 C 292 327 334 342 352 304 L 352 304 416 170 C 416 170 417 166 418 162 L418 162 418 120 C 418 120 418 76 376 106 C 376 106 400 92 402 112 L402 112 402 146 C 402 146 401.5 154 401 162 L401 162 342 270 C 342 270 324 308 286 298 L286 298Z" stroke="#cce6ff" strokeWidth="1" fill="#cce6ff" /> */}
          {/* <path d="M100 100C100 100 200 200 300 200 S 150 250 400 400z"></path> */}
          
          Sorry, your browser does not support inline SVG.
        </svg>
      <div className={classes.container}>
        <Typography variant="h6" className={classes.fontStyle}>
          {window.i18n.t("register.create_new_account")}
        </Typography>
          <div className="grey-text">
            <MDBInput
              label={window.i18n.t("login.user_id")}
              icon="user"
              group
              type="text"
              validate
              required
              name="user_id"
              value={user_id}
              onChange={changeHandler}
              style = {{backgroundColor:'rgba(243, 243, 243, 0)'}}
              />
            <MDBInput 
              label={window.i18n.t("login.password")}
              icon="lock"
              group 
              type="password" 
              validate 
              required
              name="pwd"
              value={pwd}
              onChange={changeHandler}
              style = {{backgroundColor:'rgba(243, 243, 243, 0)'}}
            />            
            <MDBInput 
              label={window.i18n.t("profile.password_verify")}
              icon="lock"
              group 
              type="password" 
              validate 
              required
              name="pwd_verify"
              value={pwd_verify}
              onChange={changeHandler}
              style = {{backgroundColor:'rgba(243, 243, 243, 0)'}}
            />            

            <MDBInput           
              label={window.i18n.t("profile.full_name")}
              icon="user"
              group
              type="text"
              validate
              required
              name="name"
              value={name}
              style = {{marginTop:'1vw', backgroundColor:'rgba(243, 243, 243, 0)'}}
              onChange={changeHandler}
              />  
         
            <i style={{fontSize:"2vw", marginRight:"2vw"}} className={ "fa fa-male"}/>
            <Select 
              style={{ width:"36.5vw",backgroundColor:'rgba(243, 243, 243, 0)'}}
              name="gender"                         
              value={gender}
              onChange={changeHandler}
              >
              <MenuItem   icon="lock"  value={0}>{window.i18n.t("register.male")}</MenuItem>
              <MenuItem value={1}>{window.i18n.t("register.female")}</MenuItem>
            </Select>
               
            {/* <MDBInput   
              icon = "star"
              group
              type="Date"
              validate
              require
              name="birth"
              value={birth}
              onChange={changeHandler}
              style = {{backgroundColor:'rgba(243, 243, 243, 0)'}}
              />
            <MDBInput
              label="phone number"
              icon="phone"
              group
              type="text"
              validate
              required
              name="phone"
              value={phone}
              onChange={changeHandler}
              style = {{backgroundColor:'rgba(243, 243, 243, 0)'}}
              />
            <MDBInput
              label="certification"
              icon="certificate"
              group
              type="text"
              validate
              required
              name="certification"
              value={certification}
              onChange={changeHandler}
              style = {{backgroundColor:'rgba(243, 243, 243, 0)'}}
              />            */}
          </div>
          <div className="text-center"  style = {{maringTop:'3vh', height:'2vw', paddingTop:'5vh'}} onClick = {submitHandler}>
            <MDBBtn style = {{width: '7vw'}} className = "px-2 py-2" color="cyan" type="submit">{window.i18n.t("menu.register")}</MDBBtn>
          </div>
      </div>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  error: store.authReducer.error,
  history: store.history,
})

const mapDispatchToProps = {
  registerUser,
  showHiddenSideBar: CommonAction.show_hidden_sidebar,
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Register))