import { Sort } from "@material-ui/icons";
import { position } from "polished";

export const MX_BOARD_SIZE = 8;
export const MN_BOARD_SIZE = 6;

export const BOARD_LEN =  MX_BOARD_SIZE * MX_BOARD_SIZE;

export const EMPTY = 0;
export const BLACK = 1;
export const WHITE = 2;

// export function APOS(x, y) { return y * MX_BOARD_SIZE + x; }
// export function X(pos) { return pos % MX_BOARD_SIZE; }
// export function Y(pos) { return parseInt(pos / MX_BOARD_SIZE); }
class OmokLogicBoard {

  constructor (board_size) {
    this.initialize(board_size);
  }

  initialize(board_size) {
    this.board_size = board_size;
    this.board = new Array(BOARD_LEN).fill(EMPTY);
    this.temp_board = new Array(BOARD_LEN).fill(EMPTY);
    this.init_check_board();
    this.numboard = new Array(BOARD_LEN).fill(null);
    this.blackStones = new Array(BOARD_LEN).fill(EMPTY);
    this.whiteStones = new Array(BOARD_LEN).fill(EMPTY);
    this.temp_boards = [];
    this.board_index = 0;
    this.moves = [];
    this.first = BLACK;
    this.turn = this.first;
    this.gridx = 0;
    this.last_num = 0;
    this.complete = false;
    this.five_stone_array = [];
    this.last_move = null;
    this.last_color = null;
    this.mine_color = BLACK;
    this.putAble = false;
    this.move_history = [];
  }

  APOS(x, y) { return y * this.board_size + x; }
  X(pos) { return pos % this.board_size; }
  Y(pos) { return parseInt(pos / this.board_size); }

  init_check_board() {
    this.hor_check_board = new Array(BOARD_LEN).fill(0);
    this.ver_check_board = new Array(BOARD_LEN).fill(0);
    this.l_cross_check_board = new Array(BOARD_LEN).fill(0);
    this.r_cross_check_board = new Array(BOARD_LEN).fill(0);
  }

  empty_board() {
    if (!!this.board) this.board = null;
    this.board = new Array(BOARD_LEN).fill(EMPTY);
    this.numboard = new Array(BOARD_LEN).fill(null);
    this.move_history = [];
  }

  set_board_size(board_size) {
    this.board_size = board_size;
  }

  get_color(x, y) {
    return this.board[this.APOS(x,y)];
  }

  getturn() {return this.turn;}

  getfirstmove() {
    return this.moves[0];
  }

  setturn(color) {
    this.turn = color;
    if (this.gridx === 0)
      this.first = this.turn;
  }

  update_temp_boards() {
    if (this.board_index !== this.temp_boards.length - 1){
      var temp_boards_temp = [];
      for (let i = 0; i < this.board_index; i ++) {
        temp_boards_temp.push([].concat(this.temp_boards[i]));
      }
      this.temp_boards = null;
      this.temp_boards = [].concat(temp_boards_temp);
    }
    this.temp_boards.push([].concat(this.board));
    if (this.temp_boards.length > 10) this.temp_boards.shift();
    this.board_index = this.temp_boards.length - 1;
  }

  remove_last_move() {
    this.board[this.last_move] = EMPTY;
    this.numboard[this.last_move] = 0;
    // this.move_history.pop(this.last_move);
  }

  back_previous_board() {
    this.board_index --;
    if (this.board_index < 0) this.board_index = 0;
    this.board = this.temp_boards[this.board_index];
  }

  back_next_board() {
    this.board_index ++;
    if (this.board_index > this.temp_boards.length - 1) this.board_index = this.temp_boards.length - 1;
    this.board = this.temp_boards[this.board_index];
  }

  put_stone(X, Y, color) {
    this.board[this.APOS(X, Y)] = color;
    this.last_move = this.APOS(X, Y);
    this.last_color = color;
    this.move_history.push(this.APOS(X, Y));
    if (color == WHITE) {
      this.whiteStones[(this.APOS(X, Y))] = WHITE;
    } else if (color == BLACK) {
      this.blackStones[(this.APOS(X, Y))] = BLACK;
    }
    // this.check_stone(APOS(X, Y));
  }
  
  check_stone(cur_pos) {
    var cur = this.board[cur_pos];
    var stone = [];
    var complete = false;
    var poss_ver = [];
    var poss_l_cross = [];
    var poss_r_cross = [];
    this.init_check_board();
    var poss_hor = this.check_hor(cur, cur_pos);
    var poss_ver = this.check_ver(cur, cur_pos);
    var poss_l_cross = this.check_l_cross(cur, cur_pos);
    var poss_r_cross = this.check_r_cross(cur, cur_pos);
    
    if (poss_hor.length >= 5) {complete = true; stone.push(poss_hor);};
    if (poss_ver.length >= 5) {complete = true; stone.push(poss_ver);};
    if (poss_l_cross.length >= 5) {complete = true; stone.push(poss_l_cross);};
    if (poss_r_cross.length >= 5) {complete = true; stone.push(poss_r_cross);};
    
    this.complete = complete;
    this.five_stone_array = stone;
  }

  check_hor(cur, cur_pos) {
    var poss = [];
    var poss_l = this.check_l_hor(cur, cur_pos, []);
    var poss_r = this.check_r_hor(cur, cur_pos, poss_l);
    this.hor_check_board[cur_pos] = 1;
    poss.push(cur_pos);
    for (let i = 0; i < poss_r.length; i ++) {
      poss.push(poss_r[i]);
    }
    return poss.sort((a, b) => a - b);
  }
  
  check_ver(cur, cur_pos) {
    var poss = [];
    var poss_up = this.check_u_ver(cur, cur_pos, []);
    var poss_down = this.check_d_ver(cur, cur_pos, poss_up);
    this.ver_check_board[cur_pos] = 1;
    poss.push(cur_pos);
    for (let i = 0; i < poss_down.length; i ++) {
      poss.push(poss_down[i]);
    }
    return poss.sort((a, b) => a - b);
  }

  check_l_cross(cur, cur_pos) {
    var poss = [];
    var poss_up_l = this.check_u_l_cross(cur, cur_pos, []);
    var poss_down_l = this.check_d_l_cross(cur, cur_pos, poss_up_l);
    this.l_cross_check_board[cur_pos] = 1;
    poss.push(cur_pos);
    for (let i = 0; i < poss_down_l.length; i ++){
      poss.push(poss_down_l[i]);
    }
    return poss.sort((a, b) => a - b);
  }

  check_r_cross(cur, cur_pos) {
    var poss = [];
    var poss_up_r = this.check_u_r_cross(cur, cur_pos, []);
    var poss_down_r = this.check_d_r_cross(cur, cur_pos, poss_up_r);
    this.r_cross_check_board[cur_pos] = 1;
    poss.push(cur_pos);
    for (let i = 0; i < poss_down_r.length; i ++) {
      poss.push(poss_down_r[i]);
    }
    return poss.sort((a, b) => a - b);
  }

  check_l_hor(cur, cur_pos, poss) {
    if(this.X(cur_pos) == 0) return poss;
    cur_pos --;
    if(this.board[cur_pos] == cur && this.hor_check_board[cur_pos] == 0) {
      poss.push(cur_pos);
      this.hor_check_board[cur_pos] = 1;
      this.check_l_hor(cur, cur_pos, poss);
    }
    return poss;
  }

  check_r_hor(cur, cur_pos, poss) {
    if (this.X(cur_pos) == this.board_size - 1) return poss;
    cur_pos ++;
    if(this.board[cur_pos] == cur && this.hor_check_board[cur_pos] == 0){
      poss.push(cur_pos);
      this.hor_check_board[cur_pos] = 1;
      this.check_r_hor(cur, cur_pos, poss);
    }
    return poss;
  };

  check_u_ver(cur, cur_pos, poss) {
    if(this.Y(cur_pos) == 0) return poss;
    cur_pos -= this.board_size;
    if (this.board[cur_pos] == cur && this.ver_check_board[cur_pos] == 0){
      poss.push(cur_pos);
      this.ver_check_board[cur_pos] = 1;
      this.check_u_ver(cur, cur_pos, poss);
    }
    return poss;
  };

  check_d_ver(cur, cur_pos, poss) {
    if(this.Y(cur_pos) == this.board_size - 1) return poss;
    cur_pos += this.board_size;
    if (this.board[cur_pos] == cur && this.ver_check_board[cur_pos] == 0){
      poss.push(cur_pos);
      this.ver_check_board[cur_pos] = 1;
      this.check_d_ver(cur, cur_pos, poss);
    }
    return poss;
  };

  check_u_l_cross(cur, cur_pos, poss) {
    if (this.X(cur_pos) == 0 || this.Y(cur_pos) == 0) return poss;
    cur_pos -= (MX_BOARD_SIZE + 1);
    if (this.board[cur_pos] == cur && this.l_cross_check_board[cur_pos] == 0) {
      poss.push(cur_pos);
      this.l_cross_check_board[cur_pos] = 1;
      this.check_u_l_cross(cur, cur_pos, poss);
    }
    return poss;
  }

  check_d_l_cross(cur, cur_pos, poss) {
    if (this.X(cur_pos) == this.board_size - 1 || this.Y(cur_pos) == this.board_size - 1) return poss;
    cur_pos += (MX_BOARD_SIZE + 1);
    if (this.board[cur_pos] == cur && this.l_cross_check_board[cur_pos] == 0) {
      poss.push(cur_pos);
      this.l_cross_check_board[cur_pos] = 1;
      this.check_d_l_cross(cur, cur_pos, poss);
    }
    return poss;
  }

  check_u_r_cross(cur, cur_pos, poss) {
    if (this.X(cur_pos) == this.board_size - 1 || this.Y(cur_pos) == this.board_size - 1) return poss;
    cur_pos -= (MX_BOARD_SIZE - 1);
    if (this.board[cur_pos] == cur && this.r_cross_check_board[cur_pos] == 0) {
      poss.push(cur_pos);
      this.r_cross_check_board[cur_pos] = 1;
      this.check_u_r_cross(cur, cur_pos, poss);
    }
    return poss;
  }

  check_d_r_cross(cur, cur_pos, poss) {
    if (this.X(cur_pos) == 0 || this.Y(cur_pos) == 1) return poss;
    cur_pos += (MX_BOARD_SIZE - 1);
    if (this.board[cur_pos] == cur && this.r_cross_check_board[cur_pos] == 0) {
      poss.push(cur_pos);
      this.r_cross_check_board[cur_pos] = 1;
      this.check_d_r_cross(cur, cur_pos, poss);
    }
    return poss;
  }
}

export default OmokLogicBoard = new OmokLogicBoard(MX_BOARD_SIZE);