import React, { useState, useEffect } from 'react';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import { Redirect, withRouter } from "react-router-dom";

import { makeStyles } from '@material-ui/core/styles';
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';
import {
  MenuItem,
  Select,
} from "@material-ui/core";
import {
  MDBBtn,
  MDBDataTable,
  MDBRow,
  MDBCol,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
  MDBFormInline,
  MDBListGroupItem,
} from "mdbreact";

import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as ProfileAction from "../../store/actions/profile.action";
import * as AuthAction from "../../store/actions/auth.action";
import CD from "../../helper/const";

import { notify_w } from "../../helper/alert";

const useStyles = makeStyles(theme => ({
  container: {
    width: "95%",
    minHeight: '83vh',
    paddingTop: '2vh',
  },
  searchStyle: {
    color: '#ced4da',
  },
  pageNaveStyle: {
    padding: 0,
    paddingBottom: 0,
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    marginTop: '6px',
    marginLeft: '3px',
    marginRight: '3px',
    textAlign: 'center',
    width: '80px',
    WebkitAppearance: 'button !important',
  },
}));

function GoTraining(props) {
  const classes = useStyles();
  const [page, setPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [find, setFind] = useState("");
  const [game_type, setGameType] = useState("");

  const problem_book_columns = [
    {
      label: window.i18n.t("train.title"),
      field: "title",
      sort: "disabled",
      width: 150,
    },
    {
      label: window.i18n.t("train.rating"),
      field: "rating",
      sort: "disabled",
      width: 100,
    },
    {
      label: window.i18n.t("train.type"),
      field: "type",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.description"),
      field: "description",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("train.difficulty"),
      field: "difficulty",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.problems"),
      field: "problems",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.user"),
      field: "author",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.updated"),
      field: "updated",
      sort: "disabled",
      width: 150
    },
  ];
  
  useEffect(() => {
    const {user, req_user_problem, req_problem_book_list} = props;
    if (!!user)
      req_user_problem();
    req_problem_book_list(CD.PROBLEM_CATEGORY.GO, rowsPerPage, page - 1);
    props.setFunc(CD.FUNC.FUNC_TRAINING);
  }, []);

  useEffect(() => {
    const {game_type} = props;
    setGameType(game_type);
  });


  const RatingObj = ({
    review: { rating, reviews }
  }) => (
    <MDBListGroupItem
      className="p-0 border-0"
      style={{ backgroundColor: "transparent" }}
    >
      <Rater total={5} rating={reviews > 0? rating / reviews : 0} interactive={true} style={{fontSize:'1rem'}}/>
      <div>
      {reviews}
      </div>
    </MDBListGroupItem>
  );

  const loadProblemBook = (id) => {
    const { history, user } = props;
    if(!!user)
      history.push('/solve_problem:'+id);
    else {
      notify_w("First, you have to login!");
      props.history.push('/login');
    }
  };

  const EditProblemBook = (id) => {
    const { history } = props;
    history.push('/make_problem:'+id);
  };

  const handleCreateNewProblemBook = () => {
    const {user} = props;
    if(!!user)
      props.history.push('/make_problem');
    else {
      notify_w("First, you have to login!");
      props.history.push('/login');
    }
  };

  var allPage = Math.ceil(props.problem_book_count / rowsPerPage);
  if (allPage === 0)
    allPage = 1;

  const handleToFirstPage = () => {
    setPage(1);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.GO, rowsPerPage, 0);
  };

  const handleToPrevPage = () => {
    var prePage = page > 1? page - 1 : 1;
    setPage(prePage);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.GO, rowsPerPage, prePage - 1);
  };

  const handleToNextPage = () => {
    var nextPage = page < allPage? page + 1 : allPage;
    setPage(nextPage);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.GO, rowsPerPage, nextPage - 1);
  };

  const handleToLastPage = () => {
    setPage(allPage);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.GO, rowsPerPage, allPage - 1);
  };

  const handleChangeFind = event => {
    setFind(event.target.value);
    setPage(1);
  };

  const handleChangePage = (event, page) => {
    setPage(page);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.GO, rowsPerPage, page - 1);
  };

  const handleChangeRowsPerPage = event => {
    setRowsPerPage(event.target.value);
    setPage(1);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.GO, event.target.value, 0);
  };

  var problem_books = [];
  var my_problem_books = [];
  if(props.func == CD.FUNC.FUNC_TRAINING) {
    props.problem_book_list.map((el, index) => el)
    // .slice((page - 1) * rowsPerPage, page * rowsPerPage)
    .map((n) => {
      problem_books.push({title: n.title, review: <RatingObj review={{rating: n.total_rating, reviews: n.reviews}} />, 
        type: n.type, description: 'Challenge to high technique', difficulty: n.difficulty, problems: n.problems, 
        author: n.created_by, updated: new Date(n.updated).toLocaleString(),
        clickEvent: () => {loadProblemBook(n._id)}});
    });

    if (props.isAuth && !!props.user) {
      props.problem_book_list.map((el, index) => el)
      .map((n) => {
        if (n.created_by === props.user.user_id)
          my_problem_books.push({title: n.title, review: <RatingObj review={{rating: n.total_rating, reviews: n.reviews}} />, 
            type: n.type, description: 'Challenge to high technique', difficulty: n.difficulty, problems: n.problems, 
            author: n.created_by, updated: new Date(n.updated).toLocaleString(),
            clickEvent: () => {EditProblemBook(n._id)}});
      });
    }
  }

  function handleChange(value) {
  }

  const {user_problem} = props;
  const handlePlayTSGame = () => {
    const {user} = props;
    if(!!user)
      props.history.push('/take');
    else {
      notify_w("First, you have to login!");
      props.history.push('/login');
    }
  };

  const handlePlayCGGame = () => {
    const {user} = props;
    if(!!user)
      props.history.push('/capture');
    else {
      notify_w("First, you have to login!");
      props.history.push('/login');
    }
  };
  
  const handlePlayOpeningGame = () => {
    const {user} = props;
    if(!!user)
      props.history.push('/opening');
    else {
      notify_w("First, you have to login!");
      props.history.push('/login');
    }
  };

  return (
    <div className={classes.container} style = {{display: game_type == 0 ? "" : "none"}}>
      <MDBRow className="py-2 mx-0 px-5 mt-2">
       <h4 className="pr-5"><strong>{window.i18n.t("train.partial_games")}</strong></h4>
      </MDBRow>
      <MDBRow className="py-2 mx-0 px-5 mt-2">
        <MDBCol size = '1'></MDBCol>
        <MDBCol >
          <MDBBtn style={{width:'15vh', height:'5vh'}} color="cyan" className="px-3 py-1" onClick={handlePlayTSGame}>
            {window.i18n.t("train.take_stone")}
          </MDBBtn>
        </MDBCol>
        <MDBCol>
          <MDBBtn color="cyan"  style={{width:'15vh', height:'5vh'}} className="px-3 py-1" onClick={handlePlayCGGame}>
            {window.i18n.t("train.capture_group")}
          </MDBBtn>
        </MDBCol>
        <MDBCol>
          <MDBBtn color="cyan" style={{width:'15vh', height:'5vh'}}  className="px-3 py-1" onClick={handlePlayOpeningGame}>
            {window.i18n.t("train.opening")} 
          </MDBBtn>
        </MDBCol>
      </MDBRow>
      <MDBRow className="mx-0 px-5 mt-5">
        <h4><strong>{window.i18n.t("train.total_problems")}</strong></h4>
      </MDBRow>
      <MDBRow className="pl-5 ml-5 mt-1" >
        <MDBCol>
          <MDBFormInline className="md-form active-cyan-2 float-left">
            <input
              className="form-control form-control-sm mr-3 w-30"
              type="text"
              placeholder = {window.i18n.t("records.search")}
              aria-label = {window.i18n.t("records.search")}
            />
            <i className={classes.searchStyle + " fa fa-search"} />
          </MDBFormInline>
          
        </MDBCol>
        <MDBCol>
          <span className="px-2 pt-2">{window.i18n.t("records.sort_by")}</span>
          <Select
            value={'created_date'}
            style={{ width: 150 }}
            className="pr-4"
            onChange={handleChange}
          >
            <MenuItem value="created_date">{window.i18n.t("records.create_date")}</MenuItem>
          </Select>
        </MDBCol>
        
        <MDBCol >
          <span className="px-2 pt-2">{window.i18n.t("records.view")}</span>
          <Select
            value={10}
            style={{ width: 150 }}
            className="pr-4"
            onChange={handleChange}
          >
            <MenuItem value={6}>{window.i18n.t("game.line").replace("{0}", 6)}</MenuItem>
            <MenuItem value={10}>{window.i18n.t("game.line").replace("{0}", 10)}</MenuItem>
          </Select>
        </MDBCol>
        <MDBCol>
          <MDBPagination className="float-right">
            <span className="px-1 pt-2">{window.i18n.t("records.page")}</span>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToFirstPage}>&laquo;</MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToPrevPage}>&lsaquo;</MDBPageNav>
            </MDBPageItem>
              <input
                type="text"
                value={page + "/" + allPage}
                readOnly={true}
                className={classes.pagenationInputStyle}
              />
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToNextPage}>&rsaquo;</MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToLastPage}>&raquo;</MDBPageNav>
            </MDBPageItem>
          </MDBPagination>
        </MDBCol>
      </MDBRow>
      <div className="my-3 pl-5 ml-5">
        <MDBDataTable hover style = {{lineHeight: 1, }} theadColor = {'cyan lighten-3'} displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data={{columns: problem_book_columns, rows: problem_books}} />
      </div>
      <MDBRow className="py-2 mx-0 px-5 mt-2">
        <h4 className="pr-5 mt-1"  style={{textAlign:'left'}}><strong>{window.i18n.t("train.write_new_problem")}</strong></h4>
        <MDBCol style={{textAlign:'right', marginRight: '20vw'}}>
          <MDBBtn color="cyan" className="px-3 py-1" onClick={handleCreateNewProblemBook}>
            {window.i18n.t("train.create_new")}
          </MDBBtn>
        </MDBCol>
      </MDBRow>
      <MDBRow className="py-2 mx-0 px-5 mt-2">
        <h4 className="float-left grey-text"><strong>{window.i18n.t("train.my_activities")}</strong></h4>
        <MDBCol size="12" className = 'pl-4'>
          <MDBRow style = {{borderBottom:'solid', borderBottomWidth: '1px', borderBottomColor: 'grey'}}>
            <MDBCol size = '6'>
              <h5 className="pl-1 pt-2 grey-text">{window.i18n.t("train.solved")}</h5>
            </MDBCol>
            <MDBCol>
              <h5 className="pl-1 pt-2 grey-text">{window.i18n.t("train.wrote")}</h5>
            </MDBCol>
          </MDBRow>
          <MDBRow>
            <MDBCol size = '6' >
              <MDBRow className="pl-4 pt-3" style = {{borderRight:'solid', borderRightWidth: '1px', borderRightColor: 'grey'}}>
                <MDBCol size="5" className="pl-1">
                  <h6 className = "grey-text">{window.i18n.t("train.problems")}</h6>
                  <h6 className = "grey-text">{window.i18n.t("train.completed")}</h6>
                </MDBCol>
                <MDBCol className="px-0">
                  <h6>: {user_problem.solved_problems} in {user_problem.solved_books} Books</h6>
                  <h6>: {user_problem.completed_books} Books</h6>
                </MDBCol>
              </MDBRow>
            </MDBCol>
            <MDBCol>
              <MDBRow className="pl-4 pt-3">
                <MDBCol size="5" className="pl-1">
                  <h6 className = "grey-text">{window.i18n.t("train.problems")}</h6>
                </MDBCol>
                <MDBCol className="px-0">
                  <h6>: {user_problem.wrote_problems} in {user_problem.wrote_books} Books</h6>
                </MDBCol>
              </MDBRow>
            </MDBCol>
          </MDBRow>
        </MDBCol>
      </MDBRow>
      <MDBRow className="m-0 px-5">
        <MDBCol md="4">
        </MDBCol>
        <MDBCol md="5">
          <MDBRow>
            <MDBCol md="6" className="pt-1">
            </MDBCol>
          </MDBRow>
        </MDBCol>
      </MDBRow>
      {
        my_problem_books.length > 0 && (
          <div className="my-3 px-5">
            <MDBDataTable hover style = {{lineHeight: 1}} theadColor = {'light-blue accent-1'} displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data={{columns: problem_book_columns, rows: my_problem_books}} />
          </div>
        )
      }
    </div>
  );
}

function mapStateToProps(store) {
  return {
    isAuth: store.authReducer.isAuth,
    user: store.authReducer.user,
    problem_book_count: store.commonReducer.total,
    problem_book_list: store.commonReducer.items,
    user_problem: store.profileReducer.user_problem,
    game_type: store.commonReducer.content,
    func: store.commonReducer.func,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      req_user_problem: ProfileAction.req_user_problem,
      req_problem_book_list: CommonAction.req_problem_book_list,

      change_room_type: GoAction.change_room_type,
      setFunc: CommonAction.setFunc,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(GoTraining));
