import React, { useState, useEffect } from "react";
import { connect } from "react-redux";
import { Link, withRouter } from "react-router-dom";
import { makeStyles } from "@material-ui/core/styles";
import {
  Avatar,
  Typography,
  Button,
  ClickAwayListener,
  Grow,
  Paper,
  Popper,
  Badge as MuiBadge,
  MenuItem,
  MenuList
} from "@material-ui/core";
import styled from "styled-components";
import { spacing } from "@material-ui/system";
import * as AuthAction from "../../store/actions/auth.action"
import * as CommonAction from "../../store/actions/common.action";
import * as ProfileAction from "../../store/actions/profile.action";
import CD from "../../helper/const";
import { bindActionCreators } from "redux";
import {notify_w} from "../../helper/alert";
import "../css/base_header.css";

const Badge = styled(MuiBadge)(spacing);
const useStyles = makeStyles(theme => ({
 
  openStyle: {
    borderBottom:"solid",
    borderRadius: "unset",
    borderBottomColor: "#00e6e6",
    textTransform: "unset",
    height: "4vh",
  },
  closeStyle: {
    borderBottom:"solid",
    borderRadius: "unset",
    borderBottomColor: "#00e6e6",
    textTransform: "unset",
    height: "4vh",
  },
  useridfontStyle: {
    color: "white",
    fontSize: "2vh",
  },
  langDivStyle: {
    position: "absolute",
    top: "1.3vh",
    left: "93vw",
    zIndex: 1111,
  },
  avatarImg: {
    height: "4vh",
    width: "4vh",
    float: "left",
  },

  tabStyle: {
    whiteSpace: 'nowrap',
    height: "7vh",
    width: '12vw',
    color: "#fff",
    fontSize: "3vh",
    fontFamily: "Bell MT",
    borderBottom:"solid",
    borderBottomColor: "rgba(0, 206, 209, 0)",
    borderRadius: "unset",
    textTransform: "unset",
    paddingTop: "1.3vh",
    paddingBottom: "1vw", 
    paddingLeft: "auto",
    paddingRight: "auto",
    borderLeft: "solid 1px rgba(0, 0, 0, 0.1)",
    borderRight: 'solid 1px rgba(0, 0, 0, 0.1)'
  },

  svgIconStyle: {
    height: "2vw",
    width: "auto",
    paddingTop: "0.6vh",
    marginRight: "0.5vw"
  },

  svgIconStyle2: {
    height: "1vw",
    width: "auto",
    paddingTop: "0vh",
    marginRight: "0.5vw"
  }
}));

const buttons = ["go_btn", "puzzle_btn", "piece_design_btn","omok_btn", "ffa_btn", "skpni_btn"];

function Baseheader(props) {
  const classes = useStyles();
  const [user, getUser ] = useState("");
  
  useEffect(() => {
    const {user} = props;
    getUser(user);
  });

  useEffect(() => {
    var btn_cur = document.getElementById(buttons[props.gameType]);
    buttons.map((button, index) => {
      if (!!document.getElementById(button)) {
        document.getElementById(button).style.backgroundColor = "rgba(255, 255, 255, 0)";
        document.getElementById(button).style.borderBottomColor = "rgba(0, 206, 209, 0)";
      }
    });
    if (!!btn_cur) {
      btn_cur.style.backgroundColor = "rgba(0, 0, 0, 0.2)";
      btn_cur.style.borderBottomColor = "rgb(255, 255, 255)";
    }
    const {gameType} = props;
    if (gameType < 3){
      document.getElementById("other_btn").style.backgroundColor = "rgba(0, 0, 0, 0)";
      document.getElementById("other_btn").style.borderBottomColor = "rgba(0, 0, 0, 0)";
    }
    console.log(props.gameType);
  }, [props.gameType]);

  useEffect(() => {
    if(props.open_other) {
      buttons.map((button, index) => {
        if (!!document.getElementById(button)) {
          document.getElementById(button).style.backgroundColor = "rgba(255, 255, 255, 0)";
          document.getElementById(button).style.borderBottomColor = "rgba(0, 206, 209, 0)";
        }
      });
      props.setGame(CD.GAME_TYPE.FFA);
    }
  }, [props.open_other])

  useEffect(()=>{
    window.addEventListener("resize", ()=>{
      set_vw1(window.innerWidth / 100);
      set_vh1(window.innerHeight / 100);
    })
  }, []);

  useEffect(() => {
    window.i18n.setLng(["en", "kp", "cn", "jp", "ru"][props.language]);
    setTimeout(() => {
      props.history.replace(props.history.location.pathname);
    }, 500)
  }, [props.language])

  const [openedPage, setOpenedPage] = React.useState(8);

  useEffect(() => {
    const {location} = props;
    var pos = location.pathname.indexOf(":", 0);
    var path = pos > 0? location.pathname.slice(0, pos) : location.pathname;
    switch (path) {
      case "/register":
      case "/login":
      case "/profile":
      case "/messagebox":
        setOpenedPage(0);
        break;
      case "/lobby":
      case "/go_room":
      case "/records":
      case "/record":
        setOpenedPage(1);
        break;
      case "/training":
      case "/solve_problem":
      case "/make_problem":
      case "/opening":
      case "/take":
      case "/capture":
        setOpenedPage(2);
        break;
      case "/tournaments":
      case "/tournament_past":
      case "/tournament_current":
        setOpenedPage(3);
        break;
      case "/teachers":
      case "/request":
      case "/teacher_pass":
      case "/lecture_rooms":
      case "/lecture_room":
        setOpenedPage(4);
        break;
      case "/forum_compose":
      case "/forum":
      case "/article":
        setOpenedPage(5);
        break;
      case "/rank":
        setOpenedPage(6);
        break;
      case "/rules":
      case "/terms_and_policy":
      case "/contact_us":
        setOpenedPage(7);
        break;
      case "/":
      default:
        setOpenedPage(8);
        break;
    } 
  });

  const [open, setOpen] = React.useState(false);
  const [open0, setOpen0] = React.useState(false);
  const anchorRef = React.useRef(null);
  const anchorRef0 = React.useRef(null);
  const anchorRef1 = React.useRef(null);
  const anchorRef2 = React.useRef(null);
  const anchorRef3 = React.useRef(null);
 
  const handleToggle = (event) => {
    setOpen(open => !open);
  };

  const setGameType = (game_type) => {
    props.setGame(game_type);
  }

  const openOtherGame = () => {
    props.setGame(CD.GAME_TYPE.FFA);
    document.getElementById("other_btn").style.backgroundColor = "rgba(0, 0, 0, 0.2)";
    document.getElementById("other_btn").style.borderBottomColor = "rgb(255, 255, 255)";
  }

  const handleToggle0 = () => {
    setOpen0(open0 => !open0);
  };
  
  const handleClose = event => {
    if (anchorRef.current && anchorRef.current.contains(event.target)) {
      return;
    }
    props.setReturnUrl(window.location.pathname);
    props.setFunc(CD.FUNC.FUNC_NONE);
    setOpen(false);
  };

  const handleClose0 = (lang) => {
    window.i18n.setLng(["en", "kp", "cn", "jp", "ru"][lang]);
    setTimeout(() => {
      props.setLanguage(lang);  
      setOpen0(false);
    }, 500);
  };

  const handleLogout = ()=> {
    const {logoutUser} = props;
    logoutUser(window.location.pathname);
  };

  const [vw1, set_vw1] = React.useState(0);
  const [vh1, set_vh1] = React.useState(0);

  useEffect(() => 
    set_vw1(window.innerWidth/100)
  );

  useEffect(() => 
    set_vh1(window.innerHeight/45)
  );

  const {language, users} = props;
  return (
    <React.Fragment>
      <svg style = {{paddingTop: "0px", width: "100vw", height: "7vh"}}>
        <rect style = {{width: "100%", height: "100%", opacity: "0.85", fill: "rgb(66, 66, 144)"}}/>
      </svg>
      <img src={"/assets/img/Mark.svg"} className = "logoImg" alt="logo" />
      <div style = {{position: "absolute", top: "0px", paddingLeft: "14.6vw"}}>
        <Button
          id = "go_btn"
          onClick={setGameType.bind(this, CD.GAME_TYPE.GO)}
          className = {classes.tabStyle}
        >
          {/* <img src={"/assets/img/GO_Icon.svg"} className = {classes.svgIconStyle} alt="icon" /> */}
          {window.i18n.t("gameType.go")}
        </Button>

        <Button
          id = "puzzle_btn"
          onClick={setGameType.bind(this, CD.GAME_TYPE.PUZZLE)}
          className = {classes.tabStyle}
        >
          {/* <i className="fa fa-puzzle-piece" style={{color: "white", fontSize: '2vw', marginRight: '0.5vw'}}/> */}
          {window.i18n.t("gameType.puzzle")}
        </Button>

        <Button
          id = "piece_design_btn"
          onClick={setGameType.bind(this, CD.GAME_TYPE.PIECE_DESIGN)}
          className = {classes.tabStyle}
        >
          {/* <i className="fa fa-cubes" style={{color: "white", fontSize: '1.5vw', marginRight: '0.5vw'}}/> */}
          {window.i18n.t("gameType.piece_design")}
        </Button>

        <Button
          id = "other_btn"
          onClick = {openOtherGame}
          className = {classes.tabStyle}
        >
          {/* <i className="fa fa-gamepad" style={{color: "white", fontSize: '2vw', marginRight: '0.5vw'}}/> */}
          {window.i18n.t("gameType.other_games")}
        </Button>
      </div>
      
      {
        user == null && (
          <div style = {{ position: 'absolute', left: '81vw', top: '1.3vh', zIndex: '1111'}}>
            <Avatar alt="Profile Picture" className={classes.avatarImg} src={"/assets/img/avatar-1.png"} />
            <Button
              ref={anchorRef}
              aria-controls={open ? "menu-list-grow" : undefined}
              aria-haspopup="true"
              onClick={handleToggle}
              className={open || openedPage === 0 ? classes.openStyle : classes.closeStyle}
            >
              <Typography variant="h6" className = {classes.useridfontStyle}>
                {window.i18n.t("menu.no_token")}
              </Typography>
            </Button>            
            <Popper open={open} anchorEl={anchorRef.current} role={undefined} transition disablePortal>
              {({ TransitionProps, placement }) => (
                <Grow
                  {...TransitionProps}
                  style={{ transformOrigin: placement === "bottom" ? "center top" : "center bottom" }}
                >
                  <Paper>
                    <ClickAwayListener onClickAway={setOpen.bind(this, false)}>
                      <MenuList autoFocusItem={open} id="menu-list-grow">
                        <Link id="login" class = "linkStyle" to="/login"><MenuItem  onClick={handleClose}>{window.i18n.t("menu.login")}</MenuItem></Link>
                        <Link class = "linkStyle" to="/register"><MenuItem onClick={handleClose}>{window.i18n.t("menu.register")}</MenuItem></Link>
                      </MenuList>
                    </ClickAwayListener>
                  </Paper>
                </Grow>
              )}
            </Popper>
          </div>
        )
      }

      {
        user != null && (
          <div style = {{ position: 'absolute', left: '81vw', top: '1.3vh', zIndex: '1111'}}>
            <Avatar alt="Profile Picture" className={classes.avatarImg} src={user.avatar} />
            <Button
              ref={anchorRef}
              aria-controls={open ? "menu-list-grow" : undefined}
              aria-haspopup="true"
              onClick={handleToggle}
              className={open || openedPage === 0? classes.openStyle : classes.closeStyle}
            >
              <Typography variant="h6" className = {classes.useridfontStyle}>
                {user.user_id}
              </Typography>
            </Button>
            <Popper open={open} anchorEl={anchorRef.current} role={undefined} transition disablePortal>
              {({ TransitionProps, placement }) => (
                <Grow
                  {...TransitionProps}
                  style={{ transformOrigin: placement === "bottom" ? "center top" : "center bottom" }}
                >
                  <Paper>
                    <ClickAwayListener onClickAway={setOpen.bind(this, false)}>
                      <MenuList autoFocusItem={open} id="menu-list-grow">
                        <MenuItem onClick={handleLogout}>{window.i18n.t("menu.logout")}</MenuItem>
                        <Link class = "linkStyle" to="/messagebox"><MenuItem onClick={handleClose}>{window.i18n.t("menu.message")}</MenuItem></Link>
                        {
                          user.role === "admin" && (
                            <Link class = "linkStyle" to="/admin"><MenuItem onClick={handleClose}>{window.i18n.t("menu.admin")}</MenuItem></Link>
                          )
                        }                        
                      </MenuList>
                    </ClickAwayListener>
                  </Paper>
                </Grow>
              )}
            </Popper>
          </div>
        )
      }
      
      <div className={classes.langDivStyle}>
        <Button
          ref={anchorRef0}
          aria-controls={open0 ? "menu-list-grow" : undefined}
          aria-haspopup="true"
          onClick={handleToggle0}
          className={open0? classes.openStyle : classes.closeStyle}
        >
          <Typography variant="h6" className={classes.useridfontStyle}>
            {["English", "한국어", "汉语", "日本語", "Русский язык"][language]}
          </Typography>
        </Button>
        <Popper open={open0} anchorEl={anchorRef0.current} role={undefined} transition disablePortal>
          {({ TransitionProps, placement }) => (
            <Grow
              {...TransitionProps}
              style={{ transformOrigin: placement === "bottom" ? "center top" : "center bottom" }}
            >
              <Paper>
                <MenuList autoFocusItem={open0} id="menu-list-grow">
                  <MenuItem onClick={handleClose0.bind(this, 0)}>English</MenuItem>
                  <MenuItem onClick={handleClose0.bind(this, 1)}>한국어</MenuItem>
                  <MenuItem onClick={handleClose0.bind(this, 2)}>汉语</MenuItem>
                  <MenuItem onClick={handleClose0.bind(this, 3)}>日本語</MenuItem>
                  <MenuItem onClick={handleClose0.bind(this, 4)}>Русский язык</MenuItem>
                </MenuList>
              </Paper>
            </Grow>
          )}
        </Popper>
      </div>
    </React.Fragment>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    users:store.authReducer.users,
    language: localStorage.lang || store.commonReducer.language,
    gameType: store.commonReducer.content,    
    open_other: store.commonReducer.content > 2,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      logoutUser : AuthAction.logoutUser,
      setReturnUrl: AuthAction.setReturnUrl,
      setGame: CommonAction.setGame,
      setLanguage: CommonAction.setLanguage,
      showHiddenSideBar:CommonAction.show_hidden_sidebar,
      update_award_dlg:ProfileAction.update_award_dlg,
      setFunc: CommonAction.setFunc,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Baseheader))