import ACTION from '../actionTypes';

const initialState = {
  problem_list: [],
  problem_book: {
    _id: '',
    title: '',
    type: '',
    difficulty: '',
    created_by: '',
    total_solved_time: 0,
    total_retry: 0,
    solved_problems: 0,
  },
};

export default function problemBookReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.LOAD_PROBLEM_BOOK:
      return {
        ...state,
        problem_book: {
          ...state.problem_book,
          _id: action.problem_book._id,
          title: action.problem_book.title,
          type: action.problem_book.type,
          difficulty: action.problem_book.difficulty,
          created_by: action.problem_book.created_by,
          updated: action.problem_book.updated,
          total_solved_time: action.book_solve.time,
          total_retry: action.book_solve.retried,
          solved_problems: action.book_solve.solved,
        },
      };
    case ACTION.UPDATE_PROBLEM_BOOK:
      return {
        ...state,
        problem_book: {
          ...state.problem_book,
          _id: !!action.problem_book._id? action.problem_book._id : state.problem_book._id,
          title: action.problem_book.title,
          type: action.problem_book.type,
          difficulty: action.problem_book.difficulty,
        }
      };
    case ACTION.UPDATE_PROBLEM_LIST:
      return {
        ...state,
        problem_list: action.problem_list,
      };
    case ACTION.UPDATE_PROBLEM_SOLVE:
      return {
        ...state,
        problem_book: {
          ...state.problem_book,
          total_solved_time: action.time,
          total_retry: action.retried,
          solved_problems: action.solved,
        }
      };
    default: return state;
  }
}
