import axios from "axios";

import ACTION from '../actionTypes';
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import store from '../index';
import {parseError} from '../../helper/utils';
import {/*swal_s, swal_w,*/ notify_s, notify_w, notify_e} from "../../helper/alert";

axios.interceptors.response.use(
  function(response) {
    return response;
  },
  function(error) {
    if (error.response.status === 401) {
    //alert("Please login.");
    store.dispatch(logoutUser('/auth/sign-in'));
    }
    // Do something with response error
    return Promise.reject(error);
  }
);

function setAuthToken(token) {
  if (token) {
    localStorage.setItem("token", token);
    axios.defaults.headers.common["Authorization"] = token;
  } else {
    localStorage.removeItem("token");
    delete axios.defaults.headers.common["Authorization"];
  }
}

function getAuthToken() {
  return localStorage.getItem("token");
}

export const loginUser = (userData, history, returnUrl) => async dispatch => {
  try {
    dispatch({ type: ACTION.USER_LOGIN_REQUEST }); 

    const result = await axios.post(config.apiUrl + "/login", {user_id: userData.user_id, pwd: userData.password});
    const { err, user } = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(setCurrentUser(user));
      notify_s("Login Success.");
      setTimeout(()=>{
        if(user.role === 'admin')
          history.replace('/admin')
        else
          history.replace(returnUrl)
      }, 100);
    } else 
      throw err;
  } catch (error) {
    let errorObj = parseError(error);
    dispatch({  type: ACTION.USER_LOGIN_FAIL,  payload: errorObj});
    notify_w("Login Failed.");
  }
}

export const registerUser = (regData, history) => async dispatch => {
  try {
    dispatch({ type: ACTION.USER_REGISTER_REQUEST });

    const result = await axios.post(config.apiUrl + "/register_user", regData);
    const { err, user } = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(setCurrentUser(user));
      notify_s("Successfuly registered.");
      setTimeout(()=>{
        history.replace("/")
      }, 100);
    } else 
      throw err;
  } catch (error) {
    let errorObj = parseError(error);
    dispatch({ type: ACTION.USER_REGISTER_FAIL,  payload: errorObj});
    notify_e("Register Failed.!");
  }
}

export const getCurrentUser = (user_token) => async dispatch => { 
  try {
    setAuthToken(user_token);
    const result = await axios.post(config.apiUrl + "/get_user_info", {});
    const { err, user } = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(setCurrentUser(user));
    } else 
      throw err;
  } catch (error) {
  }
}

export const getUserSettingInfo = () => async dispatch => { 
  try {
    const result = await axios.post(config.apiUrl + "/get_user_setting_info", {});
    const { err, user } = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch({type: ACTION.SET_USER_INFO, payload: user});
    } else 
      throw err;
  } catch (error) {
  }
}

export const setCurrentUser = (user) => async dispatch => { 
  try {
    setAuthToken(user.token);
    dispatch ({type: ACTION.SET_CURRENT_USER, payload: user});
  } catch (error) {
  }
}

export const logoutUser = (newUrl) => {
  setAuthToken(false);
  return({ type: ACTION.USER_LOGOUT, newUrl});
}

export const changePassword = (updateData) => async dispatch => {
  try {
    dispatch({ type: ACTION.USER_PWDCHANGE_REQUEST });

    const result = await axios.post(config.apiUrl + "/change_user_pwd", updateData);
    const { err } = result.data;
    if(err === ErrorCode.SUCCESS) {
      notify_s("Password changed.");
    } else {
      notify_e("Password change failed.");
    }
    dispatch({ type: ACTION.USER_PWDCHANGE_SUCCESS });
  } catch (error) {
    notify_e("Password change failed.");
    let errorObj = parseError(error);
    dispatch({ type: ACTION.USER_PWDCHANGE_FAIL, payload: errorObj });
  }
}

export const uploadFile = (formData, fileName = '') => async dispatch => {
  try {
    var token = getAuthToken();
    var options = {headers: {'Content-Type': 'multipart/form-data'}};    
    const result = await axios.post(config.apiUrl + "/upload", formData, options); 
    const {avatar} = result.data; 
    dispatch({type: ACTION.UPDATE_USER_AVATAR,avatar});
  } catch (error) {   
  }
}

export const submitUpdateSetting = (updateData) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/change_user_info', {infos: updateData});
    const {err} = result.data;
    if (err === ErrorCode.SUCCESS) {
      notify_s("Updated successfully.");
    } else {
      notify_e("Change UserSettingInfo failed.");
    }
  } catch (error) {
  }
}

