import swal from 'sweetalert';
import { toast } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';

export const swal_i = (str) => swal("Information!", str, "info");
export const swal_s = (str) => swal("Success!", str, "success");
export const swal_w = (str) => swal("Warning!", str, "warning");
export const swal_e = (str) => swal("Error!", str, "error");

toast.configure({
  autoClose: 3000,
  draggable: false,
  //etc you get the idea
});

export const notify_i = (str) => toast(str, {
  type: "info",
  position: "bottom-center"
})
export const notify_s = (str) => toast(str, {
  type: "success",
  position: "bottom-center"
})
export const notify_w = (str) => toast(str, {
  type: "warning",
  position: "bottom-center"
})
export const notify_e = (str) => toast(str, {
  type: "error",
  position: "bottom-center"
})