import React, {useState, useEffect} from 'react';
import {bindActionCreators} from "redux";
import * as GoAction from "../../store/actions/go.action";
import * as ToastAction from "../../store/actions/toast.action";
import {connect} from "react-redux";
import PROTOCOL from "../../helper/protocol";
import CD from "../../helper/const";

import {
  Button,
} from '@material-ui/core';
import { 
  MDBDataTable, 
  MDBRow, 
  MDBCol,
  MDBFormInline,
} from "mdbreact";

import { makeStyles } from '@material-ui/core/styles';
const useStyles = makeStyles(theme => ({
  menuStyle: {
    paddingTop: '2vh',
  },
  searchStyle: {
    color: '#ced4da',
  },
}));

function Players(props) {
  const classes = useStyles();
  const [find, setFind] = useState("");
  const [page, setPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(1000);  

  const columns = [
    {
      label: window.i18n.t("game.name"),
      field: "user_id",
      width: 100,
      sort: "disabled",
    },
    {
      label: window.i18n.t("game.lv"),
      field: "lv",
      sort: "disabled",
      width: 40
    },
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 80
    },
    {
      label: window.i18n.t("game.action"),
      field: "action",
      sort: "disabled",
      width: 80
    },
  ]; 
  useEffect(() => {
    getUsersInfos(0, rowsPerPage, find);
  }, [props.update_user_list, props.socketLobby]);
  
  const handleChangeFind = event => {
    setFind(event.target.value);
  }

  const getUsersInfos = (page, rowsPerPage, find) => {
    if (!!props.socketLobby) {
      props.socketLobby.emit('cs_message', PROTOCOL.CSC_LOBBY_USER_LIST, {game_type: CD.GAME_TYPE.GO, keyword: find, pagesize: rowsPerPage, page, min_coin: 0});
    }
  };

  const get_action = (to_user) => {
    const {user} = props;
    return (
      <div>
      </div>
    );
  };

  var rows = [];
  props.user_list.map((n, index) => {
    rows.push({
      user_id: n.user_id,
      lv: "" + n.level,
      coin: "" + n.coin,
      action: get_action(n)
    });
  });

  return (
    <React.Fragment>
      <MDBRow className={classes.menuStyle}>
        <MDBCol>
          <MDBFormInline className="md-form active-cyan-2 float-right">
            <input
              className="form-control form-control-sm mr-3 w-40"
              type="text"
              placeholder={window.i18n.t("game.search")}
              aria-label={window.i18n.t("game.search")}
              onChange={handleChangeFind}
            />
            <i className={classes.searchStyle + " fa fa-search"} />
          </MDBFormInline>
        </MDBCol>
      </MDBRow>
      <MDBDataTable hover theadColor="green" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="75vh" data={{columns: columns, rows:rows}} />
    </React.Fragment>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    user_count: store.goReducer.user_count,
    user_list: store.goReducer.user_list,
    socketLobby: store.commonReducer.socketLobby,
    update_user_list: store.goReducer.update_user_list,
    language: store.commonReducer.language,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      openModal: ToastAction.openModal,
      hiddenModal: ToastAction.hiddenModal,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(Players);
