import React, {useState, useEffect} from 'react';
import { connect } from "react-redux";
import { Redirect } from "react-router-dom";
import {bindActionCreators} from "redux";
import {
  MDBBtn,
  MDBRow,
  MDBCol,
} from "mdbreact";
import * as GoTeacherAction from "../../store/actions/go_teacher.action";
import CD from '../../helper/const';

function Request(props) {

  useEffect(() => {
    const {user, get_user_teacher_qualification} = props;
    if (!!user)
      get_user_teacher_qualification();
  }, []);

  const handleRequest = () => {
    const {user, add_teacher} = props;
    if (!!user)
      add_teacher();
  };
  const {teacher_qualification} = props;

  return (
    <React.Fragment>
      <MDBRow className="m-0">
        <MDBCol></MDBCol>
        <MDBCol size="4" className="py-5" style={{borderBottom:'1px solid rgb(204, 204, 204)'}}>
          <MDBRow className="pt-5">
            <MDBCol size="6" className="pl-5">
              <h5 className="font-weight-bold dark-grey-text">{window.i18n.t("lecture.level")} {CD.TEACHER_QUALIFICATION.LEVEL}</h5>
            </MDBCol>
            {
              teacher_qualification.level >= CD.TEACHER_QUALIFICATION.LEVEL && (
                <MDBCol>
                  <i className="fa fa-check" style={{ fontSize: "1.5rem"}} />
                </MDBCol>
              )
            }
            {
              teacher_qualification.level < CD.TEACHER_QUALIFICATION.LEVEL && (
                <MDBCol>
                  <i className="fa fa-remove" style={{ fontSize: "1.5rem"}} />
                  {/* <h4 className="font-weight-bold dark-grey-text float-left">{teacher_qualification.level}</h4> */}
                </MDBCol>
              )
            }
          </MDBRow>
          <MDBRow className="pt-1">
            <MDBCol size="6" className="pl-5">
              <h5 className="font-weight-bold dark-grey-text">{CD.TEACHER_QUALIFICATION.WINS} {window.i18n.t("lecture.game_wins")}</h5>
            </MDBCol>
            {
              teacher_qualification.wins >= CD.TEACHER_QUALIFICATION.WINS && (
                <MDBCol>
                  <i className="fa fa-check" style={{fontSize: "1.5rem"}} />
                </MDBCol>
              )
            }
            {
              teacher_qualification.wins < CD.TEACHER_QUALIFICATION.WINS && (
                <MDBCol>
                  <i className="fa fa-remove" style={{fontSize: "1.5rem"}} />
                </MDBCol>
              )
            }
          </MDBRow>
          <MDBRow className="pt-1">
            <MDBCol size="6" className="pl-5">
              <h5 className="font-weight-bold dark-grey-text">{CD.TEACHER_QUALIFICATION.WIN_RATE}% {window.i18n.t("lecture.win_rate")}</h5>
            </MDBCol>
            {
              teacher_qualification.win_rate >= CD.TEACHER_QUALIFICATION.WIN_RATE && (
                <MDBCol>
                  <i className="fa fa-check" style={{fontSize: "1.5rem"}} />
                </MDBCol>
              )
            }
            {
              teacher_qualification.win_rate < CD.TEACHER_QUALIFICATION.WIN_RATE && (
                <MDBCol>
                  <i className="fa fa-remove" style={{fontSize: "1.5rem"}} />
                </MDBCol>
              )
            }
          </MDBRow>
        </MDBCol>
        <MDBCol>
          <MDBBtn color="gray" className="float-right px-1 py-1 mx-5">
            <i className="fa fa-comments-o" style={{ color: "gray", fontSize: "1.2rem"}} />
          </MDBBtn>
        </MDBCol>
      </MDBRow>
      <MDBRow className="m-0">
        <MDBCol className="pt-3 pb-5 mb-5" style={{textAlign:'center'}}>
          <MDBBtn color="cyan" className="px-3 py-2 my-0" disabled={!teacher_qualification.general} onClick={handleRequest}>
            {window.i18n.t("lecture.request")}
          </MDBBtn>
        </MDBCol>
      </MDBRow>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  teacher_qualification: store.goTeacherReducer.teacher_qualification,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    add_teacher: GoTeacherAction.add_teacher,
    get_user_teacher_qualification: GoTeacherAction.get_user_teacher_qualification,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(Request);
