import ACTION from '../actionTypes';
import * as Logic from '../../components/pdesign/pdesignLogic'
import store from '..';
export const updateBoardSize = (size) => {
  return ({type: ACTION.UPDATE_BOARD_SIZE, size});
};

export const updateShowGrid = (isShow) => {
  return ({type: ACTION.UPDATE_SHOW_GRID, isShow});
};

export const updateBackground = (back) => {
  return ({type: ACTION.UPDATE_BACKGROUND, back});
};

export const update_board = (board, state) => {
  return ({type: ACTION.INIT_BOARD, board, board_updated: !state});
}