import axios from "axios";

import ACTION from '../actionTypes';
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import CD from '../../helper/const';

export const req_msg_list = () => async dispatch => {
  try {
    var result, in_list = [], sent_list = [], draft_list = [], trash_list = [];
    result = await axios.post(config.apiUrl + '/msg_list', {category: CD.MSG_TYPE.IN, pagesize: 10, page: 0});
    if (result.data.err === ErrorCode.SUCCESS)
      in_list = result.data.items;
    result = await axios.post(config.apiUrl + '/msg_list', {category: CD.MSG_TYPE.SENT, pagesize: 10, page: 0});
    if (result.data.err === ErrorCode.SUCCESS)
      sent_list = result.data.items;
    result = await axios.post(config.apiUrl + '/msg_list', {category: CD.MSG_TYPE.DRAFT, pagesize: 10, page: 0});
    if (result.data.err === ErrorCode.SUCCESS)
      draft_list = result.data.items;
    result = await axios.post(config.apiUrl + '/msg_list', {category: CD.MSG_TYPE.TRASH, pagesize: 10, page: 0});
    if (result.data.err === ErrorCode.SUCCESS)
      trash_list = result.data.items;
    dispatch({type: ACTION.UPDATE_MSG_LIST, in_list, sent_list, draft_list, trash_list});
  } catch (error) {
  }
}

export const req_msg_content = (msg_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/msg_content', {msg_id});
    const {err, content} = result.data;
    if (err === ErrorCode.SUCCESS)
      dispatch({type: ACTION.UPDATE_MSG_CONTENT, message: content});
  } catch (error) {
  }
}

