import React from 'react';
import { Link } from 'react-router-dom';
import { makeStyles } from '@material-ui/core/styles';
import AppBar from '@material-ui/core/AppBar';
import Toolbar from '@material-ui/core/Toolbar';
import Typography from '@material-ui/core/Typography';
import Container from '@material-ui/core/Container';

const useStyles = makeStyles(theme => ({
  text: {
    padding: theme.spacing(2, 2, 0),
  },
  fontStyle: {
    fontSize: 14,
  },
  link: {
    color: '#fff',
    textDecorationLine: 'underline',
  },
  footerBar: {
    top:'auto',
    hight:'5vh',
    bottom: 0,    
    // backgroundColor: '#0c6387',
    backgroundColor:'rgba(66, 66, 144, 0.85)',
    boxSizing: 'initial',
  },
  grow: {
    flexGrow: 1,
  },
  fabButton: {
    position: 'absolute',
    zIndex: 1,
    top: -30,
    left: 0,
    right: 0,
    margin: '0 auto',
  },
  iconStyle: {
    color: "white",
    height: 20,
    padding: 10,
  },
  toolbar: {
    minHeight: '3vh',
  }
}));

export default function Footer() {
  const classes = useStyles();

  return (
    <React.Fragment>
      <AppBar position="relative" color="primary" className={classes.footerBar}>
        <Container maxWidth="lg">
          <Toolbar className={classes.toolbar}>
            <Typography gutterBottom className={classes.fontStyle}>
              2021&copy;TOBMate.ALL Rights Reserved.<Link className={classes.link} to="/">Privacy Policy</Link> | <Link className={classes.link} to="/">Terms of Service</Link>
            </Typography>
              <div className={classes.grow}/>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-facebook"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-google-plus"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-dribbble"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-linkedin"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-twitter"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-skype"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-github"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-youtube"}/>
              </Link>
              <Link to="/">
                <i className={classes.iconStyle + " fa fa-dropbox"}/>
              </Link>
          </Toolbar>
        </Container>
      </AppBar>
    </React.Fragment>
  );
}