import React, { useState, useEffect, useRef } from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import PDesignBoard from "./pdesignBoard";
import {
  MDBRow,
  MDBCol,
} from "mdbreact";

import { makeStyles } from '@material-ui/core/styles';
import BoardOption from "./BoardOption";
import PieceSelect from "./pieceSelect";
import ToolSelect from "./ToolSelect";
import PDesignProblem from "./pdesignProblem";
import { Button } from "@material-ui/core"

const useStyles = makeStyles(theme => ({
  container: {
    position: 'fixed',
    left: "0vw", 
    top: '0vh',
    width: "100vw", 
    height:"100vh",
    zIndex: '1111',
    backgroundImage: "url(/assets/img/backg_2_2.jpg)"
  },
  board: {
    position: 'fixed',
    left: '24vw',
    top: '3vh',
    zIndex: '1112',
  },
  boardOption: {
    position: 'fixed',
    right: '1.5vw',
    top: '10vh',
    width: "25vw", 
    height:"auto",
    zIndex: '1112',
    color: 'black',
  },
  piece: {
    position: 'fixed',
    right: '1.5vw',
    top: '39vh',
    width: "25vw", 
    height:"35vh",
    zIndex: '1112',
    color: 'black',
  },
  tool: {
    position: 'fixed',
    right: '1.5vw',
    top: '76.5vh',
    width: "25vw", 
    height:"auto",
    zIndex: '1112',
    color: 'black',
  },
  text: {
    fontSize: '3vh',
    fontWeight: 'bold',
    fontFamily: 'cursive',
  },
  quit: {
    position: 'fixed',
    right: '0vw',
    top: '3vh',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
  sample: {
    position: 'fixed',
    width: '21vw',
    left: '1.5vw',
    bottom: '3vh',
    zIndex: '1112',
  }
}));

function TryPDesign(props) {
  const classes = useStyles();

  const handleExit = () => {
    props.history.goBack();
  }
  return (
    <div>
      <div className={classes.container}/>
      <div  className={classes.board}>
        <PDesignBoard width="52" height="94"/>
      </div>
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i class = "fa fa-home" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
      <div className={classes.boardOption}>
        <div className={classes.text}>
          <BoardOption controllable = {true} />
        </div>
      </div>
      <div className={classes.piece}>
        <div className={classes.text}>
          <PieceSelect controllable = {true} />
        </div>
      </div>
      <div className={classes.tool}>
        <div className={classes.text}>
          <ToolSelect/>
        </div>
      </div>
      <div className={classes.sample}>
        <div className={classes.text}>
          <PDesignProblem/>
        </div>
      </div>
    </div>
  )
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(TryPDesign);

