import React, {useState,useEffect} from 'react';
import { makeStyles } from '@material-ui/core/styles';
import { MDBSimpleChart } from "mdbreact";

const useStyles = makeStyles(theme => ({
  fireStyle: {
    position: 'fixed',
    transform: 'rotate(0deg)',
  }
}))

var handleTime;

function Clock2(props) {

  const classes = useStyles();
  const {leftTime, countdown, clockPosition, width} = props;
  const [percent, setPercent] = useState(0);
  const [left_time, setLeftTime] = useState(leftTime);
  
  let w = window.innerWidth;
  let h = window.innerHeight;
  let count = 2;

  // useEffect(() => {
  //   clearInterval(handleTime);
  //   document.getElementById('clock').style.display = 'none';
  //   if (props.display) {
  //     document.getElementById('clock').style.display = 'block';
  //     count = 2;
  //     handleTime  = setInterval(controlPercent, 50);
  //   }
  // },  [props.turn])

  useEffect(() => {
    document.getElementById('clock').style.display = 'none';
    if (props.display) {
      document.getElementById('clock').style.display = 'block';
    }
  }, [props.display]);

  useEffect(() => {
    setLeftTime(props.leftTime);
    setPercent(props.leftTime / props.countdown * 100);
  }, [props.leftTime]);

  // const controlPercent = () => {
  //   count ++;
  //   setPercent(count / 3);
  //   setLeftTime(Math.round(15 - count / 20));
  //   document.getElementById('clock_fire').style.transform = `rotate(${count * 360 / 300}deg)`;
  //   if (count >= 300) clearInterval(handleTime);
  // }

  return(
    <div id = "clock" style = {{zIndex:'2007'}}>
      {/* <img id = "clock_fire" src = "/assets/img/clock_fire.png" className = {classes.fireStyle} style = {{width: `${width}vw`, height: `${width}vw`,  top: `${clockPosition[1]}px`, left: `${clockPosition[0]}px`}}></img> */}
      <MDBSimpleChart
        width={w * width * 15 / 2000}
        height={w * width * 15 / 2000}
        strokeWidth={w * width / 1300}
        percent={percent}
        labelColor = "none"
        strokeColor="rgba(255, 255, 255, 0.8)"
        railColor="none"
        style = {{zIndex: '2007', position: 'fixed', top: `${clockPosition[1] + w * width * 5 / 4000}px`, left: `${clockPosition[0]+ w * width * 5 / 4000}px`}}
      />
      <div id = "left_time" style = {{position: 'fixed',zIndex: '2007',color: 'white',fontSize: `${width / 3}vw`, fontFamily: 'cursive', fontWeight: '300', top: `${clockPosition[1] + w * width / 400}px`, left: left_time >= 10 ? `${clockPosition[0] + w * width / 300}px`: `${clockPosition[0] + w * width / 250}px`}}>{left_time}</div>
      <img src = "/assets/img/clock_new.png" style = {{position: 'fixed', zIndex: '2007', width: `${width* 1.4}vw`, height: `${width * 1.4}vw`,  top: `${clockPosition[1] - width * w / 410}px`, left: `${clockPosition[0] - width * w / 500}px`}}></img>
    </div>
  );
}
export default Clock2;