import React, { useState, useEffect , useRef} from 'react';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import { withRouter } from "react-router-dom";
import { makeStyles } from '@material-ui/core/styles';
import Rater from 'react-rater';
import {
  Avatar,
} from '@material-ui/core';
import 'react-rater/lib/react-rater.css';
import {
  MenuItem,
  Select,
} from "@material-ui/core";
import {
  MDBDataTable,
  MDBRow,
  MDBCol,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
  MDBFormInline,
  MDBContainer,
} from "mdbreact";
import CD from '../../helper/const';
import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as FFAAction from '../../store/actions/ffa.action';
import * as AuthAction from '../../store/actions/auth.action';

const useStyles = makeStyles(theme => ({
  searchStyle: {
    color: '#ced4da',
  },
  pageNaveStyle: {
    margin: 'auto',
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  avatarImg: {
    height: '1.2vw',
    width: '1.2vw',  
    marginRight:'0.5vw',
  },
  pagenationInputStyle: {
    height: 'min-content',
    margin: 'auto',
    textAlign: 'center',
    width: '80px',
    WebkitAppearance: 'button !important',
  },
}));


function Records(props) {
  const classes = useStyles();
  const [page, setPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [gameType, setGameType] = useState(0);
  const [find, setFind] = useState("");

  const columns_go = [
    {
      label: window.i18n.t("game.no"),
      field: "no",
      sort: "disabled",
      width: 80,
    },
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("game.white_player"),
      field: "white_player",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.black_player"),
      field: "black_player",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.board_size"),
      field: "board_size",
      sort: "disabled",
      width: 80
    },
    {
      label: window.i18n.t("game.handicap"),
      field: "handicap",
      sort: "disabled",
      width: 80
    },
    {
      label: window.i18n.t("game.result"),
      field: "result",
      sort: "disabled",
      width: 60
    },    
    {
      label: window.i18n.t("game.step"),
      field: "step",
      sort: "disabled",
      width: 60
    }, 
    {
      label: window.i18n.t("game.review"),
      field: "review",
      sort: "disabled",
      width: 100,
    },
    {
      label: window.i18n.t("game.finished"),
      field: "finished",
      sort: "disabled",
      width: 180,
    },
  ];
  const columns_puzzle = [
    {
      label: window.i18n.t("game.no"),
      field: "no",
      sort: "disabled",
      width: 80,
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 1),
      field: "player1",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 2),
      field: "player2",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("game.time"),
      field: "time",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("game.result"),
      field: "result",
      sort: "disabled",
      width: 60
    },    
    {
      label: window.i18n.t("game.finished"),
      field: "finished",
      sort: "disabled",
      width: 180,
    },
  ];
  const columns_pdesign = [
    {
      label: window.i18n.t("game.no"),
      field: "no",
      sort: "disabled",
      width: 80,
    },
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 1),
      field: "player1",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 2),
      field: "player2",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.result"),
      field: "result",
      sort: "disabled",
      width: 60
    },    
    {
      label: window.i18n.t("game.finished"),
      field: "finished",
      sort: "disabled",
      width: 180,
    },
  ];
  const columns_ffa = [
    {
      label: window.i18n.t("game.no"),
      field: "no",
      sort: "disabled",
      width: 80
    },   
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 1),
      field: "player1",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 2),
      field: "player2",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 3),
      field: "player3",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 4),
      field: "player4",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.kind"),
      field: "kind",
      sort: "disabled",
      width: 80
    }, 
    {
      label: window.i18n.t("game.result"),
      field: "result",
      sort: "disabled",
      width: 60
    },   
    {
      label: window.i18n.t("game.finished"),
      field: "finished",
      sort: "disabled",
      width: 180
    },
  ];
  const columns_skpni = [
    {
      label: window.i18n.t("game.no"),
      field: "no",
      sort: "disabled",
      width: 80,
    },   
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 100
    },    
    {
      label:window.i18n.t("game.player").replace("{0}", 1),
      field: "player1",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 2),
      field: "player2",
      sort: "disabled",
      width: 150
    },   
    {
      label: window.i18n.t("game.result"),
      field: "result",
      sort: "disabled",
      width: 60
    },  
    {
      label: window.i18n.t("game.finished"),
      field: "finished",
      sort: "disabled",
      width: 180,
    },
  ];
  const columns_omok = [
    {
      label: window.i18n.t("game.no"),
      field: "no",
      sort: "disabled",
      width: 80,
    },
    {
      label: window.i18n.t("game.coin"),
      field: "coin",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 1),
      field: "player1",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.player").replace("{0}", 2),
      field: "player2",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("game.result"),
      field: "result",
      sort: "disabled",
      width: 60
    },
    {
      label: window.i18n.t("game.time"),
      field: "result",
      sort: "disabled",
      width: 60
    },
    {
      label: window.i18n.t("game.finished"),
      field: "finished",
      sort: "disabled",
      width: 180,
    },
  ];
  var columns = columns_go;
  if(props.game_type == CD.GAME_TYPE.PUZZLE)
    columns = columns_puzzle;
  else if(props.game_type == CD.GAME_TYPE.PIECE_DESIGN)
    columns = columns_pdesign;
  else if(props.game_type == CD.GAME_TYPE.FFA)
    columns = columns_ffa;
  else if(props.game_type == CD.GAME_TYPE.SKPNI)
    columns = columns_skpni;
  else if (props.game_type == CD.GAME_TYPE.OMOK)
    columns = columns_omok;
  var rows = [
  ];

  useEffect(() => {   
    getGameRecords(0, rowsPerPage, gameType, find);
    props.showHiddenSideBar("14.5vw",true );
    props.setFunc(CD.FUNC.FUNC_RECORDS);
    return () => {

    };
  }, []);
  useEffect(() => {   
    getGameRecords(0, rowsPerPage, gameType, find);
  }, [props.game_type]);

  const redrawContents = () => {
    props.func == CD.FUNC.FUNC_RECORDS && props.game_list.map((n, index) => {   
      const {game_type} = props;
      if(game_type === CD.GAME_TYPE.GO) {       
        var no = props.game_count - index - (page - 1) * rowsPerPage;
        let black_index = 0 ;
        if(!!n.colors && n.colors[0] === 1)
          black_index = 0;
        else if(!!n.colors && n.colors[0] === 2)
          black_index = 1;
        rows.push({no: no, coin:n.coin, 
          white_player:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[1 - black_index].avatar} /><p>{n.players[1 - black_index].user_id + " Lv" + n.players[1 - black_index].level}</p></MDBRow> ,
          black_player:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[black_index].avatar} /><p>{n.players[black_index].user_id + " Lv" + n.players[black_index].level}</p></MDBRow>,
          board_size: n.board_size, handicap: n.handicap, result: n.result,
          step: n.step, review: <ReviewObj review={{rating: n.total_rating, reviews: n.reviews}} />,  finished: new Date(n.finished).toLocaleString(),
          clickEvent: () => {loadGame(n)}});
          
      } else if(game_type === CD.GAME_TYPE.PUZZLE) {
        var no = props.game_count - index - (page - 1) * rowsPerPage;
        rows.push({no: no,
          player1:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[0].avatar} /><p>{n.players[0].user_id + " Lv" + n.players[0].level}</p></MDBRow> , 
          player2:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[1].avatar} /><p>{n.players[1].user_id + " Lv" + n.players[1].level}</p></MDBRow>,
          coin:n.coin, time: `${n.countdown / 60}min`, result:n.result,
          finished: new Date(n.finished).toLocaleString(),
          clickEvent: () => {loadGame(n)}});
      } else if(game_type === CD.GAME_TYPE.PIECE_DESIGN) {
        var no = props.game_count - index - (page - 1) * rowsPerPage;
        rows.push({no: no, coin:n.coin, 
          player1:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[0].avatar} /><p>{n.players[0].user_id + " Lv" + n.players[0].level}</p></MDBRow> , 
          player2:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[1].avatar} /><p>{n.players[1].user_id + " Lv" + n.players[1].level}</p></MDBRow>,
          board_size: n.board_size,
          result:n.result,
          finished: new Date(n.finished).toLocaleString(),
          clickEvent: () => {loadGame(n)}});
      } else if(game_type === CD.GAME_TYPE.FFA) {     
        var no = props.game_count - index - (page - 1) * rowsPerPage;
        var kind = ['2players', "individual", "fixed team"][n.game_kind];
        rows.push({no: no,         
          coin: n.coin,
          player1:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[0].avatar} /><p>{n.players[0].user_id + " Lv" + n.players[0].level}</p></MDBRow> , 
          player2:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[1].avatar} /><p>{n.players[1].user_id + " Lv" + n.players[1].level}</p></MDBRow>,
          player3:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players.length > 2 ? n.players[2].avatar:''} /><p>{n.players.length > 2 ? n.players[2].user_id + " Lv" + n.players[2].level:'    '}</p></MDBRow>,
          player4:<MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players.length > 3 ? n.players[3].avatar:''} /><p>{n.players.length > 3 ? n.players[3].user_id + " Lv" + n.players[3].level:'    '}</p></MDBRow>,
          kind: kind,
          result:n.result,
          finished: new Date(n.finished).toLocaleString(),
          clickEvent: () => {loadGame(n)}});
      } else if(game_type === CD.GAME_TYPE.SKPNI) {       
        var no = props.game_count - index - (page - 1) * rowsPerPage;
        rows.push({no: no, 
          coin: n.coin, 
          player1: <MDBRow md = {'2'}><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[0].avatar} /><p>{n.players[0].user_id + " Lv" + n.players[0].level}</p></MDBRow>, 
          player2: <MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[1].avatar} /><p>{n.players[1].user_id + " Lv" + n.players[1].level}</p></MDBRow>,
          result: n.result,      
          finished: new Date(n.finished).toLocaleString(),
          clickEvent: () => {loadGame(n)}});
      }
      else if (game_type === CD.GAME_TYPE.OMOK) {
        var no = props.game_count - index - (page - 1) * rowsPerPage;
        rows.push({
          no: no, coin: n.coin,
          player1: <MDBRow md = {'2'}><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[0].avatar} /><p>{n.players[0].user_id + " Lv" + n.players[0].level}</p></MDBRow>, 
          player2: <MDBRow><Avatar alt="Profile Picture" className={classes.avatarImg}  src={n.players[1].avatar} /><p>{n.players[1].user_id + " Lv" + n.players[1].level}</p></MDBRow>,
          result: n.result,
          countdown: `${n.countdown}s`,
          finished: new Date(n.finished).toLocaleString(),
          clickEvent: () => {loadGame(n)}
        });
      }
    });
  }
  const ReviewObj = ({review: { rating, reviews }}) => (
    <div><Rater total={5} rating={reviews > 0? rating / reviews : 0} interactive={true} style={{fontSize:'1rem'}}/>{reviews}</div>
  );
  
  const getGameRecords = (page, rowsPerPage, gameType, find) => {
    props.req_game_list(props.game_type, gameType, find, rowsPerPage, page);
  };

  const loadGame = (game) => {
    const {history, game_type} = props;
    if(game_type === CD.GAME_TYPE.GO) {
      history.push('/go_record:' + game._id);
    }
    else if(game_type === CD.GAME_TYPE.PUZZLE)
      history.push('/puzzle_record:' + game._id);
    else if(game_type === CD.GAME_TYPE.PIECE_DESIGN)
      history.push('/pdesign_record:' + game._id);
    else if(game_type === CD.GAME_TYPE.FFA) {
      const {setGameKind} = props; 
      setGameKind(game.game_kind);    
      history.push('/ffa_record:' + game._id);      
    }
    else if(game_type === CD.GAME_TYPE.SKPNI)
      history.push('/skpni_record:' + game._id);
    else if (game_type === CD.GAME_TYPE.OMOK)
      history.push('/omok_record:' + game._id);
    props.showHiddenSideBar("0px",false );
  };

  const handleChangeGameType = (event) => {
    setGameType(event.target.value);
    setPage(1);
    setFind("");
    getGameRecords(0, rowsPerPage, event.target.value, "");
  };

  var allPage = Math.ceil(props.game_count / rowsPerPage);
  if (allPage === 0)
    allPage = 1;

  const handleToFirstPage = () => {
    setPage(1);
    getGameRecords(0, rowsPerPage, gameType, find);
  };

  const handleToPrevPage = () => {
    var prePage = page > 1? page - 1 : 1;
    setPage(prePage);
    getGameRecords(prePage - 1, rowsPerPage, gameType, find);
  };

  const handleToNextPage = () => {
    var nextPage = page < allPage? page + 1 : allPage;
    setPage(nextPage);
    getGameRecords(nextPage - 1, rowsPerPage, gameType, find);
  };

  const handleToLastPage = () => {
    setPage(allPage);
    getGameRecords(allPage - 1, rowsPerPage, gameType, find);
  };

  const handleChangeFind = event => {
    setFind(event.target.value);
    setPage(1);
    getGameRecords(0, rowsPerPage, gameType, event.target.value);
  };

  redrawContents();

  return (
    <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
      <MDBContainer style={{maxWidth: '92%'}}>
        <MDBRow>
          <MDBCol>
            <Select
              style={{ width: '12vw', paddingTop: '1vh' }}
              value={gameType}
              onChange={handleChangeGameType}
            >
              <MenuItem value={0}>{window.i18n.t("records.total_records")}</MenuItem>
              <MenuItem value={1}>{window.i18n.t("records.my_records")}</MenuItem>
              <MenuItem value={2}>{window.i18n.t("records.famous")}</MenuItem>
              <MenuItem value={3}>{window.i18n.t("records.championship")}</MenuItem>
              <MenuItem value={4}>{window.i18n.t("records.preferred")}</MenuItem>
            </Select>
          </MDBCol>
          <MDBCol>
            <MDBFormInline className="md-form active-cyan-2 float-left">
              <input
                className="form-control form-control-sm mr-2 w-20"
                type="text"
                placeholder={window.i18n.t("records.search")}
                aria-label={window.i18n.t("records.search")}
                value={find}
                onChange={handleChangeFind}
              />
              <i className={classes.searchStyle + " fa fa-search"} />
            </MDBFormInline>
          </MDBCol>
          <MDBCol>
            <MDBPagination className="float-right">
              <span className="pt-3 pr-2">{window.i18n.t("records.page")}</span>
              <MDBPageItem>
                <MDBPageNav className={classes.pageNaveStyle} onClick={handleToFirstPage}>&laquo;</MDBPageNav>
              </MDBPageItem>
              <MDBPageItem>
                <MDBPageNav className={classes.pageNaveStyle} onClick={handleToPrevPage}>&lsaquo;</MDBPageNav>
              </MDBPageItem>
                <input
                  type="text"
                  value={page + "/" + allPage}
                  readOnly={true}
                  className={classes.pagenationInputStyle}
                />
              <MDBPageItem>
                <MDBPageNav className={classes.pageNaveStyle} onClick={handleToNextPage}>&rsaquo;</MDBPageNav>
              </MDBPageItem>
              <MDBPageItem>
                <MDBPageNav className={classes.pageNaveStyle} onClick={handleToLastPage}>&raquo;</MDBPageNav>
              </MDBPageItem>
            </MDBPagination>
          </MDBCol>
        </MDBRow>
        <MDBDataTable hover theadColor = {'cyan lighten-3'} style = {{lineHeight: "0.5"}} displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="65vh" data={{columns, rows}} />
      </MDBContainer>
    </div>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    game_count : store.commonReducer.total,
    game_list : store.commonReducer.items,
    game_type : store.commonReducer.content,
    func: store.commonReducer.func,
    language: store.commonReducer.language,
    open_other: store.commonReducer.content > 2,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {     
      req_game_list: CommonAction.req_game_list,
      showHiddenSideBar:CommonAction.show_hidden_sidebar,
      setGameKind:FFAAction.set_game_kind,
      setFunc: CommonAction.setFunc,
    }, 
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Records));
