import ACTION from '../actionTypes';

const initialState = {
  train_count:0,
  train_d_coin:0,
  train_game_result: '',
  train_game: {
    boardsize: 0,
    h_index: 0,
    th_history_length: 0,
    th_taken_count: 0,
    taken_black_stones: 0,
    taken_white_stones: 0, 
    ini_stones: 0,
    th_correct_moves: 0,
    cur_correct_moves: 0,
    reward_xp: 0,
  },
};

export default function goTrainReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.INIT_TRAIN_COUNT:
      return {
        ...state,
        train_count:0,
        train_d_coin:0,
      }
    case ACTION.INIT_GO_TRAIN_BOARD:
      return {
        ...state,
        train_game_result: '',
        train_game: {
          ...state.train_game,
          taken_black_stones: 0,
          taken_white_stones: 0, 
          th_taken_count: !!action.th_taken_count? action.th_taken_count : 0,
          th_history_length: !!action.th_history_length? action.th_history_length : 0,
          ini_stones: !!action.ini_stones? action.ini_stones : 0,
          h_index: !!action.ini_stones? action.ini_stones : 0,
          th_correct_moves: !!action.th_correct_moves? action.th_correct_moves : 0,
          cur_correct_moves: 0,
          reward_xp: !!action.reward_xp? action.reward_xp : 0,
        },
      };
    case ACTION.DO_GO_TRAIN_MOVE:
      return {
        ...state,
        train_game: {
          ...state.train_game,
          taken_black_stones: action.taken_bstones,
          taken_white_stones: action.taken_wstones,
          h_index: action.h_index,
          cur_correct_moves: !!action.score? action.score : state.train_game.cur_correct_moves,
        },
      };
    case ACTION.UPDATE_TRAIN_GAME_RESULT:
      return {
        ...state,
        train_game_result: action.result,
        train_count:state.train_count + 1,
        train_d_coin:action.d_coin,
      };
    default: return state;
  }
}
