import ACTION from '../actionTypes';

const initialState = {
  isAuth: false,
  isLoading: false,
  error: {},
  returnUrl: "/",
  user : null,
  user_name: '',
  user_mail: '',
  user_contact: '',
  updateUser:false,
  stored_url: '',
};

export default function authReducer(state = initialState, action) {
  switch (action.type) {
    case ACTION.USER_LOGIN_REQUEST:
    case ACTION.USER_REGISTER_REQUEST:
    case ACTION.USER_PWDCHANGE_REQUEST:
      return {
        ...state,
        isLoading: true,
        error: {},
      }
    case ACTION.USER_LOGIN_SUCCESS:
    case ACTION.SET_CURRENT_USER:
      return {
        ...state,
        isLoading: false,
        isAuth: !!action.payload,
        user: action.payload,
        // returnUrl: "/"
      }
    case ACTION.SET_USER_INFO:
      return {
        ...state,
        user_name: action.payload.user_name,
        user_mail: action.payload.email,
        user_contact: action.payload.contact,
      }
    case ACTION.USER_LOGIN_FAIL:
    case ACTION.USER_REGISTER_FAIL:
    case ACTION.USER_PWDCHANGE_FAIL:
      return {
        ...state,
        isLoading: false,
        error: action.payload
      }
    
    case ACTION.USER_LOGOUT:
      return {
        ...initialState,
        returnUrl: action.newUrl,
        user: null,
      }
    case ACTION.USER_REGISTER_SUCCESS:
    case ACTION.USER_PWDCHANGE_SUCCESS:
      return {
        ...state,
        isLoading: false,
        // returnUrl: "/"
      }
    case ACTION.UPDATE_STORED_URL:
      return {
        ...state,
        stored_url:action.stored_url,
      }
   case ACTION.SET_RETURN_URL:
      return {
        ...state,
        returnUrl: action.url,
      }
    case ACTION.UPDATE_USER_AVATAR:
      const user = state.user;
      user.avatar = action.avatar;
      return {
        ...state,
        user:user,
        updateUser:!state.updateUser,
      }
    case ACTION.UPDATE_USER_COIN:
      {
        if(!!state.user)
          state.user.coin += action.d_coin;
        return {
          ...state,
          updateUser:!state.updateUser,
        }
      }
    default:
      return state;
  }
  
}