import React, {useState,useEffect, useRef} from 'react';
import io from 'socket.io-client';
import { withRouter } from "react-router-dom";
import {
  Avatar
} from '@material-ui/core';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import * as CommonAction from "../../store/actions/common.action";

function EmoticonImg(props) {   
  const {url, spriteArray, forever} = props;    
  var index; 
  let flag_ref = useRef();
  var timeOutHandle;
  let spriteArray_ref = useRef();  
  const [sprite, setSprite] = useState(spriteArray[0]);
  const [display, setDisplay] = useState('none');
  let imgLen = spriteArray.length;   
  useEffect(()=>{
    imgLen = spriteArray.length;  
    spriteArray_ref.current = props.spriteArray;
  }, [props.spriteArray]);
  const iterateImg = ()=>{  
    if(!flag_ref.current) {
      if(!!timeOutHandle)
        clearTimeout(timeOutHandle);
      return;
    }     
    if(index ===  imgLen - 1) {
      index = 0;                  
    }     
    if(flag_ref.current) {
      setSprite(spriteArray_ref.current[index]);
      index ++;
    }
    if(!!timeOutHandle)
      clearTimeout(timeOutHandle);
    timeOutHandle = setTimeout(()=>{
      iterateImg();
    }, 50)
  }
  useEffect(()=>{
    index = 0;
    iterateImg();
    return ()=>{
      clearTimeout(timeOutHandle);
    }
  }, []);  
  useEffect(()=>{    
    if(props.display === 'block') {
      index = 0;  
      flag_ref.current = true;
      setDisplay('block');
      iterateImg();
    } else {
      flag_ref.current= false;
    } 
  }, [props.display]);

  return(
    <div id='item' style = {{zIndex:'2007'}}>  
      <img id = 'emoticonImg'  onClick = {props.onClick} className = {props.className}  style = {{ background:`url(${url}) ${-sprite[0]}px ${-sprite[1]}px`, display:`${props.display}`}}/>
    </div>
  )
}
const mapStateToProps = (store) => {
  return {     
    isOpenEmoticonDlg:store.commonReducer.isOpenEmoticonDlg,   
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {   
    updateEmoticonDlg: CommonAction.updateEmoticonDlg,
    updateEmoticon: CommonAction.updateEmoticon,
  },
 
  dispatch,
);
export default connect(mapStateToProps, mapDispatchToProps)(withRouter(EmoticonImg));

