import ACTION from '../actionTypes';

const initialState = {
  all_bot_ids: [],
  bots_lobby: [],
  bots_go: [],
  bots_ffa: [],
  bots_skpni: [],
  bots_omok: [],
  socketGoRoom: null,
  socketPuzzleRoom: null,
  socketPDesignRoom: null,
  socketFFARoom: null,
  socketSKoniRoom: null,
  socketOmokRoom: null,
};

export default function adminReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.SET_ALL_BOTS:
      return {
        ...state,
        all_bot_ids: action.bot_ids,
      }
    case ACTION.UPDATE_BOTS:
      return {
        ...state,
        bots_lobby: action.where == 'lobby'? action.bots : state.bots_lobby,
        bots_go: action.where == 'go'? action.bots : state.bots_go,
        bots_ffa: action.where == 'ffa'? action.bots : state.bots_ffa,
        bots_skpni: action.where == 'skpni'? action.bots : state.bots_skpni,
        bots_omok: action.where == 'omok'? action.bots : state.bots_omok,
      }
    case ACTION.SET_ROOM_SOCKET:
      return {
        ...state,
        socketGoRoom: action.socketGoRoom != undefined? action.socketGoRoom : state.socketGoRoom,
        socketPuzzleRoom: action.socketPuzzleRoom != undefined? action.socketPuzzleRoom : state.socketPuzzleRoom,
        socketPDesignRoom: action.socketPDesignRoom != undefined? action.socketPDesignRoom : state.socketPDesignRoom,
        socketFFARoom: action.socketFFARoom != undefined? action.socketFFARoom : state.socketFFARoom,
        socketSKoniRoom: action.socketSKoniRoom != undefined? action.socketSKoniRoom : state.socketSKoniRoom,
        socketOmokRoom: action.socketOmokRoom != undefined? action.socketOmokRoom : state.socketOmokRoom,
      }
    default: 
      return state;
  }
}