import React, {useState,useEffect, useRef} from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { 
  MDBRow,
  MDBCol,
} from "mdbreact";
import { 
  Button,
} from '@material-ui/core';
import * as RoomAction from "../../store/actions/room.action";
import CD from "../../helper/const";
import SKoniBoard from  './SKoniBoard';
import GrController from '../control/GrController';
import {
  Avatar 
} from '@material-ui/core';
import * as Icon from "@material-ui/icons";
import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles(theme => ({
  background: {
    backgroundColor: "white", 
    width: "100vw", 
    height: "100vh", 
    position:"fixed", 
    left: "0vw", 
    top: "0vh", 
    zIndex:"1112" 
  },
  result: {
    fontSize: '2vw',  
    fontWeight: 'bold', 
    position: 'fixed', 
    left: "28vw", 
    marginTop: '0px', 
    color: '#ffff60', 
    opacity: '1'
  },
  roomCoinStyle: {
    position: 'fixed',
    left: '75vw',
    top: '20vh',
    width: '20vw'
  }
}));

function SKoniReplay(props) { 
  const classes = useStyles();
  const removePassText = ()=>{
    document.getElementById("passText").style.display = 'none';   
  };
  const showPassText = (top)=>{
    document.getElementById("passText").style.left = "23vw";
    document.getElementById("passText").style.top = top? "25vh" : "65vh";
    document.getElementById("passText").style.display = 'block';
  };
  
  useEffect(() => {
    const {user,req_game} = props; 
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);  
    req_game(!!user? user.user_id:'', CD.GAME_TYPE.SKPNI, id);  
    window.addEventListener('resize', ()=>{
    })  
  }, []);  
  useEffect(()=>{
    const {move_history, gr_index, turn} = props;      
    if(move_history.length !== 0 && gr_index !== move_history.length && move_history[gr_index -1] === 9000) {  
      if(turn === 1 ^ (gr_index - 1) % 2 === 0) 
        showPassText(true);
      else
        showPassText(false);
      setTimeout(()=>{
        removePassText();
      }, 1000);
    }
  }, [props.gr_index]);
  
  const viewPlayerInfo = (top, i) => {
    const {users} = props;
    let avatar = !!users[i]? users[i].avatar : '';
    let id = !!users[i]? users[i].user_id : '';
    let level = !!users[i]? users[i].level : '';
    let coin = !!users[i]? users[i].coin : '';
    return (
      <MDBRow style = {{width: '25vw', marginLeft: "8vw", marginTop: top? "20vh" : "43vh"}}>
        <MDBCol size = {2}>
          <h6 style = {{fontSize: '1.5rem', fontWeight: 'bold', color: top? 'blue' : 'red', paddingTop: '0.5vw'}}>{top? 'Blue:' : 'Red'}</h6>
        </MDBCol>
        <MDBCol size = {2}>
          <Avatar style = {{width: "4vw", height: "4vw"}} src = {avatar}/>
        </MDBCol>
        <MDBCol>
          <MDBRow>
            <h6 style = {{fontSize: '1rem', fontWeight: 'bold', color: top? 'blue' : 'red', paddingTop: '0.5vw'}}>{id + `(${level}Lv)`}</h6>
          </MDBRow>
          <MDBRow>
            <h6 style = {{fontSize: '1rem', fontWeight: 'bold', color: 'orange'}}><i className={" fa fa-star"}/>{" "}{coin}</h6>
          </MDBRow>
        </MDBCol>
      </MDBRow>
    );
  }
  const ExitReplay = () => {
    props.history.push("/records");
  }

  const {user, users, rewards, game_result, move_history, gr_index, roomCoin, finished} = props;
  var finished_date = new Date(finished).toLocaleString();
  let downIndex = 1; //(!!user && users.length > 0 && user.user_id === users[0].user_id)? 0 : 1;
  return(  
    <div className={classes.background}>
      <SKoniBoard id='board' replay = {true}/>
      {viewPlayerInfo(true, 1 - downIndex)};
      {viewPlayerInfo(false, downIndex)};
      <div class = {classes.roomCoinStyle}>
        <h5 className = "font-weight-bold mb-2"><i className = 'fa fa-star mr-1' style = {{fontSize: '1rem'}}/>{roomCoin}</h5>
        <h5 className = "font-weight-bold mb-4">{finished_date}</h5>
        <MDBRow>
          <MDBCol size = '4'>
            <h5 className = "font-weight-bold mb-4">{window.i18n.t("go_replay.step")}</h5>
          </MDBCol>
          <MDBCol>
            <h5 className = "font-weight-bold mb-4">{move_history.length}</h5>
          </MDBCol>
        </MDBRow>
        <MDBRow>
          <MDBCol size = '4'>
            <h5 className = "font-weight-bold mb-4">{window.i18n.t("game.result") + " :"}</h5>
          </MDBCol>
          {
            game_result[0] != "d" &&
            <MDBCol>
              <MDBRow>
                <MDBCol size = "4">
                  <h5 className = "font-weight-bold">{"Blue"}</h5>
                </MDBCol>
                  <h5 className = "font-weight-bold">{ game_result[0]}</h5>
              </MDBRow>
              <MDBRow>
                <MDBCol size = "4">
                  <h5 className = "font-weight-bold">{"Red"}</h5>
                </MDBCol>
                  <h5 className = "font-weight-bold">{ game_result[1]}</h5>
              </MDBRow>
            </MDBCol>
          }
          {
            game_result[0] == "d" &&
            <MDBCol>
              <h5 className = "font-weight-bold mb-4">{"Drawn"}</h5>
            </MDBCol>
          }
        </MDBRow>
      </div> 
      <MDBRow style={{marginLeft: '75vw'}}>
        <GrController />
      </MDBRow>
      {
        move_history.length !== 0 && gr_index === move_history.length && (
          <div alt = 'result' id = 'result' style = {{width: "100vw", height: "100vh", position:"fixed", left: "0vw", top: "0vh", zIndex:"1113" }}>                 
            <div alt = 'result_back'  id = 'result_img'  style = {{backgroundColor:'black', position:'fixed', marginTop:'0px', width: "100vw", height: "100vh", left: "0vw", top: "0vh", opacity: '0.4'}}></div> 
            <p className={classes.result} style = {{top: "18vh"}}>{game_result[0]}</p>
            <p className={classes.result} style = {{top: "23vh"}}>{rewards[0]}</p> 
            <p className={classes.result} style = {{top: "72vh"}}>{game_result[1]}</p>
            <p className={classes.result} style = {{top: "77vh"}}>{rewards[1]}</p>
          </div>
        )
      }
      <p id = 'passText'  style = {{fontSize:'3vw', position:'fixed', marginTop:'0px', display:'none', textShadow :'2px 2px  5px green', color:'tomato'}}>
        Pass
      </p>     
      <Button id = 'message' alt = 'message' onClick = {ExitReplay} style = {{color:'black', position:'fixed', top:'3vh', left:'85vw',  zIndex:'1113',  width: "8vw", height: "8vh" }}>
        <Icon.ExitToApp style = {{width: '3vw', height:'auto'}} />  
      </Button> 
    </div>
  );
}
const mapStateToProps = (store) => {
  return {    
    user: store.authReducer.user,
    users: store.roomReducer.room.users,      
    game_result: store.roomReducer.room.result,
    rewards: store.roomReducer.room.rewards,
    gr_index: store.commonReducer.gr_index,
    move_history: store.roomReducer.room.move_history,
    roomCoin: store.roomReducer.room.coin,
    finished: store.roomReducer.room.finished,
    turn: store.roomReducer.room.turn,
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    req_game: RoomAction.req_game,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(SKoniReplay));
