import React, { useState, useEffect, useRef } from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import PuzzleProblem from "./puzzleProblem";
import * as ToastAction from "../../store/actions/toast.action";

import { makeStyles } from '@material-ui/core/styles';

import { Button } from '@material-ui/core'
import {
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
} from "mdbreact";

import * as PuzzleProblemAction from "../../store/actions/puzzle_problem.action";

const useStyles = makeStyles(theme => ({
  container: {
    position: 'fixed',
    left: "0vw", 
    top: '0vh',
    width: "100vw", 
    height:"100vh",
    zIndex: '1111',
    backgroundImage: "url(/assets/img/backg_2_2.jpg)"
  },
  book: {
    position: 'fixed',
    left: '0vw',
    top: '5vh',
    width: "15vw", 
    height:"10vh",
    zIndex: '1112',
    color: 'black',
    background: 'rgba(255,255,255,0.3)',
    paddingTop: '2vh',
  },
  navigationButtons: {
    position: 'fixed',
    left: '2vw',
    top: '20vh',
    width: '15vw',
    height: '7vh',
    background: 'rgba(200,200,200,0)',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
  text: {
    paddingLeft: '1.5vw', 
    fontSize: '3vh',
    fontWeight: 'bold',
    fontFamily: 'cursive',
  },
  time: {
    position: 'fixed',
    top: '30vh',
    left: '0vw',
    width: "24vw",
    zIndex: '1112',
    color: 'black',
    textAlign: 'center'
  },
  timeText: {
    fontSize: '6vh',
    fontWeight: 'bold',
    fontFamily: 'cursive',
    color: 'rgba(255, 255, 255, 0.8)',
    marginLeft: 'auto',
    marginRight: 'auto'
  },
  hint: {
    position: 'fixed',
    left: '5vw',
    top: '70vh',
    width: '15vw',
    height: '7vh',
    background: 'rgba(200,200,200,0)',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
  retry: {
    position: 'fixed',
    left: '5vw',
    top: '80vh',
    width: '15vw',
    height: '7vh',
    background: 'rgba(200,200,200,0)',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
  quit: {
    position: 'fixed',
    right: '0vw',
    top: '3vh',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
  pageNaveStyle: {
    padding: 0,
    paddingBottom: 0,
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    marginTop: '6px',
    marginLeft: '3px',
    marginRight: '3px',
    textAlign: 'center',
    color: "dark-grey",
    width: '80px',
    WebkitAppearance: 'button !important',
    fontSize: '1.3rem',
  },
}));

var globalHandleTime;

function SolvePuzzleProblem(props) {
  const classes = useStyles();

  const handleProblemNavigation = (index) => {
    const { problem_list, req_problem } = props;
    if (index >= problem_list.length)
      index = problem_list.length - 1;
    if (index <= 0)
      index = 0;
    req_problem(problem_list[index], index);
  };

  const handleExit = () => {
    props.history.goBack();
  }

  const handleHint = () => {
    let strHint = props.problem.hint_comment;
    if(strHint != "")
      props.openModal({ content: strHint, type: 'notice', clickOK: () => {}, clickCancel: () => {}});
  }
  const handleRetry = () => {
    const {problem, solved, retried, solve_time, on_resolve_problem} = props;
    on_resolve_problem(problem, solved, retried, solve_time);
  }

  const roundTimeDisplay = () =>{
    let second, minute, hour; 
    var date = new Date();
    hour = date.getHours();
    minute = date.getMinutes();
    if(minute < 10)
      minute = "0" + minute;
    second = date.getSeconds(); 
    if(second < 10)
      second = "0" + second;
    document.getElementById('time_counter').innerHTML = hour + ':' + minute + ':' + second;     
  };

  useEffect(() => {
    const {req_problem_list} = props;
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    req_problem_list(id);
    globalHandleTime = setInterval(roundTimeDisplay, 1000);
    return ()=>{
      clearInterval(globalHandleTime);
    }
  }, [])

  const {problem_book, problem_list, problem_index} = props;
  return (
    <div className={classes.container}>
      <div className={classes.book}>
        <span className={classes.text}>
          {problem_book.title}
        </span>
      </div>
      <div className={classes.navigationButtons}>
        <div className={classes.text}>
          <MDBPagination>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, 0)}><big>&laquo;</big></MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_index - 1)}><big>&lsaquo;</big></MDBPageNav>
            </MDBPageItem>
              <input
                type="text"
                value={"" + (problem_index + 1) + "/" + problem_list.length}
                readOnly={true}
                className={classes.pagenationInputStyle}
              />
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_index + 1)}><big>&rsaquo;</big></MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_list.length - 1)}><big>&raquo;</big></MDBPageNav>
            </MDBPageItem>
          </MDBPagination>
        </div>
      </div>
      <div className={classes.time}>
        <span id = "time_counter" className={classes.timeText}>
        </span>
      </div>
      <div className={classes.hint}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0.5)"}} onClick = {handleHint}>
            <i className = "fa fa-binoculars" style = {{fontSize: '1.5rem', color: 'orange'}}><span className = {classes.text} style = {{color: 'white'}}>Hint</span></i>
          </Button>
        </span>
      </div>
      <div className={classes.retry}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0.5)"}} onClick = {handleRetry}>
            <i className = "fa fa-repeat" style = {{fontSize: '1.5rem', color: 'orange'}}><span className = {classes.text} style = {{color: 'white'}}>Retry</span></i>
          </Button>
        </span>
      </div>
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i className = "fa fa-reply" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
      <div>
        <PuzzleProblem btnDisplay = {true}/>
      </div>
    </div>
  )
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  problem_book: store.problemBookReducer.problem_book,
  problem_list: store.problemBookReducer.problem_list,
  problem_index: store.puzzleProblemReducer.problem_index,
  problem: store.puzzleProblemReducer.problem,
  solved: store.puzzleProblemReducer.problem.solved,
  retried: store.puzzleProblemReducer.problem.retried,
  solved_time: store.puzzleProblemReducer.problem.solved_time,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    openModal: ToastAction.openModal,
    req_problem_list: PuzzleProblemAction.req_problem_list,
    req_problem: PuzzleProblemAction.req_problem,
    on_resolve_problem: PuzzleProblemAction.on_resolve_problem,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(SolvePuzzleProblem);

