import ACTION from '../actionTypes';
import * as Logic from '../../components/pdesign/pdesignLogic'

export const updatePieceKind = (kind) => {
  return ({type: ACTION.UPDATE_PIECE_KIND, kind});
};

export const updatePieceIndex = (index) => {
  return ({type: ACTION.UPDATE_PIECE_INDEX, index});
};

export const updateTool = (tool) => {
  return ({type: ACTION.UPDATE_TOOL, tool});
};

export const updatePenThick = (thick) => {
  return ({type: ACTION.UPDATE_PEN_THICK, thick});
};

export const updateToolProperty = (property) => {
  return ({type: ACTION.UPDATE_TOOL_PROPERTY, property});
};

export const on_complete_draw = () => {
  return ({type: ACTION.COMPLETE_PDESIGN_DRAW})
}