import React, { useEffect, useState, useRef } from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import {
  MDBContainer,
} from "mdbreact";

import io from 'socket.io-client';
import config from "../../helper/config";
import CD from "../../helper/const";
import PROTOCOL from "../../helper/protocol";
import ErrorCode from "../../helper/errorCode";

import Bots from "./Bots";
import DBUsers from "./DBUsers";

import * as AuthAction from "../../store/actions/auth.action";
import * as CommonAction from "../../store/actions/common.action";
import * as AdminAction from "../../store/actions/admin.action";

const useStyles = makeStyles(theme => ({
  container: {
    minHeight: '83vh',
    maxWidth: '92%',
    left:'7.8vw',
    marginLeft: '2vw',
  },
}));

function Admin(props) {
  const classes = useStyles();
  // const [notice, setNotice] = useState("");
  
  useEffect(() => {
    props.setFunc(CD.FUNC.FUNC_ADMIN);
  }, []);

  useEffect(() => {
    reloadContent();
  }, [props.user]);

  const reloadContent = () => {
    if (!!props.user) {
      socketWithLobby();
      socketWithGoRoom();
      socketWithPuzzleRoom();
      socketWithPDesignRoom();
      socketWithFFARoom();
      socketWithSKoniRoom();
      socketWithOmokRoom();
    }
  };

  const socketWithLobby = () => {
    const {user, setSocketLobby, updateDBUserList, setAllBots, updateBots} = props;
    let {socketLobby} = props;
    if(socketLobby === null) {
      socketLobby = io(config.SOCKET_SERVER);
      setSocketLobby(socketLobby);

      socketLobby.on('connect', function() {
      });

      socketLobby.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.CSC_BOT_LIST:
            if(err === ErrorCode.SUCCESS) {
              setAllBots(msg.items);           
            }
            break;
          case PROTOCOL.SC_BOTS_UPDATED:
            if(err === ErrorCode.SUCCESS) {
              updateBots(msg.where, msg.bots);           
            }
            break;
          case PROTOCOL.CSC_DB_USER_LIST:
            if(err === ErrorCode.SUCCESS) {
              updateDBUserList(msg.items, msg.total);           
            }
            break;
          default:
            break;
        }
      });
      socketLobby.emit('cs_message', PROTOCOL.CS_LOBBY_USER, {token: user.token});
      socketLobby.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
      socketLobby.emit('admin_message', PROTOCOL.CSC_BOT_LIST, {token: user.token});
    }    
  };
  const socketWithGoRoom = () => {
    const {user, setSocketRoom, updateBots} = props;
    let {socketGoRoom} = props;
    if(socketGoRoom === null) {
      socketGoRoom = io(config.GO_ROOM_SERVER);
      setSocketRoom(CD.GAME_TYPE.GO, socketGoRoom);

      socketGoRoom.on('connect', function() {
      });

      socketGoRoom.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.SC_BOTS_UPDATED:
            if(err === ErrorCode.SUCCESS) {
              updateBots(msg.where, msg.bots);           
            }
            break;       
          default:
            break;
        }
      });
      socketGoRoom.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
    }    
  };
  const socketWithPuzzleRoom = () => {
    const {user, setSocketRoom} = props;
    let {socketPuzzleRoom} = props;
    if(socketPuzzleRoom === null) {
      socketPuzzleRoom = io(config.PUZZLE_ROOM_SERVER);
      setSocketRoom(CD.GAME_TYPE.PUZZLE, socketPuzzleRoom);

      socketPuzzleRoom.on('connect', function() {
      });

      socketPuzzleRoom.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          default:
            break;
        }
      });
      socketPuzzleRoom.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
    }    
  };
  const socketWithPDesignRoom = () => {
    const {user, setSocketRoom} = props;
    let {socketPDesignRoom} = props;
    if(socketPDesignRoom === null) {
      socketPDesignRoom = io(config.PDESIGN_ROOM_SERVER);
      setSocketRoom(CD.GAME_TYPE.PIECE_DESIGN, socketPDesignRoom);

      socketPDesignRoom.on('connect', function() {
      });

      socketPDesignRoom.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          default:
            break;
        }
      });
      socketPDesignRoom.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
    }    
  };
  const socketWithFFARoom = () => {
    const {user, setSocketRoom, updateBots} = props;
    let {socketFFARoom} = props;
    if(socketFFARoom === null) {
      socketFFARoom = io(config.FFA_ROOM_SERVER);
      setSocketRoom(CD.GAME_TYPE.FFA, socketFFARoom);

      socketFFARoom.on('connect', function() {
      });

      socketFFARoom.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.SC_BOTS_UPDATED:
            if(err === ErrorCode.SUCCESS) {
              updateBots(msg.where, msg.bots);           
            }
            break;       
          default:
            break;
        }
      });
      socketFFARoom.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
    }    
  };
  const socketWithSKoniRoom = () => {
    const {user, setSocketRoom, updateBots} = props;
    let {socketSKoniRoom} = props;
    if(socketSKoniRoom === null) {
      socketSKoniRoom = io(config.SKPNI_ROOM_SERVER);
      setSocketRoom(CD.GAME_TYPE.SKPNI, socketSKoniRoom);

      socketSKoniRoom.on('connect', function() {
      });

      socketSKoniRoom.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.SC_BOTS_UPDATED:
            if(err === ErrorCode.SUCCESS) {
              updateBots(msg.where, msg.bots);           
            }
            break;       
          default:
            break;
        }
      });
      socketSKoniRoom.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
    }    
  };

  const socketWithOmokRoom = () => {
    const {user, setSocketRoom, updateBots} = props;
    let {socketOmokRoom} = props;
    if(socketOmokRoom === null) {
      socketOmokRoom = io(config.OMOK_ROOM_SERVER);
      setSocketRoom(CD.GAME_TYPE.OMOK, socketOmokRoom);

      socketOmokRoom.on('connect', function() {
      });

      socketOmokRoom.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.SC_BOTS_UPDATED:
            if(err === ErrorCode.SUCCESS) {
              updateBots(msg.where, msg.bots);           
            }
            break;       
          default:
            break;
        }
      });
      socketOmokRoom.emit('admin_message', PROTOCOL.CS_ADMIN_CONNECTED, {token: user.token});
    }    
  }

  // const handleChange = (event) => {
  //   switch(event.target.name) {
  //     case "notice":
  //       setNotice(event.target.value);
  //       break;
  //     default:
  //       break;
  //   }
  // };

  // const handleNotice = () => {    
  //   const {user, socketLobby}= props;  
  //   alert(notice)
  //   socketLobby.emit('admin_message', PROTOCOL.CS_NOTICE,  {token:user.token, content:notice}); //{token, content}
  // };

  return (
    <div style = {{marginTop:'2vh'}}>
      <MDBContainer className={classes.container} >
        <Bots />
        <h5>-------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------</h5>
        <DBUsers />
        {/* <MDBRow className="px-4 pb-2">
          <MDBCol size="2">
            <MDBBtn className="font-weight-bold "  color = {"green"}  style={{width: '7vw'}} onClick={handleNotice}>Notice</MDBBtn>
          </MDBCol>
          <MDBCol className="pt-2">
            <textarea name="notice" className="form-control" rows="1" value={notice} onChange={handleChange}/>
          </MDBCol>
        </MDBRow> */}
     
      </MDBContainer>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  socketLobby: store.commonReducer.socketLobby,
  socketGoRoom: store.adminReducer.socketGoRoom,
  socketPuzzleRoom: store.adminReducer.socketPuzzleRoom,
  socketPDesignRoom: store.adminReducer.socketPDesignRoom,
  socketFFARoom: store.adminReducer.socketFFARoom,
  socketSKoniRoom: store.adminReducer.socketSKoniRoom,
  socketOmokRoom: store.adminReducer.socketOmokRoom,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    registerUser: AuthAction.registerUser,
    updateDBUserList: CommonAction.updateList,
    setFunc: CommonAction.setFunc,
    setSocketLobby: CommonAction.setSocketLobby,
    setSocketRoom: AdminAction.setSocketRoom,
    setAllBots: AdminAction.setAllBots,
    updateBots: AdminAction.updateBots,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Admin));
