

import React, {useEffect, useState} from "react";
import styled from "styled-components";
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import {
  MDBRow,
  MDBCol, 
} from "mdbreact";
import {
  Button as MuiButton,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Divider as MuiDivider,
  FormControl as MuiFormControl,
  FormControlLabel,
  FormLabel,
  InputLabel,
  MenuItem,
  Radio,
  RadioGroup,
  Select as MuiSelect,  
  FormGroup,
  Switch,
} from "@material-ui/core";

import { spacing } from "@material-ui/system";
import { makeStyles } from '@material-ui/core/styles';
import * as GoAction from "../../store/actions/go.action";
import '../skpni/star.css';
const Button = styled(MuiButton)(spacing);
const Divider = styled(MuiDivider)(spacing);
const Select = styled(MuiSelect)(spacing);

const FormControlSpacing = styled(MuiFormControl)(spacing);

const FormControl = styled(FormControlSpacing)`
  min-width: 148px!important;
`;

var self;
const useStyles = makeStyles(theme => ({  
  createStyle: {
    color: '#fff',
    backgroundColor: '#0f0f0a',
    width:"14.6vw",
    height:"10vw",
   
    marginLeft:"1.4vw",
    marginTop:"0.5vw",
    fontSize:'1.8vw',
  },
  kindBtn: {   
    border: '1px solid black',   
    marginLeft:'0.5vw',
    width:'4vw',
    height:'4vh',
    color:'white',   
    backgroundColor: '#0f0f0a',
    opacity:'0.4',
    zIndex:'1200'
  },
}
)
);
 function SettingDlg(props) { 
  const classes = useStyles();
  let disabled = false; 
  const [selectedBtn, setKindBtn] = useState([true, false, false, false]);
  const kindHandle = (event)=>{
    let selectedBtn;
    switch(event.target.id) {
      case "man":
      selectedBtn = [true, false, false, false];
      setKindBtn(selectedBtn.slice());
      break;
    case "women":
      selectedBtn = [false, true, false, false];
      setKindBtn(selectedBtn.slice());
      break;
    case "boy":
      selectedBtn = [false, false, true, false];
      setKindBtn(selectedBtn.slice());
      break;
    case "girl":
      selectedBtn = [false, false, false, true];
      setKindBtn(selectedBtn.slice());
      break;
    default:
      break;
    }
  };
  const handleCancel = ()=>{
    props.history.push('/');
  };
  const handleOK= ()=>{
    props.history.push('/');
  }; 
  return (      
    <div style = {{position:'fixed', borderRadius: '15px', boxShadow:'0px 0px 20px rgba(0, 0, 0, 1)', backgroundColor:'rgba(0, 0, 0, 0.1)', left:'30vw', marginTop:'20vh',  width:'40vw', height:'45vh', zIndex:'1112'}}>
      <DialogTitle id="form-dialog-title" style = {{color:'white'}}>SETTING</DialogTitle>         
      <FormGroup >
        <MDBRow>
          <MDBCol size = "6">
            <h4 style = {{fontSize:'1.5vw', marginLeft:'2vw '}}>background music</h4>
          </MDBCol>
          <MDBCol size = "1">
            <FormControlLabel
              control={
                <Switch
                  color="primary"
                  
                />
              }               
            />
          </MDBCol>
        </MDBRow>
        <MDBRow>
          <MDBCol size = "6">
            <h4 style = {{fontSize:'1.5vw', marginLeft:'2vw '}}>effect music</h4>
          </MDBCol>
          <MDBCol size = "1">
            <FormControlLabel
              control={
                <Switch
                  color="primary"
                  // checked={true}
                  //onChange={this.handleBadgeVisibility}
                />
              }               
            />
          </MDBCol>
        </MDBRow>
        <MDBRow>
          <MDBCol size = '4'>      
            <h4 style = {{fontSize:'1.5vw', marginLeft:'2vw '}}>kind of sound</h4>
          </MDBCol>
          <MDBCol>
            {selectedBtn[0] === true? <button id='man' className = "btnOpacity" onClick = {kindHandle}>
              man
            </button>: <button id='man' className = {classes.kindBtn} onClick = {kindHandle}>
              man
            </button> }
            {selectedBtn[1]?<button id='women' className = "btnOpacity" onClick = {kindHandle}>
              women
            </button> :<button id='women' className = {classes.kindBtn} onClick = {kindHandle}>
              women
            </button> }
            {selectedBtn[2]?<button id='boy' className =  "btnOpacity" onClick = {kindHandle}>
              boy
            </button> : <button id='boy' className = {classes.kindBtn} onClick = {kindHandle}>
              boy
            </button> }
            {selectedBtn[3]?<button id='girl' className = "btnOpacity" onClick = {kindHandle}>
              girl
            </button> : <button id='girl' className = {classes.kindBtn} onClick = {kindHandle}>
              girl
            </button> }
          </MDBCol>
        </MDBRow>
      </FormGroup>
      <DialogActions style = {{position:'fixed',top:'63vh', marginLeft:'25vw'}}>
        <Button  id= 'cancel' onClick={handleCancel} color="secondary">
          <i style = {{fontSize:'2vw'}} className={ " fa fa-close"}/>
        </Button>
        <Button onClick={handleOK} color="primary" disabled = {disabled}>
          <i style = {{fontSize:'2vw' }}className={ " fa fa-check"}/>
        </Button>
      </DialogActions>
    </div>
  );
}





const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(SettingDlg);
