import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = {
  socketRoom: null,
  room: {
    room_id: '',
    room_no: 0,
    room_type: '',
    room_url: '',
    coin: 0,
    setting: {
      board_size: 0,
      handicap: 0,
      coin: 0,
      time: 1,
      kind: 1,
      inc_room_coin: 1,
      left_count: 0,
      problems: 1,
    },
    players: [],
    users: [],
    users2_count: 0,
    join_time: 0,
    prepared: false,
    room_state: 0,
    result: '',
    finished: '',
    rewards: [],
    desc: '',
    turn: 0,
    move_history: [],
    chats: [],
    emoticons: [],
    spectate_mode: 0,
  },
};

export default function roomReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_SETTING:
      return {
        ...state,
        room: {
          ...state.room,
          setting: action.setting,
        }
      };
    case ACTION.SET_ROOM_SOCKET:
      return {
        ...state,
        socketRoom: action.socketRoom,
      };
    case ACTION.JOINED_PLAYER:
      return {
        ...state,
        room: {
          ...state.room,
          players: state.room.players.concat(action.user),
          users: state.room.users.concat(action.user),
          join_time: CD.WAITING_JOIN_TIME,
        },
      }
    case ACTION.ENTER_ROOM:
      return {
        ...state,
        room: {
          ...state.room,
          room_id: action.room_id,
          room_type: action.room_type,
          room_url: action.socket_url,
        },
      };
    case ACTION.LOAD_ROOM_INFO:
      return {
        ...state,
        room: {
          ...state.room,
          room_id: action.room_id,
          room_no: action.room_no,
          coin: action.coin,
          players: action.players,
          users: action.users,
          users2_count: action.users2_count,
          join_time: action.join_time,
          prepared: action.prepared,
          room_state: action.room_state,
          result: !!action.result? action.result : state.room.result,
          rewards: !!action.rewards? action.rewards : state.room.rewards,
          desc: !!action.desc? action.desc : state.room.desc,
          turn: !!action.turn? action.turn : state.room.turn,
          move_history: !!action.move_history? action.move_history : state.room.move_history,
          chats: [],
          spectate_mode: 0,
          setting: !!action.setting? action.setting : state.room.setting,
        },
    };
    case ACTION.UPDATE_PLAYERS:
      return {
        ...state,
        room: {
          ...state.room,
          players: action.players,
        }
      };
    case ACTION.ADD_USER_IN_ROOM:
      return {
        ...state,
        room: {
          ...state.room,
          users: !!action.user? state.room.users.concat(action.user) : state.room.users,
          user2_count: !action.user? state.room.users2_count + 1 : state.room.users2_count,
        }
      };
    case ACTION.REMOVE_USER_FROM_ROOM:
      return {
        ...state,
        room: {
          ...state.room,
          users: state.room.users.filter((element) => (!action.user_id || action.user_id !== element.user_id) && element),
          players: state.room.players.filter((element) => (!action.user_id || action.user_id !== element.user_id) && element),
          users2_count: !action.user_id? state.room.users2_count - 1: state.room.users2_count,
          room_state: action.room_state,
        }
      };
    case ACTION.LOAD_RECORD:
      return {
        ...state,
        room: {
          ...state.room,
          coin:action.game.coin,
          users:action.game.players,
          players:action.game.players,
          result:action.game.result,
          rewards: !!action.game.rewards? action.game.rewards : state.room.rewards,
          room_state:action.room_state,
          finished: action.game.finished,
          turn: !!action.game.first_turn? action.game.first_turn : 0,
          move_history: !!action.game.move_history? action.game.move_history : state.room.move_history,
        }
      }
    case ACTION.INIT_MOVE_HISTORY:
      return {
        ...state,
        room: {
          ...state.room,
          move_history: [],          
        }
      };
    case ACTION.SET_MOVE_HISTORY:
      return {
        ...state,
        room: {
          ...state.room,
          move_history: action.move_history,          
        }
      };
    case ACTION.DO_MOVE:
      return {
        ...state,
        room: {
          ...state.room,
          turn: action.next_turn,
          players: action.players,
          move_history: state.room.move_history.concat(action.move),
        }, 
      };
    case ACTION.ADD_MOVE:
      return {
        ...state,
        room: {
          ...state.room,
          move_history: state.room.move_history.concat(action.move),
        }
      };
    case ACTION.UPDATE_ROOM_STATE:
      return {
        ...state,
        room: {
          ...state.room,
          room_state: action.room_state,
        },
      };
    case ACTION.UPDATE_SPECTATE_MODE:
      return {
        ...state,
        room: {
          ...state.room,
          spectate_mode: action.spectate_mode,
        }
      };
    case ACTION.UPDATE_GAME_RESULT:
      return {
        ...state,
        room:{
          ...state.room,
          result: action.result,
        }
      }
    case ACTION.UPDATE_COIN_RESULT:
      if(action.player3_update_coin === 0) {
        state.room.players[0].coin += action.player1_update_coin;
        state.room.players[1].coin += action.player2_update_coin;
      } else {
        state.room.players[0].coin += action.player1_update_coin;
        state.room.players[1].coin += action.player2_update_coin;
        state.room.players[2].coin += action.player3_update_coin;
        state.room.players[3].coin += action.player4_update_coin;
      }
      return state;
    case ACTION.ROOM_EMOTICON:
      return {
        ...state,
        room: {
          ...state.room,
          emoticons: state.room.emoticons.concat({
            user_id: action.user_id,
            emoticon: action.emoticon
          }),
        }
      };
    case ACTION.ROOM_CHAT:
      return {
        ...state,
        room: {
          ...state.room,
          chats: state.room.chats.unshift({user_id: action.user_id, chat: action.chat}) < 10? state.room.chats : state.room.chats.slice(0, 10),
        }
      };
    case ACTION.CHANGE_ROOM_TYPE:
      return {
        ...state,
        room: {
          ...state.room,
          room_type: action.room_type,
        }
      };
    default:
      return state;
  }
}