import React, { useEffect } from 'react';
import { makeStyles } from '@material-ui/core/styles';
import Typography from '@material-ui/core/Typography';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import {withRouter } from "react-router-dom";
import * as CommonAction from "../../store/actions/common.action";
import * as AuthAction from "../../store/actions/auth.action";
import CD from '../../helper/const';

const useStyles = makeStyles(theme => ({
  container: {
    display: 'inline-grid',
    backgroundImage: `url("/assets/img/landing1.png")`,
    backgroundSize: 'cover',
    height: '85vh',
    width:'100%',
    zIndex: '998'
  },
  fontStyle1: {
    color: 'rgba(66, 66, 144, 1)',
    paddingTop: '8vh',
    paddingLeft: '6vw',
    fontWeight: '500',
    fontFamily: 'cursive'
  },
}));
function Landing (props) {
 useEffect(()=>{
    props.showHiddenSideBar('14.5vw', true);
    props.setFunc(CD.FUNC.FUNC_NONE);
 },[]);
 const classes = useStyles();
    return (     
      <React.Fragment>
        <div className={classes.container}>
          <Typography variant="h3" className={classes.fontStyle1}>
            {window.i18n.t("app.powerful_intelligence")}
          </Typography>
      </div>        
      </React.Fragment>
    );
}

function mapStateToProps(store) { 
  return {
    user: store.authReducer.user,    
    language: store.commonReducer.language,
    game_type : store.commonReducer.content,
    award_open:store.goReducer.award_open,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      showHiddenSideBar:CommonAction.show_hidden_sidebar,     
      setFunc: CommonAction.setFunc,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Landing));