function OmokReplay(props) {
  const classes = useStyles();
  const [room_coin, setRoomCoin] = useState(0);
  const [players, setPlayers] = useState([]);
  const [result, setResult] = useState([]);
  const [rewards, setRewards] = useState([]);
  const [finished, setFinished] = useState();
  const [countdown, setCountdown] = useState(0);
  const [open_dialog, setOpenDialog] = useState(false);
  const [move_histories, setMoveHistories] = useState([]);
  const [disable_vote, setDisableVote] = useState(true);
  const [first_turn, setFirstTurn] = useState(0);

  useEffect(() => {
    const {user, req_game} = props;
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    req_game(!!user? user.user_id : '', CD.GAME_TYPE.OMOK, id);
    props.update_common_gr_index(0);
  }, []);

  useEffect(() => {
    setRoomCoin(props.room_coin);
  }, [props.room_coin]);

  useEffect(() => {
    setResult(props.result);
    setTimeout(() => {
      updateResultLayer(props.result);
    }, 500);
  }, [props.result]);

  useEffect(() => {
    setCountdown(props.countdown);
  }, [props.countdown]);

  useEffect(() => {
    setPlayers(props.players);
  }, [props.players]);

  useEffect(() => {
    setFinished(new Date(props.finished).toLocaleString());
  }, [props.finished]);

  useEffect(() => {
    // if (players.length != 2) return;
    // for (let i = 0; i < 2; i ++) {
    //   var img = document.getElementById(`stone_${i}`);
    //   if (i == props.first_turn) {
    //     img.setAttribute('src', 'assets/img/stone_b.png');
    //   } else img.setAttribute('src', 'assets/img/stone_w.png');
    // }
    setFirstTurn(props.first_turn);
  }, [props.first_turn]);

  const handleExit = () => {
    props.history.goBack();
  };

  const updateResultLayer = (result) => {
    var result_layer = document.getElementById('result_layer');
    if (props.players.length < 2 || !result_layer) return;
    result_layer.innerHTML = null;
    result_layer.innerHTML = "Result: "
    if (result == "drawn")
      result_layer.innerHTML += "Draw"
    else if (result == "WL")
      result_layer.innerHTML += props.players[0].user_id + " " + "Win!";
    else result_layer.innerHTML += props.players[1].user_id + " " + "Win!";
  }

  const handleChangePlayer = (index) => {
    for (let i = 0; i < players.length; i ++) {
      var div = document.getElementById(`player_${i}`);
      div.style.opacity = '0.3';
    };
    document.getElementById(`player_${index}`).style.opacity = '1';
    // board_array_init();
  }

  const handleDialogClose = () => {
    setOpenDialog(false);
  }

  const handleDialogOpen = () => {
    setOpenDialog(true);
  }

  const handlePlayerVote = (player_id ) => {
    setTimeout(() => {
      handleDialogClose();
    }, 500);
  }
  
  return (
    <div>
      <div className={classes.container}/>
      <div  className={classes.board}>
        <OmokBoard width="52" height="94" replay = {true}/>
      </div>
      <div className={classes.roomSetting}>
        <div className={classes.text_setting}>
          <img id = "coin_img" src = "assets/img/coin_i.png" className = {classes.imgStyle} /> {room_coin}
        </div>
        <div id = "time_counter" className={classes.timeText}>
          {"Finished: " + finished}
        </div>
        <div id = "Limit Time" className={classes.timeText}>
          {"Countdown: " + countdown + " s"}
        </div>
        <div id = "result_layer" className={classes.timeText}></div>
      </div>

      <div style = {{position: "fixed", right: '3vw', bottom: '15vh', zIndex: '2003'}}> <GrController /> </div>
      
      {!!players &&
        players.map((player, i) => {
          return (
            <div className={i == first_turn ? classes.playerLeftPanel : classes.playerRightPanel} >
              <img id = {`stone_${i}`} src = {first_turn == i ? 'assets/img/stone_b.png' : 'assets/img/stone_w.png'} style = {{position: 'relative', left: '14vw', top: '12vh', width: '6vh', height: '6vh', zIndex: '1113'}} />
              <Avatar alt="Profile Picture" className = {classes.avatarStyle} src={player.avatar}/>
              <div className= {classes.info_text_panel}>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1">{player.user_id + ' (LV.' + player.level + ')'}</MDBCol>
                </MDBRow>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1"><i className={" fa fa-star"} style = {{color: 'orange'}}>{" "}{player.coin}</i></MDBCol>
                </MDBRow>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1">{'Color: '}</MDBCol>
                </MDBRow>
              </div>
            </div>
          )
        })
      }
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i class = "fa fa-home" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
      <div className={classes.boardOption}>
        <div className={classes.text}>
        </div>
      </div>
      <div className={classes.piece}>
        <div className={classes.text}>
        </div>
      </div>
      <div className={classes.tool}>
        <div className={classes.text}>
        </div>
      </div>
      <div className={classes.sample}>
        <div className={classes.text}>
        </div>
      </div>
    </div>
  )
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  room_coin: store.roomReducer.room.coin,
  players: store.roomReducer.room.players,
  result: store.roomReducer.room.result,
  rewards: store.roomReducer.room.rewards,
  room_state: store.roomReducer.room.room_state,
  move_history: store.roomReducer.room.move_history,
  finished: store.roomReducer.room.finished,
  first_turn: store.roomReducer.room.turn,
  countdown: store.omokReducer.room.countdown,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    req_game: RoomAction.req_game,
    update_common_gr_index: CommonAction.update_gr_index,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(OmokReplay);

