import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = {
  user_count: '',
  update_user_list: false,
  user_list: [],
  room: {
    board_size: 0,
    handicap: 0,
    coin:0,
    time:0,
    kpmi: 0,
    rule: 0,
    main_time: 0,
    countdown: 0,
    countdown_num: 0,
    colors: [2, 1],
    first_turn: 0,
    betting: []
  },
  eval: {
    view: false,
    black_points: 0,
    white_points: 0,
    black_one_territories: [],
    white_one_territories: [],
    black_half_territories: [],
    white_half_territories: [],
    winrates: [],
    cpos: [],
    cscore: [],
    pass_score: 0,
    winrate: 0.0,
  },
  record_play:false,
  gr_index: 0,
  black_avatar: '',
  white_avatar: '',
  game: {
    _id: '',
    players:[{user_id:'', level: 0, avatar:''}, {user_id:'', level:0, avatar:''}],
    colors:[],  
    total_time:[], 
    board_size: 19,
    handicap: 0,
    kpmi: 7.5,
    rule: 0,
    main_time: 600,
    finishing_time: 30,
    finishing_count: 3,
    game_type: 0,
    ini_black_poss: [],
    ini_white_poss: [],
    first_turn: 1,
    move_history: [],
    result: '',
    created: '',
    finished: '',
    gr_index: 0,
    betting: [],
    preferred: [],
  },
  view_option: {
    view_ruler: false,
    view_number: false,
    view_background: 1,
    view_bw_mode: false,
  },
};

export default function goReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_USER_LIST:
      return {
        ...state,
        user_list: action.user_list,
        user_count: action.user_count,
      };
    case ACTION.INIT_GO_GAME:
      return {
        ...state,
        room: {
          ...state.room,
          black_player: action.black_player,
          white_player: action.white_player,
          black_time: action.black_time,
          white_time: action.white_time,
          cur_turn: action.game.first_turn,
          option: {
            ...state.room.option,
            your_color: action.your_color,
          },
          status: 'playing',
          chats: [],
        },
        black_avatar: action.black_avatar,
        white_avatar: action.white_avatar,
        game: action.game,
      };
    case ACTION.LOAD_GO_ROOM_INFO:
      return {
        ...state,
        room: {
          ...state.room,
          board_size: action.board_size,
          handicap: action.handicap,
          kpmi: action.kpmi,
          rule: action.rule,
          main_time: action.main_time,
          countdown: action.countdown,
          countdown_num: action.countdown_num,
          colors: action.colors,
          first_turn: action.first_turn,
          betting: action.betting
        },
      };
    case ACTION.INIT_GO_EVAL:
      return {
        ...state,
        eval: {
          ...state.eval,
          view: false,
          black_points: 0,
          white_points: 0,
          black_one_territories: [],
          white_one_territories: [],
          black_half_territories: [],
          white_half_territories: [],
          winrates: [],
          cpos: [],
          cscore: [],
          pass_score: 0,
          winrate: 0,
        },
      }
    case ACTION.UPDATE_GO_EVAL:
      return {
        ...state,
        eval: {
          ...state.eval,
          view: !!action.view? action.view : state.eval.view,
          black_points: !!action.bsum? action.bsum : state.eval.black_points,
          white_points: !!action.wsum? action.wsum : state.eval.white_points,
          black_one_territories: !!action.bt_one? action.bt_one : state.eval.black_one_territories,
          white_one_territories: !!action.wt_one? action.wt_one : state.eval.white_one_territories,
          black_half_territories: !!action.bt_half? action.bt_half : state.eval.black_half_territories,
          white_half_territories: !!action.wt_half? action.wt_half : state.eval.white_half_territories,
          winrates: !!action.winrates? state.eval.winrates.concat(action.winrates) : state.eval.winrates,
          cpos: !!action.cpos? action.cpos : state.eval.cpos,
          cscore: !!action.cscore? action.cscore : state.eval.cscore,
          pass_score: !!action.pass_score? action.pass_score : state.eval.pass_score,
          winrate: !!action.winrate? action.winrate : state.eval.winrate,
        },
      };
    case ACTION.SWITCH_EVAL_VIEW:
      return {
        ...state,
        eval: {
          ...state.eval,
          view: !state.eval.view,
        },
      };
    case ACTION.LOAD_GO_RECORD:
      return {
        ...state,
        room: {
          ...state.room,
          black_player: action.black_player,
          white_player: action.white_player,
          black_time: action.black_time,
          white_time: action.white_time,
        },
        black_avatar: action.black_avatar,
        white_avatar: action.white_avatar,
        game: action.game,
        gr_index: action.gr_index,
      };
    case ACTION.UPDATE_GAME_PREFERRED:
      return {
        ...state,
        game: {
          ...state.game,
          preferred: action.preferred,
        }
      };
    case ACTION.UPDATE_GO_RECORD_INDEX:
      return {
        ...state,
        room: {
          ...state.room,
          black_captures: action.black_captures,
          white_captures: action.white_captures,
        },
        gr_index: action.gr_index
      };
    case ACTION.DELETE_HISTORY_ON_COMPOSE_ARTICLE:
      return {
        ...state,
        game: {
          ...state.game,
          move_history: [],
          gr_index: 0,
        },
      };
    case ACTION.UPDATED_USER_LIST:
      return {
        ...state,
        update_user_list: !state.update_user_list,
      };
    case ACTION.ROOM_BETTED:
      return {
        ...state,
        room: {
          ...state.room,
          betting: state.room.betting.concat(
            {
              user_id: action.user_id,
              bet_coin: action.bet_coin,
              bet_to_player: action.bet_to_player,
              game_step: action.game_step,
            }
          )
        }
      };
    case ACTION.CHANGE_VIEW_OPTION:
      return {
        ...state,
        view_option: {
          ...state.view_option,
          view_ruler: action.what === 1? !state.view_option.view_ruler : state.view_option.view_ruler,
          view_number: action.what === 2? !state.view_option.view_number : state.view_option.view_number,
          view_background: action.what !== 3? state.view_option.view_background : state.view_option.view_background > 2? 1 : state.view_option.view_background + 1,
          view_bw_mode: action.what === 4? !state.view_option.view_bw_mode : state.view_option.view_bw_mode,
          left:"14vw",
          isSideBarShow:true,
        },
      }
    case ACTION.SET_VIEW_BW_MODE:
      return {
        ...state,
        view_option: {
          ...state.view_option,
          view_bw_mode: action.view_bw_mode,
          view_ruler: action.view_bw_mode,
          view_number: action.view_bw_mode,
        },
      }
    case ACTION.UPDATE_RECORD_PLAY:
      return {
        ...state,
        record_play:action.play,
      }
    case ACTION.UPDATE_GO_USER_COUNT:
      return {
        ...state,
        user_count:action.count,
      }
    case ACTION.INIT_GO_MOVE_HISTORY:
      return {
        ...state,
        game: {
          ...state.game,
          move_history: [],
        }
      }
    default: return state;
  }
}