import React, { useState, useEffect }  from 'react';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";

import { makeStyles } from '@material-ui/core/styles';
import {
  Avatar,
  MenuItem,
  MenuList,
} from '@material-ui/core';
import {
  MDBBtn,
  MDBRow,
  MDBCol,
  MDBDataTable,
} from "mdbreact";
import * as MessageAction from "../../store/actions/message.action";

const useStyles = makeStyles(theme => ({
  container: {
    //minHeight: '83vh',
   // paddingTop: '2vh',
   marginTop:"3vh",
   width:'75vw',
  },
  displayStyle: {
    display: 'none',
  },
}));

const columns = [
  {
    label: "From",
    field: "from",
    sort: "disabled",
    width: 110,
  },
  {
    label: "To",
    field: "to",
    sort: "disabled",
    width: 110,
  },
  {
    label: "Subject",
    field: "subject",
    sort: "disabled",
    width: 350,
  },
  {
    label: "When",
    field: "when",
    sort: "disabled",
    width: 150,
  },
];

const rowSelection = {
  onChange: (selectedRowKeys, selectedRows) => {
    console.log(`selectedRowKeys: ${selectedRowKeys}`, 'selectedRows: ', selectedRows);
  },
  getCheckboxProps: record => ({
    disabled: record.name === 'Disabled User', // Column configuration not to be checked
    name: record.name,
  }),
  selections: [
    {
      key: 'all-data',
      text: 'Select All',
      onSelect: () => {
        
      },
    },
    {
      key: 'mark',
      text: 'Mark as Read',
      onSelect: changableRowKeys => {
        
      },
    },
    {
      key: 'del',
      text: 'Delete',
      onSelect: changableRowKeys => {
        
      },
    },
  ],
};


function Messagebox(props) {
  const classes = useStyles();

  const [selectedMenuKey, setMenuKey] = useState(0);
  const [viewMsg, setViewMsg] = useState(false);
  const [toUsers, setToUsers] = useState("");
  const [subject, setSubject] = useState("");
  const [content, setContent] = useState("");

  const handleClick = (key) => {
    setMenuKey(key);
    setViewMsg(false);
  };

  useEffect(() => {
    const {user, req_msg_list} = props;
    if (!!user)
      req_msg_list();
  }, []);

  const view_message = (msg_id) => {
    setViewMsg(true);
    const {user, req_msg_content} = props;
    if (!!user)
      req_msg_content(msg_id);
  };

  const handleChange = (event) => {
    switch(event.target.name) {
      case 'to':
        setToUsers(event.target.value);
        break;
      case 'subject':
        setSubject(event.target.value);
        break;
      case 'content':
        setContent(event.target.value);
        break;
      default:
        break;
    }
  };

  const handleSend = () => {
    const {user, submit_msg} = props;
    if(!!user)
      submit_msg(toUsers, subject, content, 'send');
  };

  const handleDiscard = () => {
    const {user, submit_msg} = props;
    if(!!user)
      submit_msg(toUsers, subject, content, 'discard');
  };
  
  const handleDraft = () => {
    const {user, submit_msg} = props;
    if(!!user)
      submit_msg(toUsers, subject, content, 'draft');
  };
  
  const {user, in_list, sent_list, draft_list, trash_list, message} = props;

  const in_rows = [];
  const sent_rows = [];
  const draft_rows = [];
  const trash_rows = [];
  in_list.map((msg) => {
    in_rows.push({
      from: msg.sender_id,
      to: msg.to.map((m) => (m + ' ')),
      subject: msg.subject,
      when: new Date(msg.time).toLocaleString(),
      clickEvent: () => {view_message(msg._id)}
    });
  });
  sent_list.map((msg) => {
    sent_rows.push({
      from: msg.sender_id,
      to: msg.to.map((m) => (m + ' ')),
      subject: msg.subject,
      when: new Date(msg.time).toLocaleString(),
      clickEvent: () => {view_message(msg._id)}
    });
  });
  draft_list.map((msg) => {
    draft_rows.push({
      from: msg.sender_id,
      to: msg.to.map((m) => (m + ' ')),
      subject: msg.subject,
      when: new Date(msg.time).toLocaleString(),
      clickEvent: () => {view_message(msg._id)}
    });
  });
  trash_list.map((msg) => {
    trash_rows.push({
      from: msg.sender_id,
      to: msg.to.map((m) => (m + ' ')),
      subject: msg.subject,
      when: new Date(msg.time).toLocaleString(),
      clickEvent: () => {view_message(msg._id)}
    });
  });

  return (
    <div className={classes.container}>
      <MDBRow>
        <MDBCol size="2" className="px-5">
          <MDBRow className="py-3">
            <MDBCol>
              <MDBBtn color="green" className="text-left float-left py-2 mx-0 px-0" style={{ width: '16vw' }} onClick={handleClick.bind(this, 0)} >
                <i className="fa fa-pencil" style={{ color: "white", paddingLeft: 16, paddingRight: 4}} /> compose
                {selectedMenuKey === 0 && (<i className="fa fa-caret-right px-5" />)}
              </MDBBtn>
            </MDBCol>
          </MDBRow>
          <MDBRow>
            <MDBCol>
              <MenuList
                style={{ width: '16vw', backgroundColor: 'rgba(0, 0, 0, 0.2)', paddingTop: '0px', paddingBottom: '0px'}}
              >
                <MenuItem key="1" onClick={handleClick.bind(this, 1)} style={{ backgroundColor: 'rgba(0, 0, 0, 0.2)', color: 'white', border: '1px solid #f0f0f0', margin:'0px' }}>
                  <i className="fa fa-inbox" style={{ paddingRight: 4}} /> Inbox  {selectedMenuKey === 1 && (<i className="fa fa-caret-right px-5" />)}</MenuItem>
                <MenuItem key="2" onClick={handleClick.bind(this, 2)} style={{ backgroundColor: 'rgba(0, 0, 0, 0.2)', color: 'white', border: '1px solid #f0f0f0', margin:'0px' }}>
                  <i className="fa fa-sign-out" style={{ paddingRight: 4}} /> Sent {selectedMenuKey === 2 && (<i className="fa fa-caret-right px-5" />)}</MenuItem>
                <MenuItem key="3" onClick={handleClick.bind(this, 3)} style={{ backgroundColor: 'rgba(0, 0, 0, 0.2)', color: 'white', border: '1px solid #f0f0f0', margin:'0px' }}>
                  <i className="fa fa-tags" style={{ paddingRight: 4}} /> Draft {selectedMenuKey === 3 && (<i className="fa fa-caret-right px-5" />)}</MenuItem>
                <MenuItem key="4" onClick={handleClick.bind(this, 4)} style={{ backgroundColor: 'rgba(0, 0, 0, 0.2)', color: 'white', border: '1px solid #f0f0f0', margin:'0px' }}>
                  <i className="fa fa-trash-o" style={{ paddingRight: 4}} /> Trash {selectedMenuKey === 4 && (<i className="fa fa-caret-right px-5" />)}</MenuItem>
              </MenuList>
            </MDBCol>
          </MDBRow>
        </MDBCol>
        <MDBCol className={selectedMenuKey < 1 ? "" : classes.displayStyle} >
          <MDBRow className="pt-2 pb-1">
            <MDBCol size="1" className="pt-2">
              <h6>To</h6>
            </MDBCol>
            <MDBCol>
              <input type="text" name="to" onChange={handleChange} className="form-control form-control-sm" style={{border:'none', borderBottom:'1px solid rgb(204, 204, 204)',padding:'0px'}} placeholder="" />
            </MDBCol>
          </MDBRow>
          <MDBRow className="pt-2 pb-1">
            <MDBCol size="1" className="pt-2">
              <h6>Subject</h6>
            </MDBCol>
            <MDBCol>
              <input type="text" name="subject" onChange={handleChange} className="form-control form-control-sm" style={{border:'none', borderBottom:'1px solid rgb(204, 204, 204)',padding:'0px'}} placeholder="" />
            </MDBCol>
          </MDBRow>
          <MDBRow>
            <MDBCol>
              <MDBBtn color="primary" className="float-left py-2 px-2">
                <i className="fa fa-plus" style={{ color: "white"}} /> add files
              </MDBBtn>
            </MDBCol>
          </MDBRow>
          <MDBRow className="py-2">
            <MDBCol>
              <textarea name="content" onChange={handleChange} className="form-control" id="exampleFormControlTextarea1" rows="10" />
            </MDBCol>
          </MDBRow>
          <MDBRow>
            <MDBCol>
              <MDBBtn color="success" className="float-left py-2 px-2" onClick={handleSend}>
                <i className="fa fa-check" style={{ color: "white"}} /> send
              </MDBBtn>
            </MDBCol>
            <MDBCol>
              <MDBBtn color="default" className="float-left py-2 px-2" onClick={handleDiscard}>
                <i className="fa fa-remove" style={{ color: "white"}} /> discard
              </MDBBtn>
            </MDBCol>
            <MDBCol>
              <MDBBtn color="secondary" className="float-left py-2 px-2" onClick={handleDraft}>
                <i className="fa fa-tags" style={{ color: "white"}} /> draft
              </MDBBtn>
            </MDBCol>
            <MDBCol></MDBCol>
          </MDBRow>
        </MDBCol>
        <MDBCol className={selectedMenuKey === 1 && !viewMsg? "" : classes.displayStyle} >
          <MDBDataTable hover theadColor="dark" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data = {{columns: columns, rows: in_rows}} />
        </MDBCol>
        <MDBCol className={selectedMenuKey === 2 && !viewMsg ? "" : classes.displayStyle} >
          <MDBDataTable hover theadColor="dark" theadOpaticy = "0.1" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data = {{columns: columns, rows: sent_rows}} />
        </MDBCol>
        <MDBCol className={selectedMenuKey === 3 && !viewMsg ? "" : classes.displayStyle} >
          <MDBDataTable hover theadColor="dark" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data = {{columns: columns, rows: draft_rows}} />
        </MDBCol>
        <MDBCol className={selectedMenuKey === 4 && !viewMsg ? "" : classes.displayStyle} >
          <MDBDataTable hover theadColor="dark" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data = {{columns: columns, rows: trash_rows}} />
        </MDBCol>
        <MDBCol className={viewMsg ? "" : classes.displayStyle} >
          <p>
            <span className="font-weight-bold" style={{fontSize:'1.8rem'}}>{message.subject}</span>
          </p>
          <div className="py-2" style={{borderBottom:'1px solid rgb(204, 204, 204)',borderTop:'1px solid rgb(204, 204, 204)'}}>
            <Avatar alt="Profile Picture" src={message.sender_avatar} style={{float:'left'}}/>
            <span className="pl-2" style={{ fontSize: "1.5rem" }}>
              <strong>{message.sender_id}</strong><small>({message.sender_name})</small> to <strong>{(!user || message.sender_id !== user.user_id)? 'Me' : message.to.map((t) => (t + ' '))}</strong> on {new Date(message.time).toLocaleString()}
            </span>
            <MDBBtn color="blue" className="float-right py-2 px-3 mt-0" style={{borderRadius: '0.5em'}}>
              <i className="fa fa-tags" style={{ color: "white"}} className="mr-2" /> Reply
            </MDBBtn>
          </div>
          <div className="py-3" style={{borderBottom:'1px solid rgb(204, 204, 204)'}}>
            {message.content}
          </div>
          <div className="py-2" style={{ fontSize: "1.2rem" }}>
            <strong>{message.attach_files.length} Attachment - <span style={{color:'blue'}}>{message.attach_files.map((f) => (f + ' '))}</span></strong>
          </div>
        </MDBCol>
        <MDBCol size="1"></MDBCol>
      </MDBRow>
    </div>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    in_list: store.messageReducer.in_list,
    sent_list: store.messageReducer.sent_list,
    draft_list: store.messageReducer.draft_list,
    trash_list: store.messageReducer.trash_list,
    message: store.messageReducer.message,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      req_msg_list: MessageAction.req_msg_list,
      req_msg_content: MessageAction.req_msg_content,
      submit_msg: MessageAction.submit_msg,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(Messagebox);
