import React, {Component} from "react";
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import * as GoLogic from "./logic";

import * as GoAction from '../../store/actions/go.action';
import * as GoBoardAction from '../../store/actions/go_board.action';
import * as GoProblemAction from '../../store/actions/go_problem.action';
import * as GoTeacherAction from '../../store/actions/go_teacher.action';
import * as GoTrainAction from '../../store/actions/go_train.action';
import PROTOCOL from "../../helper/protocol";

function max(a, b) { return a > b ? a : b; }

function min(a, b) { return a < b ? a : b; }

function Common_IsInt(Value) {
  if ('string' != typeof Value) return false;
  for (var Index = 0; Index < Value.length; Index++) {
      var CharCode = Value.charCodeAt(Index);
      if (CharCode < 48 || CharCode > 57) return false;
  }
  return true;
}

function Common_SortIncrease(First, Second)
{
    if (First > Second)
        return 1;
    else if (Second > First)
        return -1;
    else
        return 0;
}

function Common_X_to_String(_X, nSize) {
  var Res;
  var X = Math.max(0, Math.min(_X - 1, nSize - 1));

  if (X < 8) Res = String.fromCharCode('A'.charCodeAt(0) + X);
  else if (X <= 24) Res = String.fromCharCode('A'.charCodeAt(0) + X + 1);
  else if (X < 33) Res = String.fromCharCode('A'.charCodeAt(0) + X - 25, 'A'.charCodeAt(0) + X - 25);
  else if (X < 50) Res = String.fromCharCode('A'.charCodeAt(0) + X - 24, 'A'.charCodeAt(0) + X - 24);
  else Res = String.fromCharCode('A'.charCodeAt(0) + X - 50, 'A'.charCodeAt(0) + X - 50, 'A'.charCodeAt(0) + X - 50);

  return Res;
}

var EBoardMode = {
  Move: 0,
  CountScores: 1,
  ScoreEstimate: 2,
  AddOrRemove: 3,
  AddMarkTr: 4,
  AddMarkSq: 5,
  AddMarkCr: 6,
  AddMarkX: 7,
  AddMarkTx: 8,
  AddMarkNum: 9,
  ViewPort: 10,
  ClearBoard: 11,
  Answer: 12,
};

var EDrawingMark = {
  Lm: -1,
  Tr: 0, 
  Sq: 1, 
  Cr: 2, 
  Tx: 3, 
  X: 4,
  Tb: 5, 
  Tw: 6, 
  Tb2: 7,
  Tw2: 8 
};

function CColor(r, g, b, a) {
  this.r = r;
  this.g = g;
  this.b = b;
  this.a = typeof a === 'undefined' ? 255 : a;
}

CColor.prototype.ToString = function() {
  return 'rgba(' + this.r + ',' + this.g + ',' + this.b + ',' + this.a / 255 + ')';
};

var g_dBoardCellW = 23.61;
var g_dBoardHorOffset = 17.51;
var g_dBoardCellW_2 = g_dBoardCellW / 2;

class Board extends Component {
  constructor() {
    super();
    this._inited = false;
    this.size = 19;
    this.preview_pos = { X: -1, Y: -1 };
    this.lboard = null;

    this.rulers = false;
    this.numbers = false;

    this.coeffOffsetY = 0;
    this.coeffOffsetX = 0;
    this.coeffCellW = 0;
    this.coeffCellH = 0;
    this.coeffDiam = 0;

    this.imageData = {
      W: 0,
      H: 0,
      StoneDiam: 0,
      ShadowOff: 0,
      HandiRad: 2,
      
      Lines: null,
      Handi: null,
      Board: null,
      BlackStone: null,
      WhiteStone: null,
      BoardMarkO: null,
      BoardMarkX: null,
    
      X_Black: null,
      X_White: null,
      Tr_Black: null,
      Tr_White: null,
      Tr_Hint: null,
      Sq_Black: null,
      Sq_White: null,
      Ter_Black: null,
      Ter_White: null,
      Ter_White_Border: null,
      Ter_Black2: null,
      Ter_White2: null,
      Ter_White_Border2: null,
      LastMove: null,
      Cr_Black: null,
      Cr_White: null,
    };
    this.htmlElement = {
      Board: null,
      Lines: null,
      Stones: null,
      Colors: null,
      Shadow: null,
      Marks: null,
      Target: null,
      Select: null,
      BoardMarks: null,
    };

    this.viewPort = { X0: 0, Y0: 0, X1: 18, Y1: 18 };
    this.viewPortSelection = { Start: false, StartX: -1, StartY: -1, EndX: -1, EndY: -1 };
    this._setViewPort(0, 0, 18, 18);

    var self = this;
    this._onMouseMove = function(e) {
      if(!self._inited) return;
      var pos = self._getBoardPosXY(e.offsetX, e.offsetY);
      self._moveTarget(pos);
      self._handleMouseMove(pos);
    };

    this._onMouseDown = function(e) {
      if(!self._inited) return;
      var pos = self._getBoardPosXY(e.offsetX, e.offsetY);
      self._handleMouseDown(pos, e);
    };

    this._onMouseUp = function(e) {
      if(!self._inited) return;
      var pos = self._getBoardPosXY(e.offsetX, e.offsetY);
      self._handleMouseUp(pos);
    };

    this._onKeyUp = function(e) {

    };

    this.onResize = function(force) {
      self._updateCoeffs();
      self._onResize(force);
    }
  
    this._onKeyPress = function(e) {
      if(this.props.readOnly || !this.props.putAble || !this._inited)  return;

      if([0x0D, 0x20].indexOf(e.keyCode) !== -1) { //<Enter>,<Space>
        // this._procPutStone(this.preview_pos);
        return;
      } 
      
      if([0x41, 0x61, 0x34, 0x25].indexOf(e.keyCode) !== -1) { //a,A,4,
        this.preview_pos.X --;
      } else if([0x44, 0x64, 0x36, 0x27].indexOf(e.keyCode) !== -1) { //d,D,6
        this.preview_pos.X ++;
      } else if([0x57, 0x77, 0x38, 0x26].indexOf(e.keyCode) !== -1) { //w,W,8
        this.preview_pos.Y --;
      } else if([0x53, 0x73, 0x32, 0x28].indexOf(e.keyCode) !== -1) { //s,S,2
        this.preview_pos.Y ++;
      } else {
        return;
      }

      this.preview_pos.X = Math.max(this.preview_pos.X, 0);
      this.preview_pos.X = Math.min(this.preview_pos.X, this.size - 1);
      this.preview_pos.Y = Math.max(this.preview_pos.Y, 0);
      this.preview_pos.Y = Math.min(this.preview_pos.Y, this.size - 1);
      this.drawBoard();
    }

  }

  componentDidMount() {
    this.init("GoBoard" + this.props.boardId);
    this.lboard = GoLogic.theLogicBoard;
    if (this.props.lboard2)
      this.lboard = GoLogic.theLogicBoard2;
    this.onResize(true);

    window.addEventListener("resize", ()=>{
      this.onResize();
    });
    window.addEventListener("keyup", (e)=>{
      this._onKeyPress(e);
    }); 
  }
  componentWillUnmount() {
    window.onkeypress = null;
  }

  init(name) {
    var boardElem = document.getElementById(name);
    boardElem.onmousemove = this._onMouseMove;
    boardElem.onmousedown = this._onMouseDown;
    boardElem.onmouseup = this._onMouseUp;

    this.imageData.Board = document.getElementById("GoBoardBG");
    this.imageData.WhiteStone = document.getElementById("GoWhiteStone");
    this.imageData.BlackStone = document.getElementById("GoBlackStone");

    var boardName = name + "_BoardCanvas";
    var linesName = name + "_LinesCanvas";
    var shadowsName = name + '_ShadowsCanvas';
    var stonesName = name + "_StonesCanvas";
    var marksName = name + "_MarksCanvas";
    var targetName = name + "_TargetCanvas";
    var selectName = name + "_SelectCanvas";
    var boardMarksName = name + "_BoardMarksCanvas";
    this.htmlElement.Board = this._createCanvasElem(boardElem, boardName);
    this.htmlElement.Lines = this._createCanvasElem(boardElem, linesName);
    this.htmlElement.Shadow = this._createCanvasElem(boardElem, shadowsName);
    this.htmlElement.Stones = this._createCanvasElem(boardElem, stonesName);
    this.htmlElement.Marks = this._createCanvasElem(boardElem, marksName);
    this.htmlElement.Target = this._createCanvasElem(boardElem, targetName);
    this.htmlElement.Select = this._createCanvasElem(boardElem, selectName);
    this.htmlElement.BoardMarks = this._createCanvasElem(boardElem, boardMarksName);

    this._inited = true;

    this.imageData.W = this.htmlElement.Board.width;
    this.imageData.H = this.htmlElement.Board.height;
  }

  getAspectRatio() {
    var oSize = { X: this.size, Y: this.size };
    var nSizeX = oSize.X;
    var nSizeY = oSize.Y;

    var dAbsBoardW = (this.viewPort.X1 - this.viewPort.X0) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsBoardH = (this.viewPort.Y1 - this.viewPort.Y0) * g_dBoardCellW + 2 * g_dBoardHorOffset;

    if (true === this.rulers) {
        dAbsBoardW += g_dBoardCellW;
        dAbsBoardH += g_dBoardCellW;
    }

    if (this.viewPort.X0 > 0) dAbsBoardW += g_dBoardCellW_2 / 2;

    if (this.viewPort.X1 < nSizeX - 1) dAbsBoardW += g_dBoardCellW_2 / 2;

    if (this.viewPort.Y0 > 0) dAbsBoardH += g_dBoardCellW_2 / 2;

    if (this.viewPort.Y1 < nSizeY - 1) dAbsBoardH += g_dBoardCellW_2 / 2;

    return dAbsBoardW / dAbsBoardH;
  }

  _moveTarget(pos) {
    if(this.props.readOnly || !this.props.putAble) return;

    if(pos !== this.preview_pos) {
      this.preview_pos = pos;
      this.drawBoard();
    }    
  }

  _handleMouseMove(pos) {
    if(EBoardMode.ViewPort === this.props.edit_mode) this._moveViewPortSelection(pos);
    
    this._updateSelectCanvas();
  }

  _handleMouseDown(pos, event) {
    const {edit_mode, lboard2, room_type, viewport, connection, remove_mark, add_mark, delete_move_history, set_edit_stones} = this.props;
    switch( edit_mode ) {
      case EBoardMode.Move:
        this._procPutStone(pos);
        break;
      case EBoardMode.CountScores:
        break;
      case EBoardMode.ScoreEstimate:
        break;
      case EBoardMode.AddOrRemove:
        var color;
        if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y))
          color = event.shiftKey ? GoLogic.WHITE : GoLogic.BLACK;
        else
          color = GoLogic.EMPTY;
        this.lboard.set_edit_stone(pos.X, pos.Y, color);
        delete_move_history(room_type);
        if (room_type === 'lecture') {
          if (!!connection && !!connection.socket)
            connection.socket.emit(connection.socketCustomEvent, {type: 'setEditStone', x: pos.X, y: pos.Y, color});
        } else if (room_type === 'make_problem') {
          var stones = this.lboard.getstones(viewport.x0, viewport.y0, viewport.x1, viewport.y1);
          set_edit_stones(stones.black_stones, stones.white_stones);
        }
        this.setState({});
        break;
      case EBoardMode.AddMarkTr:
        if (!!this._find_mark(pos)) {
          remove_mark(pos.X, pos.Y, lboard2);
          if (room_type === 'lecture') {
            if (!!connection && !!connection.socket)
              connection.socket.emit(connection.socketCustomEvent, {type: 'removeMark', mark_x: pos.X, mark_y: pos.Y});
          }
        } else {
          add_mark(pos.X, pos.Y, EDrawingMark.Tr, lboard2);
          if (room_type === 'lecture') {
            if (!!connection && !!connection.socket)
              connection.socket.emit(connection.socketCustomEvent, {type: 'addMark', mark_x: pos.X, mark_y: pos.Y, mark_type: EDrawingMark.Tr, mark_text: ''});
          }
        }
        delete_move_history(room_type);
        break;
      case EBoardMode.AddMarkSq:
        if (!!this._find_mark(pos))
          remove_mark(pos.X, pos.Y, lboard2);
        else
          add_mark(pos.X, pos.Y, EDrawingMark.Sq, lboard2);
        break;
      case EBoardMode.AddMarkCr:
        if (!!this._find_mark(pos))
          remove_mark(pos.X, pos.Y, lboard2);
        else
          add_mark(pos.X, pos.Y, EDrawingMark.Cr, lboard2);
        break;
      case EBoardMode.AddMarkX:
        if (!!this._find_mark(pos))
          remove_mark(pos.X, pos.Y, lboard2);
        else
          add_mark(pos.X, pos.Y, EDrawingMark.X, lboard2);
        break;
      case EBoardMode.AddMarkTx:
        if (!!this._find_mark(pos)) {
          remove_mark(pos.X, pos.Y, lboard2);
          if (room_type === 'lecture') {
            if (!!connection && !!connection.socket)
              connection.socket.emit(connection.socketCustomEvent, {type: 'removeMark', mark_x: pos.X, mark_y: pos.Y});
          }
        } else {
          var text = this._getNextTextMark();
          add_mark(pos.X, pos.Y, EDrawingMark.Tx, lboard2, text);
          if (room_type === 'lecture') {
            if (!!connection && !!connection.socket)
              connection.socket.emit(connection.socketCustomEvent, {type: 'addMark', mark_x: pos.X, mark_y: pos.Y, mark_type: EDrawingMark.Tx, mark_text: text});
          }
        }
        delete_move_history(room_type);
        break;
      case EBoardMode.AddMarkNum:
        if (!!this._find_mark(pos))
          remove_mark(pos.X, pos.Y, lboard2);
        else {
          var text = this._getNextNumMark();
          add_mark(pos.X, pos.Y, EDrawingMark.Tx, lboard2, text);
        }
        break;
      case EBoardMode.ViewPort:
        this._startViewPortSelection(pos);
        break;
    }
  }

  _handleMouseUp(pos) {
    if(EBoardMode.ViewPort === this.props.edit_mode)  this._endViewPortSelection(pos);

    this._updateSelectCanvas();
  }

  _startViewPortSelection(pos) {
    this.viewPortSelection.Start = true;
    this.viewPortSelection.StartX = pos.X;
    this.viewPortSelection.StartY = pos.Y;
    this.viewPortSelection.EndX = pos.X;
    this.viewPortSelection.EndY = pos.Y;
    
    this._updateSelectCanvas();
  }

  _moveViewPortSelection(pos) {
    if(true === this.viewPortSelection.Start) {
      this.viewPortSelection.EndX = pos.X;
      this.viewPortSelection.EndY = pos.Y;

      //expand viewport
      const {viewport} = this.props;
      var x0 = viewport.x0;
      var y0 = viewport.y0;
      var x1 = viewport.x1;
      var y1 = viewport.y1;

      if (this.viewPortSelection.EndX <= viewport.x0 && viewport.x0 > 0)
        x0 = viewport.x0 - 1;
      if (this.viewPortSelection.EndY <= viewport.y0 && viewport.y0 > 0)
        y0 = viewport.y0 - 1;
      if (this.viewPortSelection.EndX >= viewport.x1 && viewport.x1 < 18)
        x1 = viewport.x1 + 1;
      if (this.viewPortSelection.EndY >= viewport.y1 && viewport.y1 < 18)
        y1 = viewport.y1 + 1;
      if (x0 !== viewport.x0 || y0 !== viewport.y0 || x1 !== viewport.x1 || y1 !== viewport.y1)
        this.props.update_viewport(x0, y0, x1, y1);
    }
  }

  _endViewPortSelection(pos) {
    if(true === this.viewPortSelection.Start) {
      this.viewPortSelection.Start = false;
      this.viewPortSelection.EndX = pos.X;
      this.viewPortSelection.EndY = pos.Y;

      var X0 = this.viewPortSelection.StartX;
      var Y0 = this.viewPortSelection.StartY;
      var X1 = this.viewPortSelection.EndX;
      var Y1 = this.viewPortSelection.EndY;

      if (X0 > X1) {
          var Temp = X1;
          X1 = X0;
          X0 = Temp;
      }

      if (Y0 > Y1) {
          var Temp = Y1;
          Y1 = Y0;
          Y0 = Temp;
      }

      const {update_viewport, room_type, connection} = this.props;
      update_viewport(X0, Y0, X1, Y1, room_type === 'make_problem');
      if (room_type === 'lecture') {
        if (!!connection && !!connection.socket)
          connection.socket.emit(connection.socketCustomEvent, {type: 'updateViewport', x0: X0, y0: Y0, x1: X1, y1: Y1});
      }
      this.htmlElement.Select.getContext('2d').canvas.width = 0;
    }
  }

  _updateSelectCanvas() {
    if(EBoardMode.ViewPort === this.props.edit_mode && true === this.viewPortSelection.Start) {
      var W = this.imageData.W;
      var H = this.imageData.H;
      var Lines = this.imageData.Lines;

      var Canvas = this.htmlElement.Select.getContext('2d');
      Canvas.canvas.width = W;
      Canvas.canvas.height = H;
      Canvas.clearRect(0, 0, W, H);

      var X0 = this.viewPortSelection.StartX;
      var Y0 = this.viewPortSelection.StartY;
      var X1 = this.viewPortSelection.EndX;
      var Y1 = this.viewPortSelection.EndY;

      if (X0 > X1) {
          var Temp = X1;
          X1 = X0;
          X0 = Temp;
      }

      if (Y0 > Y1) {
          var Temp = Y1;
          Y1 = Y0;
          Y0 = Temp;
      }

      var Color = new CColor(255, 255, 200, 128);

      Canvas.fillStyle = Color.ToString();
      Canvas.beginPath();
      Canvas.moveTo(Lines[X0].X_L2, Lines[Y0].Y_L2);
      Canvas.lineTo(Lines[X1].X_G2, Lines[Y0].Y_L2);
      Canvas.lineTo(Lines[X1].X_G2, Lines[Y1].Y_G2);
      Canvas.lineTo(Lines[X0].X_L2, Lines[Y1].Y_G2);
      Canvas.closePath();
      Canvas.fill();
    }
  }

  _find_mark(pos) {
    var {marks, marks2} = this.props;
    if (!!this.props.lboard2)
      marks = marks2;
    for (var i = 0; i < marks.length; i ++) {
      var mark = marks[i];
      if (mark.x === pos.X && mark.y === pos.Y)
        return mark;
    }
    return null;
  }

  _getNextTextMark() {
    var {marks, marks2} = this.props;
    if (!!this.props.lboard2)
      marks = marks2;

    var arrLabels = [];
    var num = -1;

    for (var i = 0; i < marks.length; i ++) {
      var mark = marks[i];
      if(EDrawingMark.Tx === mark.type) {
        var charCode = mark.text.charCodeAt(0);
        if (1 === mark.text.length && 65 <= charCode && 90 >= charCode)
          arrLabels[charCode] = 1;
      }
    }

    for (var index = 65; index <= 90; index ++) {
      if(undefined === arrLabels[index] || "" === arrLabels[index]) {
        num = index;
        break;
      }
    }

    if(-1 == num)
      return null;
    else
      return String.fromCharCode(num);
  }

  _getNextNumMark() {
    var {marks, marks2} = this.props;
    if (!!this.props.lboard2)
      marks = marks2;

    var arrLabels = [];
    var arrayLen = 0;

    for (var i = 0; i < marks.length; i ++) {
      var mark = marks[i];
      if(EDrawingMark.Tx === mark.type) {
        if (Common_IsInt(mark.text)) {
          arrLabels[arrayLen] = parseInt(mark.text);
          arrayLen ++;
        }
      }
    }

    if (arrayLen <= 0)
      return "1";

    arrLabels.sort(Common_SortIncrease);

    var prevValue = 0;
    var result = 0;
    var find = false;
    for(var index = 0; index < arrayLen; index ++) {
      if (arrLabels[index] > prevValue + 1) {
        result = (prevValue + 1);
        find = true;
        break;
      }
      prevValue = arrLabels[index];
    }

    if(!find)
      result = prevValue + 1;
    
    return "" + result;
  }

  _procPutStone(pos) {
    const { user, socketRoom, room_id, room_type, putAble, problem, on_problem_move, on_train_game_move, do_move_in_lecture_room, add_move_on_problem_answer, connection } = this.props;
    if(this.props.readOnly || !putAble) return;
    
    let move = GoLogic.WPOS(pos.X, pos.Y);
    if (room_type === 'spectate') {
      this.lboard.domove(move, this.lboard.turn);
    } else if (room_type === 'replay') {
      this.lboard.domove(move, this.lboard.turn);
    } else if (room_type === 'play') {
      if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y))
        socketRoom.emit('cs_message', PROTOCOL.CS_GAME_MOVE, {token: !!user? user.token : null, room_id, move});
    } else if (room_type === 'solve_problem') {
      if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y)) {
        if (problem.train_mode)
          this.lboard.domove(move, this.lboard.turn);
        else
          on_problem_move(move, this.lboard.turn, problem.h_index, problem.solved_time);
      }
    } else if (room_type === 'make_problem') {
      if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y))
        add_move_on_problem_answer(move, this.lboard.turn);
    } else if (room_type === 'take_stones') {
      if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y))
        on_train_game_move(move, this.lboard.turn, 1);
    } else if (room_type === 'capture_groups') {
      if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y))
        on_train_game_move(move, this.lboard.turn, 2);
    } else if (room_type === 'opening') {
      if (GoLogic.EMPTY === this.lboard.getstate(pos.X, pos.Y))
        on_train_game_move(move, this.lboard.turn, 3);
    } else if (room_type === 'forum_compose') {
      this.lboard.domove(move, this.lboard.turn);
    } else if (room_type === 'lecture') {
      if (!!connection && !!connection.socket)
        connection.socket.emit(connection.socketCustomEvent, {type: 'putStone', x: pos.X, y: pos.Y, turn: this.lboard.turn});
      do_move_in_lecture_room(pos.X, pos.Y, this.lboard.turn);
    }
  }

  _getBoardPosXY(_X, _Y) {
    var W = this.imageData.W;
    var H = this.imageData.H;

    var dCellH = this.coeffCellH * H;
    var dCellW = this.coeffCellW * W;
    var dHorOff = this.coeffOffsetX * W - dCellH * this.viewPort.X0;
    var dVerOff = this.coeffOffsetY * H - dCellW * this.viewPort.Y0;

    var Y = 0;

    var oSize = { X: this.size, Y: this.size };
    for (Y = 0; Y < oSize.Y - 1; Y++) {
        if (_Y > dVerOff + dCellH * Y + dCellH / 2)
            continue;
        else {
            break;
        }
    }

    var X = 0;
    for (X = 0; X < oSize.X - 1; X++) {
        if (_X > dHorOff + dCellW * X + dCellW / 2)
            continue;
        else {
            break;
        }
    }

    X = Math.max(this.viewPort.X0, Math.min(this.viewPort.X1, X));
    Y = Math.max(this.viewPort.Y0, Math.min(this.viewPort.Y1, Y));

    return {X: X, Y: Y};
  }

  _createCanvasElem(parentElem, name) {
    var elem = document.createElement("canvas");
    elem.setAttribute("id", name);
    elem.setAttribute("style", "position:absolute;padding:0;margin:0;");
    elem.setAttribute("oncontextmenu", "return false;");
    elem.setAttribute("width", parentElem.clientWidth);
    elem.setAttribute("height", parentElem.clientHeight);
    parentElem.appendChild(elem);
    return elem;
  }

  _createLines() {
    var W = this.imageData.W;
    var H = this.imageData.H;

    if (0 === W || 0 === H)
        return;

    var dHorOff = this.coeffOffsetX * W;
    var dVerOff = this.coeffOffsetY * H;
    var dCellH = this.coeffCellH * H;
    var dCellW = this.coeffCellW * W;

    var Lines = new Array(this.size);

    var X_startoffset = dHorOff - dCellW * this.viewPort.X0;
    var Y_startoffset = dVerOff - dCellH * this.viewPort.Y0;

    var X, Y, X_G, Y_G, X_L, Y_L, X_G2, Y_G2, X_L2, Y_L2;
    for (var Index = 0; Index < this.size; Index++) {
        X = X_startoffset + Index * dCellW;

        X_G = X_startoffset + Index * dCellW + 0.6 * dCellW;
        X_L = X_startoffset + Index * dCellW - 0.6 * dCellW;
        X_G2 = X_startoffset + Index * dCellW + 0.5 * dCellW;
        X_L2 = X_startoffset + Index * dCellW - 0.5 * dCellW;
        Y = Y_startoffset + Index * dCellH;
        Y_G = Y_startoffset + Index * dCellH + 0.6 * dCellH;
        Y_L = Y_startoffset + Index * dCellH - 0.6 * dCellH;
        Y_G2 = Y_startoffset + Index * dCellH + 0.5 * dCellH;
        Y_L2 = Y_startoffset + Index * dCellH - 0.5 * dCellH;

        Lines[Index] =
            {
                X: Math.floor(X + 0.5),
                X_G: Math.floor(X_G + 0.5),
                X_L: Math.floor(X_L + 0.5),
                X_G2: Math.floor(X_G2 + 0.5),
                X_L2: Math.floor(X_L2 + 0.5),
                Y: Math.floor(Y + 0.5),
                Y_G: Math.floor(Y_G + 0.5),
                Y_L: Math.floor(Y_L + 0.5),
                Y_G2: Math.floor(Y_G2 + 0.5),
                Y_L2: Math.floor(Y_L2 + 0.5)
            };
    }

    this.imageData.Lines = Lines;

    var dRad = this.coeffDiam * W / 2;
    var nRad = Math.max(2, Math.ceil(dRad));
    var Diam = nRad * 2 + 1;
    var _x = nRad;
    var _y = nRad;

    this.imageData.Handi = this._drawHandiMark(_x, _y, nRad, Diam + 2, Diam + 2, new CColor(0, 0, 0, 255));
    this.imageData.HandiRad = nRad + 1;
  }

  _createShadows() {
    if (!this.imageData.Lines) return;

    var ShadowCanvas = this.htmlElement.Shadow.getContext('2d');
    var d = this.imageData.StoneDiam;
    this.imageData.Shadow = ShadowCanvas.createImageData(d, d);
    var Shadow = this.imageData.Shadow.data;
    this.imageData.ShadowOff = Math.max(parseInt(d * 0.15), 3);

    var r = (d - 5) / 2 + 1;
    for (var i = 0; i < d; i++) {
        for (var j = 0; j < d; j++) {
            var y = Math.abs(i - r);
            var x = Math.abs(j - r);
            var dist = Math.sqrt(x * x + y * y) / r;

            var f = dist < 1.0 ? 0.15 + 0.75 * (1 - dist) : 0;

            var Index = (d * i + j) * 4;
            Shadow[Index + 0] = 0;
            Shadow[Index + 1] = 0;
            Shadow[Index + 2] = 0;
            Shadow[Index + 3] = parseInt(255 * f);
        }
    }
  }

  _createMarks() {
    if(!this.imageData.Lines)
      return;

    var d = this.imageData.StoneDiam;
    this.imageData.X_Black = this._drawX(d, d, d * 0.05, new CColor(0, 0, 0, 255));
    this.imageData.X_White = this._drawX(d, d, d * 0.05, new CColor(255, 255, 255, 255));
    this.imageData.Tr_Black = this._drawTriangle(d, d, d * 0.05, new CColor(0, 0, 0, 255));
    this.imageData.Tr_White = this._drawTriangle(d, d, d * 0.05, new CColor(255, 255, 255, 255));
    this.imageData.Tr_Hint = this._drawTriangle(d, d, d * 0.05, new CColor(255, 0, 0, 255));
    this.imageData.Sq_Black = this._drawEmptySquare(d, d, d * 0.05, new CColor(0, 0, 0, 255));
    this.imageData.Sq_White = this._drawEmptySquare(d, d, d * 0.05, new CColor(255, 255, 255, 255));
    this.imageData.Ter_Black = this._drawFilledSquare(d, d, d * 0.05, false, new CColor(0, 0, 0, 255), new CColor(0, 0, 0, 255));
    this.imageData.Ter_White = this._drawFilledSquare(d, d, d * 0.05, false, new CColor(255, 255, 255, 255), new CColor(255, 255, 255, 255));
    this.imageData.Ter_White_Border = this._drawFilledSquare(d, d, d * 0.05, false, new CColor(255, 255, 255, 255), new CColor(0, 0, 0, 255));
    this.imageData.Ter_Black2 = this._drawFilledSquare(d, d, d * 0.05, true, new CColor(0, 0, 0, 255), new CColor(0, 0, 0, 255));
    this.imageData.Ter_White2 = this._drawFilledSquare(d, d, d * 0.05, true, new CColor(255, 255, 255, 255), new CColor(255, 255, 255, 255));
    this.imageData.Ter_White_Border2 = this._drawFilledSquare(d, d, d * 0.05, true, new CColor(255, 255, 255, 255), new CColor(0, 0, 0, 255));
    this.imageData.LastMove = this._drawCircle(d, d, d * 0.05, new CColor(0, 0, 255, 255));
    this.imageData.Cr_Black = this._drawCircle(d, d, d * 0.05, new CColor(0, 0, 0, 255));
    this.imageData.Cr_White = this._drawCircle(d, d, d * 0.05, new CColor(255, 255, 255, 255));
  }

  _drawX(W, H, PenWidth, Color) {
    var MarksCanvas = this.htmlElement.Marks.getContext("2d");
    MarksCanvas.clearRect(0, 0, W, H);

    MarksCanvas.strokeStyle = Color.ToString();
    MarksCanvas.fillStyle = Color.ToString();
    MarksCanvas.lineWidth = PenWidth;

    MarksCanvas.beginPath();
    MarksCanvas.moveTo((W * 1) / 4, (H * 1) / 4);
    MarksCanvas.lineTo((W * 3) / 4, (H * 3) / 4);
    MarksCanvas.moveTo((W * 3) / 4, (H * 1) / 4);
    MarksCanvas.lineTo((W * 1) / 4, (H * 3) / 4);
    MarksCanvas.stroke();

    return MarksCanvas.getImageData(0, 0, W, H);
  }

  _drawTriangle(W, H, PenWidth, Color, Alpha) {
    if (undefined === Alpha) Alpha = 1;

    var MarksCanvas = this.htmlElement.Marks.getContext("2d");
    MarksCanvas.clearRect(0, 0, W, H);

    MarksCanvas.globalAlpha = Alpha;
    MarksCanvas.strokeStyle = Color.ToString();
    MarksCanvas.fillStyle = Color.ToString();
    MarksCanvas.lineWidth = PenWidth;

    var r = W / 2;
    var _y = (H * 3) / 4;
    var shift = W * 0.1;

    var _x1 = Math.sqrt(r * r - (_y - r) * (_y - r)) + r;
    var _x2 = -Math.sqrt(r * r - (_y - r) * (_y - r)) + r;

    MarksCanvas.beginPath();
    MarksCanvas.moveTo(W / 2, shift);
    MarksCanvas.lineTo(_x1 - shift, _y);
    MarksCanvas.lineTo(_x2 + shift, _y);
    MarksCanvas.closePath();
    MarksCanvas.stroke();

    return MarksCanvas.getImageData(0, 0, W, H);
  }
  
  _drawEmptySquare(W, H, PenWidth, Color) {
    var MarksCanvas = this.htmlElement.Marks.getContext("2d");
    MarksCanvas.clearRect(0, 0, W, H);

    MarksCanvas.strokeStyle = Color.ToString();
    MarksCanvas.fillStyle = Color.ToString();
    MarksCanvas.lineWidth = PenWidth;

    var r = W / 2;
    var shift = PenWidth;

    var _y1 = ((-H / 2) * Math.sqrt(2)) / 2 + H / 2;
    var _y2 = ((H / 2) * Math.sqrt(2)) / 2 + H / 2;

    var _x1 = -Math.sqrt(r * r - (_y1 - r) * (_y1 - r)) + r;
    var _x2 = +Math.sqrt(r * r - (_y1 - r) * (_y1 - r)) + r;

    var x1 = Math.floor(_x1);
    var x2 = Math.ceil(_x2);
    var y1 = Math.ceil(_y1);
    var y2 = Math.floor(_y2);
    var width = Math.floor(PenWidth);

    var ImageData = MarksCanvas.createImageData(W, H);
    for (var i = 0; i < H; i++) {
        for (var j = 0; j < W; j++) {
            var Index = (i * W + j) * 4;

            if ((((x1 <= j && j <= x1 + width) || (x2 - width <= j && j <= x2)) && y1 <= i && i <= y2) || (((y1 <= i && i <= y1 + width) || (y2 - width <= i && i <= y2)) && x1 <= j && j <= x2)) {
                ImageData.data[Index + 0] = Color.r;
                ImageData.data[Index + 1] = Color.g;
                ImageData.data[Index + 2] = Color.b;
                ImageData.data[Index + 3] = 255;
            } else {
                ImageData.data[Index + 0] = 0;
                ImageData.data[Index + 1] = 0;
                ImageData.data[Index + 2] = 0;
                ImageData.data[Index + 3] = 0;
            }
        }
    }

    return ImageData;
  }
  
  _drawFilledSquare(W, H, PenWidth, bBig, Color, BorderColor) {
    var MarksCanvas = this.htmlElement.Marks.getContext("2d");

    var ImageData = MarksCanvas.createImageData(W, H);

    var H_3 = bBig ? (H / 4) | 0 : (H / 3) | 0;
    var H_2_3 = bBig ? ((H * 3) / 4) | 0 : ((H * 2) / 3) | 0;
    var W_3 = bBig ? (W / 4) | 0 : (W / 3) | 0;
    var W_2_3 = bBig ? ((W * 3) / 4) | 0 : ((W * 2) / 3) | 0;

    for (var i = 0; i < H; i++) {
        for (var j = 0; j < W; j++) {
            var Index = (i * W + j) * 4;

            if (((i === H_3 || i === H_2_3) && j >= W_3 && j <= W_2_3) || ((j === W_3 || j === W_2_3) && i >= H_3 && i <= H_2_3)) {
                ImageData.data[Index + 0] = BorderColor.r;
                ImageData.data[Index + 1] = BorderColor.g;
                ImageData.data[Index + 2] = BorderColor.b;
                ImageData.data[Index + 3] = 255;
            } else if (i > H_3 && i < H_2_3 && j > W_3 && j < W_2_3) {
                ImageData.data[Index + 0] = Color.r;
                ImageData.data[Index + 1] = Color.g;
                ImageData.data[Index + 2] = Color.b;
                ImageData.data[Index + 3] = 255;
            } else ImageData.data[Index + 3] = 0;
        }
    }

    return ImageData;
  }

  _drawCircle(W, H, PenWidth, Color) {
    var MarksCanvas = this.htmlElement.Marks.getContext("2d");
    MarksCanvas.clearRect(0, 0, W, H);

    var r = W / 2;
    var shift = PenWidth * 4;

    MarksCanvas.strokeStyle = Color.ToString();
    MarksCanvas.fillStyle = Color.ToString();
    MarksCanvas.lineWidth = PenWidth;
    MarksCanvas.beginPath();
    MarksCanvas.arc(W / 2, H / 2, r - shift, 0, 2 * Math.PI, false);
    MarksCanvas.stroke();

    return MarksCanvas.getImageData(0, 0, W, H);
  }

  _drawHandiMark(x, y, radius, w, h, Color) {
    var Canvas = document.createElement("canvas").getContext("2d");
    var ImageData = Canvas.createImageData(w, h);
    var Bitmap = ImageData.data;

    var pixel = 0.8;
    var d = w;
    var d_2 = Math.max(d / 2.0, 2);
    var d2 = d / 2.0 - 5e-1;
    var r = d2 - 2e-1;

    for (var i = 0; i < d; i++) {
        for (var j = 0; j < d; j++) {
            var di = i - d2;
            var dj = j - d2;
            var hh = r - Math.sqrt(di * di + dj * dj);
            var Index = (i * d + d - j - 1) * 4;
            if (hh >= 0) {
                var alpha = 255;

                if (hh <= pixel) {
                    var _hh = (pixel - hh) / pixel;
                    alpha = parseInt((1 - _hh) * 255);
                }

                Bitmap[Index + 0] = Color.r;
                Bitmap[Index + 1] = Color.g;
                Bitmap[Index + 2] = Color.b;
                Bitmap[Index + 3] = alpha;
            } else {
                Bitmap[Index + 0] = 0;
                Bitmap[Index + 1] = 0;
                Bitmap[Index + 2] = 0;
                Bitmap[Index + 3] = 0;
            }
        }
    }

    return ImageData;
  }

  _createBoardMarks() {
    var W = this.imageData.W;
    var H = this.imageData.H;
    var d = parseInt(min(W, H) * 0.6);
    this.imageData.BoardMarkO = this._drawCircle(d, d, d * 0.08, new CColor(255, 0, 0, 128));
    this.imageData.BoardMarkX = this._drawX(d, d, d * 0.08, new CColor(255, 0, 0, 128));
  }

  _onResize(force) {
    if(!this._inited) return;

    var div = document.getElementById("GoBoard"+this.props.boardId);

    if(!div)
      return;

    var W = parseInt(this.width * window.innerWidth / 100);
    var H = parseInt(this.height * window.innerHeight / 100);

    var coeff = this.getAspectRatio();
    var _W = H * coeff;
    var _H = W / coeff;
    var marginLeft = 0;
    if (_W <= W) {
      marginLeft = (W - _W) / 2;
      W = _W;
    } 
    else H = _H;

    div.style.width = W + "px";
    div.style.height = H + "px";
    div.style.marginLeft = 0 + 'px';

    if (W !== this.imageData.W || H !== this.imageData.H || force) {
        this.imageData.W = W;
        this.imageData.H = H;

        var DWidth = Math.floor(this.coeffCellW * this.imageData.W) - 1;

        var d = Math.floor(DWidth / 2) * 2 + 1;
        this.imageData.StoneDiam = d;

        this._createLines();
        this._createShadows();
        this._createMarks();
        this._createBoardMarks();
    }
    this.drawBoard();
  }

  _getLineHandiPoints(nSize) {
    var aPoints = [];
    if (5 == nSize) aPoints = [2];
    else if (7 == nSize) aPoints = [3];
    else if (8 == nSize) aPoints = [2, 5];
    else if (9 == nSize) aPoints = [2, 6];
    else if (10 == nSize) aPoints = [3, 6];
    else if (11 == nSize) aPoints = [3, 7];
    else if (nSize >= 12) {
        if (1 == nSize % 2) aPoints = [3, (nSize - 1) / 2, nSize - 4];
        else aPoints = [3, nSize - 4];
    }
    return aPoints;
  };

  _setViewPort(X0, Y0, X1, Y1) {
    var oSize = { X: this.size, Y: this.size };
    var nSizeX = oSize.X,
        nSizeY = oSize.Y;

    this.viewPort.X0 = Math.max(0, Math.min(nSizeX - 1, X0));
    this.viewPort.Y0 = Math.max(0, Math.min(nSizeY - 1, Y0));
    this.viewPort.X1 = Math.max(0, Math.min(nSizeX - 1, X1));
    this.viewPort.Y1 = Math.max(0, Math.min(nSizeY - 1, Y1));

    if (this.viewPort.X1 <= this.viewPort.X0) {
        this.viewPort.X0 = 0;
        this.viewPort.X1 = nSizeX - 1;
    }

    if (this.viewPort.Y1 <= this.viewPort.Y0) {
        this.viewPort.Y0 = 0;
        this.viewPort.Y1 = nSizeY - 1;
    }
  }

  _isPointInViewPort(X, Y) {
    if (X >= this.viewPort.X0 && X <= this.viewPort.X1 && Y >= this.viewPort.Y0 && Y <= this.viewPort.Y1) 
      return true;
    return false;
  };

  _drawTrueColorLines(Exclude) {
    if (!this.imageData.Lines)
        return;

    var W = this.imageData.W;
    var H = this.imageData.H;

    var LinesCanvas = this.htmlElement.Lines.getContext("2d");
    LinesCanvas.canvas.width = W;
    LinesCanvas.canvas.height = H;

    var oSize = {X: this.size, Y: this.size};
    var Lines = this.imageData.Lines;

    LinesCanvas.clearRect(0, 0, W, H);

    var Handi = this.imageData.Handi;
    var nRad = this.imageData.HandiRad;

    var aPoints = [];

    var aPointsX = this._getLineHandiPoints(oSize.X);
    var aPointsY = this._getLineHandiPoints(oSize.Y);

    for (var nX = 0; nX < aPointsX.length; nX++) {
        for (var nY = 0; nY < aPointsY.length; nY++) {
            aPoints.push([aPointsX[nX], aPointsY[nY]]);
        }
    }
    if ((11 == oSize.X && 1 == oSize.Y % 2) || (11 == oSize.Y && 1 == oSize.X % 2)) aPoints.push([(oSize.X - 1) / 2, (oSize.Y - 1) / 2]);

    for (var nPointIndex = 0, Count = aPoints.length; nPointIndex < Count; nPointIndex++) {
        if (true === this._isPointInViewPort(aPoints[nPointIndex][0], aPoints[nPointIndex][1])) {
            var dX = Lines[aPoints[nPointIndex][0]].X - nRad;
            var dY = Lines[aPoints[nPointIndex][1]].Y - nRad;

            LinesCanvas.putImageData(Handi, dX, dY);
        }
    }

    var X_0 = 0 === this.viewPort.X0 ? Lines[this.viewPort.X0].X : Lines[this.viewPort.X0].X_L;
    var X_1 = oSize.X - 1 === this.viewPort.X1 ? Lines[this.viewPort.X1].X : Lines[this.viewPort.X1].X_G;

    var Y_0 = 0 === this.viewPort.Y0 ? Lines[this.viewPort.Y0].Y : Lines[this.viewPort.Y0].Y_L;
    var Y_1 = oSize.Y - 1 === this.viewPort.Y1 ? Lines[this.viewPort.Y1].Y : Lines[this.viewPort.Y1].Y_G;

    var VerLine = LinesCanvas.createImageData(1, H);
    var HorLine = LinesCanvas.createImageData(W, 1);

    var LineColor = new CColor(0, 0, 0, 255);
    for (var i = 0; i < H; i++) {
        var Index = i * 4;

        if (i >= Y_0 && i <= Y_1) {
            VerLine.data[Index + 0] = LineColor.r;
            VerLine.data[Index + 1] = LineColor.g;
            VerLine.data[Index + 2] = LineColor.b;
            VerLine.data[Index + 3] = LineColor.a;
        }
    }

    for (var i = 0; i < W; i++) {
        var Index = i * 4;

        if (X_0 <= i && i <= X_1) {
            HorLine.data[Index + 0] = LineColor.r;
            HorLine.data[Index + 1] = LineColor.g;
            HorLine.data[Index + 2] = LineColor.b;
            HorLine.data[Index + 3] = LineColor.a;
        }
    }

    for (var nX = 0; nX < oSize.X; nX++) {
        if (nX >= this.viewPort.X0 && nX <= this.viewPort.X1)
            LinesCanvas.putImageData(VerLine, Lines[nX].X, 0);
    }

    for (var nY = 0; nY < oSize.Y; nY++) {
        if (nY >= this.viewPort.Y0 && nY <= this.viewPort.Y1)
            LinesCanvas.putImageData(HorLine, 0, Lines[nY].Y);
    }

    if (undefined !== Exclude) {
        var clear_w = Lines[1].X - Lines[0].X + 2;
        var clear_h = Lines[1].Y - Lines[0].Y + 2;

        for (var Index = 0, Count = Exclude.length; Index < Count; Index++) {
            var X = Exclude[Index].X;
            var Y = Exclude[Index].Y;

            if (true === this._isPointInViewPort(X, Y)) {
                if (GoLogic.EMPTY === this.lboard.getstate(X, Y)) {
                    var _X = Lines[X].X_L2;
                    var _Y = Lines[Y].Y_L2;

                    LinesCanvas.clearRect(_X, _Y, clear_w, clear_h);
                }
            }
        }
    }
  }

  _drawStones() {
    var W = this.imageData.W; 
    var H = this.imageData.H; 

    var dCellW = this.coeffCellW * W;
    var dCellH = this.coeffCellH * H;
    var dOffX = this.coeffOffsetX * W - this.viewPort.X0 * dCellW;
    var dOffY = this.coeffOffsetY * H - this.viewPort.Y0 * dCellH;

    var StonesCanvas = this.htmlElement.Stones.getContext("2d");
    StonesCanvas.canvas.width = W;
    StonesCanvas.canvas.height = H;
    var ShadowCanvas = this.htmlElement.Shadow.getContext("2d");
    
    var d = W / 64; 
    if(this.props.view_option.view_bw_mode)
      d = 0;

    ShadowCanvas.canvas.width = W + 2*d;
    ShadowCanvas.canvas.height = H + 2*d;
    ShadowCanvas.shadowBlur = d;
    ShadowCanvas.shadowOffsetX = d;
    ShadowCanvas.shadowOffsetY = d;
    ShadowCanvas.shadowColor = "black";
    ShadowCanvas.fillStyle = 'rgb(219,187,114,0.5)';
    ShadowCanvas.fillRect(0, 0, W, H);

    StonesCanvas.clearRect(0, 0, W, H);
    StonesCanvas.strokeStyle = "#000";
    StonesCanvas.lineWidth = 1;

    ShadowCanvas.clearRect(0, 0, W, H);

    d = this.imageData.StoneDiam;
    var Rad = (d - 1) / 2;
    var Lines = this.imageData.Lines;
    var Off = this.imageData.ShadowOff;

    var bShadows = true;
    if(this.props.view_option.view_bw_mode)
      bShadows = false;

    var ColorB = (new CColor(0, 0, 0, 255)).ToString();
    var ColorW = (new CColor(255, 255, 255, 255)).ToString();

    var numboard = this.lboard.getnumboard();
    for(var y = 0; y < this.size; y ++)
      for(var x = 0; x < this.size; x ++) {
        if (true === this._isPointInViewPort(x, y)) {
          var _X = Lines[x].X - Rad;
          var _Y = Lines[y].Y - Rad;
          var num = numboard[GoLogic.APOS(x, y)];
          var FontFamily = "Arial";
          var FontSize = Rad;//d / 3;
          var sFont = FontSize + "px " + FontFamily;
          StonesCanvas.font = sFont;
          var Text = "" + num;
          var y_offset = d / 2 + FontSize / 3;
          var x_offset = (d - StonesCanvas.measureText(Text).width) / 2;
          var Value = this.lboard.getstate(x, y);
          if (this.props.readOnly) {
            var state = this.props.board_str[y * this.size + x];

            if (state === 'b')
              Value = GoLogic.BLACK;
            else if (state === 'w')
              Value = GoLogic.WHITE;
            else
              Value = GoLogic.EMPTY;
          }

          switch (Value) {
            case GoLogic.BLACK: {
                if(this.props.view_option.view_bw_mode) {
                  StonesCanvas.fillStyle = ColorB;
                  StonesCanvas.beginPath();
                  StonesCanvas.arc(Lines[x].X, Lines[y].Y, Rad, 0, Math.PI * 2, false);
                  StonesCanvas.fill();
                  StonesCanvas.stroke();
                } else
                  StonesCanvas.drawImage(this.imageData.BlackStone, _X, _Y, d, d);
                if (this.numbers) {
                    if (num > 0) {
                        StonesCanvas.fillStyle = "#CCC";
                        StonesCanvas.fillText(Text, _X + x_offset, _Y + y_offset);
                    }
                }
                if (true === bShadows)
                    ShadowCanvas.putImageData(this.imageData.Shadow, _X + Off, _Y + Off);
                break;
            }
            case GoLogic.WHITE: {
                if(this.props.view_option.view_bw_mode) {
                  StonesCanvas.fillStyle = ColorW;
                  StonesCanvas.beginPath();
                  StonesCanvas.arc(Lines[x].X, Lines[y].Y, Rad, 0, Math.PI * 2, false);
                  StonesCanvas.fill();
                  StonesCanvas.stroke();
                } else
                  StonesCanvas.drawImage(this.imageData.WhiteStone, _X, _Y, d, d);
                if (this.numbers) {
                    if (num > 0) {
                        StonesCanvas.fillStyle = "#000";
                        StonesCanvas.fillText(Text, _X + x_offset, _Y + y_offset);
                    }
                }
                if (true === bShadows)
                    ShadowCanvas.putImageData(this.imageData.Shadow, _X + Off, _Y + Off);
                break;
            }
            case GoLogic.EMPTY:
            default: {
                StonesCanvas.clearRect(_X, _Y, d, d);
                if (true === bShadows) {
                  var d1 = d;
                  if (d1 > W - (_X + Off))
                    d1 = W - (_X + Off);
                  if (d1 > H - (_Y + Off))
                    d1 = H - (_Y + Off);
                  ShadowCanvas.clearRect(_X + Off, _Y + Off, d1, d1);
                }
                break;
            }
          }
        }  
      }

    // draw preview stone
    if(this.props.edit_mode == EBoardMode.Move && !this.props.readOnly && this.props.putAble && this.lboard.turn !== 0 && this.preview_pos.X >= 0 && this.lboard.getstate(this.preview_pos.X, this.preview_pos.Y) === GoLogic.EMPTY) {
      StonesCanvas.globalAlpha = 0.5;
      StonesCanvas.drawImage((this.lboard.turn === GoLogic.WHITE ? this.imageData.WhiteStone : this.imageData.BlackStone),
        dOffX + (this.preview_pos.X - 0.5) * dCellW, dOffY + (this.preview_pos.Y - 0.5) * dCellW, dCellW, dCellH);
      StonesCanvas.globalAlpha = 1;
    }
  }

  _drawMarks() {
    var MarksCanvas = this.htmlElement.Marks.getContext('2d');
    var W = this.imageData.W;
    var H = this.imageData.H;

    MarksCanvas.clearRect(0, 0, W, H);
    MarksCanvas.canvas.width = W;
    MarksCanvas.canvas.height = H;

    var Exclude = new Array();

    var { marks, marks_2, lboard2, marks2, hints } = this.props;
    if (!!marks_2) {
      marks = [];
      marks_2.map((mark) => marks.push({x: mark.mark_x, y: mark.mark_y, type: mark.mark_type, text: mark.mark_text}));
    } else if (!!lboard2) {
      marks = [];
      marks2.map((mark) => marks.push({x: mark.x, y: mark.y, type: mark.type, text: mark.text}));
    }
    for (var i = 0; i < marks.length; i ++) {
      var mark = marks[i];
      this._drawMark(mark.x, mark.y, mark.type, mark.text);
      if (EDrawingMark.Tx === mark.type) 
        Exclude.push({ X: mark.x, Y: mark.y });
    }

    var move;
    if (!this.props.readOnly)
      move = this.lboard.getcurmove();
    else
      move = this.props.last_move;
    if (!!move && move.pos !== -1) 
      this._drawMark(GoLogic.XPOS(move.pos), GoLogic.YPOS(move.pos), EDrawingMark.Lm);

    if (!this.props.readOnly && this.props.eval.view)
    {
      var territory = this.props.eval;
      var i, pos, x, y;
      
      for (i = 0; i < territory.white_one_territories.length; i ++) {
        pos = territory.white_one_territories[i];
        x = GoLogic.XPOS(pos);
        y = GoLogic.YPOS(pos);
        this._drawMark(x, y, EDrawingMark.Tw2);
      }
      for (i = 0; i < territory.black_one_territories.length; i ++) {
        pos = territory.black_one_territories[i];
        x = GoLogic.XPOS(pos);
        y = GoLogic.YPOS(pos);
        this._drawMark(x, y, EDrawingMark.Tb2);
      }
      for (i = 0; i < territory.white_half_territories.length; i ++) {
        pos = territory.white_half_territories[i];
        x = GoLogic.XPOS(pos);
        y = GoLogic.YPOS(pos);
        this._drawMark(x, y, EDrawingMark.Tw);
      }
      for (i = 0; i < territory.black_half_territories.length; i ++) {
        pos = territory.black_half_territories[i];
        x = GoLogic.XPOS(pos);
        y = GoLogic.YPOS(pos);
        this._drawMark(x, y, EDrawingMark.Tb);
      }
    }
    
    for (i = 0; i < hints.length; i ++) {
      this._drawHint(hints[i].x, hints[i].y);
      Exclude.push({ X: hints[i].x, Y: hints[i].y });
    }

    this._drawTrueColorLines(Exclude);
  }

  _drawMark(x, y, type, text) {
    if (!this.imageData.Lines)
        return;

    var MarksCanvas = this.htmlElement.Marks.getContext("2d");
    var bDarkBoard = false;

    if (true === this._isPointInViewPort(x, y)) {
        var d = this.imageData.StoneDiam;
        var Rad = (d - 1) / 2;
        var Lines = this.imageData.Lines;
        var _X = Lines[x].X - Rad;
        var _Y = Lines[y].Y - Rad;

        var Value = this.lboard.getstate(x, y);
        if (this.props.readOnly) {
          var state = this.props.board_str[y * this.size + x];

          if (state === 'b')
            Value = GoLogic.BLACK;
          else if (state === 'w')
            Value = GoLogic.WHITE;
          else
            Value = GoLogic.EMPTY;
        }

        switch (type) {
            case EDrawingMark.Tb:
                MarksCanvas.putImageData(this.imageData.Ter_Black, _X, _Y);
                break;
            case EDrawingMark.Tw:
                if (!this.props.view_option.view_bw_mode)
                    MarksCanvas.putImageData(this.imageData.Ter_White, _X, _Y);
                else
                    MarksCanvas.putImageData(this.imageData.Ter_White_Border, _X, _Y);
                break;
            case EDrawingMark.Tb2:
                MarksCanvas.putImageData(this.imageData.Ter_Black2, _X, _Y);
                break;
            case EDrawingMark.Tw2:
                if (!this.props.view_option.view_bw_mode)
                    MarksCanvas.putImageData(this.imageData.Ter_White2, _X, _Y);
                else
                    MarksCanvas.putImageData(this.imageData.Ter_White_Border2, _X, _Y);
                break;
            case EDrawingMark.Lm:
                MarksCanvas.putImageData(this.imageData.LastMove, _X, _Y);
                break;
            case EDrawingMark.Cr:
                MarksCanvas.putImageData(Value === GoLogic.BLACK || (Value == GoLogic.EMPTY && true == bDarkBoard) ? this.imageData.Cr_White : this.imageData.Cr_Black, _X, _Y);
                break;
            case EDrawingMark.Sq:
                MarksCanvas.putImageData(Value === GoLogic.BLACK || (Value == GoLogic.EMPTY && true == bDarkBoard) ? this.imageData.Sq_White : this.imageData.Sq_Black, _X, _Y);
                break;
            case EDrawingMark.Tr:
                MarksCanvas.putImageData(Value === GoLogic.BLACK || (Value == GoLogic.EMPTY && true == bDarkBoard) ? this.imageData.Tr_White : this.imageData.Tr_Black, _X, _Y);
                break;
            case EDrawingMark.X :
                MarksCanvas.putImageData(Value === GoLogic.BLACK || (Value == GoLogic.EMPTY && true == bDarkBoard) ? this.imageData.X_White : this.imageData.X_Black, _X, _Y);
                break;
            case EDrawingMark.Tx: {
                var FontSize = (text.length <= 2 ? 2 * d / 3 : d / 2);
                var FontFamily = (Common_IsInt(text) ? "Arial" : "Helvetica, Arial, Verdana");
                var sFont = FontSize + "px " + FontFamily;

                MarksCanvas.fillStyle = Value === GoLogic.BLACK || (Value == GoLogic.EMPTY && true == bDarkBoard) ? "rgb(255,255,255)" : "rgb(0,0,0)";
                MarksCanvas.font = sFont;

                var y_offset = d / 2 + FontSize / 3;
                var x_offset = (d - MarksCanvas.measureText(text).width) / 2;

                MarksCanvas.fillText(text, _X + x_offset, _Y + y_offset);

                break;
            }
        }
    }
  }

  _drawHint(X, Y) {
    if (!this.imageData.Lines)
        return;

    var MarksCanvas = this.htmlElement.Marks.getContext("2d");
    if (true === this._isPointInViewPort(X, Y)) {
        var d = this.imageData.StoneDiam;
        var Rad = (d - 1) / 2;
        var Lines = this.imageData.Lines;
        var _X = Lines[X].X - Rad;
        var _Y = Lines[Y].Y - Rad;
        MarksCanvas.putImageData(this.imageData.Tr_Hint, _X, _Y);
    }
  }

  _drawBoardMarks() {
    var BoardMarksCanvas = this.htmlElement.BoardMarks.getContext('2d');
    var W = this.imageData.W;
    var H = this.imageData.H;

    BoardMarksCanvas.clearRect(0, 0, W, H);
    BoardMarksCanvas.canvas.width = W;
    BoardMarksCanvas.canvas.height = H;

    const { solve_result } = this.props;

    var x = parseInt(W * 0.5 - min(W, H) * 0.3);
    var y = parseInt(H * 0.5 - min(W, H) * 0.3);
    if ('correct' === solve_result)
      BoardMarksCanvas.putImageData(this.imageData.BoardMarkO, x, y);
    else if ('incorrect' === solve_result)
      BoardMarksCanvas.putImageData(this.imageData.BoardMarkX, x, y);
  }

  _updateCoeffs() {
    var nSizeX = this.size,
        nSizeY = this.size;

    this.viewPort.X0 = Math.max(0, Math.min(nSizeX - 1, this.viewPort.X0));
    this.viewPort.Y0 = Math.max(0, Math.min(nSizeY - 1, this.viewPort.Y0));
    this.viewPort.X1 = Math.max(0, Math.min(nSizeX - 1, this.viewPort.X1));
    this.viewPort.Y1 = Math.max(0, Math.min(nSizeY - 1, this.viewPort.Y1));

    if (this.viewPort.X1 <= this.viewPort.X0) {
        this.viewPort.X0 = 0;
        this.viewPort.X1 = nSizeX - 1;
    }

    if (this.viewPort.Y1 <= this.viewPort.Y0) {
        this.viewPort.Y0 = 0;
        this.viewPort.Y1 = nSizeY - 1;
    }

    var dAbsBoardW = (this.viewPort.X1 - this.viewPort.X0) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsBoardH = (this.viewPort.Y1 - this.viewPort.Y0) * g_dBoardCellW + 2 * g_dBoardHorOffset;
    var dAbsHorOff = g_dBoardHorOffset;
    var dAbsVerOff = g_dBoardHorOffset;

    if (true === this.rulers) {
        dAbsBoardW += g_dBoardCellW;
        dAbsBoardH += g_dBoardCellW;
        dAbsHorOff += g_dBoardCellW_2;
        dAbsVerOff += g_dBoardCellW_2;
    }

    if (this.viewPort.X0 > 0) {
        dAbsBoardW += g_dBoardCellW_2 / 2;
        dAbsHorOff += g_dBoardCellW_2 / 2;
    }

    if (this.viewPort.X1 < nSizeX - 1) dAbsBoardW += g_dBoardCellW_2 / 2;

    if (this.viewPort.Y0 > 0) {
        dAbsBoardH += g_dBoardCellW_2 / 2;
        dAbsVerOff += g_dBoardCellW_2 / 2;
    }

    if (this.viewPort.Y1 < nSizeY - 1) dAbsBoardH += g_dBoardCellW_2 / 2;

    this.coeffCellH = g_dBoardCellW / dAbsBoardH;
    this.coeffCellW = g_dBoardCellW / dAbsBoardW;
    this.coeffOffsetX = dAbsHorOff / dAbsBoardW;
    this.coeffOffsetY = dAbsVerOff / dAbsBoardH;
    this.coeffDiam = 4 / dAbsBoardW;
  }
  
  _drawBoard() {
    this.size = this.lboard.boardsize;

    var BoardCanvas = this.htmlElement.Board.getContext("2d");
   
    var W = this.imageData.W; 
    var H = this.imageData.H;   
    BoardCanvas.canvas.width = W;
    BoardCanvas.canvas.height = H;
    //BoardCanvas.drawRect(0, 0, W, H);
    const {room_type} = this.props;
    if (!this.props.view_option.view_bw_mode)
      BoardCanvas.drawImage(this.imageData.Board, 0, 0, W, H);
    else if (room_type === 'spectate' || room_type === 'play') {
      BoardCanvas.fillStyle = 'rgb(255, 255, 255, 1)';
      BoardCanvas.fillRect(0, 0, W, H);
    }
  }

  drawBoard() {
    if(!this._inited) return;

    this._drawBoard();
    this._drawRulers();
    // this._drawTrueColorLines();
    this._drawStones();
    this._drawMarks();
    this._drawBoardMarks();
  }

  _drawRulers() {
    if (true === this.rulers && this.imageData.Lines) {
      var BoardCanvas = this.htmlElement.Board.getContext('2d');
      var W = this.imageData.W;
      var H = this.imageData.H;
      var oSize = {X: this.size, Y: this.size};

      var d = (2 * this.imageData.StoneDiam) / 3;
      var Rad = (d - 1) / 2;
      var Lines = this.imageData.Lines;
      var FontSize = (2 * d) / 3;

      var bDarkBoard = false;
      if (bDarkBoard) BoardCanvas.fillStyle = 'rgb(255,255,255)';
      else BoardCanvas.fillStyle = 'rgb(0,0,0)';

      for (var X = this.viewPort.X0; X <= this.viewPort.X1; X++) {
          var _X = Lines[X].X - Rad;
          var _Y = (this.coeffOffsetY * H) / 3 - Rad;

          var Text = Common_X_to_String(X + 1, oSize.X);
          var FontFamily = Common_IsInt(Text) ? 'Arial' : 'Helvetica, Arial, Verdana';
          var sFont = FontSize + 'px ' + FontFamily;

          BoardCanvas.font = sFont;

          var y_offset = d / 2 + FontSize / 3;
          var x_offset = (d - BoardCanvas.measureText(Text).width) / 2;

          BoardCanvas.fillText(Text, _X + x_offset, _Y + y_offset);

          _Y = H - (this.coeffOffsetY * H) / 3 - Rad;
          BoardCanvas.fillText(Text, _X + x_offset, _Y + y_offset);
      }

      for (var Y = this.viewPort.Y0; Y <= this.viewPort.Y1; Y++) {
          var _X = (this.coeffOffsetX * W) / 3 - Rad;
          var _Y = Lines[Y].Y - Rad;

          var Text = (oSize.Y - Y) + "";
          var FontFamily = Common_IsInt(Text) ? 'Arial' : 'Helvetica, Arial, Verdana';
          var sFont = FontSize + 'px ' + FontFamily;

          BoardCanvas.font = sFont;

          var y_offset = d / 2 + FontSize / 3;
          var x_offset = (d - BoardCanvas.measureText(Text).width) / 2;

          BoardCanvas.fillText(Text, _X + x_offset, _Y + y_offset);

          _X = W - (this.coeffOffsetX * W) / 3 - Rad;
          BoardCanvas.fillText(Text, _X + x_offset, _Y + y_offset);
      }
    }
  }

  render() {
    var {viewport, viewport2, view_option} = this.props;
    this.rulers = view_option.view_ruler;
    this.numbers = view_option.view_number;
    if (!!viewport2)
      viewport = viewport2;
    var force_redraw = false;
    if (this.width !== this.props.width || this.height !== this.props.height)
      force_redraw = true;
    this.width = this.props.width;
    this.height = this.props.height;
    
    if (!!this.lboard && this.size !== this.lboard.boardsize) {
      this.size = this.lboard.boardsize;
      force_redraw = true;
    }
    if (this.viewPort.X0 !== viewport.x0 || this.viewPort.Y0 !== viewport.y0 || this.viewPort.X1 !== viewport.x1 || this.viewPort.Y1 !== viewport.y1) {
      this._setViewPort(viewport.x0, viewport.y0, viewport.x1, viewport.y1);
      if(!!this._inited) {
        force_redraw = true;
      }
    }
    if (force_redraw) {
      this.onResize(true);
    }

    this.drawBoard();
    return (
      <div>
        <img id="GoBoardBG" src="/assets/img/board.jpg" alt="" style={{display: "none"}} onLoad={this.onResize}/>
        <img id="GoBlackStone" src="/assets/img/stone_b.png" alt="" style={{display: "none"}}/>
        <img id="GoWhiteStone" src="/assets/img/stone_w.png" alt="" style={{display: "none"}}/>
        <div 
          ref="canvas"
          id = {"GoBoard" + this.props.boardId}
          />
      </div>
    );
  }
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    socketRoom: store.roomReducer.socketRoom,
    room_type: store.roomReducer.room.room_type,
    room_id: store.roomReducer.room.room_id,
    putAble: store.goBoardReducer.putAble,
    eval: store.goReducer.eval,
    marks: store.goBoardReducer.marks,
    marks2: store.goBoardReducer.marks2,
    hints: store.goBoardReducer.hints,
    edit_mode: store.goBoardReducer.edit_mode,
    viewport: store.goBoardReducer.viewport,
    board_update: store.goBoardReducer.board_update,
    solve_result: store.goProblemReducer.solve_result,
    problem: store.goProblemReducer.problem,
    connection: store.goTeacherReducer.connection,
    view_option: store.goReducer.view_option,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      add_mark: GoBoardAction.add_mark,
      remove_mark: GoBoardAction.remove_mark,
      update_viewport: GoBoardAction.update_viewport_selection,
      on_problem_move: GoProblemAction.on_problem_move,
      on_train_game_move: GoTrainAction.on_train_game_move,
      do_move_in_lecture_room: GoTeacherAction.do_move_in_lecture_room,
      add_move_on_problem_answer: GoProblemAction.add_move_on_problem_answer,
      delete_move_history: GoAction.delete_move_history,
      set_edit_stones: GoBoardAction.set_edit_stones,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(Board);
