import React, {useState, useEffect} from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import moment from "moment";

import { makeStyles } from '@material-ui/core/styles';
import { Line } from "react-chartjs-2";
import {
  Avatar,
  Button,
  BottomNavigation,
  BottomNavigationAction,
} from '@material-ui/core';
import {
  MDBBtn,
  MDBRow,
  MDBCol,
  MDBCard,
  MDBCardBody,
  MDBScrollbar,
  MDBListGroup,
  MDBListGroupItem,
} from "mdbreact";

import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as GoLogic from "../go/logic";
import Board from "../go/board";
import GrController from '../control/GrController';
import ReviewAndRate from "../review/ReviewAndRate";
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';
import CD from "../../helper/const";

const useStyles = makeStyles(theme => ({
  boardStyle: {
    width: '70%',
    padding: '1rem',
  },
  leftPanelStyle: {
    paddingLeft: '5vw',
  },
  whiteStyle: {
    color: 'white',
    fontWeight: 'bold',
    textShadow: '0px 0px 4px #000000',
    fontSize: '1.2rem',
    paddingTop: '0.5rem',
  },
  avatarImg: {
    width: '6vh',
    height: '6vh',
  },
  whiteTextStyle: {
    fontSize: '1.2rem',
    paddingTop: '0.5rem',
  },
  blackStyle: {
    color: 'black',
    fontWeight: 'bold',
    textShadow: '0px 0px 4px #aaaaaa',
    fontSize: '1.2rem',
    paddingTop: '0.5rem',
  },
  blackTextStyle: {
    fontSize: '1.2rem',
    paddingTop: '0.5rem',
  },
  scrollableStyle: {
    height: '23vh',
  },
  scrollItem: {
    marginBottom: 0,
    border: 0,
    borderBottom: '1px solid',
  },
  giveBtnStyle: {
    float: 'right',
  },
  navigationButtons: {
    right: '2vw',
    width: '21vw',
    height: '8vh',
    background: '#ffffff',
    fontSize: '2.5vh',
    display: 'flex',
  },
  navigationButton1: {
    minWidth:'3.5vw',
    width:'3.5vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    color: "#404040",
  },
  navigationButton: {
    minWidth:'3.5vw',
    width:'3.5vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    borderLeft: 'none',
    color: "#404040",
  },
  modeButtons: {
    right: '2vw',
    width: '21vw',
    height: '8vh',
    background: '#ffffff',
    fontSize: '3.5vh'
  },
  modeButton1: {
    minWidth:'7vw',
    width:'7vw',
    border:'1px solid rgb(64, 64, 64)',
    color: "#404040",
  },
  modeButton: {
    minWidth:'7vw',
    width:'7vw',
    border:'1px solid rgb(64, 64, 64)',
    borderLeft:'none',
    color: "#404040",
  },
  otherButton: {
    minHeight: '8vh',
    minWidth:'7vw',
    width:'7vw',
    color: "#404040",
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
  },
  optionButton: {
    minHeight: '8vh',
    minWidth:'5vw',
    width:'5.25vw',
    color: "#404040",
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
  },
  otherBtnWrapper: {
    textTransform: 'none',
  },
}));

const dataLine = {
  labels: [],
  datasets: [{
    label: "black's winrates",
    fill: false,
    lineTension: 0.1,
    backgroundColor: "rgba(244,7,30,0.4)",
    borderColor: "rgba(244,7,30,1)",
    borderCapStyle: "butt",
    borderDash: [],
    borderDashOffset: 0.0,
    borderJoinStyle: "miter",
    pointBorderColor: "rgba(244,7,30,1)",
    pointBackgroundColor: "#fff",
    pointBorderWidth: 1,
    pointHoverRadius: 5,
    pointHoverBackgroundColor: "rgba(244,7,30,1)",
    pointHoverBorderColor: "rgba(220,220,220,1)",
    pointHoverBorderWidth: 2,
    pointRadius: 1,
    pointHitRadius: 10,
    data: []
  }]
};

function Replay(props) {
  const classes = useStyles();
  const [mode, setMode] = useState(0);
  const [openReviewAndRate, setOpenReviewAndRate] = useState(false);
  let w = window.innerWidth ;
  useEffect(() => {
    w = window.innerWidth;
    const {user, req_game, update_replay_mode, set_view_bw_mode} = props; 
    update_replay_mode(0);
    set_view_bw_mode(true);
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    req_game(!!user? user.user_id : '', CD.GAME_TYPE.GO, id);
  }, []);

  const handleRuler = () => {
    props.change_view_option(1);
  };
  const handleNumber = () => {
    props.change_view_option(2);
  };
  const handleViewMode = () => {
    props.change_view_option(4);
  };

  const Review = ({ review: { user_id, rating, text, date } }) => (
    <MDBListGroupItem
      className={classes.scrollItem+" d-flex justify-content-between p-2 border-light text-muted"}
      // style={{ backgroundColor: active ? "#eeeeee" : "" }}
    >
      <div style={{ fontSize: "0.95rem" }}>
        <i className="la la-user la-lg pr-1" />
        <strong>{user_id}</strong>
        <span className="mb-0 mx-3" style={{ fontSize: "0.75rem" }}>
          {moment(new Date(date)).fromNow()}
        </span>
        <Rater total={5} rating={rating} interactive={false} style={{fontSize:'1rem', display:'block'}}/>      
        <p style={{ fontSize: "0.85rem" }}>{text}</p>
      </div>
    </MDBListGroupItem>
  );
  
  const handleToIndex = (index) => {
    props.update_gr_index(index);
  }
  const handleMode = (new_mode) => {
    setMode(new_mode);
    const {update_replay_mode, update_gr_index, first_turn, move_history, colors} = props;
    update_replay_mode(new_mode);
    if (new_mode !== 1) {
      GoLogic.theLogicBoard.setgrcounter(0);
      var color = colors[first_turn];
      for (var i = 0; i < move_history.length; i ++) {
        GoLogic.theLogicBoard.domove(move_history[i], color);
        color = GoLogic.BLACK + GoLogic.WHITE - color;
      }
      update_gr_index(move_history.length);
    }
  };
  const handleTerritory = () => {
    const {board_size, kpmi, req_territory, territory_view, switch_eval_view} = props;
    if (territory_view) {
      switch_eval_view();
      return;
    }
    var board = GoLogic.theLogicBoard;
    var stone_board = board.getboard();
    var board_str = '';
    var boardsize = board_size;
    var x, y, i;
    for (y = 0; y < boardsize; y ++) {
      for (x = 0; x < boardsize; x ++) {
        i = y * GoLogic.MX_BOARD_SIZE + x;
        if (stone_board[i] === GoLogic.BLACK)
          board_str += 'b';
        else if (stone_board[i] === GoLogic.WHITE)
          board_str += 'w';
        else
          board_str += 'e';
      }
    }
    req_territory(boardsize, kpmi, board_str);
  };
  const handleWinrates = () => {
    const {game_id, req_winrates, move_history, winrates_to_index} = props;
    var updatedToIndex = winrates_to_index + 10;
    if (updatedToIndex > move_history.length)
      updatedToIndex = move_history.length;
    req_winrates(game_id, winrates_to_index, updatedToIndex, GoLogic.BLACK);
  };
  const handleCandidates = () => {
    const {game_id, gr_index, req_candidates} = props;
    req_candidates(game_id, gr_index);
  };
  const setLineData = () => {
    const {winrates_to_index, analyse_data} = props;
    dataLine.labels = [];
    dataLine.datasets[0].data = [];
    for(var i = 0; i < winrates_to_index; i ++) {
      dataLine.labels.push(i+1);
      dataLine.datasets[0].data.push(analyse_data.winrates[i]);
    }
  };
  const handleExit = () => {
    const {history, tournament_id, init_move_history} = props;
    props.init_move_history();
    if(!!tournament_id && tournament_id != "") history.push(`${'/tournament_past:' + tournament_id}`)
    else history.push('/records');
  };
  const handleCloseReviewAndRateDlg = (value) => {
    if (!!value) {
      setOpenReviewAndRate(false);
      const {user, game_id, add_review_to_game} = props;
      if (!!user)
        add_review_to_game(game_id, value.msg, value.rating);
    } else {
      setOpenReviewAndRate(false);
    }
  };

  const handleOpenReviewAndRateDlg = () => {
    setOpenReviewAndRate(true);
  };

  const handlePrefer = (add) => {
    const {user, game_id, prefer_game} = props;
    if(!!user)
      prefer_game(user.user_id, game_id, add);
  };

  const { user, black_player, black_avatar, black_level, black_xp, black_wins, black_loses, black_time, roomCoin,
    white_player, white_avatar, white_level, white_xp, white_wins, white_loses, white_time, move_history, result, reviews, preferred, putAble, finished} = props;  
  var finished_date = new Date(finished).toLocaleString()
  var w_h = parseInt(white_time / 3600);
  var w_m = parseInt((white_time % 3600) / 60);
  var w_s = white_time % 60;
  var b_h = parseInt(black_time / 3600);
  var b_m = parseInt((black_time % 3600) / 60);
  var b_s = black_time % 60;

  var cur_review;
  var total_rating = 0;
  for(var i in reviews) {
    total_rating += reviews[i].rating;
    if(!!user && reviews[i].user_id === user.user_id)
      cur_review = {rating: reviews[i].rating, text: reviews[i].text};
  }
  var avg_rating = reviews.length > 0? total_rating / reviews.length : 0;

  var prefer_index;
  for(var i in preferred) {
    if(!!user && preferred[i] === user.user_id) {
      prefer_index = i;
      break;
    }
  }

  setLineData();

  return (
   <div style={{backgroundColor: "white", position:"fixed", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "100vw", height: "100vh" }}> 
      <React.Fragment >
        <ReviewAndRate open={openReviewAndRate} review={cur_review} onClose={handleCloseReviewAndRateDlg}/>
        <MDBRow className="m-0">
          <MDBCol md="2" className={classes.leftPanelStyle} style = {{paddingTop: '10vh'}}>
            <h5 className = "font-weight-bold mb-2"><i className = 'fa fa-star mr-1' style = {{fontSize: '1rem'}} />{roomCoin}</h5>
            <h5 className = "font-weight-bold mb-4">{finished_date}</h5>
            <MDBRow>
              <MDBCol md="2" className={classes.whiteStyle}>
                {window.i18n.t("go_replay.white")}
              </MDBCol>
              <MDBCol md="1">
                <Avatar alt="Profile Picture" className={classes.avatarImg} src={white_avatar} />
              </MDBCol>
              <MDBCol className={classes.whiteTextStyle}>
                <div>{white_player}</div>
                <div>{"Lv" + white_level}</div>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol md="2" className={classes.blackStyle}>
                {window.i18n.t("go_replay.black")}
              </MDBCol>
              <MDBCol md="1">
                <Avatar alt="Profile Picture" className={classes.avatarImg} src={black_avatar} />
              </MDBCol>
              <MDBCol className={classes.blackTextStyle}>
                <div>{black_player}</div>
                <div>{"Lv" + black_level}</div>
              </MDBCol>
            </MDBRow>
            <MDBRow style={{marginBottom:'0px'}}>
              <MDBCol>            
                <h5 style={{marginBottom:'0px'}}>{result}</h5>
                <div>{window.i18n.t("go_replay.white_time") + w_h + window.i18n.t("go_replay.h") + w_m + window.i18n.t("go_replay.m") + w_s + window.i18n.t("go_replay.s")}</div>
                <div>{window.i18n.t("go_replay.black_time") + b_h + window.i18n.t("go_replay.h") + b_m + window.i18n.t("go_replay.m") + b_s + window.i18n.t("go_replay.s")}</div>
                <div>{window.i18n.t("go_replay.step") + move_history.length}</div>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-lg-2 py-2" style={{marginBottom:'0px'}}>
              <MDBCol
                className={classes.scrollableStyle+" px-0 mb-md-0"}
              >
                <span className="font-weight-bold mb-3 text-lg-left pr-5">{window.i18n.t("go_replay.reviews")}</span>
                <Rater total={5} rating={avg_rating} interactive={false}/>
                <MDBBtn outline color="gray"  className="px-2 py-1 ml-5 mt-0 my-3" onClick={handleOpenReviewAndRateDlg}>
                  {window.i18n.t("go_replay.rate")}
                </MDBBtn>
                {
                  !prefer_index && (
                    <MDBBtn outline color="gray" className="px-2 py-1 ml-5 mt-0 my-3" onClick={handlePrefer.bind(this, true)}>
                      <i className="fa fa-plus mr-1"/> {window.i18n.t("go_replay.prefer")}
                    </MDBBtn>
                  )
                }
                {
                  !!prefer_index && (
                    <MDBBtn outline color="gray" className="px-2 py-1 ml-5 mt-0 my-3" onClick={handlePrefer.bind(this, false)}>
                      <i className="fa fa-minus mr-1"/> {window.i18n.t("go_replay.prefer")}
                    </MDBBtn>
                  )
                }
                <MDBScrollbar className="white z-depth-1 p-3">
                  <MDBListGroup className="friend-list">
                    {reviews.map(review => (
                      <Review review={review} />
                    ))}
                  </MDBListGroup>
                </MDBScrollbar>
              </MDBCol>
            </MDBRow>
          </MDBCol>
          <MDBCol md="5" style = {{paddingTop: '2vh', paddingLeft: '2vw'}}>
            <Board boardId = {0} readOnly = {false} putAble={putAble} width = '55' height ='95' marginLeft = "0"/>
          </MDBCol>
          <MDBCol style = {{paddingTop: '5vh', paddingLeft: '8vw'}}>
            <MDBRow className="m-0  pt-5" >
              <Button className={classes.optionButton} disabled={false} style={{padding:'0px', fontSize: '2vh'}} onClick={handleRuler}>
                <span className={classes.otherBtnWrapper}><i className="fa fa-area-chart fa-lg pr-2"/>{window.i18n.t("go_replay.ruler")}</span>
              </Button>
              <Button className={classes.optionButton} style={{padding:'0px', fontSize: '2vh'}} onClick={handleNumber}>
                <span className={classes.otherBtnWrapper}><i className="fa fa-sort-numeric-asc fa-lg pr-2"/>{window.i18n.t("go_replay.number")}</span>
              </Button>
              <Button className={classes.optionButton} style={{padding:'0px', fontSize: '2vh'}} onClick={handleViewMode}>
                <span className={classes.otherBtnWrapper}><i className="fa fa-adjust fa-lg pr-2"/>{window.i18n.t("go_replay.mode")}</span>
              </Button>
              <Button className={classes.optionButton} style={{padding:'0px', fontSize: '2vh'}} onClick={handleExit}>
                <span className={classes.otherBtnWrapper}><i className="fa fa-external-link fa-lg pr-2"/>{window.i18n.t("go_replay.quit")}</span>
              </Button>          
            </MDBRow>
            <MDBRow className=" py-4">
              <MDBCol>
                <Button className={classes.otherButton} disabled={!user} style={{padding:'0px', fontSize: '2vh'}} onClick={handleTerritory}>
                  <span className={classes.otherBtnWrapper}><i className="fa fa-delicious fa-lg pr-2"/>{window.i18n.t("go_replay.territory")}</span>
                </Button>
                <Button className={classes.otherButton} disabled={!user} style={{padding:'0px', fontSize: '2vh'}} onClick={handleWinrates}>
                  <span className={classes.otherBtnWrapper}><i className="fa fa-line-chart fa-lg pr-2"/>{window.i18n.t("go_replay.win_rate")}</span>
                </Button>
                <Button className={classes.otherButton} disabled={!user} style={{padding:'0px', fontSize: '2vh'}} onClick={handleCandidates}>
                  <span className={classes.otherBtnWrapper}><i className="fa fa-sort-amount-desc fa-lg pr-2"/>{window.i18n.t("go_replay.candidate")}</span>
                </Button>
              </MDBCol>
            </MDBRow>  
                      
            <MDBRow style={{width:`${w/4}px`}}>
              <MDBCol size = "10">
                <MDBCard className="text-center">
                  <MDBCardBody>
                    <Line onElementsClick = {(e) => handleToIndex(e[0]._index)} data={{labels:dataLine.labels, datasets:dataLine.datasets}} options={{ responsive: true }} />
                  </MDBCardBody>
                </MDBCard>
              </MDBCol>
            </MDBRow>          
            <MDBRow  className="m-0 pt-4">
              <BottomNavigation
                value={mode}
                onChange={(event, newValue) => {
                  handleMode(newValue);
                }}
                showLabels
                className={classes.modeButtons}
              >
                <BottomNavigationAction label={window.i18n.t("go_replay.view_history")} icon={<i  className="fa fa-arrow-circle-o-right" />} className={classes.modeButton1} style={{padding:'0px'}} />
                <BottomNavigationAction label={window.i18n.t("go_replay.test_put")} icon={<i  className="fa fa-edit" />} className={classes.modeButton} style={{padding:'0px'}} />
              </BottomNavigation>
            </MDBRow>  
            <MDBRow  className="m-0 pt-4">
              <GrController />
            </MDBRow>         
          </MDBCol>
        </MDBRow>
      </React.Fragment>
    </div>
  );
}

const mapStateToProps = (store) => {    
  var black_index = store.goReducer.game.colors[0] === 1 ? 0:1;
  var white_index = 1 -  black_index;   
  return({
    user: store.authReducer.user,
    game_id: store.goReducer.game._id,
    board_size: store.goReducer.game.board_size,
    kpmi: store.goReducer.game.kpmi,
    black_player: store.goReducer.game.players[black_index].user_id,
    black_avatar: store.goReducer.black_avatar,
    black_level: store.goReducer.game.players[black_index].level,
    black_xp: store.goReducer.game.black_xp,
    black_wins: store.goReducer.game.black_wins,
    black_loses: store.goReducer.game.black_loses,
    black_time: store.goReducer.game.total_time[black_index],
    white_player: store.goReducer.game.players[white_index].user_id,
    white_avatar: store.goReducer.white_avatar,
    white_level: store.goReducer.game.players[white_index].level,
    white_xp: store.goReducer.game.white_xp,
    white_wins: store.goReducer.game.white_wins,
    white_loses: store.goReducer.game.white_loses,
    white_time: store.goReducer.game.total_time[white_index],
    main_time: store.goReducer.game.main_time,
    finishing_time: store.goReducer.game.finishing_time,
    user: store.authReducer.user,
    colors: store.goReducer.game.colors,
    first_turn: store.goReducer.game.first_turn,
    move_history: store.goReducer.game.move_history,
    kpmi: store.goReducer.game.kpmi,
    result: store.goReducer.game.result,
    gr_index: store.goReducer.gr_index,
    reviews: store.commonReducer.reviews,
    preferred: store.goReducer.game.preferred,
    territory_view: store.goReducer.eval.view,
    putAble: store.goBoardReducer.putAble,
    view_option: store.goReducer.view_option,
    analyse_data: store.goReducer.eval,
    winrates_to_index: store.goReducer.eval.winrates.length,
    roomCoin: store.goReducer.game.coin,
    finished: store.goReducer.game.finished,
    tournament_id: store.tournamentReducer.tournament_id,
  })
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    add_review_to_game: CommonAction.add_review_to_game,
    update_gr_index: GoAction.update_gr_index,
    req_territory: GoAction.req_territory,
    req_winrates: GoAction.req_winrates,
    req_candidates: GoAction.req_candidates,
    prefer_game: GoAction.prefer_game,
    req_game: GoAction.req_game,
    switch_eval_view: GoAction.switch_eval_view,
    update_replay_mode: GoAction.update_replay_mode,
    change_view_option: GoAction.change_view_option,
    set_view_bw_mode: GoAction.set_view_bw_mode,
    init_move_history: GoAction.init_move_history
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Replay));
