import ACTION from '../actionTypes';
import CD from "../../helper/const";

export function setAllBots(bot_ids) {
  return {
    type: ACTION.SET_ALL_BOTS,
    bot_ids,
  }
}

export function updateBots(where, bots){
  return {
    type: ACTION.UPDATE_BOTS,
    where,
    bots,
  }
}

export function setSocketRoom(game_type, socketRoom){
  if (game_type == CD.GAME_TYPE.GO)
    return { type: ACTION.SET_ROOM_SOCKET, socketGoRoom: socketRoom};
  else if (game_type == CD.GAME_TYPE.PUZZLE)
    return { type: ACTION.SET_ROOM_SOCKET, socketPuzzleRoom: socketRoom};
  else if (game_type == CD.GAME_TYPE.PIECE_DESIGN)
    return { type: ACTION.SET_ROOM_SOCKET, socketPDesignRoom: socketRoom};
  else if (game_type == CD.GAME_TYPE.FFA)
    return { type: ACTION.SET_ROOM_SOCKET, socketFFARoom: socketRoom};
  else if (game_type == CD.GAME_TYPE.SKPNI)
    return { type: ACTION.SET_ROOM_SOCKET, socketSkpniRoom: socketRoom};
  else if (game_type == CD.GAME_TYPE.OMOK)
    return { type: ACTION.SET_ROOM_SOCKET, socketOmokRoom: socketRoom};
  return { type: ACTION.SET_ROOM_SOCKET, };
}

