import { combineReducers } from 'redux';
import { connectRouter } from 'connected-react-router';

import themeReducer from './theme.reducer';
import toastReducer from "./toast.reducer";
import authReducer from './auth.reducer';
import commonReducer from './common.reducer';
import roomReducer from './room.reducer';
import goReducer from './go.reducer';
import puzzleReducer from './puzzle.reducer';
import pdesignReducer from './pdesign.reducer';
import omokBoardReducer from './omok_board.reducer';
import omokReducer from './omok.reducer';
import ffaReducer from './ffa.reducer';
import skpniReducer  from './skpni.reducer';
import goBoardReducer from './go_board.reducer';
import goProblemReducer from './go_problem.reducer';
import goTeacherReducer from './go_teacher.reducer';
import goTrainReducer from './go_train.reducer';
import puzzleBoardReducer from './puzzle_board.reducer';
import puzzleProblemReducer from './puzzle_problem.reducer';
import pdesignBoardReducer from './pdesign_board.reducer';
import pdesignTaskReducer from './pdesign_task.reducer';
import problemBookReducer from './problem_book.reducer';
import profileReducer from './profile.reducer';
import articleReducer from './article.reducer';
import tournamentReducer from './tournament.reducer';
import messageReducer from './message.reducer';
import adminReducer from './admin.reducer';

export default (history) => combineReducers({
	router: connectRouter(history),
	themeReducer,
	toastReducer,
	authReducer,
	commonReducer,
	roomReducer,
	goReducer,
	puzzleReducer,
	pdesignReducer,
	omokBoardReducer,
	omokReducer,
	ffaReducer,
	skpniReducer,
	goBoardReducer,
	goProblemReducer,
	goTeacherReducer,
	goTrainReducer,
	puzzleBoardReducer,
	puzzleProblemReducer,
	pdesignBoardReducer,
	pdesignTaskReducer,
	problemBookReducer,
	profileReducer,
	articleReducer,
	tournamentReducer,
	messageReducer,
	adminReducer,
});
