import ACTION from '../actionTypes';
import * as GoLogic from '../../components/go/logic'

export const update_viewport_selection = (x0, y0, x1, y1, make_problem) => dispatch => {
  dispatch({ type: ACTION.UPDATE_VIEWPORT_SELECTION, x0, y0, x1, y1 });
  if(!!make_problem)
    dispatch({ type: ACTION.CHANGED_GO_PROBLEM});
}

export function remove_mark(mark_x, mark_y, lboard2) {
  return {
    type: ACTION.REMOVE_GO_MARK,
    mark_x,
    mark_y,
    lboard2
  }
}

export function add_mark(mark_x, mark_y, mark_type, lboard2, mark_text) {
  return {
    type: ACTION.ADD_GO_MARK,
    mark_x,
    mark_y,
    mark_type,
    mark_text: !mark_text? "" : mark_text,
    lboard2
  }
}

export function remove_all_marks(what) {
  return {
    type: ACTION.REMOVE_GO_ALL_MARKS,
    what
  }
}

export function show_hints(hint_x, hint_y) {
  return {
    type: ACTION.SHOW_GO_HINTS,
    hint_x,
    hint_y
  }
}

export function hide_hints() {
  return {
    type: ACTION.HIDE_GO_HINTS,
  }
}

export function update_edit_mode(mode) {
  return {
    type: ACTION.UPDATE_GO_EDIT_MODE,
    mode
  }
}

export function set_edit_stone(x, y, color) {
  GoLogic.theLogicBoard.set_edit_stone(x, y, color);
  return {
    type: ACTION.UPDATED_GO_BOARD,
  }
}

export function set_edit_stones(black_stones, white_stones) {
  return {
    type: ACTION.SET_EDIT_STONES,
    black_stones,
    white_stones,
  }
}

