export const isEmpty = value =>
  value === undefined ||
  value === null ||
  (typeof value === "object" && Object.keys(value).length === 0) ||
  (typeof value === "string" && value.trim().length === 0);
  
export const parseError = error => {
  let errorObj = error.response? error.response.data  : "Connection Error";
  errorObj = (typeof errorObj === "string")? {error: errorObj} : errorObj;
  return errorObj;
};

