import React, {useState, useEffect} from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import * as GoTeacherAction from "../../store/actions/go_teacher.action";
import moment from "moment";

import {
  BottomNavigation,
  BottomNavigationAction,
  Button,
  Grid,
  Select,
  MenuItem,
  MenuList,
} from '@material-ui/core';
import {
  MDBContainer,
  MDBRow,
  MDBCol,
} from "mdbreact";

const useStyles = makeStyles(theme => ({
  container: {
    display: 'inline',
    minHeight: '83vh',
    paddingTop: '2vh',
    paddingLeft: '0.5vw',
    paddingRight: '0.5vw',
  },
  requestStyle: {
    border: '1px solid rgb(204, 204, 204)',
    paddingLeft: '3vw',
  },
  requestRowStyle: {
    backgroundColor: "#bfdeec",
    marginBottom: '1px',
  },
  leftSide: {
    borderRight: '1px solid rgb(204, 204, 204)',
  },
  modeButton: {
    width: '11vw',
    height: '4vh',
    border:'1px solid rgb(204, 204, 204)',
    borderRight:'none',
  },
  modeButton_selected: {
    width: '11vw',
    height: '4vh',
    background: '#20d0e0',
    border:'1px solid rgb(204, 204, 204)',
    borderRight:'none',
  },
  awardButton: {
    background: '#c08080',
  }
}));

function Request(props) {
  const classes = useStyles();
  const [mode, setMode] = useState(0);
  const [msgInExpandArray, setMsgInExpandArray] = useState([]);
  const [msgSentExpandArray, setMsgSentExpandArray] = useState([]);

  useEffect(() => {
    if(!!user) {
      props.get_teacher_msg();
      var array1 = [];
      var array2 = [];
      props.teacher_in_msg.map(() => array1.push(false));
      props.teacher_sent_msg.map(() => array2.push(false));
      setMsgInExpandArray(array1);
      setMsgSentExpandArray(array2);
    }
  }, [props.teacher_in_msg.length, props.teacher_sent_msg.length]);

  const handleMode = (new_mode) => {
    setMode(new_mode);
  };

  const handleExpandMsg = (i) => {
    if(mode) {
      var array = [];
      msgSentExpandArray.map((m, j) => array.push((i===j)? !m : m));
      setMsgSentExpandArray(array);
    } else {
      var array = [];
      msgInExpandArray.map((m, j) => array.push((i===j)? !m : m));
      setMsgInExpandArray(array);
    }
  }

  const handleAward = (i) => {
    const {teacher_in_msg, award_to_request} = props;
    award_to_request(teacher_in_msg[i].user_id);
  }

  const { user, teacher_in_msg, teacher_sent_msg } = props;

  return (
    <MDBContainer className={classes.container}>
      <MDBRow>
        <MDBCol size="2" className={classes.leftSide}>
          <Button className={!mode ? classes.modeButton_selected : classes.modeButton} onClick={handleMode.bind(this, 0)}>{window.i18n.t("lecture.in")}</Button>
          <Button className={!mode ? classes.modeButton : classes.modeButton_selected} onClick={handleMode.bind(this, 1)}>{window.i18n.t("lecture.sent")}</Button>
        </MDBCol>
        <MDBCol>
        {
          mode === 0 && (
            <div>
            {
              teacher_in_msg.map((m, i) => {
                var time_diff = moment(new Date(m.awarded_time)).fromNow();
                return (
                  <div key={i}>
                    <Grid onClick={handleExpandMsg.bind(this, i)}>
                      <h5 className={classes.requestRowStyle+" font-weight-bold mt-0 py-3 px-3"}>
                        from {m.user_id}
                        <small className="float-right">
                          <span>{m.awarded? "Awarded " : ""}</span>
                          {
                            m.awarded && (
                              <span>
                                {time_diff}
                              </span>
                            )
                          }
                        </small>
                        {
                          !m.awarded && (
                            <Button className={"float-right " + classes.awardButton} onClick={handleAward.bind(this, i)}>Award</Button>
                          )
                        }
                      </h5>
                    </Grid>
                    {msgInExpandArray[i] && (
                      <MDBRow>
                        <MDBCol md="4" className="mb-md-0 px-2">
                          <h6 className="px-3 dark-grey-text float-left">
                            {m.message}
                          </h6>
                        </MDBCol>
                      </MDBRow>
                    )}
                  </div>
                )
              })
            }
            </div>
          )
        }
        {
          mode === 1 && (
            <div>
            {
              teacher_sent_msg.map((m, i) => {
                var time_diff = moment(new Date(m.awarded_time)).fromNow();
                return (
                  <React.Fragment>
                    <Grid onClick={handleExpandMsg.bind(this, i)}>
                      <h5 className={classes.requestRowStyle+" font-weight-bold mt-0 py-3 px-3"}>
                        to {m.user_id}
                        <small className="float-right">
                          <span>{m.awarded? "Awarded " : "Pending"}</span>
                          {
                            m.awarded && (
                              <span>
                                {time_diff}
                              </span>
                            )
                          }
                        </small>
                      </h5>
                    </Grid>
                    {
                      msgSentExpandArray[i] && (
                        <MDBRow>
                          <MDBCol md="4" className="mb-md-0 px-2">
                            <h6 className="px-3 dark-grey-text float-left">
                              {m.message}
                            </h6>
                          </MDBCol>
                        </MDBRow>
                      )
                    }
                  </React.Fragment>
                )
              })
            }
            </div>
          )
        }
        </MDBCol>  
      </MDBRow>
    </MDBContainer>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  teacher_in_msg: store.goTeacherReducer.teacher_in_msg,
  teacher_sent_msg: store.goTeacherReducer.teacher_sent_msg,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    get_teacher_msg: GoTeacherAction.get_teacher_msg,
    award_to_request: GoTeacherAction.award_to_request,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(Request);
