import axios from "axios";
import {push} from 'connected-react-router';

import ACTION from '../actionTypes';
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import CD from '../../helper/const';

export const req_tournament = (category, tournament_id) => async dispatch => {
    try {
        const result = await axios.post(config.apiUrl + '/tournament', {category, tournament_id});
        const {tournament} = result.data;
        var prize = [{}, {}, {}];
        var games = 0;
        tournament.participants.map((participant) => {
            if(participant.rank == 1)
                prize[0] = {user_id: participant.user_id, level: participant.level, avatar: participant.avatar};
            else if(participant.rank == 2)
                prize[1] = {user_id: participant.user_id, level: participant.level, avatar: participant.avatar};
            else if(participant.rank == 3)
                prize[2] = {user_id: participant.user_id, level: participant.level, avatar: participant.avatar};
            games += participant.round_game.length;
        });
        games = parseInt(games / 2);
        dispatch( { type: ACTION.UPDATE_GO_TOURNAMENT, tournament, games, prize});
    } catch (error) {
    }
}

