import axios from "axios";

import ACTION from '../actionTypes';
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import CD from '../../helper/const';
import * as GoLogic from '../../components/go/logic'
import {/*swal_s, swal_w,*/ notify_s, notify_w, /*notify_e*/} from "../../helper/alert";

export const submit_problem_book = (book_data) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/create_problem_book', { category: CD.PROBLEM_CATEGORY.GO });
    const {err, book_id} = result.data;
    if (err === ErrorCode.SUCCESS) {
      const result2 = await axios.post(config.apiUrl + '/submit_problem_book', { book_id, detail: book_data });
      if (result2.data.err === ErrorCode.SUCCESS) {
        dispatch({  type: ACTION.UPDATE_PROBLEM_BOOK, problem_book: {_id: book_id, title: book_data.title, type: book_data.type, difficulty: book_data.difficulty }});
      }
    }
  } catch (error) {
  }
}

export const remove_problem_book = (book_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/remove_problem_book', { book_id });
    const {err} = result.data;
    if (err === ErrorCode.SUCCESS) {
    }
  } catch (error) {
  }
}

export function update_problem_book(problem_book) {
  return {
    type: ACTION.UPDATE_PROBLEM_BOOK,
    problem_book
  }
}

export function init_problem_list() {
  return {
    type: ACTION.UPDATE_PROBLEM_LIST,
    problem_list: []
  }
}

