function PDesignReplay(props) {
  const classes = useStyles();
  const [room_coin, setRoomCoin] = useState(0);
  const [players, setPlayers] = useState([]);
  const [result, setResult] = useState([]);
  const [rewards, setRewards] = useState([]);
  const [finished, setFinished] = useState();
  const [countdown, setCountdown] = useState(0);
  const [open_dialog, setOpenDialog] = useState(false);
  const [move_histories, setMoveHistories] = useState([]);
  const [disable_vote, setDisableVote] = useState(true);

  useEffect(() => {
    const {user, req_game} = props;
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    req_game(!!user? user.user_id : '', CD.GAME_TYPE.PIECE_DESIGN, id);
  }, []);

  useEffect(() => {
    setRoomCoin(props.room_coin);
  }, [props.room_coin]);

  useEffect(() => {
    setCountdown(props.countdown);
  }, [props.countdown]);

  useEffect(() => {
    setPlayers(props.players);
  }, [props.players]);

  useEffect(() => {
    setFinished(new Date(props.finished).toLocaleString());
  }, [props.finished]);

  useEffect(() => {
    setResult(props.result);
    setTimeout(() => {
      updateResultLayer(props.result);
    }, 500);
  }, [props.result]);

  useEffect(() => {
    setMoveHistories(props.move_histories);
  }, [props.move_histories]);

  const board_array_init = () => {
    PieceBoard.initialize(Logic.MN_BOARD_SIZE);
    update_board();
  };

  const update_board = () => {
    props.update_board(PieceBoard.board, props.board_updated);
    PieceBoard.update_temp_boards();
  };

  const handleExit = () => {
    props.history.goBack();
  };

  const updateResultLayer = (result) => {
    var result_layer = document.getElementById('result_layer');
    if (props.players.length < 2) return;
    result_layer.innerHTML = null;
    result_layer.innerHTML = "Result: "
    // if (result == "drawn")
    //   result_layer.innerHTML += "Draw"
    // else if (result == "WL")
    //   result_layer.innerHTML += props.players[0].user_id + " " + "Win!";
    // else result_layer.innerHTML += props.players[1].user_id + " " + "Win!";
    result_layer.innerHTML += result;
    if (result == "un_estimated") setDisableVote(false);
  }

  const handleChangePlayer = (index) => {
    for (let i = 0; i < players.length; i ++) {
      var div = document.getElementById(`player_${i}`);
      div.style.opacity = '0.3';
    };
    document.getElementById(`player_${index}`).style.opacity = '1';
    board_array_init();
    PieceBoard.board = move_histories[index];
    update_board();
  }

  const handleDialogClose = () => {
    setOpenDialog(false);
  }

  const handleDialogOpen = () => {
    setOpenDialog(true);
  }

  const handlePlayerVote = (player_id ) => {
    setTimeout(() => {
      handleDialogClose();
    }, 500);
  }

  const VoteDialog = () => {
    return (
      <Dialog 
        onClose = {handleDialogClose}
        open = {open_dialog}
        maxWidth = {"sm"}
        fullWidth = {true}
      >
      <DialogTitle>
        <span className = {classes.text} style = {{fontSize: '4vh'}}>Select one player you want! </span>
      </DialogTitle>
      <div className = {classes.dialogStyle}>
        { !!players &&
          players.map((player, i) => {
            return (
              <Button
                onClick = {handlePlayerVote.bind(this, player.id)}
                className = "mx-4"
                style = {{boxShadow: '0px 0px 5px 5px rgba(60, 95, 225, 0.7)'}}
              >
                <Avatar alt="Profile Picture" className = {classes.avatar_style + " mr-2"} src={player.avatar}/> <span className = {classes.text}>{player.user_id}</span>
              </Button>
            )
          })
        }
      </div>
      </Dialog>
    )
  }
  
  return (
    <div>
      <div className={classes.container}/>
      <div  className={classes.board}>
        <PDesignBoard width="52" height="94" replay = {true}/>
      </div>
      <div className={classes.roomSetting}>
        <div className={classes.text_setting}>
          <img id = "coin_img" src = "assets/img/coin_i.png" className = {classes.imgStyle} /> {room_coin}
        </div>
        <div id = "time_counter" className={classes.timeText}>
          {"Finished: " + finished}
        </div>
        <div id = "Limit Time" className={classes.timeText}>
          {"Time: " + countdown / 60 + " min"}
        </div>
        <div id = "result_layer" className={classes.timeText}></div>
      </div>
      <div className = {classes.btn_box}>
        <div className = {classes.btn_vote}>
          <Button onClick = {handleDialogOpen} disabled = {disable_vote} style = {{backgroundColor: 'rgba(0, 0, 0, 0.3)', fontSize: '3vh', fontFamily: 'cursive', color: 'white', boxShadow: '0px 0px 2px 2px rgba(0, 230, 0, 0.7)', opacity: disable_vote ? '0.5' : '1'}}>
            <i className ="fa fa-thumbs-o-up mr-1" style = {{fontSize: '4vh'}}/> {window.i18n.t("forum.vote")}
          </Button>
        </div>
      </div>
      {/* <div className={classes.resultInfo}>
        <span className={classes.text}>
          {"some win! total times per players, game date"}
        </span>
      </div> */}
      
      {!!players &&
        players.map((player, i) => {
          return (
            <div className={classes.playerInfos} id = {`player_${i}`} style={{top: '' + (63 + 19 * i) + 'vh'}} onClick = {handleChangePlayer.bind(this, i)}>
              <Avatar alt="Profile Picture" className = {classes.avatarStyle} src={player.avatar}/>
              <div className={classes.info_text_panel} id = {`player_${i}`}>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1 pl-2">{player.user_id + ' (LV' + player.level + ')'}</MDBCol>
                </MDBRow>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1 pl-2"><i className={" fa fa-star"} style = {{color: 'orange'}}>{" "}{player.coin}</i></MDBCol>
                </MDBRow>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1" style = {{fontSize: '2.5vh'}}>{" " + ( parseInt(player.total_time / 60) > 0 ? ( parseInt(player.total_time / 60)  + "min" ) : "" ) + " " + player.total_time % 60 + "s"}</MDBCol>
                  <MDBCol style = {{fontSize: '2.5vh', color: 'rgb(50, 255, 50)'}}>
                    <i className ="fa fa-thumbs-o-up mr-1" style = {{fontSize: '2.5vh'}}/> {`20/${0}`}
                  </MDBCol>
                </MDBRow>
              </div>
            </div>
          )
        })
      }
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i class = "fa fa-home" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
      <div className={classes.boardOption}>
        <div className={classes.text}>
          <BoardOption/>
        </div>
      </div>
      <div className={classes.piece}>
        <div className={classes.text}>
          <PieceSelect/>
        </div>
      </div>
      <div className={classes.tool}>
        <div className={classes.text}>
          <ToolSelect/>
        </div>
      </div>
      <div className={classes.sample}>
        <div className={classes.text}>
          <PDesignProblem />
        </div>
      </div>
      <VoteDialog />
    </div>
  )
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  room_coin: store.roomReducer.room.coin,
  players: store.roomReducer.room.players,
  result: store.roomReducer.room.result,
  rewards: store.roomReducer.room.rewards,
  room_state: store.roomReducer.room.room_state,
  move_histories: store.pdesignReducer.room.move_histories,
  finished: store.roomReducer.room.finished,
  countdown: store.pdesignReducer.room.countdown,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    req_game: RoomAction.req_game,
    update_board: PDesignBoardAction.update_board,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(PDesignReplay);

