

import React , {useEffect, useState}from "react";
import styled from "styled-components";
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import {
  Button as MuiButton,
  InputLabel,
  MenuItem,
  Radio,
  RadioGroup,
  Select as MuiSelect,
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableRow,
  Chip,
  LinearProgress
} from "@material-ui/core";
import {  
    MDBRow,
    MDBCol,
    MDBBtn, 
} from "mdbreact";
import * as Icon from "@material-ui/icons";
import { spacing } from "@material-ui/system";
import { makeStyles } from '@material-ui/core/styles';
import * as CommonAction from "../../store/actions/common.action";
import * as ProfileAction from "../../store/actions/profile.action";
import * as AuthAction from "../../store/actions/auth.action";
import CD from "../../helper/const";

const Button = styled(MuiButton)(spacing);
// const FormControlSpacing = styled(MuiFormControl)(spacing);

// const FormControl = styled(FormControlSpacing)`
//   min-width: 148px!important;
// `;

var self;
const useStyles = makeStyles(theme => ({
  task_panel_style: {
    width:"80vw",
    height:'auto',
    borderTop: 'none',
    borderRadius: '20px',
    borderTopRightRadius: '0px',
    borderTopLeftRadius: '0px',
    marginRight:"auto",
    marginLeft: "auto",
  },
  index_style: {
    width:"80vw",
    marginRight:"auto",
    marginLeft: "auto",
    borderBottom: "1px dashed rgb(0, 180, 210)",
    fontFamily: 'cursive'
  },
  btn_select: {
    color: 'rgb(0, 0, 0)',
    textTransform: 'none',
    fontSize: '1.2rem'
  },
  btn_no_select: {
    backgroundColor: 'rgba(0, 0, 0, 0)',
    color: 'rgb(130, 130, 130)',
    textTransform: 'none'
  },
}
)
);
 function Task(props) { 
    const classes = useStyles();
    const [period, setPeriod] = useState(0);
    const [game_type, setGameType] = useState(window.i18n.t("gameType.go"));

    useEffect(()=>{     
      props.setFunc(CD.FUNC.FUNC_TASK);
      props.req_task_progress(props.gameType, period);
    }, []);
    
    const handleChangeTaskType = (key) => {
      setPeriod(key);
    }

    const handleClickAcceptBtn = (task_id) => {
      props.clickAcceptBtn(task_id);
    }

    useEffect(() => {
      if(props.gameType == CD.GAME_TYPE.GO) setGameType(window.i18n.t("gameType.go"))
      else if (props.gameType == CD.GAME_TYPE.FFA) setGameType(window.i18n.t("gameType.FFA"))
      else setGameType(window.i18n.t("gameType.star_kpni"))
      props.req_task_progress(props.gameType, period);
    }, [props.gameType, period])

    const {tasks, func} = props;

    return (
      <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
        <MDBRow className={classes.index_style + " text-left mt-4"}>
          <Button onClick = {handleChangeTaskType.bind(this, 0)} className = {period == 0 ? classes.btn_select : classes.btn_no_select}>
            <p className = "my-2">{window.i18n.t("task.everyday_task")}</p>
          </Button>
          <Button onClick = {handleChangeTaskType.bind(this, 1)} className = {period == 1 ? classes.btn_select : classes.btn_no_select}>
            <p className = "my-2">{window.i18n.t("task.total_task")}</p>
          </Button>
        </MDBRow>
        <MDBRow className = {classes.index_style}>
          <MDBCol className = {classes.task_panel_style + " py-2"}>
            <Table>
              <TableHead>
                <TableRow>
                  <TableCell></TableCell>
                  <TableCell></TableCell>
                  <TableCell></TableCell>
                  <TableCell></TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {func == CD.FUNC.FUNC_TASK && tasks.length > 0 &&
                  tasks.map((task, index)=>{
                    return(
                      <TableRow style = {{backgroundColor: task.proceeding == task.target ? 'rgba(0, 180, 210, 0.1)' : ''}}>
                        {task.proceeding == task.target &&
                          <TableCell style = {{padding: '10px'}}>
                            <Chip
                              icon={task.done ? <Icon.Done /> : null}
                              label={window.i18n.t(`task.task_type_${task.task_type}`).replace("{0}", task.target).replace("{gameType}", game_type)}
                              color="primary"
                              variant="outlined"
                              m={1}
                            /></TableCell>
                        }
                        {task.proceeding != task.target &&
                          <TableCell style = {{padding: '10px'}}>{window.i18n.t(`task.task_type_${task.task_type}`).replace("{0}", task.target).replace("{gameType}", game_type)}</TableCell>
                        }
                        <TableCell style = {{padding: '10px', width: '15vw'}}><LinearProgress color='primary' variant={"determinate"} value={task.proceeding * 100 / task.target}/>{task.proceeding + '/' + task.target }</TableCell>  
                        <TableCell style = {{padding: '10px'}}><Icon.Star style = {{marginRight:'0.2vw', color:'yellow'}}></Icon.Star>{task.reward}</TableCell>                 
                        <TableCell style = {{padding: '10px', textAlign: 'right'}}><MDBBtn className = "py-1 px-3" disabled = {task.proceeding != task.target ? true : task.done ? true : false} onClick = {handleClickAcceptBtn.bind(this, task.task_id)} >{window.i18n.t("menu.accept")}</MDBBtn></TableCell>
                      </TableRow>
                    )
                }) }
              </TableBody>
            </Table>
          </MDBCol>
        </MDBRow>
      </div>
    );
 
}


const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  tasks: store.commonReducer.items,
  gameType:store.commonReducer.content,
  open_other: store.commonReducer.content > 2,
  func: store.commonReducer.func,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    req_task_progress: CommonAction.req_task_progress,
    setFunc: CommonAction.setFunc,
    update_award_dlg: ProfileAction.update_award_dlg,
    clickAcceptBtn: AuthAction.clickAcceptBtn,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(Task);
