import ACTION from '../actionTypes';

const initialState = {
  edit_mode: 0,
  viewport: { x0: 0, y0: 0, x1: 18, y1: 18 },
  board_updated: false,
  black_stones: [],
  white_stones: [],
  marks: [],
  marks2: [],
  hints: [],
  putAble: false,
  board_size: 6,
  board: [],
};

export default function omokBoardReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_OMOK_EDIT_MODE:
      return {
        ...state,
        edit_mode: action.mode,
      };
    case ACTION.SET_VIEWPORT:
      return {
        ...state,
        viewport : action.viewport,
      };
    case ACTION.UPDATE_VIEWPORT_SELECTION:
      return {
        ...state,
        viewport : {
          x0: action.x0,
          y0: action.y0,
          x1: action.x1,
          y1: action.y1
        },
      };
    case ACTION.UPDATED_OMOK_BOARD:
      return {
        ...state,
        board_updated: !state.board_updated,
      };
    case ACTION.CLEAR_OMOK_BOARD:
      return {
        ...state,
        black_stones: [],
        white_stones: [],
        marks: [],
        board_update: !state.board_updated,
      };
    case ACTION.SET_EDIT_OMOK_STONES:
      return {
        ...state,
        black_stones: action.black_stones,
        white_stones: action.white_stones,
      };
    case ACTION.SET_OMOK_MARKS:
      return {
        ...state,
        marks: action.marks,
      }
    case ACTION.REMOVE_OMOK_MARK:
      return {
        ...state,
        marks: !!action.lboard2? state.marks : state.marks.filter((element) => (action.mark_x !== element.x || action.mark_y !== element.y) && element),
        marks2: !action.lboard2? state.marks2 : state.marks2.filter((element) => (action.mark_x !== element.x || action.mark_y !== element.y) && element),
      };
    case ACTION.ADD_OMOK_MARK:
      return {
        ...state,
        marks: !!action.lboard2 ? state.marks : state.marks.concat(
          {
            x: action.mark_x,
            y: action.mark_y,
            type: action.mark_type,
            text: action.mark_text
          }
        ),
        marks2: !action.lboard2 ? state.marks2 : state.marks2.concat(
          {
            x: action.mark_x,
            y: action.mark_y,
            type: action.mark_type,
            text: action.mark_text
          }
        ),
      };
    case ACTION.REMOVE_OMOK_ALL_MARKS:
      return {
        ...state,
        marks: action.what === 1? [] : state.marks,
        marks2: action.what === 2? [] : state.marks2,
      };
    case ACTION.SHOW_OMOK_HINTS:
      return {
        ...state,
        hints: [
          ...state.hints,
          {
            x: action.hint_x,
            y: action.hint_y,
          },
        ]
      };
    case ACTION.HIDE_OMOK_HINTS:
      return {
        ...state,
        hints: [],
      };
    case ACTION.SET_PUTABLE:
      return {
        ...state,
        putAble: action.putAble,
      };
    case ACTION.INIT_OMOK_BOARD:
      return {
        ...state,
        board: action.board,
        board_updated: !state.board_updated
      };
    case ACTION.UPDATE_BOARD_SIZE:
      return {
        ...state,
        board_size: action.board_size
      }
    default: return state;
  }
}
