import React from 'react';
import CD from "../../helper/const";
import { withRouter } from "react-router-dom";
import FFARoomBase from './FFARoomBase';
import { connect } from "react-redux";

function FFARoom(props) {    
  return (
    <div>
      {props.game_kind === 0 && <FFARoomBase action_method = {CD.ACTION_METHOD.PLAY_2}/>}
      {props.game_kind !== 0 && <FFARoomBase action_method = {CD.ACTION_METHOD.PLAY_4}/>}
    </div>  
  );
}

const mapStateToProps = (store) => {
  return {
    game_kind: store.ffaReducer.room.game_kind,
  }
};

export default connect(mapStateToProps)(withRouter(FFARoom));
