import {/*swal_s, swal_w,*/ notify_s, notify_w, /*notify_e*/} from "../../helper/alert";
import { on_load_problem } from "./puzzle_problem.action";

var notify_change_coin = (reason, d_coin) => {
  if (!!d_coin) {
    if (d_coin > 0)
      notify_s("coin " + d_coin + " by " + reason);
    else if (d_coin > 0)
      notify_w("coin " + d_coin + " by " + reason);
  }
};

export const load_room_info = (user_id, room_info, game_type) => async dispatch => {
  let players = room_info.players.slice();
  let users2_count = 0;
  room_info.users.map(user => {
    if(!user.user_id) users2_count += 1;
  });
  dispatch({
    type: ACTION.LOAD_ROOM_INFO,
    room_id: room_info.room_id,
    room_no: room_info.room_no,
    coin: room_info.coin,
    players,  
    users: room_info.users.filter((element) => (!!element.user_id) && element),  
    users2_count,
    join_time: room_info.join_time,
    prepared: room_info.prepared,
    room_state:room_info.room_state,
    desc: room_info.desc,
    turn: room_info.turn,
    move_history: room_info.move_history,
    result: room_info.result,
    rewards: room_info.rewards,
    setting: room_info.setting,
  });
  if(game_type == CD.GAME_TYPE.FFA)
    dispatch({
      type: ACTION.LOAD_FFA_ROOM_INFO,
      multipliers: room_info.multipliers,
    });
  if (game_type == CD.GAME_TYPE.PUZZLE) {
    dispatch({
      type: ACTION.LOAD_PUZZLE_ROOM_INFO,
      countdown: room_info.countdown,
      problem: !!room_info.problem ? room_info.problem : null
    });
  }
  if (game_type == CD.GAME_TYPE.PIECE_DESIGN) {
    if (!!room_info.task) {
      var task = room_info.task;
      dispatch({ type: ACTION.UPDATE_PDESIGN_TARGET, target: task.target });
      dispatch({ type: ACTION.UPDATE_BOARD_SIZE, size: task.board_size });
      dispatch({ type: ACTION.UPDATE_SHOW_GRID, isShow: task.show_grid });
      dispatch({ type: ACTION.UPDATE_BACKGROUND, back: task.background });
      dispatch({ type: ACTION.UPDATE_PIECE_KIND, kind: task.piece_kind }); 
    }
    dispatch({ type: ACTION.LOAD_PDESIGN_ROOM_INFO, countdown: room_info.countdown});
  }
}

export const req_game = (user_id, game_type, game_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/record', {user_id, game_type, game_id});
    const {err, game, reason, d_coin} = result.data;
    if(err === ErrorCode.SUCCESS) {
      dispatch({ type: ACTION.LOAD_RECORD, game, room_state: 0, });
      if (game_type == CD.GAME_TYPE.FFA)
        dispatch({ type: ACTION.LOAD_FFA_RECORD, game });
      if (game_type == CD.GAME_TYPE.PUZZLE){
        dispatch({type: ACTION.LOAD_PUZZLE_RECORD, game});
      }
      if(game_type == CD.GAME_TYPE.SKPNI) {
        if (!!game.first_turn){
          dispatch({type: ACTION.SET_SKPNI_FIRST_TURN, first_turn: game.first_turn});
        }
      }
      if (game_type == CD.GAME_TYPE.PIECE_DESIGN) {
        dispatch({type: ACTION.LOAD_PDESIGN_RECORD, game})
        var task = game.task;
        dispatch({ type: ACTION.UPDATE_PDESIGN_TARGET, target: task.target });
        dispatch({ type: ACTION.UPDATE_BOARD_SIZE, size: task.board_size });
        dispatch({ type: ACTION.UPDATE_SHOW_GRID, isShow: task.show_grid });
        dispatch({ type: ACTION.UPDATE_BACKGROUND, back: task.background });
        dispatch({ type: ACTION.UPDATE_PIECE_KIND, kind: task.piece_kind });
      }
      if (game_type == CD.GAME_TYPE.OMOK) {
        dispatch({ type: ACTION.UPDATE_BOARD_SIZE, board_size: game.board_size });
        dispatch ({type: ACTION.LOAD_OMOK_RECORD, game});
      }
      notify_change_coin(reason, d_coin);
      // dispatch(change_room_type('review_game_record'));
    } else {
      notify_w("####game is null");
    }
  } catch (error) {
  }
}

