export const enter_room = (room_id, game_type, is_player, socket_url) => dispatch => {
  let redirect_path = ['go_room', 'puzzle_room', 'pdesign_room', 'ffa_room', 'skpni_room', 'omok_room'];
  dispatch({
    type: ACTION.ENTER_ROOM,
    room_id,
    room_type: is_player? 'play' : 'spectate',
    socket_url
  });
  dispatch({type: ACTION.REDIRECT_TO, redirect_path: redirect_path[game_type], })
}

