import React, {useState, useEffect} from 'react';
import { connect } from "react-redux";
import { Redirect, withRouter } from "react-router-dom";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import styled from "styled-components";
import {
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControl as MuiFormControl,
  Grid,
  InputLabel,
  MenuItem,
  Select,
} from '@material-ui/core';
import {
  MDBRow,
  MDBCol,
  MDBBtn,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
} from "mdbreact";
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';
import CD from "../../helper/const";
import * as CommonAction from "../../store/actions/common.action";
import * as GoTeacherAction from "../../store/actions/go_teacher.action";

import { spacing } from "@material-ui/system";

const FormControlSpacing = styled(MuiFormControl)(spacing);
const FormControl = styled(FormControlSpacing)`
  min-width: 400px!important;
`;


const useStyles = makeStyles(theme => ({
  container: {
    display: 'inline',
    paddingLeft: '1vw',
    paddingRight: '1vw',
    paddingTop: '2vh',
    minHeight: '83vh',
  },
  itemStyle: {
    width: '20vw',
    height: '25vh'
  },
  pageNaveStyle: {
    border: '1px solid #dee2e6 !important',
  },
  avatarImg: {
    height: '5vh',
    width: '5vh',
    float: 'top',
    paddingBottom: '1vh',
  },
}));

function MessageToTeacher(props) {
  const [msg, setMsg] = useState("");

  const handleCancel = () => {
    props.onClose(null);
  };
  const handleOK = () => {
    props.onClose(msg);
  };
  const handleChangeMsg = event => {
    setMsg(event.target.value);
  };

  const {user_id, ...other} = props;
  return (
    <Dialog
      open={true}
      {...other}
    >
      <DialogTitle id="form-dialog-title">To {user_id}</DialogTitle>
      <DialogContent>
        <FormControl m={2}>
          <textarea rows="5" placeholder={msg} onChange={handleChangeMsg}/>
        </FormControl>
      </DialogContent>
      <DialogActions>
        <Button onClick={handleCancel} color="primary">
          Cancel
        </Button>
        <Button onClick={handleOK} color="primary">
          Send
        </Button>
      </DialogActions>
    </Dialog>
  );
}

function Teachers(props) {
  const classes = useStyles();
  const [page, setPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(20);
  const [find, setFind] = useState("");
  const [startPage, setStartPage] = useState(1);
  const [pages, setPages] = useState(1);
  const [openEditMsg, setOpenEditMsg] = useState(false);
  const [selectedTeacher, setSelectedTeacher] = useState("");

  useEffect(() => {
    getTeachersInfos(page, rowsPerPage, find);
  }, []);

  useEffect(() => {
    var allPage = Math.ceil(props.teacher_count / rowsPerPage);
    if (allPage === 0)
      allPage = 1;
    setPages(allPage);
  });

  const handleBecomeTeacher = () => {
    props.history.push("/teacher_pass");
  };

  const handleChangePage = (event, page) => {
    setPage(page);
    getTeachersInfos(page, rowsPerPage, find);
  };

  const handleChangeRowsPerPage = event => {
    setRowsPerPage(event.target.value);
    getTeachersInfos(page, event.target.value, find);
  };

  const handleChangeFind = event => {
    setFind(event.target.value);
    getTeachersInfos(page, rowsPerPage, event.target.value);
  };

  const getTeachersInfos = (page, rowsPerPage, find) => {
    props.req_teacher_list(props.content, find, rowsPerPage, page - 1);
  };

  const handleSelectTeacher = (user_id) => {
    setSelectedTeacher(user_id);
    handleOpenEditMsgDlg();
  };

  const handleCloseEditMsgDlg = (value) => {
    if (!!value) {
      setOpenEditMsg(false);
      const {user, send_msg_to_teacher} = props;
      if (!!user)
        send_msg_to_teacher(selectedTeacher, value);
    } else {
      setOpenEditMsg(false);
    }
  };

  const handleOpenEditMsgDlg = () => {
    setOpenEditMsg(true);
  }

  const { teacher_count, teacher_list } = props;

  var pageArray = [];
  var endPage = pages;
  if (endPage > startPage + 8)
    endPage = startPage + 8;
  for(var p = startPage; p <= endPage; p ++) {
    pageArray.push(p);
  }

  return (
    <React.Fragment>
      <div className={classes.container}>
        <MessageToTeacher open={openEditMsg} onClose={handleCloseEditMsgDlg} user_id={selectedTeacher}/>
        <MDBRow className="px-1 pt-3">
          <MDBCol md="4">
            <h5 className="dark-grey-text mb-0 pt-1 float-left px-3">{teacher_count} {window.i18n.t("lecture.teachers")}</h5>
            <MDBBtn color="cyan" className="float-right px-3 py-2 mx-3 my-0" onClick={handleBecomeTeacher}>
              {window.i18n.t("lecture.become_teacher")}
            </MDBBtn>
          </MDBCol>
          <MDBCol>
            <MDBBtn color="gray" className="float-right px-2 py-2 mx-3" style={{marginTop:'-0.5rem'}}>
              <i className="fa fa-comments-o" style={{ color: "gray", fontSize: "1.4rem"}} />
            </MDBBtn>
            <MDBPagination className="float-right">
              {
                pages > 10 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&laquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 1 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&lsaquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 1 && pageArray.map((p) => {
                  if (p === page)
                    return (
                      <MDBPageItem  className="pl-2" active>
                        <MDBPageNav className={classes.pageNaveStyle}>
                          {p} <span className="sr-only"></span>
                        </MDBPageNav>
                      </MDBPageItem>
                    );
                  else
                    return (
                      <MDBPageItem className={classes.pageNaveStyle}>
                        <MDBPageNav>{p}</MDBPageNav>
                      </MDBPageItem>
                    );
                })
              }
              {
                endPage < pages && (
                  <MDBPageItem className={classes.pageNaveStyle}>
                    <MDBPageNav>...</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 1 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&rsaquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 10 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&raquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
            </MDBPagination>
            <Select
              value={rowsPerPage}
              style={{ width: 100 }}
              className="float-right pr-4"
              onChange={handleChangeRowsPerPage}
            >
              <MenuItem value={10}>10</MenuItem>
              <MenuItem value={20}>20</MenuItem>
            </Select>
          </MDBCol>
        </MDBRow>
        <MDBRow className="px-5 mx-5 my-5 text-center">
          {
            props.func == CD.FUNC.FUNC_LECTURE && teacher_list.map((t, i) => {
              return (
                <Grid key={i} onClick={handleSelectTeacher.bind(this, t.user_id)}  className={classes.itemStyle}>
                  <MDBRow className="py-3">
                    <MDBCol className="pr-0">
                      <img alt="avatar" className={classes.avatarImg} src={t.avatar} />
                      <Rater total={5} rating={t.reviews > 0? t.total_rating / t.reviews: 0} interactive={false} style={{fontSize:'1rem', display:'block'}}/>
                      <h6 className="dark-grey-text mb-0"><small>{t.reviews} Reviews</small></h6>
                    </MDBCol>
                    <MDBCol className="text-left pl-0">
                      <h5 className="dark-grey-text mb-0 pt-1">{t.user_id}</h5>
                      <h6 className="dark-grey-text mb-3"><small>Lv{t.level}</small></h6>
                      <h6 className="dark-grey-text mb-0"><small>{t.students} Students</small></h6>
                    </MDBCol>
                  </MDBRow>
                </Grid>
              );
            })
          }
        </MDBRow>
        <MDBRow className="px-5 pt-5">
          <MDBPagination className="mx-auto">
          {
                pages > 10 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&laquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 1 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&lsaquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 1 && pageArray.map((p) => {
                  if (p === page)
                    return (
                      <MDBPageItem  className="pl-2" active>
                        <MDBPageNav className={classes.pageNaveStyle}>
                          {p} <span className="sr-only"></span>
                        </MDBPageNav>
                      </MDBPageItem>
                    );
                  else
                    return (
                      <MDBPageItem className={classes.pageNaveStyle}>
                        <MDBPageNav>{p}</MDBPageNav>
                      </MDBPageItem>
                    );
                })
              }
              {
                endPage < pages && (
                  <MDBPageItem className={classes.pageNaveStyle}>
                    <MDBPageNav>...</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 1 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&rsaquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
              {
                pages > 10 && (
                  <MDBPageItem className="pl-2">
                    <MDBPageNav className={classes.pageNaveStyle}>&raquo;</MDBPageNav>
                  </MDBPageItem>
                )
              }
          </MDBPagination>
        </MDBRow>
      </div>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  teacher_count: store.commonReducer.total,
  teacher_list: store.commonReducer.items,
  content: store.commonReducer.content,
  func: store.commonReducer.func,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    req_teacher_list: CommonAction.req_teacher_list,
    add_teacher: GoTeacherAction.add_teacher,
    send_msg_to_teacher: GoTeacherAction.send_msg_to_teacher,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Teachers));
