import React, {useState, useEffect} from 'react';
import { connect } from 'react-redux';

import {
  Button,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  FormControl,
} from '@material-ui/core';
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';

function ReviewAndRate(props) {
  const [msg, setMsg] = useState(!!props.review? props.review.text : "");
  const [rating, setRating] = useState(!!props.review? props.review.rating : 0);

  const handleCancel = () => {
    props.onClose(null);
  };
  const handleOK = () => {
    props.onClose({msg, rating});
  };
  const handleChangeMsg = event => {
    setMsg(event.target.value);
  };
  const handleChangeRating = event => {
    setRating(event.rating);
  }
  const {...other} = props;
  return (
    <Dialog
      open={true}
      {...other}
    >
      <DialogTitle id="form-dialog-title">{window.i18n.t("review.review_rate")}</DialogTitle>
      <DialogContent>
        <FormControl m={2}>
          <textarea rows="5" value={msg} onChange={handleChangeMsg}/>
        </FormControl>
        <Rater total={5} rating={rating} interactive={true} onRate={handleChangeRating} style={{fontSize:'1rem', display:'block'}}/>      
      </DialogContent>
      <DialogActions>
        <Button onClick={handleCancel} color="primary">
          {window.i18n.t("review.cancel")}
        </Button>
        <Button onClick={handleOK} color="primary">
          {!!props.review? window.i18n.t("review.re_rate") : window.i18n.t("review.rate")}
        </Button>
      </DialogActions>
    </Dialog>
  );
}

const mapStateToProps = (store) => ({
});

export default connect(mapStateToProps)(ReviewAndRate);

