import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = { 
  user_count: '', 
  isGameStart:false,
  mineNumber:2, //rp
  room: {
    player1_update_coin:0,  //rp
    player2_update_coin:0,  
    turn: 0,
  },
};

export default function skpniReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_GAME_START:
      return {
        ...state,
        isGameStart:true,            
      }
    case ACTION.UPDATE_SKPNI_GAME_RESULT:
      // state.room.users[0].coin += action.player1_update_coin;
      // state.room.users[1].coin += action.player2_update_coin;
      // state.room.players[0].coin += action.player1_update_coin;
      // state.room.players[1].coin += action.player2_update_coin;
      return state;
    case ACTION.SET_MINE_NUMBER:
      return {
        ...state,
        mineNumber:action.mineNumber,            
      }
    case ACTION.UPDATE_SKPNI_USER_COUNT:
      return {
        ...state,
        user_count:action.count,
      }
    case ACTION.SET_SKPNI_FIRST_TURN:
      return {
        ...state,
        turn: action.first_turn,
      }
    default: return state;
  }
}