var notify_change_coin = (reason, d_coin) => {
  if (!!d_coin) {
    if (d_coin > 0)
        notify_s(window.i18n.t(`message.increase_reason_${reason}`).replace('{0}', d_coin));
    else if (d_coin < 0)
      notify_w(window.i18n.t(`message.decrease_reason_${reason}`).replace('{0}', -d_coin));
  }
};

export const load_room_info = (user_id, room_info) => async dispatch => {
  GoLogic.theLogicBoard.initialize(room_info.rule, room_info.board_size, room_info.handicap, room_info.kpmi);

  let color = room_info.colors[room_info.first_turn] ;
  let move_history = room_info.move_history;
  for(let i = 0; i < move_history.length; i ++) {
    GoLogic.theLogicBoard.domove(move_history[i], color);
    color = GoLogic.BLACK + GoLogic.WHITE - color;
  } 
  let players = room_info.players.slice();

  if(players.length > 0)
    players[0].captures = GoLogic.theLogicBoard.gettakencount(room_info.colors[0]);
  if(players.length > 1)
    players[1].captures = GoLogic.theLogicBoard.gettakencount(room_info.colors[1]);

  let users2_count = 0;
  room_info.users.map(user => {
    if(!user.user_id) users2_count += 1;
  });
  dispatch({
    type: ACTION.LOAD_ROOM_INFO,
    room_id: room_info.room_id,
    room_no: room_info.room_no,
    coin: room_info.coin,
    players,  
    users: room_info.users.filter((element) => (!!element.user_id) && element),  
    users2_count,
    join_time: room_info.join_time,
    prepared: room_info.prepared,
    room_state:room_info.room_state,
    desc: room_info.desc,
    turn: room_info.turn,
    move_history: room_info.move_history,
    result: room_info.result,
    rewards: room_info.rewards,
  });
  dispatch({
    type: ACTION.LOAD_GO_ROOM_INFO,
    game_type: room_info.game_type,
    setting: room_info.setting,
    board_size: room_info.board_size,
    handicap: room_info.handicap,
    kpmi: room_info.kpmi,
    rule: room_info.rule,
    main_time: room_info.main_time,
    countdown: room_info.countdown,
    countdown_num: room_info.countdown_num,
    first_turn: room_info.first_turn,
    betting: room_info.betting,
    colors: room_info.colors,
  });
  dispatch({type: ACTION.SET_PUTABLE, 
    putAble: (room_info.state === CD.ROOM_STATE.PLAYING && players[room_info.turn].user_id === user_id), 
  });
  dispatch({type: ACTION.INIT_GO_EVAL, });
}

export const req_game = (user_id, game_type, game_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/record', {user_id, game_type, game_id});
    const {err, game, reason, d_coin} = result.data;
    if(err === ErrorCode.SUCCESS) {
      dispatch(load_record(game));
      notify_change_coin(reason, d_coin);
      // dispatch(change_room_type('review_game_record'));
    } else {
      notify_w("####game is null");
    }
  } catch (error) {
  }
}

export const load_record = (game, ) => dispatch => {
  GoLogic.theLogicBoard.initialize(game.rule, game.board_size, game.handicap, game.kpmi); 
  var color = game.colors[game.first_turn];
  var black_index;
  if(game.colors[0] === 1)
    black_index = 0;
  else 
    black_index = 1;
  for (var i = 0; i < game.move_history.length; i ++) {
    GoLogic.theLogicBoard.domove(game.move_history[i], color);
    color = GoLogic.BLACK + GoLogic.WHITE - color;
  }
  var gr_index = game.move_history.length;

  var black_time = { main: game.main_time, finishing_count: game.finishing_count, finishing_time: game.finishing_time};
  var white_time = { main: game.main_time, finishing_count: game.finishing_count, finishing_time: game.finishing_time};
  var black_player = game.players[black_index];
  var white_player = game.players[1 - black_index];  
  dispatch({
    type: ACTION.LOAD_GO_RECORD,
    game,
    gr_index,
    black_player,
    white_player,
    black_avatar: game.players[black_index].avatar,
    white_avatar: game.players[1 - black_index].avatar,
    black_time,
    white_time
  });
  dispatch({type: ACTION.UPDATE_REVIEWS, reviews: game.review_detail, });
  dispatch({type: ACTION.CHANGE_ROOM_TYPE, room_type: 'replay'});
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
  dispatch({type: ACTION.INIT_GO_EVAL, });
  dispatch({type: ACTION.SET_GO_MARKS, marks: []});
}

export const prefer_game = (user_id, game_id, add) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/prefer_record', {user_id, game_id, add});
    const {err, preferred} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch( { type: ACTION.UPDATE_GAME_PREFERRED, preferred });
      if(add)
        notify_s('This game added to your preferred records!');
      else
        notify_s('This game removed from your preferred records!');
    }
  } catch (error) {
  }
}

export const req_territory = (board_size, kpmi, board_str) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/go_record_territory', {size: board_size, kpmi, board: board_str});
    const {err, boardsize, board, reason, d_coin} = result.data;
    if (err === ErrorCode.SUCCESS || err === ErrorCode.ERROR_USE_AI_COUNT_OVER) {
      dispatch(update_eval_territory(boardsize, 0, 0, board));
      if (err === ErrorCode.ERROR_USE_AI_COUNT_OVER)
        notify_change_coin(reason, d_coin);
    } else {
    }
  } catch (error) {
  }
}

