export const req_candidates = (game_id, cindex) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/go_record_candidates', {game_id, cindex});
    const {err, cpos, cscore, pass_score, winrate, reason, d_coin} = result.data;
    if (err === ErrorCode.SUCCESS || err === ErrorCode.ERROR_USE_AI_COUNT_OVER) {
      dispatch({
        type: ACTION.REMOVE_GO_ALL_MARKS,
        what: 1
      });
      for (var i = 0; i < cpos.length; i ++) {
        var x = GoLogic.XPOS(cpos[i]);
        var y = GoLogic.YPOS(cpos[i]);
        dispatch({
          type: ACTION.ADD_GO_MARK,
          mark_x: x,
          mark_y: y,
          mark_type: 3,
          mark_text: '' + cscore[i],
          lboard2: false
        });
      }
      dispatch({type: ACTION.UPDATE_GO_EVAL, cpos, cscore, pass_score, winrate});
      dispatch({type: ACTION.UPDATED_GO_BOARD, });
      if (err === ErrorCode.ERROR_USE_AI_COUNT_OVER)
        notify_change_coin(reason, d_coin);
    } else {
    }
  } catch (error) {
  }
}

export const submitTransaction = (user_id, amount, description) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/purchase', {user_id, transaction: {amount, description}});
    const {err, reason, d_coin} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch({type: ACTION.DO_TRANSACTION, transaction: {amount, description}});
      notify_change_coin(reason, d_coin);
    }
  } catch (error) {
  }
}

export const do_move = (move, turn, players, color, putAble) => async dispatch => {
  GoLogic.theLogicBoard.domove(move, color);
  players[turn].captures = GoLogic.theLogicBoard.gettakencount(color);
  var next_turn = 1 - turn;
  dispatch({type: ACTION.DO_MOVE, move, next_turn, players});
  dispatch({type: ACTION.SET_PUTABLE, putAble});
  dispatch({type: ACTION.INIT_GO_EVAL, })
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
}

export const update_room_state = (room_state) => async dispatch => {
  dispatch({type: ACTION.UPDATE_ROOM_STATE, room_state,});
  dispatch({type: ACTION.SET_PUTABLE, putAble: room_state == CD.ROOM_STATE.PLAYING, });
}

export const update_gr_index = (gr_index, players, colors) => async dispatch => {
  GoLogic.theLogicBoard.goto_idx(gr_index);
  var black_captures = GoLogic.theLogicBoard.gettakencount(GoLogic.BLACK);
  var white_captures = GoLogic.theLogicBoard.gettakencount(GoLogic.WHITE);
  if (!!players && players.length > 1) {
    if (colors[0] === GoLogic.BLACK) {
      players[0].captures = black_captures;
      players[1].captures = white_captures;
    } else {
      players[1].captures = black_captures;
      players[0].captures = white_captures;
    }
    dispatch({type: ACTION.UPDATE_PLAYERS, players});
  }
  dispatch({
    type: ACTION.UPDATE_GO_RECORD_INDEX,
    gr_index,
    black_captures,
    white_captures,
  });
  dispatch({type: ACTION.INIT_GO_EVAL, });
  dispatch({type: ACTION.SET_GO_MARKS, marks: []});
}

export const update_eval_territory = (boardsize, bsum, wsum, tboard) => dispatch => {
  var bt_one = [];
  var wt_one = [];
  var bt_half = [];
  var wt_half = [];
  var x, y, i, pos;
  for (y = 0; y < boardsize; y ++) {
    for (x = 0; x < boardsize; x ++) {
      pos = GoLogic.WPOS(x, y);
      i = y * boardsize + x; 
      if (tboard[i] === 'B')
        bt_one.push(pos);
      else if (tboard[i] === 'W')
        wt_one.push(pos);
      else if (tboard[i] === 'b')
        bt_half.push(pos);
      else if (tboard[i] === 'w')
        wt_half.push(pos);
    }
  }
  var view = true;
  dispatch({ type: ACTION.UPDATE_GO_EVAL, view, bsum, wsum, bt_one, wt_one, bt_half, wt_half, });
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
}

