import React, {useState, useEffect, useRef} from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import CD, { GAME_TYPE } from "../../helper/const";
import {
  MDBContainer,
  MDBDataTable,
  MDBRow,
  MDBCol,
  MDBBtn,
} from "mdbreact";
import { Redirect, withRouter } from 'react-router-dom';
import styled from "styled-components";
import {
  Button,
  Link,
  FormControl as MuiFormControl,
  InputLabel,
  MenuItem,
  Select as MuiSelect,
} from '@material-ui/core';

import { DatePicker, DateTimePicker } from '@material-ui/pickers';
import * as TournamentAction from "../../store/actions/tournament.action";
import * as GoAction from "../../store/actions/go.action";
import PROTOCOL from "../../helper/protocol";
import { spacing } from "@material-ui/system";

const Select = styled(MuiSelect)(spacing);
const FormControlSpacing = styled(MuiFormControl)(spacing);
const FormControl = styled(FormControlSpacing)`
  min-width: 128px!important;
`;

function CurrentTournament(props) {
  const [value, set] = useState(true);
  const [prize, setPrize] = useState("");
  const forceUpdate = () => {
    set(!value);
  };
  const socketLobby_ref = useRef();
  useEffect(() => {
    socketLobby_ref.current = props.socketLobby;   
  }, [props.socketLobby]);
  useEffect(() => {
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    props.req_tournament(props.game_type, id);
  }, [props.user]);
  
  useEffect(() => {
    const {tournament} = props;
    setPrize(tournament.prize_amount.coin[0] + ", " + tournament.prize_amount.coin[1] + ", " + tournament.prize_amount.coin[2]);
    reloadGoTournamentData(props.tournament);
  });

  function handleExit(){
    props.history.push("/tournaments")
  }

  var columns = [];
  var rows = [];
  
  const reloadGoTournamentData = (tournament) => {
    columns.push({ label: "No", field: "no", sort: "disabled", width: 50 });
    columns.push({ label: "Participant", field: "participant", sort: "disabled", width: 200 });
    for (var i = 0; i < tournament.schedule.round_start.length; i ++) {
      columns.push({ label: i + 1, field: "rnd_" + (i + 1), sort: "disabled", width: 70 });
    }
    columns.push({ label: "Wins", field: "wins", sort: "disabled", width: 60 });
    columns.push({ label: "SDS", field: "sds", sort: "disabled", width: 60 });
    columns.push({ label: "SUO", field: "suo", sort: "disabled", width: 60 });
    columns.push({ label: "Rank", field: "rank", sort: "disabled", width: 60 });

    tournament.participants.map((p, i) => {
      var row = {};
      row.no = i + 1;
      row.participant = p.user_id + " (" + " Lv" + p.level + ")";
      p.round_game.map((g, j) => {
        var gr;
        if(g.win == 1)  //win
          gr = "+";
        else if(g.win == 2) //lose
          gr = "-";
        else              //no finished
          gr = "";
        
        if (g.color == 1)   //black
          gr += "B";
        else if (g.color == 2)  //white
          gr += "W";
        
        if (g.opponent_num > 0)
          gr += g.opponent_num;
        else
          gr += "+";
        row["rnd_"+(j+1)] = <Link onClick={() => handleOpenGame(g.game_id)}>{gr}</Link>;
      });
      for(var j = tournament.cur_round + 1; j <= tournament.schedule.round_start.length; j ++)
        row["rnd_"+j] = "";
      row.wins = p.wins;
      row.sds = p.sds;
      row.suo = p.suo;
      row.rank = p.rank;
      rows.push(row);
    });
  }
  
  const handleOpenGame = (game_id) => {
    const {history} = props;
    history.push('/go_record:'+game_id);
  }

  const handleTournamentChange = event => {
    const {tournament, game_type} = props;
    tournament[event.target.name] = event.target.value;
    props.update_tournament_setting(tournament, game_type);
  };

  const handleChange = event => {
    const { tournament, game_type } = props;
    if (event.target.name === 'prize') {      
      setPrize(event.target.value);
    } else {
      tournament.setting[event.target.name] = event.target.value;
    }
    props.update_tournament_setting(tournament, game_type);
    forceUpdate();
  };

  const handleAddRound = () => {
    props.tournament.schedule.round_start.push(new Date());
    forceUpdate();
  };

  const handleRemoveRound = () => {
    props.tournament.schedule.round_start.pop();
    forceUpdate();
  };

  const handleSubmit = () => {
    const { user, game_type, tournament } = props;
    tournament.prize_amount.coin = prize.split(", ");
    socketLobby_ref.current.emit('admin_message', PROTOCOL.CSC_SUBMIT_TOURNAMENT, {token:user.token, category:game_type, tournament});
  };

  const handleJoin = () => {
    const { user, tournament, joinTournament } = props;
    if(!!user)
      joinTournament(tournament._id);
  };

  const handleDecidePairs = () => {
    const { user, game_type, tournament } = props;
    socketLobby_ref.current.emit('admin_message', PROTOCOL.CS_DECIDE_TOURNAMENT_ROUND_PAIRS, {token:user.token, category: game_type, tournament_id: tournament._id});
  };

  const handleCreateRooms = () => {
    const { user, game_type, tournament } = props;
    socketLobby_ref.current.emit('admin_message', PROTOCOL.CS_CREATE_TOURNAMENT_ROUND_ROOMS, {token:user.token, category: game_type, tournament_id: tournament._id});
  };

  const handleStartGames = () => {
    const { user, tournament } = props;
    socketLobby_ref.current.emit('admin_message', PROTOCOL.CS_TOURNAMENT_ROUND_GAME_START, {token:user.token, tournament_id: tournament._id});
  };

  const { user, tournament } = props;

  return (
    <MDBContainer>
      <div  style={{backgroundColor: "#f9f9fc", position:"fixed", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "96%", height: "100%", overflow: 'scrollY', padding: "2vw", paddingLeft: '5vw'}}>
      {
        !!user && user.role === 'admin' && (
          <React.Fragment>
            <MDBRow className="px-4 pt-2 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5 className="font-weight-bold dark-grey-text pb-3">Title</h5>
              </MDBCol>
              <MDBCol size="7">
                <input name="title" className="form-control" style={{border:'none', borderBottom:'1px solid rgb(204, 204, 204)',padding:'0px'}} 
                  placeholder={tournament.title} onChange={handleTournamentChange}/>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
              </MDBCol>
              <MDBCol className = "float-right">
                <Button style = {{boxShadow: "none", backgroundColor: "rbga(0, 0, 0, 0)"}} onClick = {handleExit}>
                  <i class = "fa fa-reply" style = {{fontSize: '2rem'}}/>
                </Button>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-2 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5 className="font-weight-bold dark-grey-text pb-3">Information</h5>
              </MDBCol>
              <MDBCol size="7">
                <input name="information" className="form-control" style={{border:'none', borderBottom:'1px solid rgb(204, 204, 204)',padding:'0px'}} 
                  placeholder={tournament.information} onChange={handleTournamentChange}/>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-2 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5 className="font-weight-bold dark-grey-text pb-3">Date</h5>
              </MDBCol>
              <MDBCol size="2">
                <DatePicker value={tournament.start_date} format="MM-dd-yyyy" onChange={v => {tournament.start_date = v; forceUpdate();}}/>
              </MDBCol>
              <h5 className="font-weight-bold dark-grey-text pb-3">~</h5>
              <MDBCol>
                <DatePicker value={tournament.end_date} format="MM-dd-yyyy" onChange={v => {tournament.end_date = v; forceUpdate();}}/>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-2 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5 className="font-weight-bold dark-grey-text pb-3">Schedule</h5>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <h6 className="font-weight-bold dark-grey-text pb-3">Accept to</h6>
              </MDBCol>
              <MDBCol>
                <DateTimePicker value={tournament.schedule.accept_to} format="hh:mm a, MM-dd" onChange={v => {tournament.schedule.accept_to = v; forceUpdate();}}/>
              </MDBCol>
            </MDBRow>
            {
              tournament.schedule.round_start.map((r, i) => {
                return (
                  <MDBRow>
                    <MDBCol size="1" className="pt-2">
                    </MDBCol>
                    <MDBCol size="2" className="pt-2">
                      <h6 className="font-weight-bold dark-grey-text pb-3">Round{i+1}</h6>
                    </MDBCol>
                    <MDBCol size="2">
                      <DateTimePicker value={tournament.schedule.round_start[i]} format="hh:mm a, MM-dd" onChange={v => {tournament.schedule.round_start[i] = v; forceUpdate();}}/>
                    </MDBCol>
                  </MDBRow>
                );
              })
            }
            <MDBRow className="py-4">
              <MDBCol size="1" className="pt-2">
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <MDBBtn color="blue" className="float-left px-3 py-2" disabled={false} onClick = {handleAddRound}>
                  add round
                </MDBBtn>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <MDBBtn color="blue" className="float-left px-3 py-2" disabled={false} onClick = {handleRemoveRound}>
                  remove round
                </MDBBtn>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-2 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5 className="font-weight-bold dark-grey-text pb-3">Setting</h5>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <FormControl m={2}>
                  <InputLabel htmlFor="coin-simple">{CD.COMMON_SETTING.coin.name}</InputLabel>
                  <Select
                    value={tournament.setting.coin}
                    onChange={handleChange}
                    inputProps={{
                      name: "coin",
                      id: "coin-simple"
                    }}
                  >
                    {CD.COMMON_SETTING.coin.items.map((item, index) =>
                      (<MenuItem key = {item} value={index}>{item}</MenuItem>))}
                  </Select>
                </FormControl>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <FormControl m={2}>
                  <InputLabel htmlFor="time-simple">{CD.COMMON_SETTING.time.name}</InputLabel>
                  <Select
                    value={tournament.setting.time}
                    onChange={handleChange}
                    inputProps={{
                      name: "time",
                      id: "time-simple"
                    }}
                  >
                    {CD.COMMON_SETTING.time.items.map((item, index) =>
                      (<MenuItem key = {item} value={index}>{item}</MenuItem>))}
                  </Select>
                </FormControl>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <FormControl m={2}>
                  <InputLabel htmlFor="board_size-simple">{CD.GO_SETTING.board_size.name}</InputLabel>
                  <Select
                    value={tournament.setting.board_size}
                    onChange={handleChange}
                    inputProps={{
                      name: "board_size",
                      id: "board_size-simple"
                    }}
                  >
                    {CD.GO_SETTING.board_size.items.map((item, index) =>
                      (<MenuItem key = {item} value={index}>{item}</MenuItem>))}
                  </Select>
                </FormControl>
              </MDBCol>
              <MDBCol size="2" className="pt-2">
                <FormControl m={2}>
                  <InputLabel htmlFor="handicap-simple">{CD.GO_SETTING.handicap.name}</InputLabel>
                  <Select
                    value={tournament.setting.handicap}
                    onChange={handleChange}
                    inputProps={{
                      name: "handicap",
                      id: "handicap-simple"
                    }}
                  >
                    {CD.GO_SETTING.handicap.items.map((item, index) =>
                      (<MenuItem key = {item} value={index}>{item}</MenuItem>))}
                  </Select>
                </FormControl>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-4 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5 className="font-weight-bold dark-grey-text pb-3">{window.i18n.t("tournament.prize")}</h5>
              </MDBCol>
              <MDBCol size="5">
                <textarea name="prize" className="form-control" rows="1" value={prize} onChange={handleChange}/>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-4 pb-4">
              <MDBBtn color="green" className="float-left px-5 py-2" disabled={false} onClick = {handleSubmit}>
                submit
              </MDBBtn>
            </MDBRow>
          </React.Fragment>
        )
      }
      {
        (!user || user.role !== 'admin') && (
          <React.Fragment>
            <MDBRow>
              <MDBCol size = "10">
                <h4 className="font-weight-bold dark-grey-text mt-4 pb-3">{ tournament.title }</h4>
                <h5 className="font-weight-bold dark-grey-text pb-3">{window.i18n.t("tournament.information")}</h5>
                <h6 className="dark-grey-text pt-1 pb-3">{ tournament.information }</h6>
                <h5 className="font-weight-bold dark-grey-text pb-3">
                {window.i18n.t("tournament.date")} {new Date(tournament.start_date).toLocaleDateString()} - {new Date(tournament.end_date).toLocaleDateString()}
                </h5>
                <h6 className="font-weight-bold dark-grey-text pb-3">{window.i18n.t("tournament.schedule")}</h6>
                <h6 className="dark-grey-text pb-3">Accept to {new Date(tournament.schedule.accept_to).toLocaleTimeString('en-US', { hour12: true, hour: "numeric", minute: "numeric"}) + ", "}
                {new Date(tournament.schedule.accept_to).toLocaleDateString('en-US', { month: "numeric", day: "numeric"})}</h6>
                {
                  tournament.schedule.round_start.map((r, i) => {
                    return (
                      <h6 className="dark-grey-text pb-2">Round{i+1} {new Date(tournament.schedule.round_start[i]).toLocaleTimeString('en-US', { hour12: true, hour: "numeric", minute: "numeric"}) + ", "}
                          {new Date(tournament.schedule.round_start[i]).toLocaleDateString('en-US', { month: "numeric", day: "numeric"})} ~
                      </h6>
                    );
                  })
                }
                <h5 className="font-weight-bold dark-grey-text pb-3">{window.i18n.t("tournament.option")}</h5>
                <h6 className="dark-grey-text pt-1 pb-3">{ CD.COMMON_SETTING.coin.items[tournament.setting.coin]}, {CD.COMMON_SETTING.time.items[tournament.setting.time]}, {CD.GO_SETTING.board_size.items[tournament.setting.board_size]} 
                    , {CD.GO_SETTING.handicap.items[tournament.setting.handicap]}</h6>
                <h5 className="font-weight-bold dark-grey-text pb-3">Prize</h5>
                <h6 className="dark-grey-text pt-1 pb-3">{window.i18n.t("tournament.coin")} {"+" + tournament.prize_amount.coin[0] }, {"+" + tournament.prize_amount.coin[1] }, {"+" + tournament.prize_amount.coin[2] } </h6>
              </MDBCol>
              <MDBCol className = "float-right">
                <Button style = {{boxShadow: "none", backgroundColor: "rbga(0, 0, 0, 0)"}} onClick = {handleExit}>
                  <i class = "fa fa-reply" style = {{fontSize: '2rem'}}/>
                </Button>
              </MDBCol>
            </MDBRow>
          </React.Fragment>
        )
      }
      <MDBRow className="py-4">
        <MDBCol size="1" className="pt-2">
          <h5 className="font-weight-bold dark-grey-text pb-2">{window.i18n.t("tournament.participant")}</h5>
        </MDBCol>
        <MDBCol size="10" className="pt-2">
          {
            tournament.participants.map((p, i) => {
              return (
                <h6 className="dark-grey-text pt-1 pb-2">{ (i + 1) + ". " + p.user_id + " (Lv" + p.level + ")" }</h6>
              );
            })
          }
          {
            tournament.cur_round === 0 && (
              <MDBBtn color="cyan" className="float-left px-5 py-2" disabled={false} onClick = {handleJoin}>
                {window.i18n.t("tournament.join")}
              </MDBBtn>
            )
          }
          {
            tournament.cur_round > 0 && (
              <React.Fragment>
                <h5 className="font-weight-bold dark-grey-text pb-3">Games</h5>
                <MDBDataTable hover bordered autoWidth theadColor="cyan lighten-3" searching={false} paging={false} small={false} scrollX scrollY maxHeight="70vh" data={{columns: columns, rows: rows}} />
              </React.Fragment>
            )
          }
        </MDBCol>
      </MDBRow>
      {
        !!user && user.role === 'admin' && (
          <MDBRow className="py-4">
            <MDBCol size="3" className="pt-2">
              <MDBBtn color="green" className="float-left px-5 py-2" disabled={false} onClick = {handleDecidePairs}>
                decide round pairs
              </MDBBtn>
            </MDBCol>
            <MDBCol size="3" className="pt-2">
              <MDBBtn color="green" className="float-left px-5 py-2" disabled={false} onClick = {handleCreateRooms}>
                create rooms for the round games
              </MDBBtn>
            </MDBCol>
            <MDBCol size="3" className="pt-2">
              <MDBBtn color="green" className="float-left px-5 py-2" disabled={false} onClick = {handleStartGames}>
                start round games
              </MDBBtn>
            </MDBCol>
          </MDBRow>
        )
      }
      <br></br>
      </div>
    </MDBContainer>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  tournament: store.tournamentReducer.go_tournament,
  socketLobby: store.commonReducer.socketLobby,
  game_type: store.commonReducer.content,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    req_tournament: TournamentAction.req_tournament,
    joinTournament: TournamentAction.joinTournament,
    update_tournament_setting: TournamentAction.update_tournament_setting,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(CurrentTournament));
