import React, {Component} from "react";
import { Route, withRouter } from 'react-router-dom';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import * as CommonAction from '../store/actions/common.action';
import CD from '../helper/const';
class BaseRoute extends Component {
  
  render() {
    const {exact, path, component, redirect_path, redirect_to, room_id, history} = this.props;   
    if (redirect_path === 'lobby') {
      redirect_to('');
      history.push('/lobby');
    }
    else if (redirect_path === 'go_room') {
      redirect_to('');
      history.push('/go_room:' + room_id);
    }
    else if (redirect_path === 'puzzle_room') {
      redirect_to('');
      history.push('/puzzle_room:' + room_id);
    }
    else if (redirect_path === 'pdesign_room') {
      redirect_to('');
      history.push('/pdesign_room:' + room_id);
    }
    else if (redirect_path === 'ffa_room') {
      redirect_to('');
      history.push('/ffa_room:' + room_id);
    }
    else if (redirect_path === 'skpni_room') {
      redirect_to('');    
      history.push('/skpni_room:' + room_id);      
    }
    else if (redirect_path === 'omok_room') {
      redirect_to('');    
      history.push('/omok_room:' + room_id);      
    }
    
    return (
      <Route exact={exact} path={path} component={component} />
    );
  }
}

function mapStateToProps(store) {
  return {
    redirect_path: store.commonReducer.redirect_path,
    room_id: store.roomReducer.room.room_id, 
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      redirect_to: CommonAction.redirect_to,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(BaseRoute));
