import React from "react";
import { BrowserRouter as Router, Switch } from 'react-router-dom';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { MuiPickersUtilsProvider } from "@material-ui/pickers";
import DateFnsUtils from "@date-io/date-fns";
import BaseRoute from "./components/BaseRoute";
import Modal from "./components/Modal/Modal";
import Baseheader from './components/layout/Baseheader';
import Landing from './components/layout/Landing';
import Register from './components/auth/Register';
import Login from './components/auth/Login';
import Footer from './components/layout/Footer';
import Lobby from './components/game/Lobby';
import Room from './components/game/Room';
import Replay from './components/replay/Replay';
import Records from './components/replay/Records';
import Tournaments from './components/tournament/Tournaments';
import Tournament_past from './components/tournament/Tournament_past';
import Tournament_current from './components/tournament/Tournament_current';
import Forum_compose from './components/forum/Forum_compose';
import Forum from './components/forum/Forum';
import Forum_view from './components/forum/Forum_view';
import Rank from './components/rank/Rank';
import Teachers from './components/lecture/Teachers';
import LectureRooms from './components/lecture/LectureRooms';
import LectureRoom from './components/lecture/LectureRoom';
import Request from './components/lecture/Request';
import TeacherPass from './components/lecture/TeacherPass';
import Training from './components/training/Training';
import Solve from './components/training/Solve';
import Make from './components/training/Make';
import Take from './components/training/Take';
import Capture from './components/training/Capture';
import Opening from './components/training/Opening';
import SolvePuzzle from './components/puzzle/solvePuzzle';
import PuzzleRoom from './components/puzzle/puzzleRoom';
import PuzzleReplay from './components/puzzle/puzzleReplay';
import TryPDesign from './components/pdesign/tryPDesign';
import PDesignRoom from './components/pdesign/pdesignRoom';
import PDesignReplay from './components/pdesign/pdesignReplay';
import OmokRoom from './components/omok/omokRoom';
import OmokReplay from './components/omok/omokReplay';
import TryOmok from './components/omok/omokTrain';
import Profile from './components/profile/Profile';
import Messagebox from './components/message/Messagebox';
import Admin from './components/admin/Admin';
import Side from "./components/layout/Side";
import FFARoom from './components/ffa/FFARoom';
import FFAReplay from './components/ffa/FFAReplay';
import Lecture from './components/lecture/Lecture';
import ForumRoom from './components/forum/ForumRoom';
import SettingDlg from "./components/setting/SettingDlg"
import "bootstrap-css-only/css/bootstrap.min.css";
import "mdbreact/dist/css/mdb.css";
import './App.css';
import SKoniRoom from "./components/skpni/SKoniRoom";
import SKoniReplay from "./components/skpni/SKoniReplay";
import Task from "./components/task/Task";
import RewardDlg from "./components/Reward/RewardDlg";
import HelpExpansionPanel from "./components/help/Help"
import TimeClock from "./components/TimeClock/TimeClock"
import OtherGameBtn from "./components/layout/OtherGameBtn"

function  App(props) { 
  return (
    <Router>
      <MuiPickersUtilsProvider  utils={DateFnsUtils}>         
        <div className="App" >
          {props.side_option.isSideBarShow &&( <Side/>)}
          <Baseheader/>   
          {props.open_other &&
            <OtherGameBtn />
          }
          <div id="route" style = {{marginLeft:props.side_option.left , height:'85vh', overflow:"auto", overflowX: 'hidden'}}>           
          <Switch>
              <BaseRoute exact path="/lobby" component={ Lobby } />
              <BaseRoute exact path="/records" component={ Records } /> 
              <BaseRoute exact path="/tournaments" component={ Tournaments } />            
              <BaseRoute exact path="/lecture" component={ Lecture } />
              <BaseRoute path="/task" component={Task}/>
              <BaseRoute path = "/time_clock" component = {TimeClock}/>
              <BaseRoute exact path="/rank" component={ Rank } />
              <BaseRoute exact path="/profile" component={ Profile } />
          
              <BaseRoute exact path="/forum_compose" component={ Forum_compose } />
              <BaseRoute exact path="/forum" component={ Forum } />
              <BaseRoute exact path="/forumroom" component={ ForumRoom } />
              <BaseRoute path="/article:id" component={ Forum_view } />
              
              <BaseRoute exact path="/" component={ Landing } /> 
              <BaseRoute exact path="/training" component={ Training } />
              <BaseRoute exact path="/take" component={ Take } />
              <BaseRoute exact path="/capture" component={ Capture } />
              <BaseRoute exact path="/opening" component={ Opening } />
              
              <BaseRoute exact path="/teachers" component={ Teachers } />
              <BaseRoute exact path="/lecture_rooms" component={ LectureRooms } />
              <BaseRoute exact path="/request" component={ Request } />
              <BaseRoute exact path="/teacher_pass" component={ TeacherPass } />
              <BaseRoute exact path="/rules" component={ Landing } />
              <BaseRoute exact path="/terms_and_policy" component={ Landing } />
              <BaseRoute exact path="/contact_us" component={ Landing } />
              <BaseRoute exact path="/register" component={ Register } />
              <BaseRoute exact path="/login" component={ Login } />
              <BaseRoute exact path="/messagebox" component={ Messagebox } />
              <BaseRoute exact path="/admin" component={ Admin } />
              <BaseRoute exact path="/make_problem" component={ Make } />
              <BaseRoute path="/go_room:id" component={ Room } />
              <BaseRoute path="/go_record:id" component={ Replay } />
              <BaseRoute path="/tournament_past:id" component={ Tournament_past }/>
              <BaseRoute path="/tournament_current:id" component={ Tournament_current } />
              <BaseRoute path="/solve_problem:id" component={ Solve } />
              <BaseRoute path="/make_problem:id" component={ Make } />
              <BaseRoute path="/lecture_room:id" component={ LectureRoom }/>
              <BaseRoute path="/solve_puzzle_problem:id" component={ SolvePuzzle } />
              <BaseRoute path="/puzzle_room:id" component={PuzzleRoom} />
              <BaseRoute path="/puzzle_record:id" component={PuzzleReplay}/>                
              <BaseRoute path="/try_pdesign:id" component={ TryPDesign } />
              <BaseRoute path="/pdesign_room:id" component={PDesignRoom} />
              <BaseRoute path="/pdesign_record:id" component={PDesignReplay}/>
              <BaseRoute path="/omok_room:id" component={OmokRoom} />
              <BaseRoute path="/try_omok:id" component={TryOmok} />                
              <BaseRoute path="/omok_record:id" component={OmokReplay} />
              <BaseRoute path="/ffa_room:id" component={FFARoom} />
              <BaseRoute path="/ffa_record:id" component={FFAReplay}/>                
              <BaseRoute path="/skpni_room:id" component={SKoniRoom}/>
              <BaseRoute path="/skpni_record:id" component={SKoniReplay}/>

              <BaseRoute path="/setting" component={SettingDlg}/>  
              
              <BaseRoute path = "/help" component = {HelpExpansionPanel}/>   
              <BaseRoute path = "/reward" component = {RewardDlg}/>
              
          </Switch>
          </div>
          <Footer />
          <Modal />   
        </div>                 
      </MuiPickersUtilsProvider>
    </Router>
  )
}

const mapStateToProps = (store) => ({
  side_option: store.commonReducer.side_show,
  open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(App);
