

import React, {useState, useEffect} from "react";
import styled from "styled-components";
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import '../skpni/star.css';
import {
  Button as MuiButton,
  Dialog,
  DialogActions,
  DialogContent,
  DialogTitle,
  Divider as MuiDivider,
  FormControl as MuiFormControl,
  FormControlLabel,
  FormLabel,
  InputLabel,
  MenuItem,
  Radio,
  RadioGroup,
  Select as MuiSelect,
} from "@material-ui/core";

import { spacing } from "@material-ui/system";
import { makeStyles } from '@material-ui/core/styles';
import * as ProfileAction from "../../store/actions/profile.action";
const Button = styled(MuiButton)(spacing);
const Divider = styled(MuiDivider)(spacing);
const Select = styled(MuiSelect)(spacing);

const FormControlSpacing = styled(MuiFormControl)(spacing);

const FormControl = styled(FormControlSpacing)`
  min-width: 148px!important;
`;

var self;
const useStyles = makeStyles(theme => ({  
  createStyle: {
    color: '#fff',
    backgroundColor: 'rgba(0, 206, 209, 1)',
    width:"14.6vw",
    height:"10vw",
    marginLeft:"1.4vw",
    marginTop:"0.5vw",
    fontSize:'1.8vw',
  },
  btn: {   
    border: '1px solid black',   
    marginLeft:'0.2vw',
    width:'10vw',
    height:'4vh',  
    zIndex:'1200'
  },
  img: {     
    marginLeft:'0.5vw',
    width:'10vw',
    height:'12vw',  
    zIndex:'1200'
  },
}
)
);
function RewardDlg(props) {
  const [kindAward, setKind] = useState(1);
  const handleOne = () => {
    props.update_award_dlg();
    
  };
  const handleOK = () => {
    props.history.push('/');
  };
  const handleCancel = () => {
   props.history.push('/');
  };
  const initBnt = ()=>{
    let btnId =['every', 'continue', 'birth'];
    var coinBtnColors = ['rgba(0,0, 0, 0)', 'rgba(0,0, 0, 0)', 'rgba(0,0, 0, 0)'];       
    btnId.map((id, index)=>{
      document.getElementById(id).style.backgroundColor = coinBtnColors[index];
      document.getElementById(id).style.color = 'black';
    });

  };
  const handleBnt = (event)=>{  
    switch(event.target.id) {
      case 'every':        
        initBnt();
        document.getElementById('every').style.backgroundColor = '#39ac73';
        document.getElementById('every').style.color = 'white';
        setKind(1);
        break;
      case 'continue':         
        initBnt();
        document.getElementById('continue').style.backgroundColor = '#39ac73';
        document.getElementById('continue').style.color = 'white';    
        setKind(2);    
        break;
      case 'birth':   
        initBnt();
        document.getElementById('birth').style.backgroundColor = '#39ac73';
        document.getElementById('birth').style.color = 'white';   
        setKind(3);
        break;       
      default:
        break;
    }      
  };
  let disabled = false; 
  const { ...other } = props;
  const classes = useStyles();   
    return (
      <div style = {{zIndex:'1200'}}>
        <div id = 'background' style = {{position:'fixed', top:'0px', left:'0px',width:'100vw', height:"100vh", backgroundColor:'black', opacity:"0.7",zIndex:'1200'}} >
        </div>
        <img src="/assets/img/settingBackground.gif" style = {{position:'fixed', width:'45vw', height:"24vw",left:'27.5vw', top:"25vh", zIndex:'1200'}}></img>         
        <div id = 'dialogContent' style = {{position:'fixed', top:'25vh', left:'34vw',  width:'40vw', height:'24vw',zIndex:'1200'}}>       
          <h5 id="form-dialog-title" style = {{marginTop:'3vh', fontSize:'3vh', fontWeight:'bold'}}>Award</h5>                
          <div style = {{paddingLeft:'1.5vw',position:'fixed',top:'35vh', left:'30.5vw' }}> 
            <button  id = 'every'   className = {classes.btn} onClick={handleBnt} style = {{backgroundColor:'#39ac73', color:'white'}} >
              Every Award
            </button>       
            <button  id='continue' className = {classes.btn} style = {{backgroundColor:'rgba(0,0, 0, 0)'}} onClick={handleBnt}>
              Continue Award               
            </button>  
            <button  id='birth' className = {classes.btn} style = {{backgroundColor:'rgba(0,0, 0, 0)'}} onClick={handleBnt}>
              Birthday Award
            </button>                 
          </div>
          {kindAward === 1 && 
          <div style = {{paddingLeft:'1.5vw',position:'fixed',top:'42vh', left:'30.5vw' }}>              
            <img  id = 'award1' src = "/assets/img/award.gif"  className = 'display' />
            <img  id = 'award1' src = "/assets/img/award.gif"   className = 'display1'  />
            <img  id = 'award1' src = "/assets/img/award.gif"   className = 'display2'  />                     
          </div>  }
          {kindAward === 2 && 
          <div style = {{paddingLeft:'1.5vw',position:'fixed',top:'42vh', left:'30.5vw' }}>              
            <img  id = 'award1' src = "/assets/img/award.gif"  className = 'display' />
            <img  id = 'award1' src = "/assets/img/award.gif"   className = 'display1'  />
            <img  id = 'award1' src = "/assets/img/award.gif"   className = 'display2'  />                     
          </div>  }
          {kindAward === 3 && 
          <div style = {{paddingLeft:'1.5vw',position:'fixed',top:'42vh', left:'30.5vw' }}>              
            <img  id = 'award1' src = "/assets/img/award.gif"  className = 'display'/>
            <img  id = 'award1' src = "/assets/img/award.gif"   className = 'display1'/>
            <img  id = 'award1' src = "/assets/img/award.gif"   className = 'display2'/>                     
          </div>  }
          <DialogActions style = {{position:'fixed',top:'65vh', marginLeft:'26vw'}}>
            <Button  id= 'cancel' onClick={handleCancel} color="secondary">
              <i style = {{fontSize:'2vw'}} className={ " fa fa-close"}/>
            </Button>
            <Button onClick={handleOK} color="primary" disabled = {disabled}>
              <i style = {{fontSize:'2vw' }} className={ " fa fa-check"}/>
            </Button>
          </DialogActions>
        </div>
      </div>
    );
 
}
const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    update_award_dlg: ProfileAction.update_award_dlg,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(RewardDlg);
