import React, { useState, useEffect } from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { withRouter } from "react-router-dom";

import { makeStyles } from '@material-ui/core/styles';
import {
  BottomNavigation,
  BottomNavigationAction,
  Button,
  Select,
  MenuItem,
} from '@material-ui/core';

import {
  MDBBtn,
  MDBRow,
  MDBCol,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
} from "mdbreact";

import * as GoBoardAction from "../../store/actions/go_board.action";
import * as GoProblemAction from "../../store/actions/go_problem.action";
import * as ProblemBookAction from "../../store/actions/problem_book.action";
import Board from "../go/board";
import CD from "../../helper/const";

const useStyles = makeStyles(theme => ({
  boardStyle: {
    width: '100%',
  },
  pageNaveStyle: {
    padding: 0,
    paddingBottom: 0,
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2.5rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    marginTop: '6px',
    marginLeft: '3px',
    marginRight: '3px',
    textAlign: 'center',
    width: '140px',
    WebkitAppearance: 'button !important',
    fontSize: '1.5rem !important',
  },
  root: {
    width: '17vw',
  },
  BottomNavigationActionStyle1: {
    minWidth:'60px',
    width:'60px',
    padding:'0px',
    height:'80px',
    border:'1px solid rgb(25, 118, 208)',
    borderRadius: '5px 0px 0px 5px',
  },
  BottomNavigationActionStyle2: {
    minWidth:'60px',
    width:'60px',
    padding:'0px',
    height:'80px',
    border:'1px solid rgb(25, 118, 208)',
    borderLeft:'none',
  },
  BottomNavigationActionStyle3: {
    minWidth:'60px',
    width:'60px',
    padding:'0px',
    height:'80px',
    border:'1px solid rgb(25, 118, 208)',
    borderLeft:'none',
    borderRadius: '0px 5px 5px 0px',
  },
  navigationButtons: {
    paddingTop: '5vh',
    width: '88%',
    height: '8vh',
    fontSize: '2.5vh',
  },
  navigationButtons1: {
    paddingTop: '2.5vh',
    width: '88%',
    height: '6vh',
    fontSize: '2.5vh',
  },
  navigationButton1: {
    width:'20%',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    color: "#404040",
  },
  navigationButton: {
    width:'20%',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    borderLeft: 'none',
    color: "#404040",
  },
}));

var EBoardMode = {
  Move: 0,
  CountScores: 1,
  ScoreEstimate: 2,
  AddOrRemove: 3,
  AddMarkTr: 4,
  AddMarkSq: 5,
  AddMarkCr: 6,
  AddMarkX: 7,
  AddMarkTx: 8,
  AddMarkNum: 9,
  ViewPort: 10,
};

var EDrawingMark = {
  Lm: -1,
  Tr: 0, 
  Sq: 1, 
  Cr: 2, 
  Tx: 3, 
  X: 4,
  Tb: 5, 
  Tw: 6, 
  Tb2: 7,
  Tw2: 8 
};

function GoMakeProblem(props) {
  const classes = useStyles();
  const [problem_book_type, setBookType] = useState('Life and Death');
  const [problem_difficulty, setProblemDifficulty] = useState('Easy');
  const [problem_first_color, setProblemFirstColor] = useState(1);
  useEffect(() => {
    const {req_problem_list, submit_problem_book, init_problem_list} = props;
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    if (id.indexOf('make_problem') == -1)
      req_problem_list(id, 'make_problem');
    else {
      submit_problem_book({_id: '', type: 'Life and death', title: '', difficulty: 'Middle'});
      init_problem_list();
    }
    return ()=>{ 
      props.exit_problem();
    };
  }, []);

  const [mode, setMode] = useState(0);
  const [answer_index, setAnswerIndex] = useState(0);
  const [prob_index, setProbIndex] = useState(0);

  const handleProblemBookChange = event => {
    const { problem_book, update_problem_book } = props;
    setBookType(event.target.value);
    problem_book[event.target.name] = event.target.value;
    update_problem_book(problem_book);
  };
  
  const handleProblemBookTypeChange = event => {
    const { problem_book, update_problem_book } = props;
    setProblemDifficulty(event.target.value);
    problem_book[event.target.name] = event.target.value;
    update_problem_book(problem_book);
  };
  
  const handleProblemBookTitleChange = event => {
    const { problem_book, update_problem_book } = props;
    problem_book[event.target.name] = event.target.value;
    update_problem_book(problem_book);
  };

  const handleProblemChange = event => {
    const { problem, update_problem } = props;
    problem[event.target.name] = event.target.value;
    update_problem(problem);
  };

  const handleProblemColorChange = event => {
    const { problem, update_problem } = props;
    setProblemFirstColor(event.target.value);
    problem[event.target.name] = event.target.value;
    update_problem(problem);
  };
  
  const handleProblemNavigation = (index) => {
    const { problem_list, req_problem } = props;
    if (index >= problem_list.length)
      index = problem_list.length - 1;
    if (index <= 0)
      index = 0;
    setProbIndex(index);
    if (problem_list.length > 0)
      req_problem(problem_list[index], index, false, true);
  };

  const handleToFirst = () => {
    const { update_problem_answer_history_index } = props;
    update_problem_answer_history_index(0);
  }

  const handleToBack = () => {
    const { problem, update_problem_answer_history_index } = props;
    update_problem_answer_history_index(problem.h_index - 1);
  }
 
  const handleToNext = () => {
    const { problem, update_problem_answer_history_index } = props;
    update_problem_answer_history_index(problem.h_index + 1);
  }

  const handleToLast = () => {
    const { problem, update_problem_answer_history_index } = props;
    update_problem_answer_history_index(problem.history_length);
  }

  const handleEditModeChange = (mode) => {
    setMode(mode);
    var edit_mode;
    switch(mode) {
      case 0:
        edit_mode = EBoardMode.ViewPort;
        break;
      case 1:
        edit_mode = EBoardMode.AddOrRemove;
        break;
      case 2:
        edit_mode = EBoardMode.AddMarkTr;
        break;
      case 3:
        edit_mode = EBoardMode.AddMarkTx;
        break;
      case 4:
        edit_mode = EBoardMode.Move;
        break;
      default:
        break;
    }
    props.update_edit_mode(edit_mode);
  };

  const clearBoard = () => {
    props.clear_problem_board();
  };

  const handleNewProblem = () => {
    clearBoard();
    setProbIndex(props.problem_list.length);
  };

  const handleRemoveProblem = () => {
    const { problem_index, problem_list, problem_book, remove_problem } = props;
    if (prob_index < problem_list.length)
      remove_problem(problem_list[prob_index], problem_book._id, problem_index);
    else
      handleProblemNavigation(problem_index);
  };

  const handleSubmitProblem = () => {
    const { user, marks, black_stones, white_stones, problem, problem_book, submit_problem, viewport, problem_list } = props;
    var _marks = [];
    marks.map((mark) => _marks.push({mark_x: mark.x, mark_y: mark.y, mark_type: mark.type, mark_text: mark.text}));

    submit_problem(prob_index, { _id: problem_book._id, title: problem_book.title, type: problem_book.type, difficulty: problem_book.difficulty }, 
      { _id: problem_list[prob_index], description: problem.description, viewport, first_color: problem.first_color, 
      black_stones, white_stones, marks: _marks, answer: problem.answer });
  };

  const handleUpdateProblemBook = (id) => {
    const { problem_book, submit_problem_book } = props;
    submit_problem_book({_id: problem_book._id, title: problem_book.title, type: problem_book.type, difficulty: problem_book.difficulty});
  };

  const handleRemoveProblemBook = (id) => {
    const {remove_problem_book, history} = props;
    remove_problem_book(id);
    history.push('/training');
  };

  const handleAddAnswer = () => {
    props.add_answer_on_problem();
  };

  const handleRemoveAnswer = () => {
    const {problem, remove_answer_on_problem} = props;
    var answer_index = problem.answer_index + 1;
    if (answer_index >= problem.answer.length)
      answer_index -= 2;
    remove_answer_on_problem(problem.answer_index, problem.answer.length, problem.answer[answer_index]);
  };

  const handleSelectAnswer = event => {
    const {problem, select_answer_on_problem} = props;
    problem.answer_index = event.target.value;
    select_answer_on_problem(problem.answer_index, problem.answer[problem.answer_index]);
  };

  const { problem, problem_book, problem_list, problem_index } = props;  

  const handleExit = () => {
    props.history.push('/training')
  }

  var p_index = problem_index + 1; 
  if (p_index > problem_list.length)
    p_index = problem_list.length;

  return (
    <React.Fragment>
      <div style={{backgroundColor: "#f9f9fc", position:"fixed", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "100vw", height: "100vh", overflow: 'scrollY', padding: "2vw"}}>
        <MDBRow className="m-0 mb-4">
          <MDBCol size="5">
            <h5 className="float-left pr-5">{window.i18n.t("train.editing_problem_book")} &rsaquo; {problem_book.type} &rsaquo; {problem_book.title}</h5>
          </MDBCol>
          <MDBCol size="5">
            <h6 className="float-left pt-1">{window.i18n.t("train.authored_by")} {problem_book.created_by}</h6>
            <h6 className="float-left pt-1 pl-5">{window.i18n.t("train.last_updated")}: {new Date(problem_book.updated).toLocaleDateString()} </h6>
          </MDBCol>
          <MDBCol className='pr-5 mr-3'>
            <Button style = {{boxShadow: "none", backgroundColor: "rbga(0, 0, 0, 0)"}} className = "float-right" onClick = {handleExit}>
              <i class = "fa fa-reply" style = {{fontSize: '2rem'}}/>
            </Button>
          </MDBCol>
        </MDBRow>
        <MDBRow className="m-0">
          <MDBCol md="3">
            <MDBRow className="px-4 py-2 mb-2">
              <MDBCol size="2" className="pt-1">
                <h6>{window.i18n.t("train.type")}</h6>
              </MDBCol>
              <MDBCol>
                <Select
                  value={problem_book_type}
                  name="type"
                  style={{ width: 180 }}
                  className="pr-4"
                  onChange={handleProblemBookChange}
                >
                  {CD.PROBLEM_BOOK.TYPE.items.map((item) => (
                    <MenuItem key={item} value={item}>
                      {item}
                    </MenuItem>
                  ))}
                </Select>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 pt-2 pb-2 mb-2">
              <MDBCol size="2" className="pt-2">
                <h6>{window.i18n.t("train.title")}</h6>
              </MDBCol>
              <MDBCol>
                <input name="title" className="form-control" style={{border:'none', borderBottom:'1px solid rgb(204, 204, 204)',padding:'0px'}} 
                placeholder={window.i18n.t("train.title")} onChange={handleProblemBookTitleChange}/>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 py-2 mb-2">
              <MDBCol size="2" className="pt-1">
                <h6>{window.i18n.t("train.difficulty")}</h6>
              </MDBCol>
              <MDBCol>
                <Select
                  name="difficulty"
                  value={problem_difficulty}
                  style={{ width: 180 }}
                  className="pr-4"
                  onChange={handleProblemBookTypeChange}
                >
                  {CD.PROBLEM_BOOK.DIFFICULTY.items.map((item) => (
                    <MenuItem key={item} value={item}>
                      {item}
                    </MenuItem>
                  ))}
                </Select>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 py-3 my-2">
              <MDBCol>
                <MDBBtn style = {{whiteSpace: 'nowrap'}} color="blue" className="px-2 py-2 my-0" onClick={handleUpdateProblemBook.bind(this, problem_book._id)}>
                  <i className="fa fa-cloud-upload fa-lg mr-2" style={{ color: "white"}} />
                  {window.i18n.t("train.update_book")}
                </MDBBtn>
                <MDBBtn style = {{whiteSpace: 'nowrap'}} color="blue" className="px-2 py-2 my-0" disabled = {problem_book._id === ''} onClick={handleRemoveProblemBook.bind(this, problem_book._id)}>
                  <i className="fa fa-trash fa-lg mr-2" style={{ color: "white"}} />
                  {window.i18n.t("train.remove_book")}
                </MDBBtn>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 py-3">
              <MDBCol className="pl-5 pt-1">
                <MDBPagination>
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, 0)}>&laquo;</MDBPageNav>
                  </MDBPageItem>
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_index - 1)}>&lsaquo;</MDBPageNav>
                  </MDBPageItem>
                    <input
                      type="text"
                      value={"" + p_index + "/" + problem_list.length}
                      readOnly={true}
                      className={classes.pagenationInputStyle}
                    />
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_index + 1)}>&rsaquo;</MDBPageNav>
                  </MDBPageItem>
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_list.length - 1)}>&raquo;</MDBPageNav>
                  </MDBPageItem>
                </MDBPagination>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4 py-1">
              <MDBCol>
                <MDBBtn color="blue" className="px-2 py-2 my-0" disabled = {problem_list.length <= 0} style={{marginLeft:'1px'}} onClick={handleRemoveProblem}>
                  <i className="fa fa-minus mr-1" style={{ color: "white"}} />
                  {window.i18n.t("train.remove_problem")}
                </MDBBtn>
              </MDBCol>
            </MDBRow>
          </MDBCol>
          <MDBCol md="5" className="py-0" style = {{marginLeft: '-2vw'}}>
            <Board boardId = {0} readOnly = {false} putAble = {true} width='52' height='80'/>
          </MDBCol>
          <MDBCol className = "ml-2">
            <MDBRow className="pt-3">
              <MDBCol size="3" className="pt-1">
                <h5><strong>{window.i18n.t("train.problem")} {prob_index + 1}</strong></h5>
              </MDBCol>
              <MDBCol>
                <MDBBtn style = {{whiteSpace: 'nowrap'}} color="blue" className="px-3 py-2 my-0" onClick={handleNewProblem}>
                  <i className="fa fa-plus mr-1" style={{ color: "white"}} />
                  {window.i18n.t("train.new")}
                </MDBBtn>
                <MDBBtn  style = {{whiteSpace: 'nowrap'}} color="blue" className="px-3 py-2 my-0" disabled = {!problem.varied} onClick={handleSubmitProblem}>
                  <i className="fa fa-cloud-upload fa-lg mr-2" style={{ color: "white"}} />
                  {window.i18n.t("train.submit")}
                </MDBBtn>
              </MDBCol>
            </MDBRow>
            <MDBRow className="pt-3">
              <MDBCol size="3" className="pt-1">
                <h6 style = {{whiteSpace: 'nowrap'}}>{window.i18n.t("train.first_color")}</h6>
              </MDBCol>
              <MDBCol>
                <Select
                  name="first_color"
                  value={problem_first_color}
                  style={{ width: 170 }}
                  className="pr-4"
                  onChange={handleProblemColorChange}
                >
                  {CD.PROBLEM_BOOK.FIRST_COLOR.items.map((item, index) => (
                    <MenuItem key={index} value={index + 1}>
                      {item}
                    </MenuItem>
                  ))}
                </Select>
              </MDBCol>
            </MDBRow>
            <MDBRow className="pt-3">
              <MDBCol size="2" className="pt-1">
                <h6>{window.i18n.t("train.description")}</h6>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol className="pr-5 pl-4">
                <textarea name="description" className="form-control" id="exampleFormControlTextarea1" rows="3" value={problem.description} onChange={handleProblemChange} style = {{width: '88%'}}/>
              </MDBCol>
            </MDBRow>
            <MDBRow className="pt-3">
              <MDBCol size="2" className="pt-1">
                <h6 className="pt-3">{window.i18n.t("train.tools")}</h6>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol className = "pr-5 pl-4">
                <BottomNavigation
                  value={mode}
                  onChange={(event, newMode) => {
                    handleEditModeChange(newMode);
                  }}
                  showLabels
                >
                  <BottomNavigationAction label="Viewport" icon={<i className="fa fa-crop fa-2x pb-2" />} className={classes.BottomNavigationActionStyle1} style={{padding:'0px'}}/>
                  <BottomNavigationAction label="Stone" icon={<i className="fa fa-plus-circle fa-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                  <BottomNavigationAction label="Symbol" icon={<i className="la la-exclamation-triangle la-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                  <BottomNavigationAction label="Alphabet" icon={<i className="fa fa-font fa-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                  <BottomNavigationAction label="Answer" icon={<i className="fa fa-arrow-circle-down fa-2x pb-2" />} className={classes.BottomNavigationActionStyle3} style={{padding:'0px'}} />
                </BottomNavigation>
              </MDBCol>
            </MDBRow>
            <MDBRow className={classes.navigationButtons + " pl-4 mt-3"}>
              <Button className={classes.navigationButton1} disabled={false} style={{padding:'0px', fontSize: 'inherit'}}  onClick={clearBoard}><i className="fa fa-trash"/></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index <= 0} style={{padding:'0px', fontSize: 'inherit'}}  onClick={handleToFirst}><i className="fa fa-fast-backward"/></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index <= 0} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToBack}><i className="fa fa-step-backward" /></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index >= problem.history_length} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToNext}><i className="fa fa-step-forward" /></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index >= problem.history_length} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToLast}><i className="fa fa-fast-forward" /></Button>
            </MDBRow>
            {
              mode === 4 && (
                <MDBRow className={classes.navigationButtons1 + " pl-4"}>
                  <Button className={classes.navigationButton1} disabled={problem.answer.length >= 10} style={{padding:'0px', fontSize: 'inherit'}}  onClick={handleAddAnswer}><i className="fa fa-plus"/></Button>
                  <Button className={classes.navigationButton} disabled={problem.answer.length <= 1} style={{padding:'0px', fontSize: 'inherit'}}  onClick={handleRemoveAnswer}><i className="fa fa-minus"/></Button>
                  <Select
                    name="answer"
                    value={problem.answer_index}
                    style={{ width: 100, paddingLeft: 40, marginLeft: '3vw'}}
                    className="pr-4"
                    onChange={handleSelectAnswer}
                  >
                    {new Array(problem.answer.length).fill(0).map((item, index) => (
                      <MenuItem key={index} value={index}>
                        {index + 1}
                      </MenuItem>
                    ))}
                  </Select>
                </MDBRow>
              )
            }
          </MDBCol>
        </MDBRow>
      </div>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  marks: store.goBoardReducer.marks,
  black_stones: store.goBoardReducer.black_stones,
  white_stones: store.goBoardReducer.white_stones,
  edit_mode: store.goBoardReducer.edit_mode,
  problem: store.goProblemReducer.problem,
  problem_book: store.problemBookReducer.problem_book,
  problem_list: store.problemBookReducer.problem_list,
  problem_index: store.goProblemReducer.problem_index,
  viewport: store.goBoardReducer.viewport,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    update_problem_book: ProblemBookAction.update_problem_book,
    init_problem_list: ProblemBookAction.init_problem_list,
    update_problem: GoProblemAction.update_problem,
    clear_problem_board: GoProblemAction.clear_problem_board,
    add_answer_on_problem: GoProblemAction.add_answer_on_problem,
    remove_answer_on_problem: GoProblemAction.remove_answer_on_problem,
    select_answer_on_problem: GoProblemAction.select_answer_on_problem,
    update_edit_mode: GoBoardAction.update_edit_mode,
    remove_all_marks: GoBoardAction.remove_all_marks,
    exit_problem: GoProblemAction.exit_problem,
    req_problem: GoProblemAction.req_problem,
    req_problem_list: GoProblemAction.req_problem_list,
    submit_problem_book: ProblemBookAction.submit_problem_book,
    submit_problem: GoProblemAction.submit_problem,
    remove_problem_book: ProblemBookAction.remove_problem_book,
    remove_problem: GoProblemAction.remove_problem,
    update_problem_answer_history_index: GoProblemAction.update_problem_answer_history_index,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(GoMakeProblem));
