import React, {useState,useEffect, useRef} from 'react';
import io from 'socket.io-client';
import { withRouter } from "react-router-dom";
import {  
    MDBRow,
    MDBCol,  
} from "mdbreact";
import { makeStyles } from '@material-ui/core/styles';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import * as CommonAction from "../../store/actions/common.action";
const useStyles = makeStyles(theme => ({
    classifyBtn: {   
        border: '1px dotted white',     
        marginLeft:'0.2vw',
        width:'10vw',
        height:'3.5vh',
        marginTop:'3vh',
        backgroundColor:'#2e2e1f',
        color:'white' ,   
    },
    mesBtn:{ 
        border: '0px solid black',   
        marginLeft:'0.2vw',
        marginTop:'1vh',
        width:'30vw',
        height:'3.5vh',
        backgroundColor:'white',
    }
    
}));

function Chat(props) {  
    const classes = useStyles();  
    let w = window.innerWidth;
    let h = window.innerHeight;
    let VW = window.innerWidth / 100;
    let VH = window.innerHeight / 100; 
    var message = ['you are wonderful', 'you are wonderful', 'thanks for thinking', 'thanks for listening', 'thank you', 'thank you', 'thank you'];
    const selectBtnClick = ()=>{
        var inner = '';
        message.map((txt, i)=>{
            let index = (i + 10).toString();
            inner += `<button  id=${index}   >
                       "${txt}"
                    </button> `;
        });       
        document.getElementById("messageBox").innerHTML = inner;     
        for(var i = 0; i < message.length; i ++) {
            let id = (i + 10).toString();                    
            document.getElementById(id).style.width = '30vw';            
            document.getElementById(id).style.height = '3.5vh';
            document.getElementById(id).style.marginTop = '1.5vh';
            document.getElementById(id).style.marginLeft = '0.2vw';
            document.getElementById(id).style.backgroundColor = 'white';
            document.getElementById(id).style.border = '0px solid black'; 
            if(i === 0) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(0) ;props.updateMessageDlg()};     
            }else if(i === 1) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(1) ;props.updateMessageDlg()};     
            } else if(i === 2) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(2) ;props.updateMessageDlg()};     
            } else if(i === 3) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(3) ;props.updateMessageDlg()};     
            } else if(i === 4) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(4) ;props.updateMessageDlg()};     
            }else if(i === 5) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(5) ;props.updateMessageDlg()};     
            } else if(i === 6) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(6) ;props.updateMessageDlg()};     
            } else if(i === 7) {
                document.getElementById(id).onclick = ()=>{              
                    props.updateMessage(7) ;props.updateMessageDlg()};     
            }
                    
        }
        
    };
    
    return(<div id='avatar' style = {{zIndex:'1112', display:'block'}}>    
                <svg height={`${h}`}  width={`${w / 1.7}`} style={{position:'fixed',left:`${w *0.2}px`, top:`${h / 3}px`}}> 
                    <rect x='0'  y={`0`} rx="20" ry="20"  width={`${w / 1.7}`} height={`${h / 2}`}  fill = 'black' style={{opacity:0.5}} />
                    <rect x={`${VW}`}  y={`${2.5 * VH}`} rx="20" ry="20"  width={`${w / 1.7 - 2 * VW}`} height={`${45*VH}`}  fill = 'rgba(153, 153, 102,0.6)' style={{opacity:0.8}} />
                </svg>
                <div style={{position:'fixed',left:`${w * 0.2}px`, top:`${h / 3}px`}}>
                    <MDBRow>
                        <MDBCol size = '2' style = {{marginLeft:'5vw', marginTop:"4vh"}}>
                            <button  id = 'coin100'   onClick = {selectBtnClick} className = {classes.classifyBtn}  style = {{backgroundColor:'#39ac73', color:'white'}} >
                                happy
                            </button>       
                            <button  id='coin200' className = {classes.classifyBtn}  >
                                enjoy
                            </button>     
                            <button  id='coin500' className = {classes.classifyBtn} >
                                sadness
                            </button>        
                            <button  id='coin1000' className = {classes.classifyBtn} >
                                amazement
                            </button>       
                            <button  id='coin2000' className = {classes.classifyBtn}  >
                                joke
                            </button>   
                        </MDBCol> 
                        <MDBCol id = 'messageBox' style = {{marginTop:"4vh"}} size = '6'>
                            {/* <button  id='coin1000' className = {classes.mesBtn}  >
                                you are wonderful
                            </button>       
                            <button  id='coin2000' className = {classes.mesBtn}  >
                                you are wonderful
                            </button>    */}
                        </MDBCol>
                        {/* <div id = "messageBox">
                        </div> */}
                    </MDBRow>
                   
                </div>       
            </div>
    )
    }
    const mapStateToProps = (store) => {
        return {     
          isOpenEmoticonDlg:store.commonReducer.isOpenEmoticonDlg,   
        }};
      
      const mapDispatchToProps = (dispatch) => bindActionCreators(
        {            
          updateMessage: CommonAction.updateMessage,
          updateMessageDlg: CommonAction.updateMessageDlg,
        },
       
        dispatch,
      );
      export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Chat));

