import React, {useEffect, useState} from "react";
import styled from "styled-components";
import CD from "../../helper/const";
import * as CommonAction from "../../store/actions/common.action";
import * as RoomAction from "../../store/actions/room.action";
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import {withRouter } from 'react-router-dom';
import {
  Button as MuiButton,
  DialogActions,
  FormControl as MuiFormControl,
  FormControlLabel,
  MenuItem,
  Switch,
  Radio,
  RadioGroup,
  Select as MuiSelect,
} from "@material-ui/core";

import {  
    MDBRow,
    MDBCol,
    MDBBtn, 
} from "mdbreact";

import { spacing } from "@material-ui/system";

const Button = styled(MuiButton)(spacing);
const Select = styled(MuiSelect)(spacing);
const FormControlSpacing = styled(MuiFormControl)(spacing);
const FormControl = styled(FormControlSpacing)`
  min-width: 148px!important;
`;

function FFASetting(props)  {
    const [coin_num, setCoinNum] = useState(100);
    const [kind_state, setKind] = useState("individual");
    const [time_state, setTimeState] = useState("normal");
    const [inc_coin_set, setIncCoin] = useState(true);
    const [yes_no, setYesNo] = useState(window.i18n.t("setting.yes"));
    const handleChangeCoin = event => {
        const { setting } = props; 
        setCoinNum(event.target.value); 
        switch(event.target.value) {
            case 100:
                setting['coin'] = 0;
                break;
            case 200:
                setting['coin'] = 1;
                break;
            case 500:
                setting['coin'] = 2;
                break;
            case 1000:
                setting['coin'] = 3;
                break;
            case 2000:
                setting['coin'] = 4;
                break;
            case 5000:
                setting['coin'] = 5;
                break;
            case 10000:
                setting['coin'] = 6;
                break;          
            default:
                break;
        }      
        props.update_setting(setting);
    };
    const handleChangeKind = event => {
        const { setting } = props;    
        setKind(event.target.value);   
        switch(event.target.value) {
            case 'two':
                setting['kind'] = 0;
                break;
            case 'individual':
                setting['kind'] = 1;
                break;
            case 'fixed_team':
                setting['kind'] = 2;
                break;                         
            default:
                break;
        }      
        props.update_setting(setting);
    };
    const handleChangeTime = event => {
        const { setting } = props;
        setTimeState(event.target.value);    
        switch(event.target.value) {
            case 'fast':
                setting['time'] = 0;
                break;
            case 'normal':
                setting['time'] = 1;
                break;
            case 'slow':
                setting['time'] = 2;
                break;
            default:
                break;
        }      
        props.update_setting(setting);
    };
    const handleChangeIncCoin = event => {
        const { setting } = props;
        setIncCoin(event.target.checked);
        switch(event.target.checked) {
            case true:
                setting['inc_room_coin'] = 1;
                setYesNo(window.i18n.t("setting.yes"));
                break;
            case false:
                setting['inc_room_coin'] = 0;
                setYesNo(window.i18n.t("setting.no"));
                break;            
            default:
                break;
        }
        props.update_setting(setting);
    };
    const handleCancel = (event) => {
        const {open_close_FFASetDlg} = props;      
        open_close_FFASetDlg();          
    };
    const handleOK = () => {
        const {user_id, setting, open_close_FFASetDlg, onSettingOK} = props; 
        open_close_FFASetDlg();
        onSettingOK(setting, user_id, CD.GAME_TYPE.FFA);
    };
    const { setting, user, ...other } = props; 
    let disabled = false;   
    let W = window.innerWidth;
    let dlgSize = 'sm';
    if(W > 1500)
        dlgSize = 'lm'       
    return (
        <div style = {{zIndex:'1200'}}>
            <div  onClick={handleCancel} id = 'background' style = {{position:'fixed', top:'0px', left:'0px',width:'100vw', height:"100vh", backgroundColor:'black', opacity:"0.8",zIndex:'1200'}} />
            <div id = 'dialogContent' style = {{position:'fixed', backgroundColor: 'rgba(255, 255, 255, 1)', top:'7vh', left:'38vw',  width:'25vw', height:'87vh', zIndex:'1200'}}>       
                <h5 id="form-dialog-title" style = {{borderBottom: 'solid', borderBottomWidth: '1px', boderBottomColor: 'white',color: 'white', marginTop:'0',marginLeft: '0', padding: '1vw', paddingLeft: '2vw', fontSize:'3vh', fontWeight:'bold', backgroundColor: 'rgb(66, 66, 225)', boxShadow: '5px, 5px, 0, 0, rgba(0,0,0,0.8)'}}>{window.i18n.t("gameType.FFA")} {window.i18n.t("setting.game_setting")} </h5>
                <MDBRow style = {{marginTop: '0', width: '24vw', height: 'auto', paddingLeft: '2vw', paddingTop: '1vh'}}>
                    <MDBCol size = '3'>
                        <p style = {{fontSize: '2.5vh', fontWeight: 'bold', color: 'black'}}>{window.i18n.t("setting.coin")}</p>
                    </MDBCol>
                    <MDBCol>
                        <Select
                            style={{ width: '8vw', color: 'black', paddingLeft: '0.5vw', fontSize: '3vh'}}
                            className="pr-3"
                            value={coin_num}
                            onChange={handleChangeCoin}>
                            <MenuItem value={100}>{100}</MenuItem>
                            <MenuItem value={200}>{200}</MenuItem>
                            <MenuItem value={500}>{500}</MenuItem>
                            <MenuItem value={1000}>{1000}</MenuItem>
                            <MenuItem value={2000}>{2000}</MenuItem>
                            <MenuItem value={5000}>{5000}</MenuItem>
                            <MenuItem value={10000}>{10000}</MenuItem>
                        </Select>
                    </MDBCol>
                </MDBRow>
                <MDBRow style = {{marginTop: '2vh', width: '24vw', height: 'auto', paddingLeft: '2vw', paddingTop: '0.5vh'}}>
                    <MDBCol size = "3">
                        <p style = {{fontSize: '2.5vh', fontWeight: 'bold', color: 'black'}}>{window.i18n.t("setting.kind")}</p>
                    </MDBCol>
                    <MDBCol style = {{width: '7vw'}}>
                        <FormControl component="fieldset">
                            <RadioGroup
                                value={kind_state}
                                onChange={handleChangeKind}>
                                <FormControlLabel
                                    value="two"
                                    control={<Radio color = {'primary'} />}
                                    label = {window.i18n.t("setting.2players")}
                                />
                                <FormControlLabel
                                    value="individual"
                                    control={<Radio color = {'primary'} />}
                                    label = {window.i18n.t("setting.individual")}
                                />
                                <FormControlLabel
                                    value="fixed_team"
                                    control={<Radio color = {'primary'} />}
                                    label = {window.i18n.t("setting.fixed_team")}
                                />
                            </RadioGroup>
                        </FormControl>
                    </MDBCol>
                </MDBRow>
                <MDBRow style = {{marginTop: '1vh', width: '24vw', height: 'auto', paddingLeft: '2vw', paddingTop: '0.5vh'}}>
                    <MDBCol size = "3">
                        <p style = {{fontSize: '2.5vh', fontWeight: 'bold', color: 'black'}}>{window.i18n.t("setting.time")}</p>
                    </MDBCol>
                    <MDBCol style = {{width: '7vw'}}>
                        <FormControl component="fieldset">
                            <RadioGroup
                                value={time_state}
                                onChange={handleChangeTime}>
                                <FormControlLabel
                                    value="fast"
                                    control={<Radio color = {'primary'} />}
                                    label = {window.i18n.t("setting.fast")}
                                />
                                <FormControlLabel
                                    value="normal"
                                    control={<Radio color = {'primary'} />}
                                    label = {window.i18n.t("setting.normal")}
                                />
                                <FormControlLabel
                                    value="slow"
                                    control={<Radio color = {'primary'} />}
                                    label = {window.i18n.t("setting.slow")}
                                />
                            </RadioGroup>
                        </FormControl>
                    </MDBCol>
                </MDBRow>
                <MDBRow style = {{marginTop: '1vh', width: '24vw', height: 'auto', paddingLeft: '2vw', paddingTop: '0.5vh'}}>
                    <MDBCol>
                        <p style = {{fontSize: '2.5vh', fontWeight: 'bold', color: 'black'}}>{window.i18n.t("setting.inc_coin")}</p>
                    </MDBCol>
                    <MDBCol>
                        <FormControlLabel
                            control={
                                <Switch
                                    color = {'primary'}
                                    checked={inc_coin_set}
                                    onChange={handleChangeIncCoin}
                                    value= 'Yes'
                                />
                            }
                            label = {yes_no}
                        />
                    </MDBCol>
                </MDBRow>
                <MDBRow style = {{width: '24vw', height: 'auto', marginLeft: 'auto', marginRight: 'auto', marginTop: '2vh'}}>
                    <MDBCol style = {{textAlign: 'center'}}>
                        <Button onClick={handleOK} color="primary" disabled = {disabled} variant = "outlined" style = {{padding : '1vh', paddingLeft: '2vh', paddingRight: '2vh',}}>
                            <i style = {{fontSize:'1.5vw', color: 'rgb(66, 66, 225)', fontWeight: '100'}} className={ " fa fa-check"}>{window.i18n.t("setting.start")}</i>
                        </Button>
                    </MDBCol>
                </MDBRow>
            </div>
        </div>
    );
}

const mapStateToProps = (store) => ({
    user: store.authReducer.user,
    setting: store.roomReducer.room.setting,
    socketLobby: store.commonReducer.socketLobby,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    update_setting: RoomAction.update_setting,
    open_close_FFASetDlg: CommonAction.updateSettingDlg,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(FFASetting));
