import React, {useEffect} from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';

import { Button } from '@material-ui/core';

import {
  MDBBtn,
  MDBRow,
  MDBCol,
  MDBSimpleChart,
} from "mdbreact";
import * as GoAction from "../../store/actions/go.action";
import * as GoTrainAction from "../../store/actions/go_train.action";
import * as AuthAction from "../../store/actions/auth.action";
import * as ProfileAction from "../../store/actions/profile.action";
import Board from "../go/board";

const useStyles = makeStyles(theme => ({
  leftPanelStyle: {
    paddingLeft: '5vw',
    paddingTop: '10vh',
  },
  pageNaveStyle: {
    padding: 0,
    paddingBottom: 0,
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    marginTop: '6px',
    marginLeft: '3px',
    marginRight: '3px',
    textAlign: 'center',
    width: '80px',
    WebkitAppearance: 'button !important',
  },
}));

function Opening(props) {
  const classes = useStyles();

  useEffect(() => {
    const {change_room_type, initTrainCount} = props;
    change_room_type('opening');
    NewGame();
    props.get_my_profile();
    return ()=>{
      initTrainCount();
    }
  }, []);
  useEffect(()=>{
    let {updateUserCoin, train_d_coin} = props;
    if(props.train_count !== 0) {
      updateUserCoin(train_d_coin);
      props.get_my_profile();
    }
  }, [props.train_count]);
  const NewGame = () => {
    const { new_game_op } = props;
    new_game_op();
  };

  function handleExit(){
    props.history.push("/training");
  }

  const { train_game, train_game_result, games_op, wins_op, putAble, user } = props;
  if(user == null) props.history.push('/login');
  return (
    <div style={{backgroundColor: "#f9f9fc", position:"fixed", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "100vw", height: "100vh", overflow: 'scrollY', padding: "2vw"}}>
      <React.Fragment>
        <MDBRow className="m-0">
          <MDBCol md="2" className={classes.leftPanelStyle}>
            <h3 className="pr-5 font-weight-bold mb-5">{window.i18n.t("train.opening")}</h3>
            {/* <h6 className="py-3 text" style={{color:'blue'}}>
              You will win in this game when you take more scores than 30 in 10 ~ 50 moves.
              This game starts from a board that occupied already 10 stones on.
              You will train the way to find urgent and big moves in opening stage.
            </h6> */}
            <MDBRow className="px-4">
              <MDBCol size="3">
                <h6 className="font-weight-bold">{window.i18n.t("train.games")}</h6>
              </MDBCol>
              <MDBCol>
                <h5 className="font-weight-bold">{games_op}</h5>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-4">
              <MDBCol size="3">
                <h6 className="font-weight-bold">{window.i18n.t("train.wins")}</h6>
              </MDBCol>
              <MDBCol>
                <h5 className="font-weight-bold">{wins_op}</h5>
              </MDBCol>
              <MDBCol className = 'py-5'>
                <MDBBtn color="cyan" className="px-3 py-2 my-0" onClick={NewGame}>
                  {window.i18n.t("train.new_game")}
                </MDBBtn>
              </MDBCol>
            </MDBRow>
          </MDBCol>
          <MDBCol md="5">
            <MDBRow>
              <MDBCol>
                <Board boardId = {0} readOnly = {false} putAble = {putAble} width='50' height='90'/>
              </MDBCol>
            </MDBRow>
          </MDBCol>
          <MDBCol style = {{marginLeft: '8vw', marginTop: '5vh'}}>
            <MDBRow className="py-2 pr-5 pb-3" style = {{paddingLeft: '13vw'}}>
              <Button style = {{boxShadow: "none", backgroundColor: "rbga(0, 0, 0, 0)"}} onClick = {handleExit}>
                <i class = "fa fa-reply" style = {{fontSize: '2rem'}}/>
              </Button>
            </MDBRow>
            <MDBRow className="py-5">
              <MDBCol size="4" className="pr-0 pt-1">
                <h6 className="font-weight-bold">{window.i18n.t("train.reward")}</h6>
              </MDBCol>
              <MDBCol>
                <h6 className="font-weight-bold">{window.i18n.t("train.coin")} +{train_game.reward}</h6>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol md="4">
                <div className="my-3" style={{width:100,height:100,position:'relative'}}>
                  <MDBSimpleChart
                    width={100}
                    height={100}
                    strokeWidth={10}
                    percent={train_game.th_history_length > 0? parseInt((train_game.h_index - train_game.ini_stones) * 100 / train_game.th_history_length) : 0}
                    labelColor="none"
                    strokeColor="#202020"
                    railColor="#808080"
                  />
                  <span style={{position:'absolute',top:'25%',left:'28%',textAlign:'center'}}>
                    <h6 className="mb-0">{window.i18n.t("train.moves")}</h6>
                    <h6 className="font-weight-bold">{train_game.h_index - train_game.ini_stones} : {train_game.th_history_length}</h6>
                  </span>
                </div>
              </MDBCol>
              <MDBCol >
                <div className="my-3" style={{width:100,height:100,position:'relative'}}>
                  <MDBSimpleChart
                    width={100}
                    height={100}
                    strokeWidth={10}
                    percent={train_game.th_correct_moves > 0? parseInt(train_game.cur_correct_moves * 100 / train_game.th_correct_moves) : 0}
                    labelColor="none"
                    strokeColor="#00ff00"
                    railColor="#808080"
                  />
                  <span style={{position:'absolute',top:'25%',left:'28%',textAlign:'center'}}>
                    <h6 className="mb-0">{window.i18n.t("train.score")}</h6>
                    <h6 className="font-weight-bold">{train_game.cur_correct_moves} : {train_game.th_correct_moves}</h6>
                  </span>
                </div>
              </MDBCol>
            </MDBRow>
            <MDBRow className="py-2">
              <MDBCol size="4" className="pr-0 pt-1">
                <h6 className="font-weight-bold">{window.i18n.t("train.result")} </h6>
              </MDBCol>
              <MDBCol>
                <h6 className="font-weight-bold">{train_game_result}</h6>
              </MDBCol>
            </MDBRow>
          </MDBCol>
        </MDBRow>
      </React.Fragment>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  train_game: store.goTrainReducer.train_game,
  train_game_result: store.goTrainReducer.train_game_result,
  games_op: store.profileReducer.user_partial_game.games_op,
  wins_op: store.profileReducer.user_partial_game.wins_op,
  putAble: store.goBoardReducer.putAble,
  train_count:store.goTrainReducer.train_count,
  train_d_coin:store.goTrainReducer.train_d_coin,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    change_room_type: GoAction.change_room_type,
    new_game_op: GoTrainAction.new_game_op,
    update_user_partial_game: ProfileAction.update_user_partial_game,
    updateUserCoin:AuthAction.updateUserCoin,
    get_my_profile: ProfileAction.get_my_profile,
    initTrainCount:GoTrainAction.init_train_count,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(Opening);
