import ACTION from '../actionTypes';
import * as PCB from '../../components/puzzle/puzzleBaseClasses';

const initialState = {
  board_size: 11,
  cell_size: 1,
  show_cell: 0,
  array_board_data: [],
  array_picture: [],
  array_shape_data: [],
  board_point: [], 
  board_border: [], 
  board_inside: [], 
  block_board_point: [], 
  block_board_border: [], 
  block_board_inside: [], 
  array_click_pos: new PCB.INT_ARRAY(), 
  array_move_pos: new PCB.INT_ARRAY(),
  array_solve_data: [],
  lb_down_pos: {x: -1, y: -1},
  lb_down_pt: {x: -1, y: -1},
  lb_down_index: [0],
  mouse_move_pt: {x: -1, y: -1},
  pt_first_pos: {x: -1, y: -1},
  pt_last_pos: {x: -1, y: -1},
  last_selected_index: -1,
  user_cell_board: [],
  pair_move_count: 0,
  stick_remove_count: 0, 
  stick_total_action_count: 0, 
  stick_move_count: 0,
  board_updated: false,
  show_digit_edit: false,
  offset_digit_edit: {x: -1, y: -1},
  input_number: 0,
};

export default function puzzleBoardReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.INIT_PUZZLE_BOARD:
      return {
        ...state,
        array_click_pos: new PCB.INT_ARRAY(), 
        array_move_pos: new PCB.INT_ARRAY(),
        array_solve_data: [],
        lb_down_pos: {x: -1, y: -1},
        lb_down_pt: {x: -1, y: -1},
        lb_down_index: [0],
        mouse_move_pt: {x: -1, y: -1},
        pt_first_pos: {x: -1, y: -1},
        pt_last_pos: {x: -1, y: -1},
        last_selected_index: -1,
        user_cell_board: [],
        pair_move_count: 0,
        stick_remove_count: 0, 
        stick_total_action_count: action.stick_total_action_count, 
        stick_move_count: 0,
        board_updated: false,
        show_digit_edit: false,
        offset_digit_edit: {x: -1, y: -1},
        input_number: 0,
      }
    case ACTION.SET_PUZZLE_BOARD:
      return {
        ...state,
        board_size: action.problem.board_size,
        cell_size: action.problem.cell_size,
        show_cell: action.problem.show_cell,
        array_board_data: action.problem.array_board_data,
        array_picture: action.problem.array_picture,
        array_shape_data: action.problem.array_shape_data,
      }
    case ACTION.UPDATE_PUZZLE_BOARD:
      return {
        ...state,
        board_point: !!action.boardPoint? action.boardPoint : state.board_point, 
        board_border: !!action.boardBorder? action.boardBorder : state.board_border, 
        board_inside: !!action.boardInside? action.boardInside : state.board_inside, 
        block_board_point: !!action.blockBoardPoint? action.blockBoardPoint : state.block_board_point, 
        block_board_border: !!action.blockBoardBorder? action.blockBoardBorder : state.block_board_border, 
        block_board_inside: !!action.blockBoardInside? action.blockBoardInside : state.block_board_inside, 
        board_updated: !state.board_updated,
      }
    case ACTION.UPDATE_PUZZLE_PROC_ACTION_DATA:
      return {
        ...state,
        pt_first_pos: action.pt_first_pos, 
        pt_last_pos: action.pt_last_pos, 
        last_selected_index: action.last_selected_index, 
        user_cell_board: action.user_cell_board,
        lb_down_pos: action.lb_down_pos, 
        pair_move_count: action.pair_move_count,
        stick_remove_count: action.stick_remove_count, 
        stick_total_action_count: action.stick_total_action_count, 
        stick_move_count: action.stick_move_count,
        array_solve_data: action.array_solve_data,
      }
    case ACTION.SET_LB_DOWN_PT:
      return {
        ...state,
        lb_down_pt: action.pt,
      }
    case ACTION.SET_MOUSE_MOVE_PT:
      return {
        ...state,
        mouse_move_pt: action.pt,
      }
    case ACTION.UPDATED_PUZZLE_BOARD:
      return {
        ...state,
        board_updated: !state.board_updated,
      }
    case ACTION.SHOW_DIGIT_EDIT:
      return {
        ...state,
        show_digit_edit: action.show_hide != undefined? action.show_hide : true,
        offset_digit_edit: action.pt,
      }
    case ACTION.EDITED_NUMBER:
      return {
        ...state,
        input_number: action.number,
      }
    default: return state;
  }
}
