  domove(srcpos, dstpos, who) {
    // if (move == 0)
    //   return;

    // let 	srcpos = move & 0xff;
    // let 	dstpos = (move >> 8) & 0xff;

    this.m_board[dstpos] = this.m_board[srcpos];
    this.m_board[srcpos] = 0;
    if (who == 0)
      this.m_stonepos[0][this.m_snumboard[srcpos.current] - 1] = dstpos;
    else
      this.m_stonepos[1][this.m_snumboard[srcpos] - this.m_stonecount - 1] = dstpos;
    let num = this.m_snumboard[srcpos];
    this.m_snumboard[dstpos] = num;
    this.m_snumboard[srcpos] = 0;

    this.update_jlgboard();
  }

  undomove(move, who) {
    if (move == 0)
      return;

    let srcpos = move & 0xff;
    let dstpos = (move >> 8) & 0xff;

    this.m_board[srcpos] = this.m_board[dstpos];
    this.m_board[dstpos] = 0;

    if (who == 0)
      this.m_stonepos[0][this.m_snumboard[dstpos] - 1] = srcpos;
    else
      this.m_stonepos[1][this.m_snumboard[dstpos] - this.m_stonecount - 1] = srcpos;
    this.m_snumboard[srcpos] = this.m_snumboard[dstpos];
    this.m_snumboard[dstpos] = 0;

    this.update_jlgboard();
  }

  ispossible(dstpos, srcpos) {
    let 	mpos = new Array(BSIZE);
    let 	count = this.getmovablepos(srcpos, mpos);
    for (let i = 0; i < count; i++)
    {
      if (mpos[i] == dstpos)
        return	true;
    }
    return	false;
  }

  getmovepath(dstpos, srcpos, middlepos) {
    let 	markboard = new Array(BSIZE).fill(0);
    markboard[srcpos] = 1;

    let layer1 = [], layer2 = [];
    let pcurlayer = layer1, pnextlayer = layer2;
    pcurlayer.push([]);
    pcurlayer[0].push(srcpos);

    for (let step = 0; step < this.m_maxmovestep; step++)
    {
      //expand next layer
      for (let j = 0; j < pcurlayer.length; j++)
      {
        let curpath = pcurlayer[j];
        let pos = curpath[curpath.length - 1];
        let surpos;
        for (let i = 0; i < 6; i++)
        {
          surpos = this.m_jumppos[pos][i];
          if (surpos >= 0 && this.m_board[surpos] == 0 && markboard[surpos] == 0 && this.m_board[this.m_adjpos[pos][i]] != 0)
          {
            if (this.appendpos(pnextlayer, surpos, dstpos, curpath, markboard, middlepos))
              return step;
          }
        }
        if ((surpos = this.m_jumptropos[pos][0]) >= 0)
        {
          if (markboard[surpos] == 0 && this.m_board[surpos] == 0 && this.m_board[this.m_jumptropos[pos][1]] != 0 && this.m_board[this.m_jumptropos[pos][2]] != 0)
          {
            if (this.appendpos(pnextlayer, surpos, dstpos, curpath, markboard, middlepos, this.m_jumptropos[pos][3]))
              return step;
          }
          if ((surpos = this.m_jumptropos[pos][4]) >= 0 && this.m_board[surpos] == 0 && markboard[surpos] == 0 && this.m_board[this.m_jumptropos[pos][5]] != 0 && this.m_board[this.m_jumptropos[pos][6]] != 0)
          {
            if (this.appendpos(pnextlayer, surpos, dstpos, curpath, markboard, middlepos, this.m_jumptropos[pos][7]))
              return step;
          }
        }
      }
      //swap
      pcurlayer = pnextlayer;     
      pnextlayer = [];
    }
    return 0;
  }
