  appendpos(nextlayer, newpos, dstpos, oldpath, markboard, path, mid ) {
    let newpath = oldpath.slice();
    if (mid == undefined)
      newpath.push(newpos);
    else
    {
      newpath.push(mid);
      newpath.push(newpos);
    }
    nextlayer.push(newpath);

    markboard[newpos] = newpath.length;
    if (newpos == dstpos)
    {
      let j = 0;
      for (let i = 1; i < newpath.length - 1; i++, j++)
        path[j] = newpath[i];
      path[j] = -1;
      return	true;
    }
    return false;
  }

  update_jlgboard() {
    this.m_jlgpos = [];
    this.m_jlgboard.fill(0);

    this.m_jlgpos.push([]);

    let 	gnum = 1;
    for (let pos = 0; pos < this.m_bsize; pos++)
    {
      if (this.m_board[pos] == 0 && this.m_jlgboard[pos] == 0)
      {
        this.m_jlgpos.push([]);
        this.set_jlgnum(pos, gnum);
        gnum++;
      }
    }
  }

  set_jlgnum(pos, gnum) {
    this.m_jlgboard[pos] = gnum;
    this.m_jlgpos[gnum].push(pos);

    let 	surpos;
    for (let i = 0; i < 6; i++)
    {
      surpos = this.m_jumppos[pos][i];
      if (surpos >= 0 && this.m_board[surpos] == 0 && this.m_jlgboard[surpos] == 0 && this.m_board[this.m_adjpos[pos][i]] != 0)
        this.set_jlgnum(surpos, gnum);
    }
    if ((surpos = this.m_jumptropos[pos][0]) >= 0)
    {
      if (this.m_board[surpos] == 0 && this.m_jlgboard[surpos] == 0 && this.m_board[this.m_jumptropos[pos][1]] != 0 && this.m_board[this.m_jumptropos[pos][2]] != 0)
        this.set_jlgnum(surpos, gnum);
      if ((surpos = this.m_jumptropos[pos][4]) >= 0 && this.m_board[surpos] == 0 && this.m_jlgboard[surpos] == 0 && this.m_board[this.m_jumptropos[pos][5]] != 0 && this.m_board[this.m_jumptropos[pos][6]] != 0)
        this.set_jlgnum(surpos, gnum);
    }
  }

  addmovablepos(dstpos, count, gnum, markboard)
  {
    for (let i = 0; i < this.m_jlgpos[gnum].length; i++)
      dstpos[count[0]++] = this.m_jlgpos[gnum][i];
    markboard[gnum] = 1;
  }
