import ACTION from '../actionTypes';

const initialState = {
  tournament_id: '',
  go_tournament: {
    _id: '',
    title: '',
    information: '',
    start_date: '',
    end_date: '',
    cur_round: 0,
    games: 0,
    schedule: {
      accept_to: '',
      round_start: [],
    },
    prize_amount: {
      coin: [5000, 2000, 1000],
    },
    setting: {
      board_size: 0,
      handicap: 0,
      coin: 0,
      time: 0,
    },
    participants: [],
    prize: [],
  }, 
}
export default function tournamentReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_TOURNAMENT_SETTING:
      {
        if(action.game_type === 0) {
          return {
            ...state,
            go_tournament:action.tournament,
          }; 
        }
      }
    case ACTION.UPDATE_GO_TOURNAMENT:
      return {
        ...state,
        go_tournament: {
          ...state.tournament,
          _id: action.tournament._id,
          title: action.tournament.title,
          information: action.tournament.information,
          start_date: action.tournament.start_date,
          end_date: action.tournament.end_date,
          cur_round: action.tournament.cur_round,
          games: action.games,
          schedule: action.tournament.schedule,
          setting: action.tournament.setting,
          prize_amount: action.tournament.prize_amount,
          participants: action.tournament.participants,
          prize: action.prize,
        },
      }; 
       
    case ACTION.SAVE_TOURNAMENT_ID:
      return {
        ...state,
        tournament_id: action.id,
      };
    default:
      return state;
  }
  
}