import ACTION from '../actionTypes';

const initialState = {
    articles: [],
    edit_article: {
        reply_to_article_id: '',
        reply_to_article_title: ''
    },
}
export default function articleReducer(state=initialState, action){
    switch (action.type) {
        case ACTION.SET_ARTICLES:
            return {
                ...state,
                articles: action.articles.map((article, index) => ({
                _id: article._id,
                id: index * 2,
                author_id: article.author_id,
                title: article.title,
                content: article.content,
                boards: article.boards,
                date: article.date,
                votes: article.votes,
                devotes: article.devotes,
                replied: article.replied,
                parent: article.parent,
                expanded: (article._id === action.article_id || article.parent === "")? true : false
                }))
        };
        case ACTION.UPDATE_ARTICLE:
            return {
                ...state,
                articles: state.articles.map((article, index) => {
                if (article._id !== action.article._id)
                    return article;
                return {
                    _id: action.article._id,
                    id: index * 2,
                    author_id: action.article.author_id,
                    title: action.article.title,
                    content: action.article.content,
                    boards: action.article.boards,
                    date: action.article.date,
                    votes: action.article.votes,
                    devotes: action.article.devotes,
                    replied: action.article.replied,
                    parent: action.article.parent,
                    expanded: action.article.expanded
                };
                })
        };
        case ACTION.ADD_ARTICLE:
            return {
                ...state,
                articles: state.articles.concat({
                _id: action.article._id,
                id: state.articles.length * 2,
                author_id: action.article.author_id,
                title: action.article.title,
                content: action.article.content,
                boards: action.article.boards,
                date: action.article.date,
                votes: action.article.votes,
                devotes: action.article.devotes,
                replied: action.article.replied,
                parent: action.article.parent,
                expanded: true
                })
        };

        case ACTION.REPLY_TO_ARTICLE:
            return {
                ...state,
                edit_article: {
                    reply_to_article_id: action.article_id,
                    reply_to_article_title: action.article_title
                }
            }

        case ACTION.SET_ARTICLE_ID_TO_REPLAY:
            return {
                ...state,
                edit_article:{
                    reply_to_article_id: action.id,
                    reply_to_article_title: ''
                }
            }
        
        default:
            return state;
    }
}