import React, {useState, useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import {
  Avatar,
  Button,
  DialogActions,
  FormControl as MuiFormControl,
  FormControlLabel,
  MenuItem,
  Radio,
  Switch,
  RadioGroup,
  Select,
  LinearProgress
} from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { bindActionCreators } from 'redux';
import {
  MDBRow,
  MDBCol,
  MDBBtn,
} from "mdbreact";
import * as PDesignAction from '../../store/actions/pdesign.action';
import * as PDesignTaskAction from '../../store/actions/pdesign_task.action';

const useStyles = makeStyles(theme => ({
  btnStyle: {
    width: '4vw',
    height: '4vw',
    paddingLeft: '0px',
    paddingRight: '0px'
  },

  imgStyle: {
    width: '3vw',
    height: '3vw',
  },

  txtStyle: {
    fontSize: '1.5vw',
    fontFamily: 'cursive',
    fontWeight: 'bold',
  },
  
  propertyStyle: {
    width: '2.5vw',
    height: '2.5vw',
    padding: '0.2vw'
  },
}));
var pen_thick = 0, tool = 0, property_arr = [];
function ToolSelect(props) {

  const classes = useStyles();
  const [property_array, setPropertyArray] = useState(['pen']);

  useEffect(() => {
    handleChangeTool(0);
  }, []);
  
  useEffect(() => {
    pen_thick = props.pen_thick;
    tool = props.tool;
  }, [props.pen_thick, props.tool]);
  
  const handleChangeTool = (value) => {
    var type_btn  = document.getElementById("tool_type_" + `${value}`);
    for (let i = 0; i < 5 ; i ++) {
      var btn = document.getElementById("tool_type_" + `${i}`);
      btn.style.boxShadow = 'none';
    }
    type_btn.style.boxShadow = '0px 0px 5px 5px rgb(30, 130, 200)';
    props.update_tool(value);
    switch(value){
      case 0:
        property_arr = ['thin', 'normal', 'thick'];
        break;
      case 1:
        property_arr = ['shape_0', 'shape_1', 'shape_2', 'shape_3', 'shape_4'];
        break;
      case 2:
        property_arr = ['paint'];
        break;
      case 3:
        property_arr = ['select'];
        break;
      case 4:
        property_arr = ['eraser', 'empty'];
        break;
      default: break;
    }
    setPropertyArray(property_arr);
    tool = value;
    if (value == 0) {
      handleChangeProperty(pen_thick);
    } else handleChangeProperty(0);
  }

  const handleChangeProperty = (value) => {
    var type_btn  = document.getElementById("property_" + `${value}`);
    for (let i = 0; i < property_array.length ; i ++) {
      var btn = document.getElementById("property_" + `${i}`);
      btn.style.boxShadow = 'none';
    }
    if (!type_btn) return;
    type_btn.style.boxShadow = '0px 0px 5px 5px rgb(30, 130, 200)';
    if (tool == 0) props.update_pen_thick(value);
    props.update_tool_property(value);
  }

  return (
    <div>
    <div style = {{width: "100%", borderTopLeftRadius: '1vw', borderTopRightRadius: '1vw', backgroundColor: 'rgba(240, 200, 90, 0.5)'}}> 
      <MDBRow className = "px-2 ml-1 py-2">
        <MDBCol className = 'px-0 pr-2' size = '2'><Button className = {classes.btnStyle} onClick = {handleChangeTool.bind(this, 0)}> <img id = "tool_type_0" src = {"/assets/img/pen.png"} className = {classes.imgStyle} /></Button></MDBCol>
        <MDBCol className = 'px-0 pr-2' size = '2'><Button className = {classes.btnStyle} onClick = {handleChangeTool.bind(this, 1)}> <img id = "tool_type_1" src = {"/assets/img/shape.png"} className = {classes.imgStyle} /></Button></MDBCol>
        <MDBCol className = 'px-0 pr-2' size = '2'><Button className = {classes.btnStyle} onClick = {handleChangeTool.bind(this, 2)}> <img id = "tool_type_2" src = {"/assets/img/paint.png"} className = {classes.imgStyle} /></Button></MDBCol>
        <MDBCol className = 'px-0 pr-2' size = '2'><Button className = {classes.btnStyle} onClick = {handleChangeTool.bind(this, 3)}> <img id = "tool_type_3" src = {"/assets/img/select.png"} className = {classes.imgStyle} /></Button></MDBCol>
        <MDBCol className = 'px-0' size = '2'><Button className = {classes.btnStyle} onClick = {handleChangeTool.bind(this, 4)}> <img id = "tool_type_4" src = {"/assets/img/eraser.png"} className = {classes.imgStyle} /></Button></MDBCol>
      </MDBRow>
    </div>
    <div style = {{width: "100%", marginTop: '0.5vh', borderBottomLeftRadius: '1vw', borderBottomRightRadius: '1vw', backgroundColor: 'rgba(240, 200, 90, 0.5)'}}> 
      <MDBRow className = "px-2 ml-1 py-2">
      {
        property_array.map((property, index) => {
          return (
            <MDBCol className = 'px-0 pr-2' size = '2'><Button className = {classes.btnStyle} onClick = {handleChangeProperty.bind(this, index)}> <img id = {"property_" + `${index}`} src = {`/assets/img/${property}.png`} className = {classes.propertyStyle} /></Button></MDBCol>
          );
        })
      }
      </MDBRow>
    </div>
    </div>
  );
}
function mapStateToProps(store) {
  return {
    tool: store.pdesignTaskReducer.tool,
    pen_thick: store.pdesignTaskReducer.pen_thick,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      update_tool: PDesignTaskAction.updateTool,
      update_tool_property: PDesignTaskAction.updateToolProperty,
      update_pen_thick: PDesignTaskAction.updatePenThick
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(ToolSelect));