import React, {useState,useEffect, useRef} from 'react';
function Clock(props) {  
  const {clockPosition, leftTime} = props;
  const [showClock, setShowClock] = useState(false);
  let w = window.innerWidth;
  let h = window.innerHeight;
  let VW = window.innerWidth / 100;
  let VH = window.innerHeight / 100;
  var circleCanvas;
  var cirCtx;
  var cirCtx_ref = useRef();
  var clockImg
  useEffect(()=>{
    circleCanvas = document.getElementById('circle');
    cirCtx = circleCanvas.getContext('2d');
    cirCtx_ref.current = cirCtx; 
    clockImg = document.getElementById('clockImg');
  }, []);
  useEffect(()=>{
    if(props.leftTime === 0) {
      cirCtx_ref.current.clearRect(0, 0, w, h);  
      return;
    }
    var srcpos = Math.PI *1.5;
    var progress = (14 - props.leftTime) / 14;
    var dstpos = 3.5 * Math.PI - progress * Math.PI * 2;
    var center_pos = [[clockPosition[0] + 2 * VW], [clockPosition[1] + 2.1 * VW]];
    cirCtx_ref.current.clearRect(0, 0, w, h);     
    cirCtx_ref.current.beginPath(); 
    cirCtx_ref.current.fillStyle = " #663300";
    if(clockPosition[0] > 100) {
      cirCtx_ref.current.arc(center_pos[0],center_pos[1] , 1.1 *VW ,  srcpos, dstpos); 
      if(!showClock)
        setShowClock(true);
    }      
    cirCtx_ref.current.lineTo(center_pos[0], center_pos[1]);
    cirCtx_ref.current.fill();
  }, [props.leftTime]);

  return(  
    <div id='clock' style = {{display:`${props.display}`}}>            
      {showClock && <img id="clockImg" alt='clockImg' src='/assets/img/clock.png'  style={{position:'fixed',left:`${clockPosition[0]}px`, top:`${clockPosition[1]}px`, width:'4vw', height:'4vw'}}></img> }
      <canvas id="circle" width={`${w}px`} height={`${h}px`} style={{position:'fixed', left:"0px", top:'0px'}}>
      </canvas> 
      {showClock && leftTime >= 10 &&
        <p id = 'ClockText'  style = {{fontSize:'2vw', position:'fixed', left:`${clockPosition[0] +VW * 0.9}px`, top:`${clockPosition[1] +0.7 * VW}px`,  marginTop:'0px', color:'white'}}> {leftTime}    
        </p>
      }
      {showClock && leftTime < 10 &&
        <p id = 'ClockText'  style = {{fontSize:'2vw', position:'fixed', left:`${clockPosition[0] + VW * 1.5}px`, top:`${clockPosition[1] +0.7 * VW}px`,  marginTop:'0px', color:'white'}}> {leftTime}      
        </p>
      }                             
    </div>
  );
}
export default Clock;

