import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = {
  room: {
    coin: 0,
    time: 0,
    countdown: 0,
    first_turn: 0,
  },
};

export default function omokReducer(state = initialState, action) {
  switch (action.type) {
    case ACTION.LOAD_OMOK_ROOM_INFO:
      return {
        ...state,
        room: {
          ...state.room,
          countdown: !!action.countdown ? action.countdown : state.room.countdown,
        },
      };
    case ACTION.LOAD_OMOK_RECORD:
      return {
        ...state,
        room: {
          ...state.room,
          countdown: !!action.game.countdown ? action.game.countdown : state.room.countdown,
          first_turn: !!action.game.first_turn ? action.game.first_turn : state.room.first_turn,
        }
      };
    default: return state;
  }
}