import React, { useState, useEffect } from 'react';
import { withRouter } from "react-router-dom";
import moment from "moment";

import {bindActionCreators} from "redux";
import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as AuthAction from "../../store/actions/auth.action";
import * as ArticleAction from "../../store/actions/article.action";
import {connect} from "react-redux";

import {
  Select,
  MenuItem,
} from '@material-ui/core';

import { makeStyles } from '@material-ui/core/styles';
import {notify_w} from "../../helper/alert";
import {
  MDBRow,
  MDBCol,
  MDBCard,
  MDBCardBody,
  MDBCardText,
  MDBCardHeader,
  MDBBtn,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
  MDBFormInline,
} from "mdbreact";
import { array } from 'prop-types';
import CD from '../../helper/const'

const useStyles = makeStyles(theme => ({
  pageNaveStyle: {
    border: '1px solid #dee2e6 !important',
  },
  searchStyle: {
    color: '#ced4da',
  },
  avatarImg: {
    height: '3vh',
    width: '3vh',
    float: 'left',
  },
  textStyle: {
    whiteSpace: 'nowrap',
    width: '90%',
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    textAlign: 'left',
    marginLeft: '1vw'
  }
}));

function Forum(props) {
  const classes = useStyles();
  const [page, setPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [find, setFind] = useState("");
  const [startPage, setStartPage] = useState(1);
  const [pages, setPages] = useState(1);

  useEffect(() => {
    props.req_article_list(0, find, rowsPerPage, 0);
    props.req_article_list(1, "", 3, 0);
    props.req_article_list(2, "", 3, 0);
    props.req_article_list(3, "", 3, 0);
    props.setFunc(CD.FUNC.FUNC_FORUM);
  }, []);

  useEffect(() => {
    var allPage = Math.ceil(props.article_count / rowsPerPage);
    if (allPage === 0)
      allPage = 1;
    setPages(allPage);
  });

  const handleChangeFind = event => {
    setFind(event.target.value);
    props.req_article_list(0, event.target.value, rowsPerPage, 0);
  };

  const handleToFirstPage = () => {
    handleChangePage(1);
  };

  const handleToPrevPage = () => {
    var prePage = page > 1? page - 1 : 1;
    handleChangePage(prePage);
  };

  const handleToNextPage = () => {
    var nextPage = page < pages? page + 1 : pages;
    handleChangePage(nextPage);
  };

  const handleToLastPage = () => {
    handleChangePage(pages);
  };

  const handleChangePage = (page) => {
    setPage(page);
    props.req_article_list(0, find, rowsPerPage, page - 1);
  };
  const handleChangeRowsPerPage = event => {
    setRowsPerPage(event.target.value);
    props.req_article_list(0, find, event.target.value, 0);
  }
  const handleSelectArticle = (article_id) => {
    props.history.push('/article:'+article_id);
  };

  const paginationElement = (top) => {
    return (
      <MDBPagination className={ top? "float-right" : "mx-auto" }>
        {
          pages > 10 && (
            <MDBPageItem className="pl-2">
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToFirstPage}>&laquo;</MDBPageNav>
            </MDBPageItem>
          )
        }
        {
          pages > 1 && (
            <MDBPageItem className="pl-2">
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToPrevPage}>&lsaquo;</MDBPageNav>
            </MDBPageItem>
          )
        }
        {
          pages > 1 && pageArray.map((p) => {
            if (p === page)
              return (
                <MDBPageItem  className="pl-2" active>
                  <MDBPageNav className={classes.pageNaveStyle}>
                    {p} <span className="sr-only"></span>
                  </MDBPageNav>
                </MDBPageItem>
              );
            else
              return (
                <MDBPageItem className={classes.pageNaveStyle}>
                  <MDBPageNav onClick={handleChangePage.bind(this, p)}>{p}</MDBPageNav>
                </MDBPageItem>
              );
          })
        }
        {
          endPage < pages && (
            <MDBPageItem className={classes.pageNaveStyle}>
              <MDBPageNav>...</MDBPageNav>
            </MDBPageItem>
          )
        }
        {
          pages > 1 && (
            <MDBPageItem className="pl-2">
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToNextPage}>&rsaquo;</MDBPageNav>
            </MDBPageItem>
          )
        }
        {
          pages > 10 && (
            <MDBPageItem className="pl-2">
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToLastPage}>&raquo;</MDBPageNav>
            </MDBPageItem>
          )
        }
      </MDBPagination>
    );
  };

  const { func, article_list, article_news_list, article_sensational_list, article_remarkable_list, user } = props;
  const handlePost = ()=>{
    if(!user){
      notify_w('Sorry! Please log in');
      props.history.push('/login');
    } else {
      props.replyToArticle("", "");
      props.history.push("/forum_compose");
    }
  };
  var pageArray = [];
  var endPage = pages;
  if (endPage > startPage + 8)
    endPage = startPage + 8;
  for(var p = startPage; p <= endPage; p ++) {
    pageArray.push(p);
  }

  return (
    <React.Fragment>
      <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
        <MDBRow style = {{width: '96%', paddingLeft: '2vw'}}>
          <MDBCol  size="8">
            <MDBRow className="px-4 pt-3">
              <MDBCol  size='3'>
                <MDBBtn style={{width:'20vh', height:'4vh', fontSize:'2.3vh', textTransform: 'unset'}} color="cyan" className="px-3 py-1" onClick={handlePost}>
                  {window.i18n.t("forum.article_post")}
                </MDBBtn>
              </MDBCol>
              <MDBCol md="3">
                <MDBFormInline className="md-form active-cyan-2">
                  <input
                    className="form-control form-control-sm w-75"
                    type="text"
                    placeholder={window.i18n.t("records.search")}
                    aria-label={window.i18n.t("records.search")}
                    onChange={handleChangeFind}
                  />
                  <i className={classes.searchStyle + " fa fa-search"}/>
                </MDBFormInline>
              </MDBCol>
              <MDBCol>
                {paginationElement(true)}
                <Select
                  value={rowsPerPage}
                  style={{ width: 80 }}
                  className="float-right pr-4"
                  onChange={handleChangeRowsPerPage}
                >
                  <MenuItem value={6}>{window.i18n.t("game.line").replace("{0}", 6)}</MenuItem>
                  <MenuItem value={10}>{window.i18n.t("game.line").replace("{0}", 10)}</MenuItem>
                </Select>
              </MDBCol>
            </MDBRow>
            <MDBRow className="px-5">
              {
                func == CD.FUNC.FUNC_FORUM && article_list.map((article, index) => {
                  var time_diff = moment(new Date(article.date)).fromNow();
                  return (
                    <MDBCard className="mt-3 px-1 text-center w-100" key={index}>
                      <MDBCardBody className="pb-1" onClick={handleSelectArticle.bind(this, article._id)}>
                        <MDBRow >
                          <MDBCol md="7" className="mb-md-0 px-1">
                            <h5 className = {classes.textStyle + " font-weight-bold dark-grey-text pl-2 pb-2"}>
                              {article.title}
                            </h5>
                          </MDBCol>
                          <MDBCol md="2" className="mb-md-0">
                            <img alt="avatar" className={classes.avatarImg} src={article.avatar} />
                            <h6 className="dark-grey-text pt-1">
                              <small>
                                {article.author_id}
                              </small>
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <h6 className="dark-grey-text pt-1 pr-3 float-right">
                              <small>
                                {time_diff}
                              </small>
                            </h6>
                          </MDBCol>
                        </MDBRow>
                        <MDBRow>
                          <MDBCol size = "11" className="mb-md-0 px-3" style={{textAlign:'left'}}>
                            <h6 className = {classes.textStyle + " dark-grey-text pt-1"}>
                              <small>
                                {article.abstract}...
                              </small>
                            </h6>
                          </MDBCol>
                        </MDBRow>
                        <MDBRow>
                          <MDBCol size="7" className="mb-md-0 px-1">
                            <h6 className="dark-grey-text pl-2 pt-2 float-left">
                              <i className="fa fa-thumbs-o-up pr-1"/>
                                {article.votes}
                              <i className="fa fa-thumbs-o-down pl-3 pr-1"/>
                                {article.devotes} 
                              <i className="fa fa-comment-o pl-5 pr-1"/>
                                {article.replied}
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                          </MDBCol>
                        </MDBRow>
                      </MDBCardBody>
                    </MDBCard>
                  );
                })            
              }
            </MDBRow>
          </MDBCol>

          <MDBCol className="pt-3" size = '3'>
            <MDBCard style={{ width: "110%" }} className="mb-3">
              <MDBCardHeader color="deep-orange lighten-1">{window.i18n.t("forum.news")}</MDBCardHeader>
              <MDBCardBody className="pb-1">
                {
                  func == CD.FUNC.FUNC_FORUM && article_news_list.map((article, index) => {
                    return (
                      <div key={index}>
                        <MDBRow onClick={handleSelectArticle.bind(this, article._id)}>
                          <MDBCol md="6" className="mb-md-0 px-1">
                            <h6 className = {classes.textStyle + " font-weight-bold dark-grey-text pl-2"}>
                              {article.title}
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <img alt="avatar" className={classes.avatarImg} src={article.avatar} />
                            <h6 className="font-weight-bold dark-grey-text pr-3 float-right">
                              <small>
                                {article.author_id}
                              </small>
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <h6 className="font-weight-bold dark-grey-text pr-3 float-right">
                              <small>
                                {new Date(article.date).toLocaleDateString()}
                              </small>
                            </h6>
                          </MDBCol>
                        </MDBRow>
                        <MDBCardText className="pl-2 pb-2">{article.abstract}...</MDBCardText>
                      </div>
                    );
                  })
                }
                <MDBBtn outline color="gray" className="float-right px-3 py-1 text-lowercase"><i className="fa fa-angle-right pr" /><i className="fa fa-angle-right pr-1" />{window.i18n.t("forum.more")}</MDBBtn>
              </MDBCardBody>
            </MDBCard>
            <MDBCard style={{ width: "110%" }} className="mr-1 mb-3">
              <MDBCardHeader color="green lighten-1">{window.i18n.t("forum.sensational_posts")}</MDBCardHeader>
              <MDBCardBody className="pb-1">
                {
                  func == CD.FUNC.FUNC_FORUM && article_sensational_list.map((article, index) => {
                    return (
                      <div key={index}>
                        <MDBRow key={index} onClick={handleSelectArticle.bind(this, article._id)}>
                          <MDBCol md="6" className="mb-md-0 px-1">
                            <h6 className = {classes.textStyle + " font-weight-bold dark-grey-text pl-2"}>
                              {article.title}
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <img alt="avatar" className={classes.avatarImg} src={article.avatar} />
                            <h6 className="font-weight-bold dark-grey-text pr-3 float-right">
                              <small>
                                {article.author_id}
                              </small>
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <h6 className="font-weight-bold dark-grey-text pr-3 float-right">
                              <small>
                                {new Date(article.date).toLocaleDateString()}
                              </small>
                            </h6>
                          </MDBCol>
                        </MDBRow>
                        <MDBCardText className="pl-2 pb-2">{article.abstract}...</MDBCardText>
                      </div>
                    );
                  })
                }
                <MDBBtn outline color="gray" className="float-right px-3 py-1 text-lowercase"><i className="fa fa-angle-right pr" /><i className="fa fa-angle-right pr-1" />{window.i18n.t("forum.more")}</MDBBtn>
              </MDBCardBody>
            </MDBCard>
            <MDBCard style={{ width: "110%" }} className="mr-1 mb-3">
              <MDBCardHeader color="purple lighten-1">{window.i18n.t("forum.remarkable_topics")}</MDBCardHeader>
              <MDBCardBody className="pb-1">
                {
                  func == CD.FUNC.FUNC_FORUM && article_remarkable_list.map((article, index) => {
                    return (
                      <div key={index}>
                        <MDBRow key={index} onClick={handleSelectArticle.bind(this, article._id)}>
                          <MDBCol md="6" className="mb-md-0 px-1">
                            <h6 className = {classes.textStyle + " font-weight-bold dark-grey-text pl-2"}>
                              {article.title}
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <img alt="avatar" className={classes.avatarImg} src={article.avatar} />
                            <h6 className="font-weight-bold dark-grey-text pr-3 float-right">
                              <small>
                                {article.author_id}
                              </small>
                            </h6>
                          </MDBCol>
                          <MDBCol className="mb-md-0 px-1">
                            <h6 className="font-weight-bold dark-grey-text pr-3 float-right">
                              <small>
                                {new Date(article.date).toLocaleDateString()}
                              </small>
                            </h6>
                          </MDBCol>
                        </MDBRow>
                        <MDBCardText className="pl-2 pb-2">{article.abstract}...</MDBCardText>
                      </div>
                    );
                  })
                }
                <MDBBtn outline color="gray" className="float-right px-3 py-1 text-lowercase"><i className="fa fa-angle-right pr" /><i className="fa fa-angle-right pr-1" />{window.i18n.t("forum.more")}</MDBBtn>
              </MDBCardBody>
            </MDBCard>
          </MDBCol>
        </MDBRow>
      </div>
    </React.Fragment>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    article_count: store.commonReducer.total,
    article_list: store.commonReducer.items,
    article_news_list: store.commonReducer.items2,
    article_sensational_list: store.commonReducer.items3,
    article_remarkable_list: store.commonReducer.items4,
    open_other: store.commonReducer.content > 2,
    func: store.commonReducer.func,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {    
      req_article_list: CommonAction.req_article_list,
      setFunc: CommonAction.setFunc,
      replyToArticle: ArticleAction.replyToArticle,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Forum));
