import React, {useState, useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import {
  Avatar,
  Button,
  DialogActions,
  FormControl as MuiFormControl,
  FormControlLabel,
  MenuItem,
  Radio,
  Switch,
  RadioGroup,
  Select as MuiSelect,
  LinearProgress
} from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { bindActionCreators } from 'redux';
import {
  MDBRow,
  MDBCol,
  MDBBtn,
} from "mdbreact";
import * as PDesignAction from "../../store/actions/pdesign.action";
import * as PDesignBoardAction from "../../store/actions/pdesign_board.action";

const useStyles = makeStyles(theme => ({
  btnStyle: {
    width: '3vw',
    height: '3vw'
  },
  sizeStyle: {
    position: 'fixed',
    zIndex: '1112',
    backgroundColor: 'rgba(0, 0, 0, 0.5)',
    boxShadow: '0px 0px 5px 5px rgba(255, 255, 255, 0.7)',
    top: '4vh',
    right: '6vw',
    fontSize: '2.5vh',
    color: 'white',
    transitionDelay: '400ms',
    transitionDuration: '800ms',
    opacity: '1',
    display : 'none'
  }
}));

var cur_percent = 1;
var canvas, zero_percent_line, cur_percent_line, controller, drag_panel;
var w = window.innerWidth;
var px;
var handleDisplay;
var panel;
var inited = false;

function BoardOption(props) {
  const classes = useStyles();
  const [show_grid, setShowGrid] = useState(true);
  const [yes_no, setYesNo] = useState(window.i18n.t("setting.yes"));
  const [board_size, setBoardSize] = useState(9);

  useEffect(() => {
    if (!props.controllable && inited){
      controller_position(1- props.size / 90);
      setBoardSize(props.size);
    }
  }, [props.size]);

  useEffect(() => {
    if (!props.controllable && inited)
      changeShowGrid({target: {checked: props.isShowGrid}});
  }, [props.isShowGrid]);

  useEffect(() => {
    if (!props.controllable && inited){
      var board_back = props.board_back - 1;
      // if (board_back == -1) return;
      handleChangeBack(board_back);
    }
  }, [props.board_back]);

  const changeShowGrid = event => {
    if (!props.controllable && event.target.checked != props.isShowGrid) return;
    setShowGrid(event.target.checked);    
    switch(event.target.checked) {
      case true:
        setYesNo(window.i18n.t("setting.yes"));
        break;
      case false:
        setYesNo(window.i18n.t("setting.no"));
        break;            
      default:
        break;
    }
    if (props.controllable)
      props.update_show_grid(event.target.checked);
  };

  useEffect(() => {
    zero_percent_line = document.getElementById("zero_percent_line");
    cur_percent_line = document.getElementById("cur_percent_line");
    controller = document.getElementById("controller");
    var mouse_down_pos, mouse_drag_pos;
    var drag_state = false;
    init();
    drawRender();
    window.addEventListener("resize", drawRender);
    if(!!canvas) {
      canvas.addEventListener("mousedown", function(event){
        mouse_down_pos = event.pageX;
        drag_state = true;
        cur_percent = (w - mouse_down_pos - w / 25) / (w / 10);
        drag_panel.style.display = "block"
        controller_position(cur_percent);
      });
      drag_panel.addEventListener("mousemove", function(event){
        mouse_drag_pos = event.pageX;
        if(drag_state){
          cur_percent = (w - mouse_drag_pos - w / 25) / (w / 10);
          if (cur_percent < 0) cur_percent = 0;
          if (cur_percent > 1) cur_percent = 1;
          controller_position(cur_percent);
        }
      });
      drag_panel.addEventListener("mouseup", function(event){
        drag_state = false;
        drag_panel.style.display = 'none';
      });
    }
    return () => {
      window.removeEventListener("resize", drawRender);
    }
  }, [])

  const init = () => {
    inited = true;
    drawRender();
    controller_position(cur_percent);
  }

  const drawRender = () => {
    canvas = document.getElementById("canvas");
    drag_panel = document.getElementById("drag_panel")
  }

  const controller_position = (percent) => {
    if (!props.controllable && percent != (1- props.size / 90)) return;
    panel = document.getElementById("board_size_display");
    panel.style.display = 'none';
    panel.style.opacity = '1';
    cur_percent_line.style.width = `${w * percent / 10}px`
    controller.style.right = `${w * percent / 10 - w / 200 + w / 25}px`
    px = Math.round((1 - percent) * 90) + 9;
    if (props.controllable)
      props.update_board_size(px);
    setBoardSize(px);
    displayBoardSize();
  }
  const displayBoardSize = () => {
    clearTimeout(handleDisplay);
    panel.style.display = 'block'
    handleDisplay = setTimeout(() => {
      panel.style.opacity = '0';
    }, 50)
  }
  const handleChangeBack = (value) => {
    if (!props.controllable && value != props.board_back - 1) return;
    if (value == -1) return;
    var back = document.getElementById('back_'+`${value}`);
    for (let i = 0 ; i < 3 ; i ++) {
      var back_init = document.getElementById('back_' + `${i}`);
      back_init.style.boxShadow = 'none';
    }
    back.style.boxShadow = '0px 0px 5px 5px rgb(30, 130, 200)';
    
    if (props.controllable)
      props.update_background(value + 1);
  }

  return (
    <div style = {{width: "100%", borderRadius: '1vw', backgroundColor: 'rgba(240, 200, 90, 0.5)'}}>
      <div id = "board_size_display" className = {classes.sizeStyle + " px-3 py-2"} style = {{position: 'fixed', }}>
        {board_size + " X " + board_size}
      </div>
      <MDBRow className = "pl-4 pt-1 ">
        <MDBCol size = '4'>Board Size</MDBCol>
        <MDBCol className = "pr-4">
          <div id = "zero_percent_line" style = {{position: "fixed", top: '12.5vh', right: '4vw', width: "10%", height: '1vh', backgroundColor: 'blue', borderRadius: '1vh'}}></div>
          <div id = "cur_percent_line" style = {{position: 'fixed',top: '12.5vh', right: '4vw', width: "10%", height: '1vh', backgroundColor: 'black', borderRadius: '1.5vh'}}></div>
          <div id = "controller" style = {{position: "fixed", top: '11.75vh', width: '1vw', height: '2.5vh', backgroundColor: 'white', borderRadius: '2px'}}></div>
          <canvas id = "canvas" style = {{position:'fixed', width: '10%', top: '12.5vh', right: '4vw', height: '1vh', backgroundColor: 'rgba(140, 140, 140, 0)', borderRadius: '1vh', cursor: 'pointer'}}></canvas>
          <canvas id = "drag_panel" style = {{position: 'fixed', width: '100%', height: '100%', display: 'none', zIndex: '1115'}}/>
        </MDBCol>
      </MDBRow>
      <MDBRow className = "pl-4 pt-3">
        <MDBCol size = '4'>Show Grid</MDBCol>
        <MDBCol>
          <FormControlLabel 
            control={
              <Switch
                color = {'primary'}
                checked={show_grid}
                onChange={changeShowGrid}
                value= 'Yes'
              />
            }
            label = {yes_no}
          />
        </MDBCol>
      </MDBRow>
      <MDBRow className = "pl-4 pt-0">
        <MDBCol size = '10'>Background</MDBCol>
        <MDBCol>
          <MDBRow className = 'px-2 py-2 mb-2'>
            <MDBCol><Button id = 'back_0' onClick = {handleChangeBack.bind(this, 0)} className = {classes.btnStyle} style = {{backgroundColor: 'rgb(220, 180, 120)'}}/></MDBCol>
            <MDBCol><Button id = 'back_1' onClick = {handleChangeBack.bind(this, 1)} className = {classes.btnStyle} style = {{backgroundColor: 'rgb(0, 0, 0)'}}/></MDBCol>
            <MDBCol><Button id = 'back_2' onClick = {handleChangeBack.bind(this, 2)} className = {classes.btnStyle} style = {{backgroundColor: 'rgb(255, 255, 255)'}}/></MDBCol>
          </MDBRow>
        </MDBCol>
      </MDBRow>
    </div>
  );
}
function mapStateToProps(store) {
  return {
    size: store.pdesignBoardReducer.board_size,
    isShowGrid: store.pdesignBoardReducer.isShowGrid,
    board_back: store.pdesignBoardReducer.board_back,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      update_board_size: PDesignBoardAction.updateBoardSize,
      update_show_grid: PDesignBoardAction.updateShowGrid,
      update_background: PDesignBoardAction.updateBackground,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(BoardOption));