import axios from "axios";
import {push} from 'connected-react-router';

import ACTION from '../actionTypes';
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import CD from '../../helper/const';
import {parseError} from '../../helper/utils';
import {/*swal_s, swal_w,*/ notify_s, notify_w, /*notify_e*/} from "../../helper/alert";

var notify_change_coin = (reason, d_coin) => {
  if (!!d_coin) {
    if (d_coin > 0)
      notify_s("coin " + d_coin + " by " + reason);
    else if (d_coin > 0)
      notify_w("coin " + d_coin + " by " + reason);
  }
};

export const get_my_profile = () => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/my_profile', {category: 0});
    const {err, data} = result.data;      
    if (err === ErrorCode.SUCCESS)
      dispatch( { type: ACTION.UPDATE_MY_PROFILE, profile: data });
  } catch (error) {
  }
}
export const get_user_profile = (user_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/user_profile', {user_id, category: 0});
    const {err, data} = result.data;
    if (err === ErrorCode.SUCCESS)
      dispatch( { type: ACTION.UPDATE_USER_PROFILE, profile: data });
  } catch (error) {
  }
}
export const req_user_problem = () => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/go/reqUserProblem', {});
    const {user_problem} = result.data;
    dispatch({type: ACTION.UPDATE_GO_USER_PROBLEM, user_problem });
  } catch (error) {
  }
}
export const req_user_partial_game = () => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/go/reqUserPartialGame', {});
    const {user_partial_game} = result.data;
    dispatch({type: ACTION.UPDATE_GO_USER_PARTIAL_GAME, user_partial_game });
  } catch (error) {
  }
}
export const submitTransaction = (user_id, amount, description) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/purchase', {user_id, transaction: {amount, description}});
    const {err, reason, d_coin} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch({type: ACTION.DO_TRANSACTION, transaction: {amount, description}, d_coin});
      notify_change_coin(reason, d_coin);
    }
  } catch (error) {
  }
}

export const initPurchaseCount = () =>  {
  return ({type: ACTION.INIT_PURCHASE_COUNT});  
}

export function update_user_partial_game(user_partial_game) {
  return {
    type: ACTION.UPDATE_GO_USER_PARTIAL_GAME,
    user_partial_game,
  }
}

export function update_award_dlg() {
  return {
    type: ACTION.UPDATE_AWARD_DLG,
  }
}
