import React, { useState, useEffect } from 'react';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import { Redirect, withRouter } from "react-router-dom";
import RTCMultiConnection from './RTCMultiConnection';
import config from "../../helper/config";
import CD from "../../helper/const";

import { makeStyles } from '@material-ui/core/styles';
import {
  Button,
} from '@material-ui/core';
import {
  MDBBtn,
  MDBDataTable,
  MDBRow,
  MDBCol,
} from "mdbreact";
import { TimePicker } from '@material-ui/pickers';

import * as CommonAction from "../../store/actions/common.action";
import * as GoTeacherAction from "../../store/actions/go_teacher.action";
 
const useStyles = makeStyles(theme => ({
  container: {
    display: 'inline',
    minHeight: '83vh',
    paddingTop: '2vh',
  },
  avatarImg: {
    height: '4vh',
    width: '4vh',
    float: 'left',
    paddingRight: '1vh',
  },
}));

const columns = [
  {
    label: window.i18n.t("lecture.room_id"),
    field: "room_id",
    sort: "disabled",
    width: 50
  },
  {
    label: window.i18n.t("lecture.teacher"),
    field: "teacher",
    sort: "disabled",
    width: 80
  },
  {
    label: window.i18n.t("lecture.title"),
    field: "title",
    sort: "disabled",
    width: 200
  },
  {
    label: window.i18n.t("lecture.start"),
    field: "start",
    sort: "disabled",
    width: 100
  },
  {
    label: window.i18n.t("lecture.state"),
    field: "state",
    sort: "disabled",
    width: 100
  },
  {
    label: window.i18n.t("lecture.participant"),
    field: "participants",
    sort: "disabled",
    width: 100
  },
  {
    label: window.i18n.t("lecture.action"),
    field: "action",
    sort: "disabled",
    width: 50
  },
];

function LectureRooms(props) {
  const classes = useStyles();

  const [title, setTitle] = useState("Lecture Title");
  const [start_time, setStartTime] = useState(new Date());

  useEffect(() => {
    if (!props.connection) {
      window.enableAdapter = true; // enable adapter.js
      var connection = new RTCMultiConnection();
      connection.socketURL = config.rtcUrl;
      connection.publicRoomIdentifier = 'lecture';
      connection.socketMessageEvent = 'lecture';
      connection.userid = props.user? props.user.user_id : '';
      connection.enableFileSharing = true; // by default, it is "false".
      connection.autoCloseEntireSession = true;
      connection.session = {
        audio: true,
        video: true,
        data: true
      };
      
      connection.sdpConstraints.mandatory = {
        OfferToReceiveAudio: true,
        OfferToReceiveVideo: true
      };
      
      connection.connectSocket(function(socket) {
        getRooms();
      });

      const getRooms = () => {
        if(!!connection.socket)
          connection.socket.emit('get-public-rooms', connection.publicRoomIdentifier, function(listOfRooms) {
            props.update_lecture_room_list(listOfRooms);
            setTimeout(getRooms, 3000);
          });
        else {
          connection.connectSocket(function(socket) {
            getRooms();
          });
        }
      };

      window.currentUserMediaRequest.mutex = false;
    
      props.reset_rtc_connection(connection);
    }
  }, []);

  useEffect(() => {

  });

  const handleChangeLectureTitle = (e) => {
    setTitle(e.target.value);
  };

  const handleChangeStartTime = (value) => {
    setStartTime(value);
  }

  const handleCreateRoom = (user) => {
    const {connection, lecture_room_list, func} = props;
    if (!user || func != 4)
      return;
    for(var i in lecture_room_list) {
      if (lecture_room_list[i].owner === user.user_id)
        return;
    }
    //check I'm teacher
    connection.extra = {avatar: user.avatar, title: title, start: start_time, status: 'waiting'};
    var room_id = (Math.random() * 100).toString().replace('.', '');
    connection.sessionid = room_id;
    connection.isInitiator = true;
    connection.dontCaptureUserMedia = true;
    connection.open(room_id);
  };

  const handleEnterRoom = (room) => {
    props.history.push('/lecture_room:' + room.sessionid)
  };

  const handleCloseRoom = (room, user) => {
    props.connection.onbeforeunload(false, false);
  };

  const teacher = (owner, avatar) => (
    <div>
      <img alt="avatar" className={classes.avatarImg} src={avatar} />
      <h6 className="dark-grey-text mb-0">{owner}</h6>
    </div>
  );

  var rows = [];
  if (props.func == CD.FUNC.FUNC_LECTURE) {
    props.lecture_room_list.map((r, i) => {
      var extra = r.extra || {};
      if(!!props.user && r.owner === props.user.user_id)
        rows.push({room_id: r.sessionid, teacher: teacher(r.owner, extra.avatar), title: extra.title, 
          start: new Date(extra.start).toLocaleTimeString('en-US', { hour12: true, hour: "numeric", minute: "numeric"}), 
          state: extra.status,
          participants: r.participants.length,
          action: <div><Button onClick={handleEnterRoom.bind(this, r)}>Enter</Button>
          <Button onClick={handleCloseRoom.bind(this, r, props.user)}>Close</Button></div>});
      else
        rows.push({room_id: r.sessionid, teacher: teacher(r.owner, extra.avatar), title: extra.title, 
          start: new Date(extra.start).toLocaleTimeString('en-US', { hour12: true, hour: "numeric", minute: "numeric"}), 
          state: extra.status, participants: r.participants.length,
          action: <Button onClick={handleEnterRoom.bind(this, r)}>Enter</Button>});
    })
  }

  var isTeacher = true;

  var {user} = props;
  return (
    <div className={classes.container}>
      { isTeacher && (
        <React.Fragment>
          <MDBRow className="m-0 px-5 py-3">
            <MDBCol size = "2">
              <h5>{window.i18n.t("lecture.title")} :</h5>
            </MDBCol>
            <MDBCol size = "3">
              <input
                className="form-control form-control-sm mr-3 w-40"
                type="text"
                placeholder={title}
                aria-label="lecture title"
                onChange={handleChangeLectureTitle}
              />
            </MDBCol>
          </MDBRow>
          <MDBRow className="m-0 px-5 py-3">
            <MDBCol size = "2">
              <h5>{window.i18n.t("lecture.start_time")} :</h5>
            </MDBCol>
            <MDBCol >
              <TimePicker value={start_time} format="hh:mm a, MM-dd" onChange={handleChangeStartTime}></TimePicker>
            </MDBCol>
          </MDBRow>
          <MDBRow className="m-0 px-5 py-3">
            <MDBBtn color="cyan" onClick={handleCreateRoom.bind(this, user)}>{window.i18n.t("button.create_room")}</MDBBtn>
          </MDBRow>
        </React.Fragment>
      )}

      <MDBRow className="m-0 px-5 py-3">        
        <MDBDataTable hover theadColor="cyan lighten-3" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data={{columns: columns, rows: rows}} />        
      </MDBRow>
    </div>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    lecture_room_list: store.commonReducer.items,
    connection: store.goTeacherReducer.connection,
    func: store.commonReducer.func,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      reset_rtc_connection: GoTeacherAction.reset_rtc_connection,
      update_lecture_room_list: CommonAction.updateList,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(LectureRooms));
