import {Howl/*, Howler*/} from 'howler'; //for sound play

class SoundManager {
  constructor() {
    this._aSounds = {};
  }

  initSounds = function() {
    let rootUrl = window.location.origin + '/'; //'http://localhost:3000/';
    this._aSounds["putstone"] = new Howl({src: [rootUrl+'assets/sound/putstone.mp3'], preload:true, volume:1.0, onload:this._onload, onend:this._onend});
    this._aSounds["beep"] = new Howl({src: [rootUrl+'assets/sound/beep.wav'], preload:true, volume:1.0, onload:this._onload, onend:this._onend});
    this._aSounds["buttonclick"] = new Howl({src: [rootUrl+'assets/sound/buttonclick.mp3'], preload:true, volume:1.0, onload:this._onload, onend:this._onend});
  }

  playSound = function(name) {
    if(!this._aSounds[name]) {
      console.warn(`!!! Sound Error: ${name}`);
      return;
    }
    this._aSounds[name].play();
  }

  _onload = function() {
  }
  _onend = function() {
  }
}

var g_SM = new SoundManager();
export default g_SM;




