import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = {
  room: {
    countdown: 0,
    complete_draw: false,
    move_histories: [],
  },
};

export default function pdesignReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.LOAD_PDESIGN_ROOM_INFO:
      return {
        ...state,
        room: {
          ...state.room,
          countdown: !!action.countdown ? action.countdown : state.room.countdown,
        },       
      };
    case ACTION.LOAD_PDESIGN_RECORD:
      return {
        ...state,
        room: {
          ...state.room,
          countdown: !!action.game.countdown ? action.game.countdown : state.room.countdown,
          move_histories: !!action.game.board_data ? action.game.board_data : state.room.move_histories,
        }
      };
    default: return state;
  }
}
