
export const MX_BOARD_SIZE = 99;
export const MN_BOARD_SIZE = 9;

export const BOARD_LEN =  MX_BOARD_SIZE * MX_BOARD_SIZE;

export const PIECE_NONE = -1;

export const PIECE_KIND_STONE = 0;
export const PIECE_KIND_RECTANGLE = 1;
export const PIECE_KIND_ALPHABET = 2;
export const PIECE_KIND_NUMBER = 3;
export const PIECE_KIND_MATH_SYMBOL = 4;
export const PIECE_KIND_FRUIT = 5;
export const PIECE_KIND_ANIMAL = 6;

export const MX_PIECES_ONE_KIND = 32;

export const TOOL_PENCIL = 0;
export const TOOL_FIGURE = 1;
export const TOOL_BUCKET = 2;
export const TOOL_DIP = 3;
export const TOOL_ERASER = 4;

export function PIECE(kind, index) { return kind * MX_PIECES_ONE_KIND + index; }
export function KIND(piece) { return parseInt(piece / MX_PIECES_ONE_KIND); }
export function INDEX(piece) { return piece % MX_PIECES_ONE_KIND; }

export function APOS(x, y) { return y * MX_BOARD_SIZE + x; }
export function X(pos) { return pos % MX_BOARD_SIZE; }
export function Y(pos) { return parseInt(pos / MX_BOARD_SIZE); }


class PieceBoard {
  constructor (board_size) {
    this.initialize(board_size);
  }
  initialize(board_size) {
    this.board_size = board_size;
    this.board = new Array(BOARD_LEN).fill(PIECE_NONE);
    this.temp_board = new Array(BOARD_LEN).fill(0);
    this.temp_boards = [];
    this.board_index = 0;
  }

  empty_board() {
    if (!!this.board) this.board = null;
    this.board = new Array(BOARD_LEN).fill(PIECE_NONE);
  }
  set_board_size(board_size) {
    this.board_size = board_size;
  }
  set_piece(x, y, kind, index) {
    this.board[APOS(x,y)] = PIECE(kind, index);
  }
  get_piece(x, y) {
    return this.board[APOS(x,y)];
  }
  get_point_poss(x, y, thick) {
    let poss = [];
    //push middle poss
    for (let i = 0; i <= thick; i ++) {
      for (let j = 0; j <= thick; j ++) {
        poss.push(APOS(x + i, y + j));
      }
    }
    return poss;
  }
  get_line_poss(s_x, s_y, e_x, e_y, thick) {
    let poss = [], poss_1 = [], poss_2 = [];
    var s_X = s_x, e_X = e_x, s_Y = s_y, e_Y = e_y;
    //push ...

    if (s_x > e_x) {
      s_X = e_x;
      e_X =  s_x;
    }
    if (s_y > e_y) {
      s_Y = e_y;
      e_Y = s_y;
    }

    if (s_x == e_x && s_y == e_y) {
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss.push(APOS(s_x + i, s_y + j));
        }
      }
      return poss;
    }

    var k_1 = (e_y - s_y) / (e_x - s_x);
    var k_2 = (e_x - s_x) / (e_y - s_y);

    for (let x = s_X; x <= e_X; x ++) {
      var y = Math.floor(s_y + k_1 * (x - s_x));
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss_1.push(APOS(x + i, y + j));
        }
      }
    }
    
    for (let y = s_Y; y <= e_Y; y ++) {
      var x = Math.floor(s_x + k_2 * (y - s_y));
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss_2.push(APOS(x + i, y + j));
        }
      }
    }
    if (poss_1.length > poss_2.length) poss = poss_1;
    else poss = poss_2;

    return poss;
  }
  get_rectangle_border_poss(s_x, s_y, e_x, e_y, thick, shift) {
    let poss = [];
    var s_X = s_x, e_X = e_x, s_Y = s_y, e_Y = e_y;
    var a, b;
    //push ...
    if (s_x > e_x) {
      s_X = e_x;
      e_X =  s_x;
    }
    if (s_y > e_y) {
      s_Y = e_y;
      e_Y = s_y;
    }

    a = e_X - s_X;
    if (shift) {
      e_Y = s_Y + a;
    }

    for (let x = s_X; x <= e_X; x ++) {
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss.push(APOS(x + i, s_Y + j));
          poss.push(APOS(x + i, e_Y + j))
        }
      }
    }
    for (let y = s_Y; y <= e_Y; y ++) {
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss.push(APOS(s_X + i, y + j));
          poss.push(APOS(e_X + i, y + j))
        }
      }
    }
    return poss;
  }
  get_rectangle_inside_poss(s_x, s_y, e_x, e_y, shift) {
    let poss = [];
    var s_X = s_x, e_X = e_x, s_Y = s_y, e_Y = e_y;
    var a, b;
    //push ...
    if (s_x > e_x) {
      s_X = e_x;
      e_X =  s_x;
    }
    if (s_y > e_y) {
      s_Y = e_y;
      e_Y = s_y;
    }

    a = e_X - s_X;
    if (shift) {
      e_Y = s_Y + a;
    }

    for (let x = s_X; x <= e_X; x ++) {
      for (let y = s_Y; y <= e_Y; y ++) {
        poss.push(APOS(x, y));
      }
    }
    return poss;
  }
  get_ellipse_border_poss(s_x, s_y, e_x, e_y, thick, shift) {
    let poss = [];
    var s_X = s_x, e_X = e_x, s_Y = s_y, e_Y = e_y;
    //push ...
    if (s_x > e_x) {
      s_X = e_x;
      e_X =  s_x;
    }
    if (s_y > e_y) {
      s_Y = e_y;
      e_Y = s_y;
    }


    var a = (e_X - s_X) / 2;
    var b = (e_Y - s_Y) / 2;

    if (shift) {
      if (a > b) {
        a = b;
        e_X = s_X + 2 * a;
      } else if (a < b) {
        b = a;
        e_Y = s_Y +  2 * b;
      }
    }

    if (a == 0 || b == 0) { return null; }

    var o_X = Math.floor(e_X - a);
    var o_Y = Math.floor(e_Y - b);

    for (let x = s_X; x <= e_X; x ++) {
      var delta_x = x - o_X;
      var delta_y = Math.floor(Math.sqrt(b * b - (b * b) * (delta_x * delta_x) / (a * a)));
      var y1 = o_Y + delta_y;
      var y2 = o_Y - delta_y;
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss.push(APOS(x + i, y1 + j));
          poss.push(APOS(x + i, y2 + j));
        }
      }
    }

    for (let y = s_Y; y <= e_Y; y ++) {
      var delta_y = y - o_Y;
      var delta_x = Math.floor(Math.sqrt(a * a - (a * a) * (delta_y * delta_y) / (b * b)));
      var x1 = o_X + delta_x;
      var x2 = o_X - delta_x;
      for (let i = 0; i <= thick; i ++) {
        for (let j = 0; j <= thick; j ++) {
          poss.push(APOS(x1 + i, y + j));
          poss.push(APOS(x2+ i, y + j));
        }
      }
    }

    return poss;
  }
  get_ellipse_inside_poss(s_x, s_y, e_x, e_y, shift) {
    let poss = [];
    var s_X = s_x, e_X = e_x, s_Y = s_y, e_Y = e_y;
    //push ...
    if (s_x > e_x) {
      s_X = e_x;
      e_X =  s_x;
    }
    if (s_y > e_y) {
      s_Y = e_y;
      e_Y = s_y;
    }


    var a = (e_X - s_X) / 2;
    var b = (e_Y - s_Y) / 2;

    if (shift) {
      if (a > b) {
        a = b;
        e_X = s_X + 2 * a;
      } else if (a < b) {
        b = a;
        e_Y = s_Y +  2 * b;
      }
    }
    
    if (a == 0 || b == 0) { return null; }

    var o_X = Math.floor(e_X - a);
    var o_Y = Math.floor(e_Y - b);

    for (let x = s_X; x <= e_X; x ++) {
      var delta_x = x - o_X;
      var delta_y = Math.floor(Math.sqrt(b * b - (b * b) * (delta_x * delta_x) / (a * a)));
      var y1 = o_Y + delta_y;
      var y2 = o_Y - delta_y;
      for (let y = y2; y <= y1; y ++) {
        poss.push(APOS(x, y));
      }
    }
    return poss;
  }
  get_same_piece_region_poss(pos0, size, ref) {
    this.temp_board = new Array(BOARD_LEN).fill(0);
    let poss = [];
    let pos_array = [];
    poss.push(pos0);
    this.temp_board[pos0] = 1;

    while(poss.length > 0) {
      var pos = poss.shift();
      var u_pos = pos - MX_BOARD_SIZE;
      var d_pos = pos + MX_BOARD_SIZE;
      var l_pos = pos - 1;
      var r_pos = pos + 1;

      if (Y(d_pos) < size && this.board[d_pos] == ref && this.temp_board[d_pos] == 0) {
        poss.push(d_pos);
        this.temp_board[d_pos] = 1;
      }
      if (X(pos) < size - 1 && this.board[r_pos] == ref && this.temp_board[r_pos] == 0) {
        poss.push(r_pos);
        this.temp_board[r_pos] = 1;
      }
      if (Y(u_pos) >= 0 && this.board[u_pos] == ref && this.temp_board[u_pos] == 0) {
        poss.push(u_pos);
        this.temp_board[u_pos] = 1;
      }
      if (X(pos) >= 1 && this.board[l_pos] == ref && this.temp_board[l_pos] == 0) {
        poss.push(l_pos);
        this.temp_board[l_pos] = 1;
      }
    }

    for (let i = 0; i < this.temp_board.length; i ++) {
      if(this.temp_board[i] == 1) pos_array.push(i);
    }
    //push ...
    // this.temp_board = new Array(BOARD_LEN).fill(0);
    return pos_array;
  }

  update_temp_boards() {
    if (this.board_index !== this.temp_boards.length - 1){
      var temp_boards_temp = [];
      for (let i = 0; i < this.board_index; i ++) {
        temp_boards_temp.push([].concat(this.temp_boards[i]));
      }
      this.temp_boards = null;
      this.temp_boards = [].concat(temp_boards_temp);
    }
    this.temp_boards.push([].concat(this.board));
    if (this.temp_boards.length > 10) this.temp_boards.shift();
    this.board_index = this.temp_boards.length - 1;
  }

  back_previous_board() {
    this.board_index --;
    if (this.board_index < 0) this.board_index = 0;
    this.board = this.temp_boards[this.board_index];
  }

  back_next_board() {
    this.board_index ++;
    if (this.board_index > this.temp_boards.length - 1) this.board_index = this.temp_boards.length - 1;
    this.board = this.temp_boards[this.board_index];
  }
}

export default PieceBoard = new PieceBoard(MX_BOARD_SIZE);