import ACTION from '../actionTypes';

const initialState = {
    purchase_coin:0,
    purchase_count:0,
    award_open: false,
    user_partial_game: {
        games_ts: 0,
        wins_ts: 0,
        rank_ts: 0,
        games_cg: 0,
        wins_cg: 0,
        rank_cg: 0,
        games_op: 0,
        wins_op: 0,
        rank_op: 0,
        best_ts: [],
        best_cg: [],
        best_op: [],
      },
    user_problem: {
        solved_problems: 0,
        solved_books: 0,
        completed_books: 0,
        wrote_problems: 0,
        wrote_books: 0,
    },
    user_profile: {
        user_id: '',
        user_name: '',
        level: '',
        win: 0,
        lose: 0,
        total: 0,
        coin: 0,
        sex:'',
        prize: {
            medals: [],
            championship: [],
        },
        article: {
            articles: 0,
            votes: 0,
            devotes: 0,
            replied: 0
        },
        backup: [],
        start: '',
        history: {
            go_level: [],
            puzzle_level: [],
            pdesign_level: [],
            ffa_level: [],
            skpni_level:[],
        },
        rank: 0,
        is_teacher: false,
        go_coin:0,
        go_level:1,
        go_total:0,
        go_win:0,
        go_win_on_level:0,
        go_wl:0,
        go_wl_on_level:0,
        puzzle_coin:0,
        puzzle_level:1,
        puzzle_total:0,
        puzzle_win:0,
        puzzle_win_on_level:0,
        puzzle_wl:0,
        puzzle_wl_on_level:0,
        pdesign_coin:0,
        pdesign_level:1,
        pdesign_total:0,
        pdesign_win:0,
        pdesign_win_on_level:0,
        pdesign_wl:0,
        pdesign_wl_on_level:0,
        ffa_coin:0,
        ffa_level:1,
        ffa_total:0,
        ffa_win:0,
        ffa_win_on_level:0,
        ffa_wl:0,
        ffa_wl_on_level:0,
        skpni_coin:0,
        skpni_level:1,
        skpni_total:0,
        skpni_win:0,
        skpni_win_on_level:0,
        skpni_wl:0,
        skpni_wl_on_level:0,
    },
    other_user_profile: {
        user_id: '',
        user_name: '',
        sex: "1",
        avatar: '',
        coin: 0,
        level: 0,
        win: 0,
        lose: 0,
        total: 0,
        prize: {},
        article: {},
    },
}
export default function profileReducer(state=initialState, action){
    switch (action.type) {
        case ACTION.UPDATE_MY_PROFILE:
            return {
                ...state,
                user_partial_game: {
                    ...state.user_partial_game,
                    games_ts: action.profile.train_game.take_stone_games,
                    wins_ts: action.profile.train_game.take_stone_wins,
                    games_cg: action.profile.train_game.capture_group_games,
                    wins_cg: action.profile.train_game.capture_group_wins,
                    games_op: action.profile.train_game.opening_games,
                    wins_op: action.profile.train_game.opening_wins,
                },
                user_profile: {
                    ...state.user_profile,
                    user_id: action.profile.user_id,
                    user_name: action.profile.user_name,
                    level: action.profile.level,
                    win: action.profile.win,
                    lose: action.profile.lose,
                    total: action.profile.total,
                    coin: action.profile.coin,
                    prize: action.profile.prize,
                    article: action.profile.article,
                    backup: action.profile.backup,
                    start: action.profile.registered,
                    history: action.profile.history,
                    rank: action.profile.rank,
                    is_teacher: action.profile.is_teacher,
                    sex:action.profile.sex,
                    go_coin: action.profile.go_coin,
                    go_level: action.profile.go_level,
                    go_total: action.profile.go_total,
                    go_win: action.profile.go_win,
                    go_win_on_level: action.profile.go_win_on_level,
                    go_wl: action.profile.go_wl,
                    go_wl_on_level: action.profile.go_wl_on_level,
                    puzzle_coin: action.profile.puzzle_coin,
                    puzzle_level: action.profile.puzzle_level,
                    puzzle_total: action.profile.puzzle_total,
                    puzzle_win: action.profile.puzzle_win,
                    puzzle_win_on_level: action.profile.puzzle_win_on_level,
                    puzzle_wl: action.profile.puzzle_wl,
                    puzzle_wl_on_level: action.profile.puzzle_wl_on_level,
                    pdesign_coin: action.profile.pdesign_coin,
                    pdesign_level: action.profile.pdesign_level,
                    pdesign_total: action.profile.pdesign_total,
                    pdesign_win: action.profile.pdesign_win,
                    pdesign_win_on_level: action.profile.pdesign_win_on_level,
                    pdesign_wl: action.profile.pdesign_wl,
                    pdesign_wl_on_level: action.profile.pdesign_wl_on_level,
                    ffa_coin: action.profile.ffa_coin,
                    ffa_level: action.profile.ffa_level,
                    ffa_total: action.profile.ffa_total,
                    ffa_win: action.profile.ffa_win,
                    ffa_win_on_level: action.profile.ffa_win_on_level,
                    ffa_wl: action.profile.ffa_wl,
                    ffa_wl_on_level: action.profile.ffa_wl_on_level,
                    skpni_coin: action.profile.skpni_coin,
                    skpni_level: action.profile.skpni_level,
                    skpni_total: action.profile.skpni_total,
                    skpni_win: action.profile.skpni_win,
                    skpni_win_on_level: action.profile.skpni_win_on_level,
                    skpni_wl: action.profile.skpni_wl,
                    skpni_wl_on_level: action.profile.skpni_wl_on_level,
                    start:action.profile.registered,
                },
            };  
        case ACTION.UPDATE_USER_PROFILE:
            return {
                ...state,
                other_user_profile: {
                ...state.other_user_profile,
                user_id: action.profile.user_id,
                user_name: action.profile.user_name,
                sex: action.profile.sex,
                avatar: action.profile.avatar,
                coin: action.profile.coin,
                level: action.profile.level,
                win: action.profile.win,
                lose: action.profile.lose,
                total: action.profile.total,
                prize: action.profile.prize,
                article: action.profile.article,
                },
            };       
        case ACTION.UPDATE_GO_USER_PROBLEM:
            return {
                ...state,
                user_problem: action.user_problem,
            };
        case ACTION.UPDATE_GO_USER_PARTIAL_GAME:
            return {
                ...state,
                user_partial_game: {
                ...state.user_partial_game,
                games_ts: !!action.user_partial_game.games_ts? action.user_partial_game.games_ts : state.user_partial_game.games_ts,
                wins_ts: !!action.user_partial_game.wins_ts? action.user_partial_game.wins_ts : state.user_partial_game.wins_ts,
                rank_ts: !!action.user_partial_game.rank_ts? action.user_partial_game.rank_ts : state.user_partial_game.rank_ts,
                games_cg: !!action.user_partial_game.games_cg? action.user_partial_game.games_cg : state.user_partial_game.games_cg,
                wins_cg: !!action.user_partial_game.wins_cg? action.user_partial_game.wins_cg : state.user_partial_game.wins_cg,
                rank_cg: !!action.user_partial_game.rank_cg? action.user_partial_game.rank_cg : state.user_partial_game.rank_cg,
                games_op: !!action.user_partial_game.games_op? action.user_partial_game.games_op : state.user_partial_game.games_op,
                wins_op: !!action.user_partial_game.wins_op? action.user_partial_game.wins_op : state.user_partial_game.wins_op,
                rank_op: !!action.user_partial_game.rank_op? action.user_partial_game.rank_op : state.user_partial_game.rank_op,
                best_ts: !!action.user_partial_game.best_ts? action.user_partial_game.best_ts : state.user_partial_game.best_ts,
                best_cg: !!action.user_partial_game.best_cg? action.user_partial_game.best_cg : state.user_partial_game.best_cg,
                best_op: !!action.user_partial_game.best_op? action.user_partial_game.best_op : state.user_partial_game.best_op,
                }
            };
        case ACTION.INIT_PURCHASE_COUNT:
            return {
                ...state,
               purchase_count:0,
            };
        case ACTION.DO_TRANSACTION:
            {
                let count = state.purchase_count;
                count ++;
                return {
                    ...state,
                    purchase_coin:action.d_coin,
                    purchase_count:count,
                    //coin add
                };
            }
        case ACTION.UPDATE_AWARD_DLG:
            return {
                ...state,
                award_open:!state.award_open,
            }
        default:
            return state;
    }
}