import React, { useEffect, useState } from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import {
  MDBRow,
  MDBCol,
  MDBBtn,
  MDBDataTable,
  MDBFormInline,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
} from "mdbreact";

import CD from "../../helper/const";
import PROTOCOL from "../../helper/protocol";

const useStyles = makeStyles(theme => ({
  searchStyle: {
    color: '#ced4da',
  },
  pageNaveStyle: {
    margin: 'auto',
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    margin: 'auto',
    textAlign: 'center',
    width: '80px',
    WebkitAppearance: 'button !important',
  },
}));

function DBUsers(props) {
  const classes = useStyles();
  const [page, setPage] = useState(1);
  const [find, setFind] = useState("");
  const [rowsPerPage, setRowsPerPage] = useState(5);
  const [user_infos, setUserInfos] = useState([]);
  
  useEffect(() => {
    getDBUserList(0, rowsPerPage, find);
    let infos = [];
    for(let i=0; i < rowsPerPage; i++) {
      infos.push({});
    }
    setUserInfos(infos);
  }, []);

  useEffect(() => {
    getDBUserList(0, rowsPerPage, find);
  }, [props.socketLobby]);

  const getDBUserList = (page, rowsPerPage, find) => {
    const {user, socketLobby}= props;
    if (!!socketLobby)  
      socketLobby.emit('admin_message', PROTOCOL.CSC_DB_USER_LIST, {token: user.token, keyword: find, pagesize: rowsPerPage, page: page});
  };

  var allPage = Math.ceil(props.dbuser_count / rowsPerPage);
  if (allPage === 0)
    allPage = 1;

  const handleToFirstPage = () => {
    setPage(1);
    getDBUserList(0, rowsPerPage, find);
  };

  const handleToPrevPage = () => {
    var prePage = page > 1? page - 1 : 1;
    setPage(prePage);
    getDBUserList(prePage - 1, rowsPerPage, find);
  };

  const handleToNextPage = () => {
    var nextPage = page < allPage? page + 1 : allPage;
    setPage(nextPage);
    getDBUserList(nextPage - 1, rowsPerPage, find);
  };

  const handleToLastPage = () => {
    setPage(allPage);
    getDBUserList(allPage - 1, rowsPerPage, find);
  };

  const handleChangeFind = event => {
    setFind(event.target.value);
    setPage(1);
    getDBUserList(0, rowsPerPage, event.target.value);
  };

  const handleChangePage = (event, page) => {
    setPage(page);
    getDBUserList(page, rowsPerPage, find);
  };

  const handleChange = (event, index, user_id) => {
    user_infos[index]["user_id"] = user_id;
    user_infos[index][event.target.name] = event.target.value;
  };

  const handleSave = (index) => {
    const {user, socketLobby}= props;
    let user_info = user_infos[index];
    user_info.token = user.token;
    if (!!socketLobby)  
      socketLobby.emit('admin_message', PROTOCOL.CS_UPDATE_USER_INFO, user_info);
  };

  const handleInit = (index) => {
    const {user, dbuser_list, socketLobby}= props;
    let user_id = dbuser_list[index].user_id;
    if (!!socketLobby)  
      socketLobby.emit('admin_message', PROTOCOL.CS_INIT_USER_INFO, {token: user.token, user_id: user_id});
  };

  const columns_dbuser = [
    {
      label: "No",
      field: "no",
      sort: "disabled",
      width: 70
    },    
    {
      label: "UserID",
      field: "user_id",
      sort: "disabled",
      width: 120,
    },
    {
      label: "Go Lv",
      field: "go_level",
      sort: "disabled",
      width: 120,
    },
    {
      label: "FFA Lv",
      field: "ffa_level",
      sort: "disabled",
      width: 120,
    },
    {
      label: "SKoni Lv",
      field: "skpni_level",
      sort: "disabled",
      width: 120,
    },
    {
      label: "Omok Lv",
      field: "omok_level",
      sort: "disabled",
      width: 120,
    },
    {
      label: "Coin",
      field: "coin",
      sort: "disabled",
      width: 120,
    },
    {
      label: "Action",
      field: "action",
      sort: "disabled",
      width: 120,
    },
    {
      label: "Init",
      field: "init",
      sort: "disabled",
      width: 120,
    },
  ];

  let {func, dbuser_list} = props;
  var rows_dbuser = []; 
  if (func == CD.FUNC.FUNC_ADMIN) {
    dbuser_list.map((n, index) => {
      var no = (page - 1) * rowsPerPage + index + 1;
      var user_id = n.user_id;
      rows_dbuser.push({no, user_id, 
        go_level: <input type="number" name="go_level" onChange={event=>handleChange(event, index, user_id)} style={{border: 'none', width: "40px"}} placeholder={n.go_level}/>, 
        ffa_level: <input type="number" name="ffa_level" onChange={event=>handleChange(event, index, user_id)} style={{border: 'none', width: "40px"}} placeholder={n.ffa_level}/>, 
        skpni_level: <input type="number" name="skpni_level" onChange={event=>handleChange(event, index, user_id)} style={{border: 'none', width: "40px"}} placeholder={n.skpni_level}/>, 
        omok_level: <input type="number" name="omok_level" onChange={event=>handleChange(event, index, user_id)} style={{border: 'none', width: "40px"}} placeholder={n.omok_level}/>,
        coin: <input type="number" name="coin" onChange={event=>handleChange(event, index, user_id)} style={{border: 'none', width: "110px"}} placeholder={n.coin}/>,
        action: <MDBBtn style={{width: '30%', height: '2vh', fontSize:'1.2vh', padding: "0.4vh"}} onClick={event=>handleSave(index)}>save</MDBBtn>,
        init: <MDBBtn style={{width: '30%', height: '2vh', fontSize:'1.2vh', padding: "0.4vh"}} onClick={event=>handleInit(index)}>init</MDBBtn>});
    });
  }

  return (
    <div>
      <MDBRow className="px-4 pt-2">
        <MDBCol size="2">
        <h5 className="font-weight-bold dark-grey-text">DB Users</h5>
        </MDBCol>
        <MDBCol size="2">
          <MDBFormInline className="md-form active-cyan-2 float-left">
              <input
                className="form-control form-control-sm mr-2 w-20"
                type="text"
                placeholder={window.i18n.t("records.search")}
                aria-label={window.i18n.t("records.search")}
                value={find}
                onChange={handleChangeFind}
              />
              <i className={classes.searchStyle + " fa fa-search"} />
          </MDBFormInline>
        </MDBCol>
        <MDBCol size="2">
          <MDBPagination className="float-right">
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToFirstPage}>&laquo;</MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToPrevPage}>&lsaquo;</MDBPageNav>
            </MDBPageItem>
              <input
                type="text"
                value={page + "/" + allPage}
                readOnly={true}
                className={classes.pagenationInputStyle}
              />
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToNextPage}>&rsaquo;</MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToLastPage}>&raquo;</MDBPageNav>
            </MDBPageItem>
          </MDBPagination>
        </MDBCol>
      </MDBRow>
      <MDBRow className="px-4 pb-2">
        <MDBDataTable hover theadColor="cyan lighten-3" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="75vh" data={{columns: columns_dbuser, rows:rows_dbuser}} />
      </MDBRow>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  func: store.commonReducer.func,
  dbuser_list: store.commonReducer.items,
  dbuser_count: store.commonReducer.total,
  socketLobby: store.commonReducer.socketLobby,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(DBUsers));
