import ACTION from '../actionTypes';
import PCD from '../../components/puzzle/puzzleConst';

export const update_proc_action_data = (pt_first_pos, pt_last_pos, last_selected_index,
  user_cell_board,
  lb_down_pos, pair_move_count,
  stick_remove_count, stick_total_action_count, stick_move_count,
  array_solve_data) => dispatch => {
  dispatch({ type: ACTION.UPDATE_PUZZLE_PROC_ACTION_DATA, 
    pt_first_pos, pt_last_pos, last_selected_index, 
    user_cell_board,
    lb_down_pos, pair_move_count,
    stick_remove_count, stick_total_action_count, stick_move_count,
    array_solve_data
  });
}
export function clear_board_data() {
  let boardPoint = [];
  let boardBorder = [];
  let boardInside = [];
  let blockBoardPoint = [];
  let blockBoardBorder = [];
  let blockBoardInside = [];
  for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
    boardPoint.push(new Array(PCD.MAX_BOARD_SIZE).fill(PCD.EMPTY_DATA));
    blockBoardPoint.push(new Array(PCD.MAX_BOARD_SIZE).fill(PCD.EMPTY_DATA));
  }
  for(let j = 0; j < 4; j ++) {
    boardBorder.push([]);
    blockBoardBorder.push([]);
    for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
      boardBorder[j].push(new Array(PCD.MAX_BOARD_SIZE).fill(PCD.EMPTY_BORDER));
      blockBoardBorder[j].push(new Array(PCD.MAX_BOARD_SIZE).fill(PCD.EMPTY_BORDER));
    }
  }
  for(let j = 0; j < 2; j ++) {
    boardInside.push([]);
    blockBoardInside.push([]);
    for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
      boardInside[j].push(new Array(PCD.MAX_BOARD_SIZE).fill(PCD.EMPTY_DATA));
      blockBoardInside[j].push(new Array(PCD.MAX_BOARD_SIZE).fill(PCD.EMPTY_DATA));
    }
  }
  console.log('clear_board_data');
  return {
    type: ACTION.UPDATE_PUZZLE_BOARD,
    boardPoint,
    boardBorder,
    boardInside,
    blockBoardPoint,
    blockBoardBorder,
    blockBoardInside,
  }
}

export function update_board_data(_boardPoint, _boardBorder, _boardInside) {
  let boardPoint = [];
  let boardBorder = [];
  let boardInside = [];
  for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
    boardPoint.push([]);
    boardPoint[i] = [].concat(_boardPoint[i]);
  }
  for(let j = 0; j < 4; j ++) {
    boardBorder.push([]);
    for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
      boardBorder[j].push([]);
      boardBorder[j][i] = [].concat(_boardBorder[j][i]);
    }
  }
  for(let j = 0; j < 2; j ++) {
    boardInside.push([]);
    for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
      boardInside[j].push([]);
      boardInside[j][i] = [].concat(_boardInside[j][i]);
    }
  }
  console.log('update_board_data');
  return {
    type: ACTION.UPDATE_PUZZLE_BOARD,
    boardPoint,
    boardBorder,
    boardInside,
  }
}

export function update_block_board_data(_blockBoardPoint, _blockBoardBorder, _blockBoardInside) {
  let blockBoardPoint = [];
  let blockBoardBorder = [];
  let blockBoardInside = [];
  for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
    blockBoardPoint.push([]);
    blockBoardPoint[i] = [].concat(_blockBoardPoint[i]);
  }
  for(let j = 0; j < 4; j ++) {
    blockBoardBorder.push([]);
    for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
      blockBoardBorder[j].push([]);
      blockBoardBorder[j][i] = [].concat(_blockBoardBorder[j][i]);
    }
  }
  for(let j = 0; j < 2; j ++) {
    blockBoardInside.push([]);
    for(let i = 0; i < PCD.MAX_BOARD_SIZE; i ++) {
      blockBoardInside[j].push([]);
      blockBoardInside[j][i] = [].concat(_blockBoardInside[j][i]);
    }
  }
  console.log('update_black_board_data');
  return {
    type: ACTION.UPDATE_PUZZLE_BOARD,
    blockBoardPoint,
    blockBoardBorder,
    blockBoardInside,
  }
}

export function set_lb_down_pt(pt) {
  return {
    type: ACTION.SET_LB_DOWN_PT,
    pt
  }
}

export function set_mouse_move_pt(pt) {
  return {
    type: ACTION.SET_MOUSE_MOVE_PT,
    pt
  }
}

export function update_board() {
  return {
    type: ACTION.UPDATED_PUZZLE_BOARD,
  }
}

export function show_digit_edit(pt, show_hide) {
  return {
    type: ACTION.SHOW_DIGIT_EDIT,
    show_hide,
    pt,
  }
}

export function edited_number(number) {
  return {
    type: ACTION.EDITED_NUMBER,
    number,
  }
}

