import React, {useState,useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import {
  Button,
  Avatar
} from '@material-ui/core';
import * as Icon from "@material-ui/icons";
import { makeStyles } from '@material-ui/core/styles';
import * as AuthAction from '../../store/actions/auth.action';
import * as CommonAction from "../../store/actions/common.action";
import { bindActionCreators } from 'redux';
import {
  MDBRow, 
  MDBBtn,
} from "mdbreact";
import CD from "../../helper/const";
import {notify_w} from "../../helper/alert";

const useStyles = makeStyles(theme => ({  
  createStyle: {
    justifyContent: 'left',
    width: '14.5vw',
    paddingLeft: '3vw',
    color: 'black',
    fontSize:'1vw',
    borderRadius:'unset',
    borderColor:'none',
    boxShadow: 'none',
    textTransform: 'unset'
  },
  avatarImg: {
    marginTop:'7vh',
    height: '6vw',
    width: '6vw',   
    marginLeft:'auto',
    marginRight:'auto',
  },
}));

const menuItems = ['play', 'records', 'tournaments', 'training', 'lecture', 'rank', 'profile', 'forum', 'task','time_clock', 'landing', ];
const btnColor1 = '#2bbbad';
const btnColor2 = '#30f0c0';

function Side(props) {
  const classes = useStyles();
  const { updateStoredUrl } = props;
  const initBackGroundOfButtons = ()=>{
    menuItems.map((id, index)=>{
      if (document.getElementById(id)) {
        document.getElementById(id).style.color = 'black';
        document.getElementById(id).style.backgroundColor = 'white';
      }
    });
  }
  useEffect(()=>{
    initBackGroundOfButtons();
    let item = menuItems[props.func];
    if (document.getElementById(item)) {
      document.getElementById(item).style.color = 'white';
      document.getElementById(item).style.backgroundColor = 'rgb(0, 180, 210)';
    }  
  },[props.func]);
  useEffect(()=>{
  }, [props.user]);
 
  const handlePlay = ()=>{
    updateStoredUrl('/lobby');
    props.history.push('/lobby');
  };
  const handleRecords = ()=>{
    updateStoredUrl('/records');
    props.history.push('/records');
  };
  const handleTournament = ()=>{
    updateStoredUrl('/tournaments');
    props.history.push('/tournaments');
  };
  const handleTraining = ()=>{
    updateStoredUrl('/training');
    props.history.push('/training');
  };
  const handleLecture = ()=>{
    updateStoredUrl('/lecture');
    props.history.push('/lecture');
  };
  const handleRank = ()=>{
    updateStoredUrl('/rank');
    props.history.push('/rank');
  };
  const handleProfile = ()=>{
    let {user} = props;
    updateStoredUrl('/profile');
    if(!!user){
      props.history.push('/profile');
    } else {
      notify_w('Sorry! Please log in');
      props.history.push('/login');
    }   
  };
  const handleForum = ()=>{
    updateStoredUrl('/forum');
    props.history.push('/forum');
  };
  const handleTask = ()=>{
    let {user} = props;
    updateStoredUrl('/task');
    if(!!user)
      props.history.push('/task');
    else {
      notify_w('Sorry! If you do not log on, no validate');
    }
  };

  const handleClock = ()=>{
    let {user} = props;
    updateStoredUrl('/time_clock');
    if(!!user)
      props.history.push('/time_clock');
    else {
      notify_w('Sorry! If you do not log on, no validate');
    }
  };
 
  let {user} = props;

  return (
    <div style = {{position:"absolute", top:"7vh", left:"0px", width:"14.5vw", marginRight:"0", height:"87.5vh", borderRight: "solid", borderRightColor: 'lightBlue', borderRightWidth: '0.05vw'}}>
      {
        (!!user && !!user.user_id) && (
          <div><Avatar alt="Profile Picture" className={classes.avatarImg} src={user.avatar}/>
          <br/><h4 style = {{textAlign:'center', fontSize:'1.2vw', marginBottom: '3vh'}}>{user.user_id} (<i className={" fa fa-star"} style = {{fontSize:'1vw', color:'orange'}}></i><small style = {{fontSize:'1vw'}}>{user.coin}</small>) </h4> </div>
        )
      }
      {
        (!user || !user.user_id) && (
          <div><Avatar alt="Profile Picture" className={classes.avatarImg}  src={"assets/img/avatar-1.png"}/>
          <br/><br/> </div>
        )  
      } 
      <Button id = 'play' variant="contained" className={classes.createStyle}  onClick = {handlePlay}>
        <i  className="fa fa-adjust pr-2" style={{color: props.func == CD.FUNC.FUNC_PLAY? btnColor2 : btnColor1}}/>{window.i18n.t("menu.play")}          
      </Button>
      <Button id='records' variant="contained" className={classes.createStyle} onClick = {handleRecords}>
        <i  className="fa fa-video-camera pr-2" style={{color: props.func == CD.FUNC.FUNC_RECORDS? btnColor2 : btnColor1}} />{window.i18n.t("menu.records")}     
      </Button>    
      <Button id='tournaments' variant="contained"  className={classes.createStyle} onClick = {handleTournament}>
        <i  className="fa fa-trophy pr-2" style={{color: props.func == CD.FUNC.FUNC_TOURNAMENTS? btnColor2 : btnColor1}}/>{window.i18n.t("menu.tournaments")}   
      </Button>
      <Button id='training' variant="contained" className={classes.createStyle} onClick = {handleTraining}>
        <i  className="fa fa-random pr-2" style={{color: props.func == CD.FUNC.FUNC_TRAINING? btnColor2 : btnColor1}}/>{window.i18n.t("menu.training")}          
      </Button>
      <Button id = 'lecture' variant="contained" className={classes.createStyle} onClick = {handleLecture}>
        <i  className="fa fa-bell pr-2" style={{color: props.func == CD.FUNC.FUNC_LECTURE? btnColor2 : btnColor1}}/>{window.i18n.t("menu.lecture")}         
      </Button>
     
      <Button id = 'rank' variant="contained" className={classes.createStyle} onClick = {handleRank}>
        <i  className="fa fa-sort-numeric-asc pr-2" style={{color: props.func == CD.FUNC.FUNC_RANK? btnColor2 : btnColor1}}/>{window.i18n.t("menu.rank")}          
      </Button> 
      <Button id = 'profile' variant="contained" className={classes.createStyle} onClick = {handleProfile}>
        <i  className="fa fa-line-chart pr-2" style={{color: props.func == CD.FUNC.FUNC_PROFILE? btnColor2 : btnColor1}}/>{window.i18n.t("menu.profile")}          
      </Button>   
      <Button id = 'forum' variant="contained" className={classes.createStyle} onClick = {handleForum}>
        <i  className="fa fa-edit pr-2" style={{color: props.func == CD.FUNC.FUNC_FORUM? btnColor2 : btnColor1}}/>{window.i18n.t("menu.forum")}         
      </Button>   
      <Button id = 'task' variant="contained" className={classes.createStyle}  onClick = {handleTask}>
        <i  className="fa fa-check-square-o pr-2" style={{color: props.func == CD.FUNC.FUNC_TASK? btnColor2 : btnColor1}}/>{window.i18n.t("menu.task")}        
      </Button> 
      <Button id = 'time_clock' variant="contained" className={classes.createStyle}  onClick = {handleClock}>
        <i  className="fa fa-clock-o pr-2" style={{color: props.func == CD.FUNC.FUNC_TIME_CLOCK? btnColor2 : btnColor1}}/>{window.i18n.t("menu.time_clock")}        
      </Button> 
    </div>
  );
}
function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    language: store.commonReducer.language,
    func:store.commonReducer.func,
    updateUser:store.authReducer.updateUser,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      logoutUser : AuthAction.logoutUser,
      showHiddenSideBar:CommonAction.show_hidden_sidebar,
      updateStoredUrl:AuthAction.updateStoredUrl,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Side));