import ACTION from '../actionTypes';
import * as PBC from '../../components/puzzle/puzzleBaseClasses';

const initialState = {
  problem_index: 0,
  solve_result: '',
  view_state: 0,
  array_candidate_index: new PBC.INT_ARRAY(),
  extra_indices: [],
  cur_extra_index: -1,
  complete_solve: false,
  problem_num_set: 0,
  problem: {
    _id: '',
    solved: false,
    retried: 0,
    solved_time: 0,
    prob_type: "",
    prob_comment: "",
    solution_type: 0,
    board_type: 1,
    array_extra_data: [],
    array_action_data: [],
    time_count_type: 0,
    time_over1: 300,
    time_over2: 0,
    success_effect: 0,
    success: "",
    success_res_id: 0,
    fail_effect: 0,
    fail: "",
    fail_res_id: 0,
    array_answer_data: [],
    hint_comment: "",
    score: 0,
    score_per_error: 0,
  }, 
};

export default function puzzleProblemReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.LOAD_PUZZLE_PROBLEM:
      return {
        ...state,
        problem_index: action.problem_index,
        solve_result: '',
        complete_solve: false,
        problem: {
          ...state.problem,
          _id: action.problem._id,
          prob_type: action.problem.prob_type,
          prob_comment: action.problem.prob_comment,
          solution_type: action.problem.solution_type,
          board_type: action.problem.board_type,
          array_extra_data: action.problem.array_extra_data,
          array_action_data: action.problem.array_action_data,
          time_count_type: action.problem.time_count_type,
          time_over1: action.problem.time_over1,
          time_over2: action.problem.time_over2,
          success_effect: action.problem.success_effect,
          success: action.problem.success,
          success_res_id: action.problem.success_res_id,
          fail_effect: action.problem.fail_effect,
          fail: action.problem.fail,
          fail_res_id: action.problem.fail_res_id,
          array_answer_data: action.array_answer_data,
          hint_comment: action.problem.hint_comment,
          score: action.problem.score,
          score_per_error: action.problem.score_per_error,
        }
      };
    case ACTION.RESOLVE_PUZZLE_PROBLEM:
      return {
        ...state,
        solve_result: '',
        complete_solve: false,
        problem: {
          ...state.problem,
          solved: action.solved,
          retried: action.retried,
          solved_time: action.time,
        }
      };
    case ACTION.SET_PUZZLE_STATE:
      return {
        ...state,
        view_state: action.new_state,
      }
    case ACTION.COMPLETE_SOLVE_PUZZLE:
      return {
        ...state,
        complete_solve: true,
      }
    case ACTION.SET_CUR_EXTRA_INDEX:
      return {
        ...state,
        cur_extra_index: action.cur_extra_index,
      }
    case ACTION.SET_EXTRA_INDICES:
      return {
        ...state,
        extra_indices: action.extra_indices,
      }
    case ACTION.RESET_CUR_EXTRA_INDEX:
      return {
        ...state,
        cur_extra_index: -1,
      }
    case ACTION.RESET_EXTRA_INDICES:
      return {
        ...state,
        extra_indices: new Array(state.extra_indices.length).fill(false),
      }
    case ACTION.SET_PROB_INDEX:
      return {
        ...state,
        problem_index: action.prob_idx,
      }
    default: return state;
  }
}
