import React, { useState, useEffect } from 'react';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import { withRouter } from "react-router-dom";
import { makeStyles } from '@material-ui/core/styles';
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';

import {
  MenuItem,
  Select,
} from "@material-ui/core";
import {
  MDBBtn,
  MDBDataTable,
  MDBRow,
  MDBCol,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
  MDBFormInline,
  MDBListGroupItem,
} from "mdbreact";

import CD from "../../helper/const";
import { notify_w } from "../../helper/alert";

import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as AuthAction from "../../store/actions/auth.action";


const useStyles = makeStyles(theme => ({
  container: {
    width: "95%",
    minHeight: '83vh',
    paddingTop: '2vh',
  },
  searchStyle: {
    color: '#ced4da',
  },
  pageNaveStyle: {
    padding: 0,
    paddingBottom: 0,
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    marginTop: '6px',
    marginLeft: '3px',
    marginRight: '3px',
    textAlign: 'center',
    width: '80px',
    WebkitAppearance: 'button !important',
  },
}));

function PuzzleTraining(props) {
  const classes = useStyles();
  const [page, setPage] = useState(1);
  const [rowsPerPage, setRowsPerPage] = useState(10);
  const [find, setFind] = useState("");
  const [game_type, setGameType] = useState("");
  const problem_book_columns = [
    {
      label: window.i18n.t("train.title"),
      field: "title",
      sort: "disabled",
      width: 150,
    },
    {
      label: window.i18n.t("train.rating"),
      field: "rating",
      sort: "disabled",
      width: 100,
    },
    {
      label: window.i18n.t("train.type"),
      field: "type",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.description"),
      field: "description",
      sort: "disabled",
      width: 150
    },
    {
      label: window.i18n.t("train.difficulty"),
      field: "difficulty",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.problems"),
      field: "problems",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.user"),
      field: "author",
      sort: "disabled",
      width: 100
    },
    {
      label: window.i18n.t("train.updated"),
      field: "updated",
      sort: "disabled",
      width: 150
    },
  ];

  useEffect(() => {
    const {user, req_problem_book_list} = props;
    req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, rowsPerPage, page - 1);
    props.setFunc(CD.FUNC.FUNC_TRAINING);
  }, []);

  useEffect(() => {
    const {game_type} = props;
    setGameType(game_type);
  });

  const RatingObj = ({
    review: { rating, reviews }
  }) => (
    <MDBListGroupItem
      className="p-0 border-0"
      style={{ backgroundColor: "transparent" }}
    >
      <Rater total={5} rating={reviews > 0? rating / reviews : 0} interactive={true} style={{fontSize:'1rem'}}/>
      <div>
      {reviews}
      </div>
    </MDBListGroupItem>
  );

  const loadPuzzleBook = (id) => {
    const { history, user } = props;
    if(!!user)
      history.push('/solve_puzzle_problem:'+id);
    else {
      notify_w("First, you have to login!");
      props.history.push('/login');
    }
  };

  var allPage = Math.ceil(props.problem_book_count / rowsPerPage);
  if (allPage === 0)
    allPage = 1;

  const handleToFirstPage = () => {
    setPage(1);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, rowsPerPage, 0);
  };

  const handleToPrevPage = () => {
    var prePage = page > 1? page - 1 : 1;
    setPage(prePage);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, rowsPerPage, prePage - 1);
  };

  const handleToNextPage = () => {
    var nextPage = page < allPage? page + 1 : allPage;
    setPage(nextPage);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, rowsPerPage, nextPage - 1);
  };

  const handleToLastPage = () => {
    setPage(allPage);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, rowsPerPage, allPage - 1);
  };

  const handleChangeFind = event => {
    setFind(event.target.value);
    setPage(1);
  };

  const handleChangePage = (event, page) => {
    setPage(page);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, rowsPerPage, page - 1);
  };

  const handleChangeRowsPerPage = event => {
    setRowsPerPage(event.target.value);
    setPage(1);
    props.req_problem_book_list(CD.PROBLEM_CATEGORY.PUZZLE, event.target.value, 0);
  };

  function handleChange(value) {
  }

  var problem_books = [];
  if(props.func == CD.FUNC.FUNC_TRAINING) {
    props.problem_book_list.map((el, index) => el)
    // .slice((page - 1) * rowsPerPage, page * rowsPerPage)
    .map((n) => {
      problem_books.push({title: n.title, review: <RatingObj review={{rating: n.total_rating, reviews: n.reviews}} />, 
        type: n.type, description: 'Challenge to high technique', difficulty: n.difficulty, problems: n.problems, 
        author: n.created_by, updated: new Date(n.updated).toLocaleString(),
        clickEvent: () => {loadPuzzleBook(n._id)}});
    });
  }
  return (
    <div className={classes.container} style = {{display: game_type == CD.GAME_TYPE.PUZZLE? "" : "none"}}>
      <MDBRow className="mx-0 px-5 mt-5">
        <h4><strong>{window.i18n.t("train.total_problems")}</strong></h4>
      </MDBRow>
      <MDBRow className="pl-5 ml-5 mt-1" >
        <MDBCol>
          <MDBFormInline className="md-form active-cyan-2 float-left">
            <input
              className="form-control form-control-sm mr-3 w-30"
              type="text"
              placeholder = {window.i18n.t("records.search")}
              aria-label = {window.i18n.t("records.search")}
            />
            <i className={classes.searchStyle + " fa fa-search"} />
          </MDBFormInline>
          
        </MDBCol>
        <MDBCol>
          <span className="px-2 pt-2">{window.i18n.t("records.sort_by")}</span>
          <Select
            value={'created_date'}
            style={{ width: 150 }}
            className="pr-4"
            onChange={handleChange}
          >
            <MenuItem value="created_date">{window.i18n.t("records.create_date")}</MenuItem>
          </Select>
        </MDBCol>
        
        <MDBCol >
          <span className="px-2 pt-2">{window.i18n.t("records.view")}</span>
          <Select
            value={10}
            style={{ width: 150 }}
            className="pr-4"
            onChange={handleChange}
          >
            <MenuItem value={6}>{window.i18n.t("game.line").replace("{0}", 6)}</MenuItem>
            <MenuItem value={10}>{window.i18n.t("game.line").replace("{0}", 10)}</MenuItem>
          </Select>
        </MDBCol>
        <MDBCol>
          <MDBPagination className="float-right">
            <span className="px-1 pt-2">{window.i18n.t("records.page")}</span>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToFirstPage}>&laquo;</MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToPrevPage}>&lsaquo;</MDBPageNav>
            </MDBPageItem>
              <input
                type="text"
                value={page + "/" + allPage}
                readOnly={true}
                className={classes.pagenationInputStyle}
              />
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToNextPage}>&rsaquo;</MDBPageNav>
            </MDBPageItem>
            <MDBPageItem>
              <MDBPageNav className={classes.pageNaveStyle} onClick={handleToLastPage}>&raquo;</MDBPageNav>
            </MDBPageItem>
          </MDBPagination>
        </MDBCol>
      </MDBRow>
      <div className="my-3 pl-5 ml-5">
        <MDBDataTable hover style = {{lineHeight: 1, }} theadColor = {'cyan lighten-3'} displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="70vh" data={{columns: problem_book_columns, rows: problem_books}} />
      </div>
    </div>
  );
}

function mapStateToProps(store) {
  return {
    isAuth: store.authReducer.isAuth,
    user: store.authReducer.user,
    problem_book_count: store.commonReducer.total,
    problem_book_list: store.commonReducer.items,
    game_type: store.commonReducer.content,
    func: store.commonReducer.func,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      req_problem_book_list: CommonAction.req_problem_book_list,
      setFunc: CommonAction.setFunc,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(PuzzleTraining));
