import React, { Component } from 'react';

function Dot(x, y, color){
    this.x = x;
    this.y = y;
    this.color = color;
    this.vx = Math.random().toFixed(2) > 0.5 ? -1.0 * (Math.random().toFixed(2) - .8) : 
                Math.random().toFixed(2) * (Math.random().toFixed(2) - .8);
    this.vy = Math.random().toFixed(2) > 0.5 ? -1.0 * (Math.random().toFixed(2) - .8) :
                 Math.random().toFixed(2) * (Math.random().toFixed(2) - .8);
    
    this.radius = 10 * Math.random();
}

Dot.prototype = {
    create: function(ctx){
        ctx.fillStyle = this.color;
        ctx.beginPath();
        ctx.arc(this.x, this.y, this.radius, 0, Math.PI * 2, false);
        ctx.fill();
    },

    animate: function(dots, canvas){
        for(var i = 0, dot=false; i < dots.nb; i++){
            dot = dots.array[i];
            if(dot.y < 0 || dot.y > canvas.height){
                dot.vx = dot.vx;
                dot.vy = - dot.vy;
            }else if(dot.x < 0 || dot.x > canvas.width){
                dot.vx = - dot.vx;
                dot.vy = dot.vy;
            }
            dot.x += dot.vx;
            dot.y += dot.vy;
        }
    },

    line: function(ctx, dots, mousePosition){
        for(var i = 0; i < dots.nb; i++){
            for(var j = 0; j < dots.nb; j++){
                var i_dot = dots.array[i];
                var j_dot = dots.array[j];

                if((i_dot.x - j_dot.x) < dots.distance && (i_dot.y - j_dot.y) < dots.distance && (i_dot.x - j_dot.x) > - dots.distance && (i_dot.y - j_dot.y) > - dots.distance){
                    if((i_dot.x - mousePosition.x) < dots.d_radius && (i_dot.y - mousePosition.y) < dots.d_radius && (i_dot.x - mousePosition.x) > - dots.d_radius && (i_dot.y - mousePosition.y) > - dots.d_radius){
                        ctx.beginPath();
                        ctx.moveTo(i_dot.x, i_dot.y);
                        ctx.lineTo(j_dot.x, j_dot.y);
                        ctx.stroke();
                        ctx.closePath();
                    }
                }
            }
        }
    }
};

class SparkLine extends Component {
    constructor(){
        super();
        this.state = {
            canvas: null,
            ctx: null
        }
        this.mousePosition = {
            x: 0,
            y: 0
        }
        this.dots = {
            nb: 150,
            distance: 50,
            d_radius: 150,
            array: []
        }
        this.createDots = this.createDots.bind(this);
    }


    createDots() {
        this.state.ctx.clearRect(0, 0, this.state.canvas.width, this.state.canvas.height);
        for(var i = 0; i < this.dots.nb; i++) {
            var color = "rgba(255, 99, 71, 0.5)";
            this.dots.array.push(new Dot(this.state.canvas.width * Math.random(), this.state.canvas.height * Math.random(), color));
            var dot = this.dots.array[i];

            dot.create(this.state.ctx);
        }
        dot.line(this.state.ctx, this.dots, this.mousePosition);
        dot.animate(this.dots, this.state.canvas);
    }

    handleMouseMoveOnCanvas = (e) => {
        if(e.type === 'mousemove'){
            this.mousePosition.x = e.pageX;
            this.mousePosition.y = e.pageY;
        }
        if(e.type === 'mouseleave'){
            this.mousePosition.x = this.state.canvas.width / 2;
            this.mousePosition.y = this.state.canvas.height / 2;
        }
    }

    componentDidMount () {
        this.state.canvas = document.querySelector('.dot-line-canvas');
        this.state.canvas.width = window.innerWidth;
        this.state.canvas.height = window.innerHeight;
        this.state.canvas.style.display = 'block';
        this.state.ctx = this.state.canvas.getContext('2d');
        var color = 'lightblue';
        this.state.ctx.fillStyle = color;
        this.state.ctx.lineWidth = .5;
        this.state.ctx.strokeStyle = color;
        setInterval(this.createDots, 1000 / 30);
    }

    render () {
        return (
            <canvas 
                className="dot-line-canvas" 
                onMouseMove={(e) => this.handleMouseMoveOnCanvas(e)} 
                onMouseLeave={(e) => this.handleMouseMoveOnCanvas(e)} 
                style={{ position: "fixed", zIndex: 0}}></canvas>
        );
    }

}

export default SparkLine;
