import ACTION from '../actionTypes';

const initialState = {
  in_list: [],
  sent_list: [],
  draft_list: [],
  trash_list: [],
  message: {
    _id: '',
    sender_id: '',
    sender_avatar: '',
    sender_name: '',
    to: [],
    read: false,
    type: '',
    subject: '',
    content: '',
    attach_files: [],
    time: '',
  }
};

export default function messageReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_MSG_LIST:
      return {
        ...state,
        in_list: action.in_list,
        sent_list: action.sent_list,
        draft_list: action.draft_list,
        trash_list: action.trash_list,
      };
    case ACTION.UPDATE_MSG_CONTENT:
      return {
        ...state,
        message: action.message,
      };
    default: return state;
  }
}
