export function INT_ARRAY() {
  this.type = 0;
  this.dataArray = [];
  this.Init = () => {
    this.type = 0;
    this.dataArray = [];
  };
  this.IsEqual = (objectOther, bSeq /*= true*/, bIgnorType /*= false*/ ) => {
    if (!bIgnorType)
    {
      if (this.type != objectOther.type)
        return false;
    }
    let nCount = this.dataArray.length;
    if (nCount != objectOther.dataArray.length)
      return false;
    let nSum = 0;
    for (let i = 0; i < nCount; i++)
    {
      if (bSeq)
      {
        if (this.dataArray[i] != objectOther.dataArray[i])
          return false;
      } 
      else
      {
        for (let j = 0; j < nCount; j++)
        {
          if (this.dataArray[i] == objectOther.dataArray[j])
          {
            nSum += i+1;
            break;
          }
        }
      }
    }
    if (!bSeq && nSum != nCount * (nCount + 1) / 2)
      return false;
    return true;
  };
  this.IsIntersect = (objectOther) => {
    let nCount = this.dataArray.length;
    let nCount1 = objectOther.dataArray.length;
    for (let i = 0; i < nCount; i++)
    {
      for (let j = 0; j < nCount1; j++)
      {
        if (this.dataArray[i] == objectOther.dataArray[j])
        {
          return true;
        }
      }
    }
    return false;
  };
  this.IsContainArray = (objectOther, bSeq /*= true*/ ) => {
    let nCount = this.dataArray.length;
    let nCount1 = objectOther.dataArray.length;
    if (nCount < nCount1)
      return false;
    if (bSeq)
    {
      for (let i = 0; i < nCount1; i++)
      {
        if (this.dataArray[i] != objectOther.dataArray[i])
          return false;
      }
      return true;
    } 
    else
    {
      let nSum = 0;
      for (let i = 0; i < nCount; i++)
      {
        for (let j = 0; j < nCount1; j++)
        {
          if (this.dataArray[i] == objectOther.dataArray[j])
          {
            nSum += j+1;
            break;
          }
        }
      }
      if (!bSeq && nSum != nCount1 * (nCount1 + 1) / 2)
        return false;
      return true;
    }
  };
  this.IsContainElement = (n) => {
    for (let i = 0; i < this.dataArray.length; i++)
    {
      if (this.dataArray[i] == n)
        return true;
    }
    return false;
  }
}
export function CPoint(x, y) {
  this.x = parseInt(x);
  this.y = parseInt(y);
}
export function CSize(cx, cy) {
  this.cx = parseInt(cx);
  this.cy = parseInt(cy);
  this.width = () => (this.cx);
  this.height = () => (this.cy);
	this.setWidth = (cx1) => {this.cx = parseInt(cx1);};
	this.setHeight = (cy1) => {this.cy = parseInt(cy1);};
}
export function Rect(x, y, w, h) {
	this.X = parseInt(x);
	this.Y = parseInt(y);
	this.Width = parseInt(w);
	this.Height = parseInt(h);
}
export function CRect(x1, y1, x2, y2) {
  this.left = parseInt(x1);
  this.top = parseInt(y1);
  this.right = parseInt(x2);
  this.bottom = parseInt(y2);
  this.Width = () => (this.right - this.left);
  this.Height = () => (this.bottom - this.top);
	this.CenterPoint = () => { return new CPoint((this.left + this.right) / 2, (this.top + this.bottom) / 2 ); };
	this.PtInRect = (pt) => { return pt.x >= this.left && pt.x < this.right && pt.y >= this.top && pt.y < this.bottom; };
	this.OffsetRect = (x, y) => { this.left += x; this.right += x; this.top += y; this.bottom += y; };
	this.DeflateRect = (dw, dh, dw2, dh2) => {
		this.left += parseInt(dw);
		this.top += parseInt(dh);
		this.right -= parseInt(!!dw2? dw2 : dw);
		this.bottom -= parseInt(!!dh2? dh2 : dh);
	};
}

