import React, { useState, useEffect, useRef } from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import moment from "moment";

import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as GoProblemAction from "../../store/actions/go_problem.action";
import * as GoTrainAction from "../../store/actions/go_train.action";
import * as AuthAction from "../../store/actions/auth.action";
import * as ProfileAction from "../../store/actions/profile.action";
import { makeStyles } from '@material-ui/core/styles';
import {
  Button,
  Select,
  MenuItem,
  LinearProgress,
} from '@material-ui/core';
import {
  MDBBtn,
  MDBRow,
  MDBCol,
  MDBPagination, 
  MDBPageItem, 
  MDBPageNav,
  MDBSimpleChart,
  MDBScrollbar,
  MDBListGroup,
  MDBListGroupItem,
} from "mdbreact";
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';
import Board from "../go/board";
import ReviewAndRate from "../review/ReviewAndRate";

const useStyles = makeStyles(theme => ({
  boardStyle: {
    width: '100%',
  },
  leftPanelStyle: {
    paddingLeft: '2vw',
  },
  scrollableStyle: {
    height: '20vh',
  },
  scrollItem: {
    marginBottom: 0,
    border: 0,
    borderBottom: '1px solid',
  },
  pageNaveStyle: {
    padding: 0,
    paddingBottom: 0,
    paddingLeft: 5,
    paddingRight: 5,
    fontSize: '2rem !important',
  },
  pagenationInputStyle: {
    height: 'min-content',
    marginTop: '6px',
    marginLeft: '3px',
    marginRight: '3px',
    textAlign: 'center',
    color: "dark-grey",
    width: '80px',
    WebkitAppearance: 'button !important',
    fontSize: '1.3rem',
  },
  navigationButtons: {
    width: '12vw',
    height: '8vh',
    background: '#ffffff',
    fontSize: '2.5vh',
    marginLeft: 'auto',
    marginRight: 'auto'
  },
  navigationButton1: {
    minWidth:'3vw',
    width:'3vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    color: "#404040",
  },
  navigationButton: {
    minWidth:'3vw',
    width:'3vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    borderLeft: 'none',
    color: "#404040",
  },
  progressStyle: {
    backgroundColor: '#00f000'
  }
}));

function GoSolveProblem(props) {
  const classes = useStyles();
  const timeoutRef = useRef(null);
  const [openReviewAndRate, setOpenReviewAndRate] = useState(false);

  const Review = ({ review: { user_id, rating, text, date } }) => (
    <MDBListGroupItem
      className={classes.scrollItem+" d-flex justify-content-between p-2 border-light text-muted"}
      // style={{ backgroundColor: active ? "#eeeeee" : "" }}
    >
      <div style={{ fontSize: "0.95rem" }}>
        <i className="la la-user la-lg pr-1" />
        <strong>{user_id}</strong>
        <span className="mb-0 mx-3" style={{ fontSize: "0.75rem" }}>
          {moment(new Date(date)).fromNow()}
        </span>
        <Rater total={5} rating={rating} interactive={false} style={{fontSize:'1rem', display:'block'}}/>      
        <p style={{ fontSize: "0.85rem" }}>{text}</p>
      </div>
    </MDBListGroupItem>
  );

  useEffect(() => {
    const {req_problem_list, initTrainCount, get_my_profile, set_view_bw_mode} = props;
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    req_problem_list(id, 'solve_problem');
    get_my_profile();
    set_view_bw_mode(true);
    return ()=>{
      if (!!timeoutRef.current)
        clearTimeout(timeoutRef.current);
      props.exit_problem();
      initTrainCount();
    };
  }, []);
  useEffect(()=>{
    let {updateUserCoin, train_d_coin} = props;
    if(props.train_count !== 0) {
      updateUserCoin(train_d_coin);
      props.get_my_profile();
    }
  }, [props.train_count]);
  useEffect(() => {
    if (!!timeoutRef.current)
        clearTimeout(timeoutRef.current);
    if (!props.solved && props.solve_result === '')
      timeoutRef.current = setTimeout(incSolvingTime, 1000);
  });

  const incSolvingTime = () => {
    const { update_solve_time } = props;
    timeoutRef.current = null;
    update_solve_time(problem.solved_time + 1);
  };

  const handleProblemNavigation = (index) => {
    const { problem_list, train_mode, req_problem } = props;
    if (index >= problem_list.length)
      index = problem_list.length - 1;
    if (index <= 0)
      index = 0;
    req_problem(problem_list[index], index, train_mode, false);
  };

  const handleResolve = () => {
    const { user, problem_list, problem_index, train_mode, resolve_problem } = props;
    if (!!user)
      resolve_problem(problem_list[problem_index], train_mode);
  };

  const handleToFirst = () => {
    const { solve_result, update_problem_history_index } = props;
    update_problem_history_index(0, solve_result === '');
  };

  const handleToBack = () => {
    const { solve_result, problem, update_problem_history_index } = props;
    update_problem_history_index(problem.h_index - 1, solve_result === '' && (problem.h_index % 2) === 1);
  };
 
  const handleToNext = () => {
    const { solve_result, problem, update_problem_history_index } = props;
    update_problem_history_index(problem.h_index + 1, solve_result === '' && (problem.h_index % 2) === 1);
  };

  const handleToLast = () => {
    const { solve_result, problem, update_problem_history_index } = props;
    update_problem_history_index(problem.history_length, solve_result === '' && (problem.history_length % 2) === 0);
  };

  const handleModeChange = (event) => {
    const { problem_list, problem_index, switch_solve_problem_mode, req_problem } = props;
    switch_solve_problem_mode(event.target.value);
    req_problem(problem_list[problem_index], problem_index, event.target.value, false);
  };

  const handleCloseReviewAndRateDlg = (value) => {
    if (!!value) {
      setOpenReviewAndRate(false);
      const {user, problem_book, add_review_to_problem_book} = props;
      if(!!user)
        add_review_to_problem_book(user.user_id, problem_book._id, value.msg, value.rating);
    } else {
      setOpenReviewAndRate(false);
    }
  };

  function handleExit(){
    props.history.push('/training');
  }

  const handleOpenReviewAndRateDlg = () => {
    setOpenReviewAndRate(true);
  }

  var { user, problem, problem_book, problem_list, problem_index, train_mode, total_solved_time, total_retry, solved_problems, solved, retried, reviews, putAble } = props; 
  if(user == null) props.history.push('/login');
  var solved_percent = problem_list.length > 0? parseInt(solved_problems * 100 / problem_list.length) : 0;

  var cur_review;
  var total_rating = 0;
  for(var i in reviews) {
    total_rating += reviews[i].rating;
    if(!!user && reviews[i].user_id === user.user_id)
      cur_review = {rating: reviews[i].rating, text: reviews[i].text};
  }
  var avg_rating = reviews.length > 0? total_rating / reviews.length : 0;
  return (
    <div style={{backgroundColor: "#f9f9fc", position:"fixed", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "100vw", height: "100vh", overflow: 'scrollY', padding: "2vw"}}>
      <React.Fragment>
        <ReviewAndRate open={openReviewAndRate} review={cur_review} onClose={handleCloseReviewAndRateDlg}/>
        <MDBRow className="m-0">
          <MDBCol className={classes.leftPanelStyle}>
            <h4 className="float-left pr-5 font-weight-bold">{window.i18n.t("train.solving_problem_book")} </h4>
            <h5 className="float-left pt-1 pl-5">{problem_book.title}</h5>
            <h6 className="float-left pt-1 pl-5">{problem_book.type}</h6>
            <h6 className="float-left pt-1 pl-5">{window.i18n.t("train.authored_by")} {problem_book.created_by}</h6>
            <h6 className="float-left pt-1 pl-5">{window.i18n.t("train.last_updated")}: {new Date(problem_book.updated).toLocaleDateString()} </h6>
            <h6 className="float-left pt-1 pl-5">{window.i18n.t("train.difficulty")}: {problem_book.difficulty}</h6>
            { solved_problems === problem_list.length && (
              <svg height="70" width="210" style = {{position: 'fixed', top: '40vh', left: "40vw"}}>
                <rect x="5" y="5" rx="10" ry="10" width="250" height="58" style={{fill:'white',stroke:'red',strokeWidth:5,opacity:1}} />
                <text x="20" y="50" fill="red" style={{fontSize:'3rem', fontWeight:'bold', fontFamily:'Haettenschweiler'}}>COMPLETED</text>
              </svg>
            )} 
            <Button className = 'float-right mr-4' style = {{boxShadow: "none", backgroundColor: "rbga(0, 0, 0, 0)"}} onClick = {handleExit}>
              <i class = "fa fa-reply" style = {{fontSize: '2rem'}}/>
            </Button>
          </MDBCol>
        </MDBRow>
        <MDBRow className="m-0">
          <MDBCol size = '3' className='pl-2 pr-3 my-3 px-4 ml-3'>
            <MDBRow>
              <MDBCol className="py-2">
                <br></br>
                <h6>{window.i18n.t("train.total_time")} : {parseInt(total_solved_time / 3600) + 'h ' + parseInt((total_solved_time % 3600) / 60) + 'min ' + (total_solved_time % 60) + 's'}</h6>
                <h6>{window.i18n.t("train.total_retry")} : {total_retry}</h6>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol>
                <h6>{solved_percent}% {window.i18n.t("train.completed")}</h6>
                <LinearProgress value={solved_percent} my={2} variant="determinate"/>
                <LinearProgress value={solved_percent} my={2} variant="determinate"/>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol></MDBCol>
              <MDBCol className="mx-3 py-5">
                <MDBPagination>
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, 0)}><big>&laquo;</big></MDBPageNav>
                  </MDBPageItem>
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_index - 1)}><big>&lsaquo;</big></MDBPageNav>
                  </MDBPageItem>
                    <input
                      type="text"
                      value={"" + (problem_index + 1) + "/" + problem_list.length}
                      readOnly={true}
                      className={classes.pagenationInputStyle}
                    />
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_index + 1)}><big>&rsaquo;</big></MDBPageNav>
                  </MDBPageItem>
                  <MDBPageItem>
                    <MDBPageNav className={classes.pageNaveStyle} onClick={handleProblemNavigation.bind(this, problem_list.length - 1)}><big>&raquo;</big></MDBPageNav>
                  </MDBPageItem>
                </MDBPagination>
              </MDBCol>
              <MDBCol></MDBCol>
            </MDBRow>
            <MDBRow className="px-lg-2 py-2">
              <MDBCol
                className={classes.scrollableStyle+" px-0 mb-4 mb-md-0"}
              >
                <span className="font-weight-bold mb-3 text-lg-left pr-5">{window.i18n.t("train.reviews")}</span>
                <Rater total={5} rating={avg_rating} interactive={false}/>
                <MDBBtn outline color="gray" className="px-2 py-1 ml-5 mt-0 my-3" onClick={handleOpenReviewAndRateDlg} disabled = {!!user && user.user_id === problem_book.created_by}>
                  {window.i18n.t("go_replay.rate")}
                </MDBBtn>
                
                <MDBScrollbar className="white z-depth-1 p-3">
                  <MDBListGroup className="friend-list">
                    {reviews.map(review => (
                      <Review review={review} />
                    ))}
                  </MDBListGroup>
                </MDBScrollbar>
              </MDBCol>
            </MDBRow>

          </MDBCol>
          <MDBCol className=" py-4" md="5" >
            <Board boardId = {0} readOnly = {false} putAble = {putAble} width='40' height='85'/>
            {solved && (
              <svg height="70" width="230" style={{transform:'rotate(45deg)',position:'absolute',top:'15%',left:'60%'}}>
                <rect x="5" y="5" rx="10" ry="10" width="220" height="58" style={{fill:'transparent',stroke:'red',strokeWidth:5,opacity:1}} />
                <text x="20" y="50" fill="red" style={{fontSize:'3rem', fontWeight:'bold', fontFamily:'Haettenschweiler'}}>SOLVED</text>
              </svg>
            )}
          </MDBCol>
          <MDBCol className='pl-2 pr-3 my-3 px-4 ml-3'>
            <br></br>
            <h5>{problem.first_color === 1? window.i18n.t("train.black_first") : window.i18n.t("train.white_first")}</h5>
            <h6>{problem.description}
            </h6>
            <MDBRow>
              <MDBCol>
                <div className="my-5 ml-2" style={{width:100,height:100,position:'relative'}}>
                  <MDBSimpleChart
                    width={100}
                    height={100}
                    strokeWidth={10}
                    percent={parseInt((problem.solved_time % 60) * 100 / 60)}
                    labelColor="none"
                    strokeColor="blue"
                    railColor="red"
                  />
                  <span style={{position:'absolute',top:'25%',left:'25%',textAlign:'center'}}>
                    <h5 className="mb-0">{parseInt(problem.solved_time / 60)}min</h5>
                    <h5>{problem.solved_time % 60}s</h5>
                  </span>
                </div>
              </MDBCol>
              <MDBCol>
                <div className="my-5" style={{width:100,height:100,textAlign:'center'}}>
                  <i className="fa fa-repeat py-2" style={{color: "red",fontSize:'3rem'}} />
                  <h5>{retried} {window.i18n.t("train.retried")}</h5>
                </div>
              </MDBCol>
            </MDBRow>
            <MDBRow>
              <MDBCol style={{textAlign:'center'}} className="py-3">
                <Select
                  value={train_mode}
                  style={{ width: 150 }}
                  onChange={handleModeChange}
                >
                  <MenuItem value={true}>{window.i18n.t("train.train_mode")}</MenuItem>
                  <MenuItem value={false}>{window.i18n.t("train.test_mode")}</MenuItem>
                </Select>
              </MDBCol>
              <MDBCol style={{textAlign:'center'}} className="py-1">
                <MDBBtn color="blue" className="px-3 py-2 my-0" disabled={problem.history_length === 0 } onClick={handleResolve}>
                  {window.i18n.t("train.resolve")}
                </MDBBtn>
              </MDBCol>
            </MDBRow>
            <MDBRow className="py-3">
            </MDBRow>
            <MDBRow className={classes.navigationButtons}>
              <Button className={classes.navigationButton1} disabled={problem.h_index <= 0} style={{padding:'0px', fontSize: 'inherit'}}  onClick={handleToFirst}><i className="fa fa-fast-backward"/></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index <= 0} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToBack}><i className="fa fa-step-backward" /></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index >= problem.history_length} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToNext}><i className="fa fa-step-forward" /></Button>
              <Button className={classes.navigationButton} disabled={problem.h_index >= problem.history_length} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToLast}><i className="fa fa-fast-forward" /></Button>
            </MDBRow>
          </MDBCol>
        </MDBRow>
      </React.Fragment>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  problem: store.goProblemReducer.problem,
  problem_book: store.problemBookReducer.problem_book,
  problem_list: store.problemBookReducer.problem_list,
  problem_index: store.goProblemReducer.problem_index,
  train_mode: store.goProblemReducer.problem.train_mode,
  solve_result: store.goProblemReducer.solve_result,
  total_solved_time: store.problemBookReducer.problem_book.total_solved_time,
  total_retry: store.problemBookReducer.problem_book.total_retry,
  solved_problems: store.problemBookReducer.problem_book.solved_problems,
  solved: store.goProblemReducer.problem.solved,
  retried: store.goProblemReducer.problem.retried,
  solved_time: store.goProblemReducer.problem.solved_time,
  reviews: store.commonReducer.reviews,
  putAble: store.goBoardReducer.putAble,
  train_count:store.goTrainReducer.train_count,
  train_d_coin:store.goTrainReducer.train_d_coin,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    updateUserCoin:AuthAction.updateUserCoin,
    add_review_to_problem_book: CommonAction.add_review_to_problem_book,
    get_my_profile: ProfileAction.get_my_profile,
    switch_solve_problem_mode: GoProblemAction.switch_solve_problem_mode,
    update_problem_history_index: GoProblemAction.update_problem_history_index,
    exit_problem: GoProblemAction.exit_problem,
    req_problem_list: GoProblemAction.req_problem_list,
    req_problem: GoProblemAction.req_problem,
    resolve_problem: GoProblemAction.resolve_problem,
    update_solve_time: GoProblemAction.update_solve_time,
    initTrainCount:GoTrainAction.init_train_count,
    set_view_bw_mode: GoAction.set_view_bw_mode,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(GoSolveProblem);
