import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = { 
  user_count: '',  
  openMultipleDlg:false,
  room: {
    initial_hands:[],
    last_multiplier:1,
    multipliers: [1, 1, 1, 1],
    last_move: [],
    last_move_turn: 0,
    last_turn: 0,
    last_move_type: -1,
    game_kind: 0,
  },
};

export default function ffaReducer(state=initialState, action){
  switch (action.type) {   
    case ACTION.LOAD_FFA_ROOM_INFO:
      return {
        ...state,
        room: {
          ...state.room,
          game_kind: !!action.game_kind? action.game_kind : state.room.game_kind,
          multipliers: action.multipliers,
        },       
      };    
    case ACTION.LOAD_FFA_RECORD:
      return {
        ...state,
        room: {
          ...state.room,
          initial_hands:action.game.initial_hands,
          multipliers: action.game.multipliers,
        },
      };  
    case ACTION.REMOVE_FFA_PLAYER:
      return {
        ...state,
        room: {
          ...state.room,
          players: state.room.players.filter((element) => (!action.user_id || action.user_id !== element.user_id) && element),
          users: state.room.users.filter((element) => (!action.user_id || action.user_id !== element.user_id) && element),
          room_state: action.room_state,
        }
      }; 
    case ACTION.SET_FFA_GAME_KIND:
      return {
        ...state,
        room:{
          ...state.room,
          game_kind: action.game_kind,
        }  
      };
    case ACTION.SET_OPEN_MULTIPLE_DLG:
      return {
        ...state,
        openMultipleDlg:action.open,
      };
    case ACTION.UPDATE_FFA_USER_COUNT:
      return {
        ...state,
        user_count:action.count,
      }      
    case ACTION.SET_LAST_MULTIPLIER:
      return {
        ...state,
        room:{
          ...state.room,
          last_multiplier:action.multiplier,
        },
      }
    case ACTION.UPDATE_LAST_MOVE:
      return {
        ...state,
        room: {
          ...state.room,
          last_move: action.last_move[0],
          last_move_turn: action.last_move[1],
          last_move_type: action.last_move[2],
        }
      }
    case ACTION.UPDATE_LAST_TURN:
      return {
        ...state,
        room: {
          ...state.room,
          last_turn: action.last_turn,
        }
      }
    case ACTION.UPDATE_FFA_GAME_RESULT:
      // if(action.player3_update_coin === 0) {
      //   state.room.players[0].coin += action.player1_update_coin;
      //   state.room.players[1].coin += action.player2_update_coin;
      // } else {
      //   state.room.players[0].coin += action.player1_update_coin;
      //   state.room.players[1].coin += action.player2_update_coin;
      //   state.room.players[2].coin += action.player3_update_coin;
      //   state.room.players[3].coin += action.player4_update_coin;
      // }
      return state;
    default: return state;
  }
}