import React, {useEffect} from 'react';
import { Redirect, withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import LectureRooms from './LectureRooms';
import Request from './Request';
import TeacherPass from './TeacherPass';
import Teachers from './Teachers'
import {
  MDBRow,
  MDBCol,
} from "mdbreact";
import {   
    Select,
    MenuItem,
    MenuList,
  } from '@material-ui/core';
import CD from "../../helper/const";
import * as CommonAction from "../../store/actions/common.action";
import * as AuthAction from "../../store/actions/auth.action";

const useStyles = makeStyles(theme => ({
    container: {
      display: 'fixed',
      width: '90%',
      top:'15vh',
      left:'8.8vw',
      paddingLeft: '1vw',
      paddingRight: '1vw',
      paddingTop: '2vh',
      minHeight: '83vh',
    },
}));
function Lecture(props) { 

    const [selectedMenuKey, setMenuKey] = React.useState(1);
    const classes = useStyles();    
    const handleSelect = (key) => {   
        setMenuKey(key);
    };
    useEffect(()=>{
        props.setFunc(CD.FUNC.FUNC_LECTURE);
    }, [])
    return (
    <React.Fragment>
        <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
            <div className={classes.container}>
                <MDBRow>
                    <MDBCol size="2" style = {{marginLeft: '2vw', marginTop: '2vh'}}>
                        <MenuList>
                            <MenuItem onClick={handleSelect.bind(this, 1)} key="1" style={{ border: '1px solid #f0f0f0', backgroundColor: selectedMenuKey === 1? '#e0e0e0' : 'white'}}>{window.i18n.t("lecture.teachers")}</MenuItem>
                            <MenuItem onClick={handleSelect.bind(this, 2)} key="2" style={{ border: '1px solid #f0f0f0', backgroundColor: selectedMenuKey === 2? '#e0e0e0' : 'white'}}>{window.i18n.t("lecture.teacher_pass")} </MenuItem>
                            <MenuItem onClick={handleSelect.bind(this, 3)} key="3" style={{ border: '1px solid #f0f0f0', backgroundColor: selectedMenuKey === 3? '#e0e0e0' : 'white'}}>{window.i18n.t("lecture.lecture_rooms")}</MenuItem>                    
                            <MenuItem onClick={handleSelect.bind(this, 4)} key="4" style={{ border: '1px solid #f0f0f0', backgroundColor: selectedMenuKey === 4? '#e0e0e0' : 'white'}}>{window.i18n.t("lecture.request")}</MenuItem>
                        </MenuList>
                    </MDBCol>
                    <MDBCol>
                        {selectedMenuKey === 1 && <Teachers/>}
                        {selectedMenuKey === 2 && <TeacherPass/>}
                        {selectedMenuKey === 3 && <LectureRooms/>}
                        {selectedMenuKey === 4 && <Request/>}
                    </MDBCol>
                </MDBRow>      
            </div>
        </div>
    </React.Fragment>
    );
}

const mapStateToProps = (store) => ({ 
    open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    setFunc: CommonAction.setFunc,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Lecture));
