import React, {useState, useEffect} from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { withRouter } from "react-router-dom";

import Players from './Players';
import Rooms from './Rooms';
import { makeStyles } from '@material-ui/core/styles';

import io from 'socket.io-client';
import config from "../../helper/config";
import PROTOCOL from "../../helper/protocol";
import CD from '../../helper/const';
import ErrorCode from "../../helper/errorCode";
import * as CommonAction from "../../store/actions/common.action";
import * as RoomAction from "../../store/actions/room.action";
import * as GoAction from "../../store/actions/go.action";
import * as PuzzleAction from "../../store/actions/puzzle.action";
import * as PDesignAction from "../../store/actions/pdesign.action";
import * as FFAAction from "../../store/actions/ffa.action";
import * as SKoniAction from "../../store/actions/skpni.action";
import * as AuthAction from "../../store/actions/auth.action";
//import * as ToastAction from '../../store/actions/toast.action';
import { notify_s, notify_w} from "../../helper/alert";


const useStyles = makeStyles(theme => ({
  container: {
    display: 'inline',
    paddingLeft: '0.5vw',
    paddingRight: '0.5vw',
  },
  roomsWidth: {
    minHeight: '85vh',
    width: '80vw',
    float: 'left',
    marginLeft: '16px',
   // borderRight: '2px solid rgb(204, 204, 204)',
    paddingRight: '26px',
  },
  playersWidth: {
    width: '22vw',
    float: 'left',
    marginLeft: '16px',
  },
}));

function Lobby(props) {
  const classes = useStyles();
  useEffect(() => {
    props.setFunc(CD.FUNC.FUNC_PLAY);
    const {user, setSocketLobby} = props;
    let {socketLobby} = props;   
    // var socketLobby = io(config.SOCKET_SERVER);
    // setSocketLobby(socketLobby);
    if(socketLobby === null) {
      socketLobby = io(config.SOCKET_SERVER);
      setSocketLobby(socketLobby);
      socketLobby.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.SC_KICK_OUT:
            if (msg.reason == CD.REASON.ENTERED_ANOTHER_WITH_SAME_ID) {
              notify_w("Entered another user with same id. You are kicked");
              props.logoutUser('/');
              props.history.push('/');
            }
            break;
          case PROTOCOL.SC_NOTICE:
            if(err === ErrorCode.SUCCESS) {    
              notify_s(msg)
            }
            break;
          case PROTOCOL.CSC_ROOM_LIST:
            if (err === ErrorCode.SUCCESS) {            
              let {total, items} = msg;
              props.updateRoomList(items, total);
            }
            break;
          case PROTOCOL.SC_UPDATED_ROOM_LIST:
            props.changedList();
            break;
          case PROTOCOL.SC_CREATE_ROOM:
            {
              if (err === ErrorCode.SUCCESS) {
                let {room_id, game_type} = msg;         
                socketLobby.emit('cs_message', PROTOCOL.CS_ENTER_ROOM, {game_type, room_id});
              }    
            }          
            break;
          case PROTOCOL.SC_JOIN_ROOM:
            {
              if (err === ErrorCode.SUCCESS) {
                let {room_id, game_type} = msg;
                socketLobby.emit('cs_message', PROTOCOL.CS_ENTER_ROOM, {game_type, room_id});
              }
            }
            break;
          case PROTOCOL.SC_ENTER_ROOM:
            if (err == ErrorCode.SUCCESS) {
              let {room_id, game_type, is_player, url, game_kind} = msg;   
              if(game_type === CD.GAME_TYPE.FFA)
                props.setGameKind(game_kind);
              props.enter_room(room_id, game_type, is_player, url);
              socketLobby.emit('close');  // when entering to room, kill lobbySocket
              props.setSocketLobby(null);
            }
            break;
          case PROTOCOL.CSC_LOBBY_USER_LIST:
            if (err === ErrorCode.SUCCESS) {
              let {total, items} = msg;
              alert('user_list');
              props.updateUserList(total, items);
            }
            break;
          case PROTOCOL.SC_INVITE_ROOM:
            break;
          case PROTOCOL.SC_UPDATED_USER_COUNT:
            {
              let user_counts = msg.user_counts;       
              const {update_ffa_user_count, update_go_user_count, update_skpni_user_count, updateAllUsers} = props;
              update_ffa_user_count(user_counts[2]);
              update_go_user_count(user_counts[1]);
              update_skpni_user_count(user_counts[3]);
              updateAllUsers(user_counts[0] + user_counts[1] + user_counts[2] + user_counts[3]);
              props.updated_user_list();
            }
            break;        
          default:
            break;
        }
      });
    }
    props.showHiddenSideBar("14.5vw", true);
    socketLobby.on('connect', function() {
    });
    
   
    if(!!user)
      socketLobby.emit('cs_message', PROTOCOL.CS_LOBBY_USER, {token: user.token});

    return ()=>{
      if (!!socketLobby) {
        socketLobby.emit('close');
        setSocketLobby(null);
      }
    };
  }, []);

  return (
    <React.Fragment>
      <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
        <div className={classes.container}>       
          <div className={classes.roomsWidth}>
            <Rooms />
          </div>
        </div>
      </div>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  socketLobby: store.commonReducer.socketLobby,
  user: store.authReducer.user,
  open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    logoutUser : AuthAction.logoutUser,

    changedList: CommonAction.changedList,
    updateRoomList: CommonAction.updateList,
    setSocketLobby: CommonAction.setSocketLobby,
    enter_room: RoomAction.enter_room,

    updated_user_list: GoAction.updated_user_list,
    updateUserList: GoAction.updateUserList,
    showHiddenSideBar: CommonAction.show_hidden_sidebar,
    setGameKind: FFAAction.set_game_kind,
    //SKPNI
    setFunc: CommonAction.setFunc,
    update_ffa_user_count:FFAAction.update_ffa_user_count,
    update_go_user_count:GoAction.update_go_user_count,
    update_skpni_user_count:SKoniAction.update_skpni_user_count,
    updateAllUsers: CommonAction.updateAllUsers,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Lobby));
