var w = window.innerWidth;
var h = window.innerHeight;

const clock_position_base = [
  [9 * w / 100, 63 * h / 100],
  [87 * w / 100, 36 * h / 100]
];
var globalHandleTime, handle_timeout, count_timer;

function OmokRoom(props) {
  const classes = useStyles();
  const socketRoom_ref = useRef();
  const players_ref = useRef();
  const ready_state_ref = useRef([false, false]);
  const countdown_ref = useRef(0);
  const round_time_ref = useRef(-1);
  const mineNumber_ref = useRef(0);
  
  const {user} = props;
  const [players, setPlayers] = useState([]);
  const [room_no, setRoomNumber] = useState(0);
  const [room_coin, setRoomCoin] = useState(0);
  const [time, setTime] = useState('Fast');
  const [btn_disabled, setBtnDisable] = useState(false);
  const [mine_number, setMineNum] = useState(0);
  const [countdown, setCountdown] = useState(5);
  const [left_time, setLeftTime] = useState(5);
  const [clock_position, setClockPosition] = useState(clock_position_base[0]);
  const [clock_display, setClockDisplay] = useState(false);
  const [exit_request, setExitRequest] = useState([false, false]);

  const colors = [Logic.BLACK, Logic.WHITE];
  const board_size_array = [6, 8];
  let token = !!user? user.token : null;
  let user_id = !!user? user.user_id : null;
  var animation_layer;

  useEffect(() => {
    setRoomCoin(props.room_coin);
  }, [props.room_coin]);
  
  useEffect(() => {
    setRoomNumber(props.room_no);
  }, [props.room_no]);
  
  useEffect(() => {
    setPlayers(props.players);
    players_ref.current = props.players;
  }, [props.players]);
  
  useEffect(() => {
    countdown_ref.current = props.countdown;
  }, [props.countdown]);

  useEffect(() => {
    socketRoom_ref.current = props.socketRoom;
  }, [props.socketRoom]);

  // useEffect(() => {
  //   setBtnDisable(props.complete_draw);
  // }, [props.complete_draw]);

  useEffect(() => {
    if (props.setting.time == 0)
      setTime('Fast');
    else if (props.setting.time == 1)
      setTime("Normal");
    else setTime('Slow');
    // OmokLogicBoard.set_board_size(board_size_array[props.setting.board_size]);
    props.update_board_size([board_size_array[props.setting.board_size]]);
  }, [props.setting]);
  
  const handleComplete = () => {
    // props.on_complete_draw();
  }

  const init = () => {
    animation_layer = document.getElementById("animation_layer");
    animation_layer.innerHTML = null;
    var start_animation = document.createElement("div");
    start_animation.setAttribute("id", "start_animation");
    start_animation.setAttribute("style", "transition-duration: 200ms; font-family: cursive; font-size: 40vh; color: white; opacity: 1;");
    animation_layer.appendChild(start_animation);
    var result_animation = document.createElement("div");
    result_animation.setAttribute("id", "result_animation");
    result_animation.setAttribute("style", "transition-duration: 200ms; font-family: cursive; font-size: 40vh; color: white; opacity: 1;");
    animation_layer.appendChild(result_animation);
    var result_animation_0 = document.createElement('div');
    result_animation_0.setAttribute("id", "result_animation_0");
    result_animation_0.setAttribute("style", "position: fixed; top: 75vh; left: 5vw; font-size: 5vh");
    result_animation.appendChild(result_animation_0);
    var result_animation_1 = document.createElement('div');
    result_animation_1.setAttribute("id", "result_animation_1");
    result_animation_1.setAttribute("style", "position: fixed; top: 20vh; left: 80vw; font-size: 5vh");
    result_animation.appendChild(result_animation_1);
  }

  const init_state = () => {
    init();
    animation_layer.style.display = 'none';
    OmokLogicBoard.initialize(props.board_size);
    document.getElementById('play_buttons').style.display = "none";
  }
  
  const setMineNumber = (msg) => {
    for (let i = 0; i < msg.players.length; i ++) {
      if (props.user.user_id == msg.players[i].user_id) {
        mineNumber_ref.current = i;
        break;
      }
    }
    setMineNum(mineNumber_ref.current);
    OmokLogicBoard.putable = false;
    if (mineNumber_ref.current == msg.first_turn) {
      OmokLogicBoard.mine_color = Logic.BLACK;
      OmokLogicBoard.putable = true;
      setClockPosition(clock_position_base[0]);
      document.getElementById('play_buttons').style.display = 'block';
    } else {
      document.getElementById('play_buttons').style.display = 'none';
      OmokLogicBoard.mine_color = Logic.WHITE;
      setClockPosition(clock_position_base[1]);
    }
    for (let i = 0; i < 2; i ++) {
      var image = document.getElementById(`stone_${i}`);
      if (!!image) {
        if (i == msg.first_turn) {
          image.setAttribute('src', '/assets/img/stone_b.png');
          colors[i] = Logic.BLACK;
        } else {
          image.setAttribute('src', '/assets/img/stone_w.png');
          colors[i] = Logic.WHITE;
        }
      }
    }
  }

  const countTimeDisplay = (countdown) => {
    countdown --;
    if (countdown < 0) {
      clearTimeout(count_timer);
      return;
    }
    setLeftTime(countdown);
    count_timer = setTimeout(() => {
      countTimeDisplay(countdown);
    }, 1000);
  }
  
  const EndAnimation = (result, rewards) => {
    var result_animation = document.getElementById("result_animation");
    var start_animation = document.getElementById("start_animation");
    var result_animation_0 = document.getElementById("result_animation_0");
    var result_animation_1 = document.getElementById("result_animation_1");
    animation_layer.style.display = 'block';
    start_animation.style.display = 'none';
    result_animation.style.display = 'block';
    if (result == 'drawn') {
      result_animation.innerHTML = "Draw";
    } else {
      // if (result[mineNumber_ref.current] == 'W')
      //   result_animation.innerHTML += "Win!";
      // else result_animation.innerHTML += "Lose!";
      result_animation_0.innerHTML = `${result[mineNumber_ref.current]}` + " " + rewards[mineNumber_ref.current];
      result_animation_1.innerHTML = `${result[1 - mineNumber_ref.current]}` + " " + rewards[1 - mineNumber_ref.current];
    }
    // props.updateGameResult(result, rewards[0], rewards[1]);
  }

  useEffect(() => {
    const {room_id, roomURL, setSocketRoom} = props;
    var socketRoom = io(roomURL);   
    setSocketRoom(socketRoom);  
    socketRoom.on('sc_message', function(protocol, err, msg) {
      console.log(protocol);
      switch(protocol) {
        case PROTOCOL.SC_ROOM_INFO:
          if (err === ErrorCode.SUCCESS) {
            let room_info = msg;      
            props.load_room_info(user_id, room_info, CD.GAME_TYPE.OMOK);
            setMineNumber(msg);
          }
          break;
        case PROTOCOL.SC_JOINED_PLAYER:
          {
            if (err === ErrorCode.SUCCESS) {
              props.joined_player(msg.user);
            }
          }
          break;      
        case PROTOCOL.SC_START_PREPARE:
          {
            let room_info = msg;
            props.load_room_info(user_id, room_info, CD.GAME_TYPE.OMOK);
            init_state();
            setClockDisplay(false);
            if (props.room_type == "play") {
              if (!!handle_timeout)
                clearTimeout(handle_timeout);
              handle_timeout = setTimeout(() => {
                openPrepareDlg();
              },  500);
            }
          }
          break;
        case PROTOCOL.SC_REMOVE_USER:
          if (err === ErrorCode.SUCCESS) {
            props.remove_user_from_room(msg.user_id, msg.room_state);
          }
        break;
        case PROTOCOL.SC_PREPARED_STATE:
          // updateReadyState(msg);
          break;
        case PROTOCOL.SC_GAME_START:
          {
            if (err === ErrorCode.SUCCESS) {
              if (!!handle_timeout) clearTimeout(handle_timeout);
              let room_info = msg;
              props.load_room_info(user_id, room_info, CD.GAME_TYPE.OMOK);
              if (!!handle_timeout)
                clearTimeout(handle_timeout);
              handle_timeout = setTimeout(() => {
                setMineNumber(msg);
              },  500);
              globalHandleTime = setInterval(roundTimeDisplay, 1000);
              setClockDisplay(true);
              if (!!count_timer) clearTimeout(count_timer);
              countTimeDisplay(msg.countdown);
            }
          }
          break; 
        case PROTOCOL.SC_GAME_MOVE:
          {
            if (err === ErrorCode.SUCCESS) {
              let {move, turn} = msg;
              var next_turn = 1 - turn;
              if (next_turn == mineNumber_ref.current) setClockPosition(clock_position_base[0]);
              else setClockPosition(clock_position_base[1]);
              setCountdown(msg.countdown);
              setLeftTime(msg.countdown);
              if (!!count_timer) clearTimeout(count_timer);
              countTimeDisplay(msg.countdown);
              OmokLogicBoard.putable = false;
              if (move != 100)
                props.do_move(move, colors[turn], turn);
              if (next_turn == mineNumber_ref.current) {
                document.getElementById('play_buttons').style.display = 'block';
                OmokLogicBoard.putable = true;
              } else document.getElementById('play_buttons').style.display = 'none';
            } else {
              console.log(err);
            }
          }
          break;
        case PROTOCOL.SC_KICK_OUT:
          {
            if (msg.reason == CD.REASON.ENTERED_ANOTHER_WITH_SAME_ID) {
              notify_w("Entered another user with same id. You are kicked");
              props.logoutUser('/');
              props.history.push('/');
            }
          }
          break;
        case PROTOCOL.SC_OUT_ROOM: 
          {
            if (err === ErrorCode.SUCCESS) {
              setClockDisplay(false);
              clearTimeout(count_timer);
              clearInterval(globalHandleTime);
              setTimeout(() => {
                props.history.push('/lobby');
              }, 1000);
            }
          }
          break;
        case PROTOCOL.SC_WILL_OUT_ROOM:
          {
            if (err === ErrorCode.SUCCESS) {
              let {user_id} = msg;
              for (let i = 0; i < players_ref.current.length; i ++) {
                if (user_id == players_ref.current[i].user_id) {
                  exit_request[i] = true;
                }
              }
              setExitRequest(exit_request.slice());
            }
          }
          break;
        case PROTOCOL.SC_GAME_END:
          {
            if (err === ErrorCode.SUCCESS) {
              let gameResult = msg.game_result;
              let rewards = msg.rewards;
              clearTimeout(count_timer);
              setClockDisplay(false);
              EndAnimation(gameResult, rewards);
            }
          }
          break;
        case PROTOCOL.SC_UPDATED_COIN:
          {
            if (err === ErrorCode.SUCCESS) {
              let {reason, d_coin} = msg;
              if (d_coin > 0)
                notify_s("coin +" + d_coin + " by " + reason);
              else if(d_coin < 0)
                notify_w("coin " + d_coin + " by " + reason);
              props.updateUserCoin(d_coin);
            }
          }
          break;
        case PROTOCOL.SC_ROOM_CHAT:
          break;
        case PROTOCOL.SC_ROOM_EMOTICON:
          break;
        default:
          break;
      }
    });    
    socketRoom.on('connect', function() {
      socketRoom.emit('cs_message', PROTOCOL.CS_ENTERED_ROOM, {token, room_id});
      socketRoom.emit('cs_message', PROTOCOL.CS_ROOM_INFO, {room_id});
    });  
    return ()=>{
      socketRoom.emit('close');
      clearInterval(globalHandleTime);
    }
  }, []);
  
  const roundTimeDisplay = () =>{
    let second, minute, hour;
    var date = new Date();
    hour = date.getHours();
    minute = date.getMinutes();
    if (minute < 10)
      minute = '0' + minute;
    second = date.getSeconds();
    if (second < 10)
      second = '0' + second;
    document.getElementById('time_counter').innerHTML = hour + ':' + minute + ':' + second;     
  };

  const handleExit = () => {
    const {history, user, room_id, room_type} = props;
    if (room_type == "play") {
      if (players_ref.current.length == 2) {
        let token = user.token;
        socketRoom_ref.current.emit("cs_message", PROTOCOL.CS_WILL_OUT_ROOM, {
          token,
          room_id
        });
      } else {
        clearInterval(globalHandleTime);
        clearTimeout(count_timer);
        clearTimeout(handle_timeout);
        history.push('/lobby');
      }
    } else history.push('/lobby');
  }

  const openPrepareDlg = () => {
    var {user,  room_id, socketRoom } = props;
    var token = !!user? user.token : null;
    props.openModal({
      content: window.i18n.t("go_game.ready_sentence"),
      type: 'query',
      className: "modalStyle",
      clickOK: () => {
        socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_CONFIRM_PREPARED, {token, room_id});
      },
      clickCancel: () => {
        props.history.push('/lobby');
      }
    });
  };

  const handlePass = () => {
    const {socketRoom, user, room_id} = props;
    let move = 100;
    if (!!socketRoom_ref.current){
      socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_GAME_MOVE, {token: !!user? user.token : null, room_id: room_id, move: move});
    }
  }

  const handleResign = () => {
    const {socketRoom, user, room_id} = props;
    socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_GAME_MOVE, {token, room_id, move: 0x2020});
  }

  return (
    <div>
      <div className={classes.container}/>
      <div  className={classes.board}>
        <OmokBoard width="52" height="94" replay = {false}/>
      </div>
      <div className={classes.roomSetting}>
        <div className={classes.text_setting}>
          {room_no}
          <img id = "coin_img" src = "assets/img/coin_i.png" className = {classes.imgStyle} /> {room_coin + "  " + time}
        </div>
      </div>
      {/* <div className={classes.playButtons}>
        <span className={classes.text}>
          {"completed, resign"}
        </span>
      </div> */}
      <div className={classes.time}>
        <span id = "time_counter" className={classes.timeText}>
        </span>
      </div>
      {/* <div className={classes.result}>
        <span className={classes.text}>
          {"finished, some win!"}
        </span>
      </div> */}
      {!!players_ref.current &&
        players_ref.current.map((player, i) => {
          return (
            <div className={player.user_id == props.user.user_id ? classes.playerLeftPanel : classes.playerRightPanel} >
              <img id = {`stone_${i}`} style = {{position: 'relative', left: '15vw', top: '14vh', width: '6vh', height: '6vh', zIndex: '1113'}} />
              <Icon.ExitToApp style={{position: 'relative', color: 'white', width: "3vw", height: "auto", top: '5vh', height: '10vh', zIndex: '2003', opacity: exit_request[i] ? '1' : '0' }} />
              <Avatar alt="Profile Picture" className = {classes.avatarStyle} src={player.avatar}/>
              <div className= {classes.info_text_panel}>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1">{player.user_id + ' (LV.' + player.level + ')'}</MDBCol>
                </MDBRow>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1"><i className={" fa fa-star"} style = {{color: 'orange'}}>{" "}{player.coin}</i></MDBCol>
                </MDBRow>
                <MDBRow>
                  <MDBCol size = '1'></MDBCol>
                  <MDBCol className = "px-1">{'Ready: '}</MDBCol>
                </MDBRow>
              </div>
            </div>
          )
        })
      }
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i class = "fa fa-home" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i class = "fa fa-home" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
      {/* <div className={classes.completed} >
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0.5)"}} onClick = {handleComplete} disabled = {btn_disabled}>
            <i className = "fa fa-check" style = {{fontSize: '2.5rem', color: btn_disabled ? 'rgb(150, 150, 150)' : 'rgb(0, 240, 0)'}}><span style = {{color: btn_disabled ? 'rgb(150, 150, 150)' : 'white', fontSize: '1.5rem', fontFamily: 'cursive'}}>Complete</span></i>
          </Button>
        </span>
      </div> */}
      <Clock2 display = {clock_display} leftTime = {left_time} countdown = {countdown} clockPosition = {clock_position} width = {4} />
      <div className={classes.playButtons} id = {'play_buttons'} style = {{display: 'none'}}>
        <Button className={classes.playButton} disabled={false} style={{padding:'0px', fontSize: 'inherit'}} onClick={handlePass}>
          <span className={classes.toolWrapper}><i className="fa fa-paypal"/><span className={classes.toolText}>{window.i18n.t("go_game.pass")}</span></span>
        </Button>
        <Button className={classes.playButton} disabled={false} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleResign}>
          <span className={classes.toolWrapper}><i className="fa fa-flag"/><span className={classes.toolText}>{window.i18n.t("go_game.resign")}</span></span>
        </Button>
      </div>
      <div id = "animation_layer" style = {{display: 'none', backgroundColor: 'rgba(0, 0, 0, 0.8)', position: 'fixed', width: '100vw', height: '100vh', top : '0px', left: '0px', zIndex: '2003', textAlign: 'center', paddingTop: '20vh'}}></div>
    </div>
  )
}

