import React, {useState, useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import {
  Avatar,
  Button,
  DialogActions,
  FormControl as MuiFormControl,
  FormControlLabel,
  MenuItem,
  Radio,
  Switch,
  RadioGroup,
  Select,
  LinearProgress
} from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { bindActionCreators } from 'redux';
import {
  MDBRow,
  MDBCol,
  MDBBtn,
} from "mdbreact";

import * as PDesignAction from '../../store/actions/pdesign.action';
import * as PDesignTaskAction from '../../store/actions/pdesign_task.action';

const useStyles = makeStyles(theme => ({
  btnStyle: {
    width: '1.6vw',
    height: '1.6vw'
  },

  imgStyle: {
    width: '75%',
    height: 'auto',
    paddingLeft: '10%'
  },

  txtStyle: {
    fontSize: '1.5vw',
    fontFamily: 'cursive',
    fontWeight: 'bold',
  },
  
  pieceStyle: {
    width: '1.6vw',
    height: '1.6vw',
    padding: '0.1vw'
  },
}));

function PDesignProblem(props) {

  const classes = useStyles();
  const [sample_problem, setSampleProblem] = useState('');
  
  useEffect(() => {
    setSampleProblem(`Draw ${props.target}`);
  }, [props.target])

  return (
    <div style = {{width: "100%", borderRadius: '1vw', backgroundColor: 'rgba(235, 235, 235, 1)'}}>
      <MDBRow className = "px-4 pb-2 pt-2">
        <MDBCol className = {classes.textStyle}>{sample_problem}</MDBCol>
      </MDBRow>
    </div>
  );
}
function mapStateToProps(store) {
  return {
    target: store.pdesignTaskReducer.target,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(PDesignProblem));