import React, {useState, useEffect, useRef} from 'react';
import { connect } from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import {
  Avatar,
  Button,
  DialogActions,
  FormControl as MuiFormControl,
  FormControlLabel,
  MenuItem,
  Radio,
  Switch,
  RadioGroup,
  Select,
  LinearProgress
} from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import { bindActionCreators } from 'redux';
import {
  MDBRow,
  MDBCol,
  MDBBtn,
} from "mdbreact";

import * as PDesignAction from '../../store/actions/pdesign.action';
import * as PDesignTaskAction from '../../store/actions/pdesign_task.action';

const useStyles = makeStyles(theme => ({
  btnStyle: {
    width: '1.6vw',
    height: '1.6vw'
  },

  imgStyle: {
    width: '1.7vw',
    height: '1.7vw',
    marginRight: '1vw'
  },

  txtStyle: {
    fontSize: '1.5vw',
    fontFamily: 'cursive',
    fontWeight: 'bold',
  },
  
  pieceStyle: {
    width: '1.6vw',
    height: '1.6vw',
    padding: '0.1vw'
  },
}));

const items = [["Stones", 0, 29], ["Rectangles", 1, 28], ["Alphabets", 2, 28], ["Numbers", 4, 10], ["Math Symbols", 7, 29], ["Fruits", 8, 20], ["Animals", 9, 20],];

function PieceSelect(props) {
  
  const classes = useStyles();
  const [piece_selected, setPieceSelect] = useState(0);
  const [pieces_array, setPiecesArray] = useState(new Array(29).fill(0));

  useEffect(() => {
    for (let i = 0; i < items.length; i ++) {
      if (props.piece_kind == items[i][1]) {
        setPieceSelect(i);
        setPiecesArray(new Array(items[i][2]).fill(0));
      }
    }
  }, [props.piece_kind]);

  useEffect(() => {
    handleChangePieceIndex(props.piece_index);
  }, [props.piece_index]);

  const handleChangePieceKind = (event) => {
    if (!props.controllable && event.target.value != props.piece_kind) return;
    setPieceSelect(event.target.value);
    setPiecesArray(new Array(items[event.target.value][2]).fill(0));
    handleChangePieceIndex(0);
    props.update_piece_kind(items[event.target.value][1]);
  }

  const handleChangePieceIndex = (value) => {
    var piece = document.getElementById('piece_btn_'+`${value}`);
    for (let i = 0 ; i < items[piece_selected][2] ; i ++) {
      var piece_init = document.getElementById('piece_btn_' + `${i}`);
      piece_init.style.boxShadow = 'none';
    }
    piece.style.boxShadow = '0px 0px 3px 3px rgb(30, 130, 200)';
    props.update_piece_index(value);
  }

  return (
    <div style = {{width: "100%", borderRadius: '1vw', backgroundColor: 'rgba(240, 200, 90, 0.5)', height: '36vh'}}> 
      <MDBRow className = "px-4 pb-2 pt-2">
        <MDBCol>
          <Select
            style={{ width: '100%',}}
            value={piece_selected}
            onChange={handleChangePieceKind}
          >
            {
              items.map((item, index) => {
                return (
                  <MenuItem value={index}>
                    <h5 className = {classes.txtStyle}><img src = {"/assets/img/cell/" + `${item[1]}/1.png`} className = {classes.imgStyle} />{item[0]}</h5>
                  </MenuItem>
                );
              })
            }
          </Select>
        </MDBCol>
      </MDBRow>
      <MDBRow className = 'px-4 pb-2'>
        {
          pieces_array.map((piece, index) => {
            return (
              <MDBCol size = '2' className = "px-0 py-0">
                <Button onClick = {handleChangePieceIndex.bind(this, index)} className = 'py-1'>
                  <div id = {"piece_btn_" + `${index}`}><img src = {"/assets/img/cell/" + `${items[piece_selected][1]}/` + `${index}.png`} className = {classes.pieceStyle} /></div>
                </Button>
              </MDBCol>
            );
          })
        }
      </MDBRow>
    </div>
  );
}
function mapStateToProps(store) {
  return {
    piece_kind: store.pdesignTaskReducer.piece_kind,
    piece_index: store.pdesignTaskReducer.piece_index,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
      update_piece_kind: PDesignTaskAction.updatePieceKind,
      update_piece_index: PDesignTaskAction.updatePieceIndex,
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(PieceSelect));