import React, { useState, useEffect } from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import GoTraining from './GoTraining';
import PuzzleTraining from './PuzzleTraining';
import PDesignTraining from './PDesignTraining';
import OmokTraining from './OmokTraining';
import CD from "../../helper/const";
import * as AuthAction from "../../store/actions/auth.action";
import * as CommonAction from "../../store/actions/common.action";

function Training(props) { 
    useEffect(() => {
      props.setFunc(CD.FUNC.FUNC_TRAINING);
    }, []);
    const {game_type} = props;
    return (
      <React.Fragment>
        {game_type === CD.GAME_TYPE.GO && <GoTraining/>}
        {game_type === CD.GAME_TYPE.PUZZLE && <PuzzleTraining/>}
        {game_type === CD.GAME_TYPE.PIECE_DESIGN && <PDesignTraining/>}
        {game_type === CD.GAME_TYPE.OMOK && <OmokTraining />}
      </React.Fragment>
    );
}

const mapStateToProps = (store) => ({
  game_type: store.commonReducer.content,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    setFunc: CommonAction.setFunc,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Training));
