import React, {useEffect} from 'react';
import { connect } from "react-redux";
import { Redirect, withRouter } from "react-router-dom";
import {bindActionCreators} from "redux";
import styled from "styled-components";
import { makeStyles } from '@material-ui/core/styles';
import * as GoAction from "../../store/actions/go.action";
import * as ArticleAction from "../../store/actions/article.action";
import {Avatar} from '@material-ui/core';
import {
  MDBContainer,
  MDBRow,
  MDBCol,
  MDBCard,
  MDBCardBody,
  MDBBtn,
  MDBMedia,
} from "mdbreact";
import Board from "../go/board";

const useStyles = makeStyles(theme => ({
  container: {
    display: 'inline',
    minHeight: '83vh',
    paddingTop: '2vh',
    paddingLeft: '0.5vw',
    paddingRight: '0.5vw',
  },
  forumStyle: {
    border: '1px solid rgb(204, 204, 204)',
    paddingLeft: '3vw',
  },
  forumRowStyle: {
    backgroundColor: "#bfdeec",
    marginBottom: '1px',
  },
  avatarStyle: {
    width: "7vw",
    height: "7vw",
    marginLeft: "auto",
    marginRight: "auto",
    marginBottom: "1vh",
  },
  infoTxtStyle: {
    fontSize: "1.2rem",
    fontWeight: "thick",
    padding: "0.5rem",
    marginLeft: "1rem",
  }
}));
function Forum_view(props) {
  const classes = useStyles();

  useEffect(() => {
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    props.req_article(id);
  }, []);

  const handleVote = (article_id) => {
    const { user, voteArticle } = props;
    if (!!user)
      voteArticle(article_id);
  };

  const handleDevote = (article_id) => {
    const { user, devoteArticle } = props;
    if (!!user)
      devoteArticle(article_id);
  }

  const handleExpand = (article) => {
    article.expanded = !article.expanded;
    props.expandArticle(article);
  }

  const viewArticleDetail = (article) => {

    const handleReply = () => {
      const { user, replyToArticle, history} = props;
      props.replyToArticle(article._id, article.title);
      if (!!user) {
        history.push('/forum_compose');
      }
    }

    if (!article)
      return (<div></div>);
    var active_vote = true;
    var active_devote = true;
    var active_reply = true;
    if (!user || article.author_id === user.user_id) {
      active_vote = false;
      active_devote = false;
      active_reply = false;
    }
    else {
      article.votes.map((user_id, index) => {
        if (user_id === user.user_id)
          active_vote = false;
      });
      article.devotes.map((user_id, index) => {
        if (user_id === user.user_id)
          active_devote = false;
      })
    }

    return (
      <div style = {{width: "90%"}}>
        <MDBRow style = {{borderBottom: "solid", borderBottomWidth: "1px", width: "90%", marginLeft: "auto", marginLeft: "auto"}}>
          <MDBCol md="5" className="mb-md-0 px-2">
            <h5 className="font-weight-bold dark-grey-text float-left" style = {{fontSize: "1.5rem"}}>
              { article.title }
            </h5>
          </MDBCol>
          <MDBCol className="mb-md-0 px-1">
            <h6 className="dark-grey-text pl-3 pr-3 float-right">
              <small>
                {new Date(article.date).toLocaleString()}
              </small>
            </h6>
            <h6 className="dark-grey-text pl-3 float-right">
              <small>
                {article.author_id}
              </small>
            </h6>
            <h6 className="dark-grey-text pl-2 pb-3 float-right">
              <i className="fa fa-thumbs-o-up pr-1"/>
                {article.votes.length}
              <i className="fa fa-thumbs-o-down pl-3 pr-1"/>
                {article.devotes.length} 
              <i className="fa fa-comment-o pl-5 pr-1"/>
                {article.replied.length}
            </h6>
          </MDBCol>
        </MDBRow>
        <MDBRow style = {{width: "90%", marginLeft: "auto", marginLeft: "auto"}}>
          <MDBCol className="mb-md-0 px-1 pt-4" style={{textAlign:'left', width: '90%'}}>
            <MDBCard style = {{width: '100%', height: "55vh", overflowY:"scroll"}}>
              <MDBCardBody>
                {article.boards.length != 0 &&
                  <MDBRow style = {{width: "98%"}}>
                    <MDBCol md = "5" style = {{position: "fixed"}}>
                      {
                        article.boards.map((board, index) => 
                          (<Board key = {index} boardId = {article.id + index} viewport2 = {board.viewport} marks_2 = {board.marks} readOnly = {true} putAble = {false} board_str = {board.board_str} last_move = {0} width={article.boards.length > 1 ? 12 : 25} height={50}/>)
                        )
                      }
                    </MDBCol>
                    <MDBCol md = "7" style = {{marginLeft: "42%"}}>
                      <div dangerouslySetInnerHTML={{__html:article.content}}/>
                    </MDBCol>
                  </MDBRow>
                }
                { article.boards.length == 0 &&
                  <div dangerouslySetInnerHTML={{__html:article.content}}/>
                }
              </MDBCardBody>
            </MDBCard>
          </MDBCol>
        </MDBRow>
        <MDBRow className = "mt-4 pt-3" style = {{borderTop: "solid", borderTopWidth: "1px", width: "90%", marginLeft: "auto", marginLeft: "auto"}}>
          <MDBCol md="6" className="mb-md-0 px-1">
            <MDBBtn color="green" className="float-left px-3 py-2" disabled={!active_vote} onClick={handleVote.bind(this, article._id)}>
              <i className ="fa fa-thumbs-o-up mr-1" style={{ color: "white"}}/> {window.i18n.t("forum.vote")}
            </MDBBtn>
            <MDBBtn color="green" className="float-left px-3 py-2" disabled={!active_devote} onClick={handleDevote.bind(this, article._id)}>
              <i className="fa fa-thumbs-o-down mr-1" style={{ color: "white"}}/> {window.i18n.t("forum.devote")}
            </MDBBtn>
          </MDBCol>

          <MDBCol className="mb-md-0 px-1">
            <MDBBtn color="green" className="float-right px-3 py-2" disabled={!active_reply} onClick={handleReply.bind(this, article._id, article.title)}>
              <i className="fa fa-reply mr-1" style={{ color: "white"}}/>  {window.i18n.t("forum.reply")}
            </MDBBtn>
          </MDBCol>

        </MDBRow>
      </div>
    );
  }

  const viewArticleTitle = (article) => {
    return (
      <MDBCard onClick={handleExpand.bind(this, article)}>
        <h5 className={classes.forumRowStyle+" font-weight-bold mt-0 py-3 px-3"}>
          {article.title}
          <small className="float-right">
            <i className="fa fa-thumbs-o-up pr-1"/>
              {article.votes.length}
            <i className="fa fa-thumbs-o-down pl-3 pr-1"/>
              {article.devotes.length}
            <i className="fa fa-comment-o pl-5 pr-1"/>
              {article.replied.length}
            <span className="px-5">
              {article.author_id}
            </span>
            <span>
              {new Date(article.date).toLocaleString()}
            </span>
          </small>
        </h5>
      </MDBCard>
    );
  }

  const viewRepliedTree = (article) => {
    if (!article)
      return (<div></div>);
    return (
      <MDBMedia className="d-block d-md-flex">
        <MDBMedia body className="text-center text-md-left ml-md-5 ml-0">
          {
            article.replied.map((article_reply_id, index) => {
              var article_reply = null;
              props.articles.map((atc) => {
                if(atc._id === article_reply_id)
                  article_reply = atc;
              });
              if (!article_reply || !article_reply.replied)
                return;

              return (
                <React.Fragment key={index}>
                  {
                    article_reply.expanded && viewArticleDetail(article_reply)
                  }
                  {
                    !article_reply.expanded && viewArticleTitle(article_reply)
                  }
                  {
                    article_reply.replied.length > 0 && viewRepliedTree(article_reply)
                  }
                </React.Fragment>
              );
            })
          }
        </MDBMedia>
      </MDBMedia>
    )
  }

  const { user, articles } = props;
  var ascendant = null;
  articles.map((article) => {
    if(article.parent === "")
      ascendant = article;
  });
  return (
    <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
      <MDBContainer className={classes.container}>
        {
          viewArticleDetail(ascendant)
        }
        {
          viewRepliedTree(ascendant)
        }
      </MDBContainer>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  articles: store.articleReducer.articles,
  edit_article: store.articleReducer.edit_article,
  open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    voteArticle: ArticleAction.voteArticle,
    devoteArticle: ArticleAction.devoteArticle,
    replyToArticle: ArticleAction.replyToArticle,
    expandArticle: ArticleAction.expandArticle,
    req_article: ArticleAction.req_article,
    setArticleIdToReplay:ArticleAction.setArticleIdToReplay,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Forum_view));
