import axios from "axios";
import ACTION from '../actionTypes';
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import PCD from '../../components/puzzle/puzzleConst';
import * as PBC from '../../components/puzzle/puzzleBaseClasses';

export const req_problem_list = (book_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/problem_list', { book_id });
    const {err, problem_book, problem_list, book_solve, reviews} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch({ type: ACTION.LOAD_PROBLEM_BOOK, problem_book, book_solve, });
      dispatch({ type: ACTION.UPDATE_PROBLEM_LIST, problem_list, });
      dispatch({ type: ACTION.UPDATE_REVIEWS, reviews});
      dispatch(req_problem(problem_list[0], 0));
    }
  } catch (error) {
  }
}

export const req_problem = (problem_id, problem_index) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/problem', { problem_id });
    const {err, problem} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(on_load_problem(problem, problem_index));
    }
  } catch (error) {
  }
}

function get_stick_total_action_count(problem) {
  let stick_total_action_count = 0;
  if (PCD.BOARD_ACTION_TYPE(problem.board_type) == PCD.BACTION_TYPE.BORDER)
  {
      for (let i = 0; i < problem.array_action_data.length; i++)
      {
          let data = problem.array_action_data[i];
          if (data.operation_effect == PCD.ACTION_VISIBLE.ACTION_VSTICKMOVE || data.operation_effect == PCD.ACTION_VISIBLE.ACTION_VSTICKREMOVE)
          {
              stick_total_action_count = data.sub_operation_effect;
              break;
          }
      }
  }
  return stick_total_action_count;
}

function toArrayBoardData(prob) {
  let ncount = prob.pieces_data.length;
  let bd_index = -1;
  let array_board_data = [];
  for (let i = 0; i < ncount; i++) {
    let pieces_data = prob.pieces_data[i];
    let board_type = pieces_data.piece_type >> 4;
    let p_count = pieces_data.pieces_array.length;
    let board = {data_array: []};
    board.data_type = pieces_data.piece_type & 0x0f;
    let bsize = pieces_data.board_size;
    for (let j = 0; j < bsize; j++) {
      board.data_array.push(-1 >>> 0);
    }
    for (let k = 0; k < p_count; k++) {
      let piece = pieces_data.pieces_array[k].piece;
      let pre_pos = 0;
      var dpos_array = Buffer.from(pieces_data.pieces_array[k].dpos, "base64");
      let count2 = dpos_array.length;
      for (let j = 0; j < count2; j++) {
        let dp = dpos_array[j];
        var delta;
        if (dp >= 0x80) {
          j++;
          let np = dpos_array[j];
          delta = ((dp & 0x7f) << 8) | np;
        }
        else {
          delta = dp;
        }
        let p = pre_pos + delta;
        board.data_array[p] = piece >>> 0;
        pre_pos = p;
      }
    }
    if (bd_index >= 0 && array_board_data[bd_index].board_type == board_type) {
      array_board_data[bd_index].array_board.push(board);
    }
    else {
      let boardData = {array_board: []};
      boardData.board_type = board_type;
      boardData.array_board.push(board);
      bd_index++;
      array_board_data.push(boardData);
    }
  }
  return array_board_data;
}
function toArrayAnswerData(prob) {
  let ncount = prob.answer_board_data.length;
  let array_answer_data = [];
  for (let i = 0; i < ncount; i++) {
    let pieces_data = prob.answer_board_data[i];
    let p_count = pieces_data.pieces_array.length;
    let board = {dataArray: []};
    board.type = pieces_data.piece_type;
    let bsize = pieces_data.board_size;
    for (let j = 0; j < bsize; j++) {
      board.dataArray.push(-1 >>> 0);
    }
    for (let k = 0; k < p_count; k++) {
      let piece = pieces_data.pieces_array[k].piece;
      let pre_pos = 0;
      var dpos_array = Buffer.from(pieces_data.pieces_array[k].dpos, "base64");
      let count2 = dpos_array.length;
      for (let j = 0; j < count2; j++) {
        let dp = dpos_array[j];
        var delta;
        if (dp >= 0x80) {
          j++;
          let np = dpos_array[j];
          delta = ((dp & 0x7f) << 8) | np;
        }
        else {
          delta = dp;
        }
        let p = pre_pos + delta;
        board.dataArray[p] = piece >>> 0;
        pre_pos = p;
      }
    }
    array_answer_data.push(board);
  }
  return array_answer_data;
}

export const on_load_problem = (problem, problem_index) => dispatch => {
  console.log('###', problem);
  let array_answer_data = toArrayAnswerData(problem);
  for(let i = 0; i < problem.array_answer_data.length; i ++) {
    let array = new PBC.INT_ARRAY();
    array.type = problem.array_answer_data[i].answer_type;
    array.dataArray = problem.array_answer_data[i].data_array;
    for(let k = 0; k < array.dataArray.length; k ++) {
      array.dataArray[k] >>>= 0;
    }
    array_answer_data.push(array);
  }
  problem.array_board_data = toArrayBoardData(problem);
  for(let i = 0; i < problem.array_board_data.length; i ++) {
    for(let j = 0; j < problem.array_board_data[i].array_board.length; j ++) {
      let dataArray = problem.array_board_data[i].array_board[j].data_array;
      for(let k = 0; k < dataArray.length; k ++) {
        dataArray[k] >>>= 0;
      }
    }
  }
  let stick_total_action_count = get_stick_total_action_count(problem);
  dispatch({ type: ACTION.INIT_PUZZLE_BOARD, stick_total_action_count });
  dispatch({ type: ACTION.LOAD_PUZZLE_PROBLEM, problem, problem_index, array_answer_data });
  dispatch({ type: ACTION.SET_PUZZLE_BOARD, problem });
  dispatch({ type: ACTION.SET_PUZZLE_STATE, new_state: PCD.VIEW_STATE.ST_SOLVEPROB});
  dispatch({ type: ACTION.RESET_CUR_EXTRA_INDEX, });
  dispatch({ type: ACTION.RESET_EXTRA_INDICES, });
}

export const on_resolve_problem = (problem, solved, retried, time) => dispatch => {
  let stick_total_action_count = get_stick_total_action_count(problem);
  dispatch({ type: ACTION.INIT_PUZZLE_BOARD, stick_total_action_count });
  dispatch({ type: ACTION.RESOLVE_PUZZLE_PROBLEM, solved, retried, time });
  dispatch({ type: ACTION.RESET_CUR_EXTRA_INDEX, });
  dispatch({ type: ACTION.RESET_EXTRA_INDICES, });
}

export function on_complete_solve() {
  return { type: ACTION.COMPLETE_SOLVE_PUZZLE, };
}

export function set_cur_extra_index(cur_extra_index) {
  return { type: ACTION.SET_CUR_EXTRA_INDEX, cur_extra_index };
}

export function set_extra_indices(extra_indices) {
  return { type: ACTION.SET_EXTRA_INDICES, extra_indices };
}

export function set_prob_index(prob_idx) {
  return { type: ACTION.SET_PROB_INDEX, prob_idx}
}