import React, {useState,useEffect, useRef} from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import ErrorCode from "../../helper/errorCode";
import  PROTOCOL  from"../../helper/protocol";
import g_SM from "../../helper/SoundManager";
import skpniGame,  {g_inistonepos} from './skpniGame';
import * as Icon from "@material-ui/icons";
import Emoticon from "../emoticon/Emoticon";
import Chat from "../chat/Chat";
import {
  Button,
} from '@material-ui/core';

import * as CommonAction from "../../store/actions/common.action";
import * as RoomAction from "../../store/actions/room.action";
import * as SKoniAction from "../../store/actions/skpni.action";
import * as AuthAction from "../../store/actions/auth.action";

var handle_timeout;

function SKoniBoard(props) { 
  const [emoticon_dlg_open, setEmoticonDlgOpen] = useState(false);
  const [chat_dlg_open, setChatDlgOpen] = useState(false);
  var SKCanvas;
  var SKCtx;
  var BackgroundCanvas;
  var BackCtx;
  var BackCtx_ref = useRef();
  var SMCanvas;
  var SMCanvas_ref = useRef();
  var SMCtx;
  var SMCtx_ref = useRef();
  var RSImg, BSImg, backgroundImg;
  var RSImg_ref = useRef();
  var BSImg_ref = useRef();
  var SKCtx_ref = useRef();
  var spectate_mode_ref = useRef();
  var mineNumber_ref = useRef();
  var W = window.innerWidth;
  var H = window.innerHeight;
  var VW = W / 100;
  var VH = H / 100;
  var h = 5.625 ; //vh
  var b = 6.5 * VH / VW; //vw  
  var node0 = [50 - 1.4, 5 - VW / VH * 1.9];
  let srcPos = 100;
  let dstPosGroup ;
  let moveIndex = 0;
  let isMove = true;
  var selectedStarIndex_ref = useRef();  
  let turn_ref = useRef();
  var StarsPos;
  const resetStarsPos = () => {
    W = window.innerWidth;
    H = window.innerHeight;
    VW = W / 100;
    VH = H / 100;   
    h = 5.625 ; //vh
    b = 6.5 * VH / VW; //vw 
    node0 = [50 - 1.4, 5 - VW / VH * 1.9];
    StarsPos = [
      [node0[0], node0[1]], // one row
      [node0[0]  + b / 2, node0[1] + h],
      [node0[0]  + b, node0[1] + h * 2],
      [node0[0]  + b * 3 / 2, node0[1] + h * 3],
      [node0[0]  + b * 2, node0[1] + h * 4],
      [node0[0]  + b * 5 / 2, node0[1] + h * 5],
      [node0[0]  + b * 3, node0[1] + h * 6],
      [node0[0]  + b * 7 / 2, node0[1] + h * 7],
      [node0[0]  + b  * 8 / 2, node0[1] + h * 8],
    
      [node0[0]  - b / 2, node0[1] + h], // two row
      [node0[0], node0[1] + h * 2],
      [node0[0]  + b / 2, node0[1] + h * 3],
      [node0[0]  + b, node0[1] + h * 4],
      [node0[0]  + b * 3 / 2, node0[1] + h * 5],
      [node0[0]  + b * 2, node0[1] + h * 6],
      [node0[0]  + b * 5 / 2, node0[1] + h * 7],
      [node0[0]  + b * 3, node0[1] + h * 8],
      [node0[0]  + b * 7/ 2, node0[1] + h * 9],
    
      [node0[0]  - b, node0[1] + h * 2], // three  row 
      [node0[0]  - b / 2, node0[1] + h * 3],
      [node0[0], node0[1] + h * 4],
      [node0[0]  + b / 2, node0[1] + h * 5],
      [node0[0]  + b , node0[1] + h * 6],
      [node0[0]  + b * 3 / 2, node0[1] + h * 7],
      [node0[0]  + b * 2, node0[1] + h * 8],
      [node0[0]  + b * 5 / 2, node0[1] + h * 9],
      [node0[0]  + b * 3, node0[1] + h * 10],  
    
      [node0[0]  - b * 3/ 2, node0[1] + h * 3], // four row
      [node0[0]  - b, node0[1] + h * 4],
      [node0[0]  - b / 2, node0[1] + h * 5],
      [node0[0], node0[1] + h * 6],
      [node0[0] + b / 2, node0[1] + h * 7],
      [node0[0]  + b, node0[1] + h * 8],
      [node0[0]  + b * 3 / 2, node0[1] + h * 9],
      [node0[0]  + b * 2, node0[1] + h * 10],
      [node0[0]  + b * 5 / 2, node0[1] + h * 11],
      
      [node0[0]  - b * 2, node0[1] + h * 4], // five row
      [node0[0]  - b * 3 / 2, node0[1] + h * 5],
      [node0[0]  - b, node0[1] + h * 6],
      [node0[0]  - b / 2, node0[1] + h * 7],
      [node0[0], node0[1] + h * 8],
      [node0[0]  + b / 2, node0[1] + h * 9],
      [node0[0]  + b, node0[1] + h * 10],
      [node0[0]  + b * 3 / 2, node0[1] + h * 11],
      [node0[0]  + b * 2, node0[1] + h * 12],
    
      [node0[0]  - b * 5 / 2, node0[1] + h * 5], // six row
      [node0[0]  - b * 2, node0[1] + h * 6],
      [node0[0]  - b * 3 / 2, node0[1] + h * 7],
      [node0[0]  - b, node0[1] + h * 8],
      [node0[0] - b / 2 , node0[1] + h * 9],
      [node0[0], node0[1] + h * 10],
      [node0[0]  + b / 2, node0[1] + h * 11],
      [node0[0]  + b , node0[1] + h * 12],
      [node0[0]  + b * 3 / 2, node0[1] + h * 13],
      
      [node0[0]  - b * 3, node0[1] + h * 6], // seven row
      [node0[0]  - b * 5 / 2, node0[1] + h * 7],
      [node0[0]  - b * 2, node0[1] + h * 8],
      [node0[0]  - b * 3 / 2, node0[1] + h * 9],
      [node0[0]  - b , node0[1] + h * 10],
      [node0[0]  - b / 2, node0[1] + h * 11],
      [node0[0], node0[1] + h * 12],
      [node0[0] + b / 2, node0[1] + h * 13],
      [node0[0] + b , node0[1] + h * 14],
      
      [node0[0] - b * 7 / 2, node0[1] + h * 7], // eight row
      [node0[0] - b * 3, node0[1] + h * 8],
      [node0[0] - b * 5 / 2, node0[1] + h * 9],
      [node0[0] - b * 2, node0[1] + h * 10],
      [node0[0] - b * 3 / 2, node0[1] + h * 11],
      [node0[0] - b, node0[1] + h * 12],
      [node0[0] - b / 2, node0[1] + h * 13],
      [node0[0], node0[1] + h * 14],
      [node0[0] + b / 2, node0[1] + h * 15],
      
      [node0[0] - b * 4, node0[1] + h * 8],// nine row
      [node0[0] - b * 7 / 2, node0[1] + h * 9],
      [node0[0] - b * 3, node0[1] + h * 10],
      [node0[0] - b * 5 / 2, node0[1] + h * 11],
      [node0[0] - b * 2, node0[1] + h * 12],
      [node0[0] - b * 3 / 2, node0[1] + h * 13],
      [node0[0] - b, node0[1] + h * 14],
      [node0[0] - b / 2, node0[1] + h * 15],
      [node0[0], node0[1] + h * 16],
    ];
  }
  const mapDomToVar = ()=>{
    SKCanvas = document.getElementById('StarBoard');
    if(props.replay){
      BSImg =  document.getElementById('B_Star_r');
      RSImg =  document.getElementById('R_Star_r');
    } else {
      BSImg =  document.getElementById('B_Star');
      RSImg =  document.getElementById('R_Star');
    }
    BSImg_ref.current = BSImg;
    RSImg_ref.current = RSImg;
    backgroundImg =  document.getElementById('SKoniBoard');
    SKCtx = SKCanvas.getContext("2d");
    SKCtx_ref.current = SKCtx;
    BackgroundCanvas = document.getElementById('BackgroundBoard');
    BackCtx = BackgroundCanvas.getContext('2d');
    BackCtx_ref.current = BackCtx;
    SMCanvas = document.getElementById('StarMoveBoard');      
    SMCanvas_ref.current = SMCanvas;
    SMCtx = SMCanvas.getContext('2d');
    SMCtx_ref.current = SMCtx;
  };
  const drawLine = () => {
    BackCtx_ref.current.clearRect(0, 0, W, H);  
    BackCtx_ref.current.beginPath();
    BackCtx_ref.current.moveTo( W / 2, H / 20 - VW * 1.4);
    BackCtx_ref.current.lineTo(W / 2 - 54 / 138.5 * H - VW * 1.4, 29 / 40 * H + VW * 1.4 * 0.58);
    BackCtx_ref.current.lineTo(W / 2 + 54 / 138.5 * H + VW * 1.4, 29 / 40 * H + VW * 1.4 * 0.58);
    if (props.replay) {
      BackCtx_ref.current.fillStyle = 'white'; 
    } else BackCtx_ref.current.fillStyle = 'grey';  
    BackCtx_ref.current.fill();  
    BackCtx_ref.current.beginPath();
    BackCtx_ref.current.moveTo( W / 2, H * 19 / 20 + VW * 1.4);
    BackCtx_ref.current.lineTo(W / 2 - 54 / 138.5 * H - VW * 1.4, 11 / 40 * H - VW * 1.4 * 0.58);
    BackCtx_ref.current.lineTo(W / 2 + 54 / 138.5 * H + VW * 1.4, 11 / 40 * H - VW * 1.4 * 0.58);
    if (props.replay) {
      BackCtx_ref.current.fillStyle = 'white'; 
    } else BackCtx_ref.current.fillStyle = 'grey';  
    BackCtx_ref.current.fill();  
    //   
    BackCtx_ref.current.beginPath();
    BackCtx_ref.current.moveTo( W / 2, H / 20);
    BackCtx_ref.current.lineTo(W / 2 - 54 / 138.5 * H, 29 / 40 * H);
    BackCtx_ref.current.lineTo(W / 2 + 54 / 138.5 * H, 29 / 40 * H);
    if (props.replay) {
      BackCtx_ref.current.fillStyle = 'white';    
    } else BackCtx_ref.current.fillStyle = '#f7cac9';     
    BackCtx_ref.current.fill();
    BackCtx_ref.current.beginPath();
    BackCtx_ref.current.moveTo( W / 2, H * 19 / 20);
    BackCtx_ref.current.lineTo(W / 2 - 54 / 138.5 * H, 11 / 40 * H);
    BackCtx_ref.current.lineTo(W / 2 + 54 / 138.5 * H, 11 / 40 * H);
    if (props.replay) {
      BackCtx_ref.current.fillStyle = 'white';    
    } else BackCtx_ref.current.fillStyle = '#98ddde';
    BackCtx_ref.current.fill();
    BackCtx_ref.current.beginPath();
    BackCtx_ref.current.moveTo( W / 2 - 54 / 415.8 * H, H * 29 / 40);
    BackCtx_ref.current.lineTo(W / 2  +  54 / 415.8 * H, 29 / 40 * H);
    BackCtx_ref.current.lineTo(W / 2 + 108 / 415.8 * H,  H / 2);
    BackCtx_ref.current.lineTo(W / 2 + 54 / 415.8 * H,  H / 40 * 11);
    BackCtx_ref.current.lineTo(W / 2 - 54 / 415.8 * H,  H / 40 * 11);
    BackCtx_ref.current.lineTo(W / 2 - 108 / 415.8 * H,  H / 2);
    if (props.replay) {
      BackCtx_ref.current.fillStyle = 'white';    
    } else BackCtx_ref.current.fillStyle = '#adff2f';
    BackCtx_ref.current.fill();
    let srcNode = [W / 2, H / 20];
    for(let i = 1; i <= 12; i ++) {
      BackCtx_ref.current.beginPath();
      BackCtx_ref.current.moveTo(srcNode[0] - b / 2 * i * VW, srcNode[1] + h * i * VH);
      BackCtx_ref.current.lineTo(srcNode[0] + b / 2 * i * VW, srcNode[1] + h * i * VH);
      BackCtx_ref.current.stroke();
    }
    srcNode = [W / 2, H * 19 / 20];
    for(let i = 1; i <= 12; i ++) {
      BackCtx_ref.current.beginPath();
      BackCtx_ref.current.moveTo(srcNode[0] - b / 2 * i * VW, srcNode[1] - h * i * VH);
      BackCtx_ref.current.lineTo(srcNode[0] + b / 2 * i * VW, srcNode[1] - h * i * VH);
      BackCtx_ref.current.stroke();
    }    
    srcNode = [W / 2 - 54 / 138.5 * H, H * 11 / 40];
    for(let i = 1; i <= 12; i ++) {
      BackCtx_ref.current.beginPath();
      BackCtx_ref.current.moveTo(srcNode[0] + b  * i * VW , srcNode[1]);
      BackCtx_ref.current.lineTo(srcNode[0] + b  * i * VW / 2, srcNode[1] + h * i * VH);
      BackCtx_ref.current.stroke();
    }
    srcNode = [W / 2 + 54 / 138.5 * H, H * 29 / 40];
    for(let i = 1; i <= 12; i ++) {
      BackCtx_ref.current.beginPath();
      BackCtx_ref.current.moveTo(srcNode[0] - b  * i * VW , srcNode[1]);
      BackCtx_ref.current.lineTo(srcNode[0] - b  * i * VW / 2, srcNode[1] - h * i * VH);
      BackCtx_ref.current.stroke();
    }
    srcNode = [W / 2 - 54 / 138.5 * H, H * 29 / 40];
    for(let i = 1; i <= 12; i ++) {
      BackCtx_ref.current.beginPath();
      BackCtx_ref.current.moveTo(srcNode[0] + b  * i * VW , srcNode[1]);
      BackCtx_ref.current.lineTo(srcNode[0] + b  * i * VW / 2, srcNode[1] - h * i * VH);
      BackCtx_ref.current.stroke();
    }
    srcNode = [W / 2 + 54 / 138.5 * H, H * 11 / 40];
    for(let i = 1; i <= 12; i ++) {
      BackCtx_ref.current.beginPath();
      BackCtx_ref.current.moveTo(srcNode[0] - b  * i * VW , srcNode[1]);
      BackCtx_ref.current.lineTo(srcNode[0] - b  * i * VW / 2, srcNode[1] + h * i * VH);
      BackCtx_ref.current.stroke();
    }
  }
  const calTroPos = (troPos)=> {
    let y = troPos & 0xff;
    let x = (troPos>>8) & 0xff;
    let posX, posY;
    //const {mineNumber} = props;
    //rotate????
    // if(mineNumber !== 0) {
    //   if(x === 0xff) {       
    //     x = 9;
    //     y = 8 - y;
    //   } else if(x === 9) {        
    //     x = 0xff;
    //     y = 8 - y;
    //   } else if(y === 0xff) {         
    //     x = 8 - x ;
    //     y = 9;
    //   } else if(y === 9) {        
    //     x = 8 - x;
    //     y = 0xff;
    //   }
    // };
    //x, y pos get
    if(x === 0xff) {
      posX = node0[0] - b / 2 * (y + 1);
      posY = node0[1] + h * (y - 1) ;
    } else if(y === 0xff) {
      posX = node0[0] + b / 2 * (x + 1);
      posY = node0[1] + h * (x - 1);
    } else if(x === 9) {
      posX = node0[0] + b / 2 * (x - y);
      posY = node0[1] + h * (x + y);
    } else if(y === 9) {
      posX = node0[0] - b / 2 * (y - x);
      posY = node0[1] + h * (x + y);
    }
    return [posX, posY];
  };
  const starsDraw = ()=>{
    SKCtx_ref.current.clearRect(27.5 * VW , -12 * VW , 43 * VW, 86* VW);
    resetStarsPos();
    drawLine();
    let board = skpniGame.m_board.slice();
    board.map((B_OR_R,index)=>{
      if(B_OR_R  === 1) {
        let pos = StarsPos[index];
        SKCtx_ref.current.drawImage(RSImg_ref.current, pos[0] * VW, pos[1] * VH, 2.8 * VW, 2.8 * VW); 
      } else if(B_OR_R === 2) {
        let pos = StarsPos[index];
        SKCtx_ref.current.drawImage(BSImg_ref.current, pos[0] * VW, pos[1] * VH, 2.8 * VW, 2.8 * VW); 
      }
    });
  };  
  const onExit = ()=>{
    let {user, room_id, room_type, players} = props;
    if(!!room_type){
      if(room_type == "spectate") props.history.push('/lobby');
      else {
        if (players.length == 2) {
          let token = user.token;
          socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_WILL_OUT_ROOM, {token, room_id});
        } else props.history.push('/lobby');
      }
    } else props.history.push('/lobby');
  }; 
  const StarMove = (srcNum, MiddleNumArr, step)=>{          
    let index = 0;  
    SMCtx_ref.current.clearRect( 0, 0, W, H ); 
    const move = ()=>{ 
      if(moveIndex === MiddleNumArr.length) {
        SMCtx_ref.current.clearRect( 0, 0, W, H );
        //skpniGame.m_board[MiddleNumArr[MiddleNumArr.length - 1]] = 2 - turn_ref.current;
        g_SM.playSound('putstone'); 
        drawDstNode(MiddleNumArr[MiddleNumArr.length - 1]);
        starsDraw();
        moveIndex = 0;
        SMCanvas_ref.current.style.opacity = 1;
        return;
      }
      if (!!handle_timeout) clearTimeout(handle_timeout);                
      if(srcPos === 100 || moveIndex === 0)
        srcPos = StarsPos[srcNum].slice();
      else {
        if(MiddleNumArr[moveIndex - 1] > 0xff) {     // trojumpposition
          srcPos = calTroPos(MiddleNumArr[moveIndex - 1]);
        } else {
          srcPos = StarsPos[MiddleNumArr[moveIndex-1]].slice();
        }          
      }
      if(MiddleNumArr[moveIndex] > 0xff) {    // trojumpposition
        dstPosGroup = calTroPos(MiddleNumArr[moveIndex]);
      } else {
        dstPosGroup = StarsPos[MiddleNumArr[moveIndex]].slice();
      }       
      let delta_x = (dstPosGroup[0] - srcPos[0]) / step;
      let delta_y = (dstPosGroup[1] - srcPos[1]) / step;
      
      SMCtx_ref.current.clearRect( (srcPos[0] + delta_x * (index - 1)) * VW - 5, (srcPos[1]  + delta_y * (index - 1)) * VH - 5 , 3.3 * VW + 5, 3.3 * VW + 5);
      //SMCtx_ref.current.drawImage(RSImg, (srcPos[0] + delta_x * index) * VW, (srcPos[1]  + delta_y * index) * VH ,3.3 * VW, 3.3 * VW );
      if(1 - turn_ref.current === mineNumber_ref.current)
        SMCtx_ref.current.drawImage(RSImg_ref.current, (srcPos[0] + delta_x * index) * VW, (srcPos[1]  + delta_y * index) * VH ,3.3 * VW, 3.3 * VW );
      else if(mineNumber_ref.current >= 2) {
        if(1 - turn_ref.current === 0)
          SMCtx_ref.current.drawImage(BSImg_ref.current, (srcPos[0] + delta_x * index) * VW, (srcPos[1]  + delta_y * index) * VH ,3.3 * VW, 3.3 * VW );
        else
          SMCtx_ref.current.drawImage(RSImg_ref.current, (srcPos[0] + delta_x * index) * VW, (srcPos[1]  + delta_y * index) * VH ,3.3 * VW, 3.3 * VW );
      } else 
          SMCtx_ref.current.drawImage(BSImg_ref.current, (srcPos[0] + delta_x * index) * VW, (srcPos[1]  + delta_y * index) * VH ,3.3 * VW, 3.3 * VW );
      index ++; 
      if(index -1  === step) {
        moveIndex ++;
        index = 0;
        handle_timeout = setTimeout(move, 20);
      }  else {
        handle_timeout = setTimeout(move, 5);
      }
    };
    move();  
  } 
  const getSelectNum = (event)=>{
    for(let i = 0; i < StarsPos.length; i ++) {
      if(Math.abs(StarsPos[i][0] * VW + 1.4 * VW - event.pageX) < 1.4 * VW && Math.abs(StarsPos[i][1] * VH + 1.4 * VW- event.pageY) < 1.4 * VW) 
        return i; 
    }
  };
  const drawDstNode = (point)=>{
    SMCtx_ref.current.clearRect(0, 0, W, H);
    SMCtx_ref.current.lineWidth = VW / 6;
    if (props.replay) {
      SMCtx_ref.current.strokeStyle = "black";
    } else SMCtx_ref.current.strokeStyle = "grey";
    
    for(let i = 0; i < 6; i ++) {
      SMCtx_ref.current.beginPath();
      SMCtx_ref.current.arc((StarsPos[point][0] + 1.4) * VW, (StarsPos[point][1] ) * VH + 1.8 * VW, VW * 1.3  ,  i * Math.PI / 3 - Math.PI / 15, i * Math.PI / 3 + Math.PI / 15 );
      SMCtx_ref.current.stroke();
    }
  }
  const drawMovableNodes=(points)=>{
    SMCanvas.style.opacity = 0.7; 
    let index = 0;
    let handleTimeout;
    const drawPoints = ()=>{
      if(isMove) {          
        clearTimeout(handleTimeout);
        return;
      }
      clearTimeout(handleTimeout);
      SMCtx_ref.current.clearRect(0, 0, W, H);
      points.map((point, i)=>{
        if(i < points.length - 1) {
          SMCtx_ref.current.save();        
          SMCtx_ref.current.lineWidth = VW / 3;
          SMCtx_ref.current.strokeStyle = "grey";
          SMCtx_ref.current.beginPath();
          SMCtx_ref.current.arc((StarsPos[point][0] + 1.4) * VW, StarsPos[point][1] * VH + 1.9 * VW, VW / 2,  0, 2 * Math.PI);
          SMCtx_ref.current.stroke();
          SMCtx_ref.current.beginPath();
          SMCtx_ref.current.strokeStyle = "black";
          SMCtx_ref.current.arc((StarsPos[point][0] + 1.4) * VW, StarsPos[point][1] * VH + 1.9 * VW, VW / 2 ,  0 + Math.PI/ 4 * index,  Math.PI / 2 + Math.PI / 4 * index);
          SMCtx_ref.current.stroke();
          SMCtx_ref.current.restore();      
        } else {
          SMCtx_ref.current.save();        
          SMCtx_ref.current.lineWidth = VW / 2;
          SMCtx_ref.current.strokeStyle = "yellow";
          SMCtx_ref.current.beginPath();
          SMCtx_ref.current.arc((StarsPos[point][0] + 1.4) * VW, StarsPos[point][1] * VH + 1.9 * VW, VW * 1.7,  0, 2 * Math.PI);
          SMCtx_ref.current.stroke();
          SMCtx_ref.current.beginPath();
          SMCtx_ref.current.strokeStyle = "green";
          SMCtx_ref.current.arc((StarsPos[point][0] + 1.4) * VW, StarsPos[point][1] * VH + 1.9 * VW, VW * 1.7 ,  0 + Math.PI/ 4 * index,  Math.PI / 2 + Math.PI / 4 * index);
          SMCtx_ref.current.stroke();
          SMCtx_ref.current.restore();   
        }
      })
      index ++;
      handleTimeout = setTimeout(drawPoints,100);
    }
    drawPoints();
  } ;
  const rotate_PI_Matrix = (x, y)=> {
    let r_x, r_y;
    r_x = 8 - x;
    r_y = 8 - y;
    return [r_x, r_y];
  }
  const calServerMove=(srcpos, dstpos)=> {
    let src_x, src_y, dst_x, dst_y , move ;    
    //mineNumber = 1  // rps sljdojfoiw
    src_x = srcpos % 9;
    src_y = Math.floor(srcpos / 9);
    dst_x = dstpos % 9;
    dst_y = Math.floor(dstpos / 9);
    if(mineNumber_ref.current >= 1) {
      [src_x, src_y] = rotate_PI_Matrix(src_x, src_y);
      [dst_x, dst_y] = rotate_PI_Matrix(dst_x, dst_y);
    }
    move = src_x * 1000 + src_y * 100 + dst_x * 10 + dst_y;
    return move;
  };
  const kpniMove = (turn, move)=>{
    let srcPos , dstPos;
    let middlePos = [];  
    let StarMoveRoute = [];
    [srcPos, dstPos] = calClientMove(move);                 
    skpniGame.getmovepath(dstPos, srcPos, middlePos);          
    skpniGame.domove(srcPos, dstPos, turn); 
    if(move === 9000) {
      return;  
    }
    skpniGame.m_board[dstPos] = 0;      
    starsDraw();
    if(1 - turn_ref.current === mineNumber_ref.current)    
      skpniGame.m_board[dstPos] = 1; 
    else if(mineNumber_ref.current >= 2) {
      skpniGame.m_board[dstPos] = 2 - turn;                       
    } else 
        skpniGame.m_board[dstPos] = 2; 
    SMCanvas_ref.current.style.opacity = 0.5;
    if(middlePos.length === 0 && middlePos.length === 1) {
      StarMove(srcPos, [dstPos], 20);
    } else {
      StarMoveRoute = middlePos.slice();
      StarMoveRoute.pop();
      StarMoveRoute.push(dstPos);
      StarMove(srcPos, StarMoveRoute, 10);
    }  
  };
  const starVibration = (posIndex)=>{
    let move_index = 0;
    let temp_move = isMove;
    SKCtx_ref.current.clearRect((StarsPos[posIndex][0]) * VW, (StarsPos[posIndex][1]) * VH, 3 * VW, 3* VW);
    const vibration = ()=>{
      if(temp_move !== isMove) {
        SMCtx_ref.current.clearRect((StarsPos[posIndex][0]) * VW, (StarsPos[posIndex][1]) * VH, 3.3 * VW, 3.3* VW);
        return;
      }          
      if(move_index %2 === 0) {
        SMCtx_ref.current.clearRect((StarsPos[posIndex][0] -0.2) * VW, (StarsPos[posIndex][1] - 0.2) * VH, 3 * VW, 3* VW);
        SMCtx_ref.current.drawImage(RSImg_ref.current, (StarsPos[posIndex][0]-0.05) * VW, StarsPos[posIndex][1] * VH ,2.8 * VW, 2.8 * VW );
      } 
      else {
        SMCtx_ref.current.clearRect((StarsPos[posIndex][0] - 0.2) * VW, (StarsPos[posIndex][1] - 0.2) * VH, 3 * VW, 3 * VW);
        SMCtx_ref.current.drawImage(RSImg_ref.current, (StarsPos[posIndex][0]+0.05) * VW, StarsPos[posIndex][1] * VH ,2.8 * VW, 2.8 * VW );
      }
      move_index ++;
      setTimeout(()=>{
        vibration();
      }, 80)
    };
    vibration();
    // SKCtx_ref.current.clearRect(0, 0, W, H);
  };
  const calClientMove = (move)=> {
    let src_x, src_y, dst_x, dst_y , srcpos, dstpos;    
    src_x = Math.floor(move / 1000);
    src_y = (Math.floor(move / 100)) % 10;
    dst_x = (Math.floor(move / 10)) % 10;
    dst_y = move % 10;
    if(mineNumber_ref.current >= 1) {
      [src_x, src_y] = rotate_PI_Matrix(src_x, src_y);
      [dst_x, dst_y] = rotate_PI_Matrix(dst_x, dst_y);
    }
    srcpos = src_x + src_y * 9;
    dstpos = dst_x + dst_y * 9;
    return [srcpos, dstpos];
  };
  let isGameStart_ref = useRef();
  let socketRoom_ref = useRef();
  useEffect(()=>{    
    isGameStart_ref.current = props.isGameStart;
  }, [props.isGameStart]);

  useEffect(()=>{  
    setEmoticonDlgOpen(props.isOpenEmoticonDlg);
  },[props.isOpenEmoticonDlg]);

  useEffect(()=>{
    setChatDlgOpen(props.isShowMesDlg);
  },[props.isShowMesDlg]);
  

  const chatDlgOpen = () => {
    props.updateMessageDlg();
  };
  
  const emoticonDlgOpen = () => {
    props.updateEmoticonDlg();
  };

  useEffect(()=>{    
    const {move_history, turn, gr_index} = props;
    spectate_mode_ref.current = props.spectate_mode;
    if(props.spectate_mode === 1) {       
      props.update_skpni_gr_index(-gr_index);
      SMCtx_ref.current.clearRect(0, 0, W, H); 
      skpniGame.initgame(1, 2);           
      starsDraw();
    }
    if(props.spectate_mode === 0) {
      skpniGame.initgame(1, 2);         
      for(let i = 0; i < move_history.length; i ++) {
        let srcPos, dstPos;
        [srcPos, dstPos] = calClientMove(move_history[i]);
        if(turn === 1)
          skpniGame.domove(srcPos, dstPos, (i + 1) % 2); 
        else 
          skpniGame.domove(srcPos, dstPos,  i % 2); 
      }       
      if(move_history.length >= 1) {
        starsDraw();
      }              
    };     
  }, [props.spectate_mode]);

  useEffect(()=>{
    if(props.gr_index === 0 || props.gr_index === props.move_history.length - 1) {
      if(props.gr_index === 0 &&  props.move_history.length !== 0) {   // skipping first render.....
        SMCtx_ref.current.clearRect( 0, 0, W, H );
        skpniGame.initgame(1, 2);
        starsDraw();
      }
      return; 
    }               
    if(props.spectate_mode === 1) {
      let  {gr_index, move_history, turn} = props;       
      skpniGame.initgame(1, 2);       
      
      for(let i = 0; i < gr_index - 1 ; i ++) {
        let srcPos, dstPos;
        [srcPos, dstPos] = calClientMove(move_history[i]);
        if(turn === 1)
          skpniGame.domove(srcPos, dstPos, (i + 1) % 2); 
        else 
          skpniGame.domove(srcPos, dstPos,  i % 2); 
      }      
      starsDraw();
      if(turn === 0) {
        turn_ref.current = (gr_index) % 2;          
        kpniMove(( gr_index - 1)   % 2, move_history[gr_index - 1]);
      } else {
        turn_ref.current = (gr_index - 1) % 2;        
        kpniMove(gr_index % 2, move_history[gr_index - 1]);
      }   
    } else if(props.replay) {      
      let  {gr_index, move_history, turn} = props;
      skpniGame.initgame(1, 2);    
      for(let i = 0; i < gr_index - 1 ; i ++) {
        let srcPos, dstPos;
        if(move_history[i] !== 9000) {
          [srcPos, dstPos] = calClientMove(move_history[i]);
        if(turn === 1)
          skpniGame.domove(srcPos, dstPos, (i + 1) % 2); 
        else 
          skpniGame.domove(srcPos, dstPos,  i % 2); 
        }
      }      
      starsDraw();
      if(turn === 0) {
        turn_ref.current = (gr_index) % 2;          
        kpniMove(( gr_index - 1) % 2, move_history[gr_index - 1]);
      } else {
        turn_ref.current = (gr_index - 1) % 2;        
        kpniMove(gr_index % 2, move_history[gr_index - 1]);
      }
    }
  }, [props.gr_index]);

  useEffect(()=>{
    socketRoom_ref.current = props.socketRoom;
    if(!!socketRoom_ref.current) {
      socketRoom_ref.current.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.SC_GAME_MOVE:
            {                    
              if(spectate_mode_ref.current === 1) {   // in view history
                props.add_move(msg.move);
                return;
              }                             
              if (err === ErrorCode.SUCCESS) {                   
                let temp_turn = msg.turn, move = msg.move;                  
                turn_ref.current = 1 - temp_turn;
                props.add_move(move);
                if(move !== 9000)
                  kpniMove(temp_turn, move);                      
              }
            }
            break;
          case PROTOCOL.SC_START_PREPARE:
            skpniGame.initgame(1, 2);             
            break; 
          case PROTOCOL.SC_GAME_START:
            {
              if (err === ErrorCode.SUCCESS) {
                turn_ref.current = msg.turn; 
                // skpniGame.initgame(1, 2);       //  game init for replay....
                starsDraw();
              }
            }
            break;
          case PROTOCOL.SC_JOINED_PLAYER:
            {
              if (err === ErrorCode.SUCCESS) {
                props.joined_player(msg.user);
              }
            } 
            break;  
          case PROTOCOL.SC_ROOM_INFO:
            let move_history = msg.move_history;
            let first_turn = msg.first_turn;                      
            move_history.map((move, index)=>{
              let srcPos, dstPos, turn;
              [srcPos, dstPos] = calClientMove(move);
              if(first_turn === 1)
                skpniGame.domove(srcPos, dstPos, (index + 1) % 2); 
              else 
                skpniGame.domove(srcPos, dstPos,  index % 2); 
            });
            starsDraw();  
            break;
          default:
            break;
        }
      });
    }
  }, [props.socketRoom]);
  const {user, room_id, room_type} = props;
  let token = !!user?user.token:null;
  useEffect(()=>{
    resetStarsPos();
    mapDomToVar();
    document.getElementById('B_Star').addEventListener('load', starsDraw);    
    window.addEventListener('resize', starsDraw);        
    document.getElementById('StarMoveBoard').addEventListener('click', function(event) {      
      if(mineNumber_ref.current === turn_ref.current && mineNumber_ref.current <= 1) {
        let dstPosGroup = [];
        let dstPos;
        let move;
        isMove = !isMove;   
        g_SM.playSound('buttonclick'); 
        //isGameStart_ref.current = true;   // dfwfow        
        if(!isMove && isGameStart_ref.current) {
          selectedStarIndex_ref.current = getSelectNum(event);  
          if(skpniGame.m_board[selectedStarIndex_ref.current] !== 1)
            return;  
          skpniGame.getmovablepos(selectedStarIndex_ref.current, dstPosGroup);   
          dstPosGroup.push(selectedStarIndex_ref.current);      
          drawMovableNodes(dstPosGroup);                        
          return;
        } else if(isMove && isGameStart_ref.current) {
          SMCtx_ref.current.clearRect(0, 0, W, H);          
          dstPos = getSelectNum(event);     
          if(!skpniGame.ispossible(dstPos, selectedStarIndex_ref.current)) {            
            return;
          }           
        }       
        //  starVibration(dstPos);   
        move = calServerMove(selectedStarIndex_ref.current, dstPos);     
        let clientmove = calClientMove(move);           
        socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_GAME_MOVE, {token:token, room_id:room_id, move:move});   
        }            
    });    
    g_SM.initSounds();
    return ()=>{
      props.init_move_history();
    }
  }, []);
  useEffect(()=>{
    mineNumber_ref.current = props.mineNumber;
  }, [props.mineNumber]);
  return(  
    <div id='board' style={{width:'100vh', backgroundColor:"rgba(0, 0, 0, 0)",height: '100vh', position:"fixed", top: `${0}px`,left:`${W/ 2 - H / 2}px`,zIndex:"1112"}}>                                              
      
      <img id="SKoniBoard" alt='SKoniBoard' src='/assets/img/SkpniBoard.png' style={{position:'fixed',left:`27.5vw`, top:`-12vw`, display:'none'}}></img>
      <img id="R_Star" alt='R_Star' src='/assets/img/R_S.png' style={{position:'fixed',left: `${47.8 * VW}px`, top:`${2 * VH}px`, width:'3vw', height:'4.2vw', display:'none'}}></img>  
      <img id="B_Star" alt='B_Star' src='/assets/img/B_S.png' style={{position:'fixed',left:`49.5vw`, top:`7.625vh`, width:'3vw', height:'4.2vw', display:'none'}}></img> 
      <img id="R_Star_r" alt='R_Star_r' src='/assets/img/R_Sr.png' style={{position:'fixed',left: `${47.8 * VW}px`, top:`${2 * VH}px`, width:'3vw', height:'4.2vw', display:'none'}}></img>  
      <img id="B_Star_r" alt='B_Star_r' src='/assets/img/B_Sr.png' style={{position:'fixed',left:`49.5vw`, top:`7.625vh`, width:'3vw', height:'4.2vw', display:'none'}}></img> 
      <canvas id="BackgroundBoard" width={`${W}px`} height={`${H}px`} style={{position:'fixed', left:"0px", top:'0px'}}>
      </canvas>
      <canvas id="StarBoard" width={`${W}px`} height={`${H}px`} style={{position:'fixed', left:"0px", top:'0px'}}>
      </canvas>
      <canvas id="StarMoveBoard"  alt = 'StarMoveBoard' width={`${W}px`} height={`${H}px`} style={{position:'fixed', left:"0px", top:'0px'}}>
      </canvas>  
      {props.action === 'play' && 
        <div>
          <Button id = 'message' alt = 'message' onClick = {chatDlgOpen} style = {{display: room_type == "spectate" ? 'none' : '', color:'white', position:'fixed', top:'3vh', left:'71vw',  zIndex:'1113',  width:`${H / 10}px`, height:`${H / 13}px`, }}>
            <Icon.Chat style = {{width: '3vw', height:'auto'}}/>
          </Button> 
          <Button id = 'message' onClick = {emoticonDlgOpen} alt = 'message' style = {{display: room_type == "spectate" ? 'none' : '', color:'white', position:'fixed', top:'3vh', left:'78vw',  zIndex:'1113',  width:`${H / 10}px`, height:`${H / 13}px`, }}>
            <Icon.TagFaces style = {{width: '3vw', height:'auto'}}/>
          </Button>
          <Button id = 'message' alt = 'message' onClick = {onExit} style = {{color:'white', position:'fixed', top:'3vh', left:'85vw',  zIndex:'1113',  width:`${H / 10}px`, height:`${H / 13}px`, }}>
            <Icon.ExitToApp style = {{width: '3vw', height:'auto'}}/>
          </Button>   
        </div>
      }  
      {emoticon_dlg_open && <Emoticon /> }
      {chat_dlg_open && <Chat /> }  
    </div> 
  );
}
const mapStateToProps = (store) => {
  return {    
    users: store.roomReducer.room.users,
    mineNumber:store.skpniReducer.mineNumber,    
    gr_index: store.commonReducer.gr_index,
    move_history: store.roomReducer.room.move_history,
    isGameStart:store.skpniReducer.isGameStart,
    turn:store.roomReducer.room.turn, 
    socketRoom: store.roomReducer.socketRoom,
    room_type: store.roomReducer.room.room_type,

    room_id: store.roomReducer.room.room_id, //RP
    spectate_mode: store.roomReducer.room.spectate_mode, //    
    isOpenEmoticonDlg:store.commonReducer.isOpenEmoticonDlg,  
    isShowMesDlg:store.commonReducer.isShowMesDlg, 
    players: store.roomReducer.room.players,    
    user: store.authReducer.user,   
}};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    //rp
    add_move: RoomAction.add_move,
    update_skpni_gr_index: CommonAction.update_gr_index,
    init_move_history: RoomAction.init_move_history,
    joined_player: RoomAction.joined_player,    
    updateEmoticonDlg: CommonAction.updateEmoticonDlg,   
    updateMessageDlg: CommonAction.updateMessageDlg,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(SKoniBoard));

