import ACTION from '../actionTypes';

const initialState = {
  teacher_in_msg: [],
  teacher_sent_msg: [],
  teacher_students: [],
  teacher_qualification: {
    general: false,
    level: 0,
    wins: 0,
    win_rate: 0,
  },
  connection: null,
  lecture_room: {
    room_id: '',
    teacher: '',
    title: '',
    start: '',
    status: '',
    move_history: [],
    h_index: 0,
  }, 
};

export default function goTeacherReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_TEACHER_DATA:
      return {
        ...state,
        teacher_students: action.students,
      };
    case ACTION.UPDATE_TEACHER_MSG:
      return {
        ...state,
        teacher_in_msg: action.in_msg,
        teacher_sent_msg: action.sent_msg,
      };
    case ACTION.UPDATE_USER_TEACHER_QUALIFICATION:
      return {
        ...state,
        teacher_qualification: {
          ...state.teacher_qualification,
          general: action.qualification.general,
          level: action.qualification.level,
          wins: action.qualification.wins,
          win_rate: action.qualification.win_rate,
        },
      };   
    case ACTION.DELETE_HISTORY_ON_LECTURE:
      return {
        ...state,
        lecture_room: {
          ...state.lecture_room,
          move_history: [],
          h_index: 0,
        },
      };
    case ACTION.RESET_RTC_MULTI_CONNECTION:
      return {
        ...state,
        connection: action.connection,
      };
    case ACTION.ENTER_LECTURE_ROOM:
      return {
        ...state,
        lecture_room: {
          ...state.lecture_room,
          room_id: action.room_id,
          teacher: action.teacher,
          title: action.title,
          start: action.start,
          status: action.status,
        },
      };
    case ACTION.LOAD_BOARD_IN_LECTURE_ROOM:
      return {
        ...state,
        lecture_room: {
          ...state.lecture_room,
          move_history: action.move_history,
          h_index: action.h_index,
        },
      };
    case ACTION.UPDATE_LECTURE_BOARD_HISTORY_INDEX:
      return {
        ...state,
        lecture_room: {
          ...state.lecture_room,
          h_index: action.h_index,
        },
      };
    case ACTION.DO_GO_LECTURE_MOVE:
      return {
        ...state,
        lecture_room: {
          ...state.lecture_room,
          move_history: state.lecture_room.move_history.concat(action.wpos),
          h_index: action.h_index,
        }
      };
    case ACTION.CLEAR_LECTURE_BOARD:
      return {
        ...state,
        lecture_room: {
          ...state.lecture_room,
          move_history: [],
          h_index: 0,
        },
      };
    default: return state;
  }
}
