var notify_change_level = (reason, d_level) => {
  if (!!d_level) {
    if (d_level > 0) 
      notify_s(window.i18n.t(`message.increase_level_reason_${reason}`).replace('{0}', d_level));
    else if (d_level < 0)
      notify_w(window.i18n.t(`message.decrease_level_reason_${reason}`).replace('{0}', -d_level));
  } 
};

export const req_problem_list = (book_id, room_type) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/problem_list', { book_id });
    const {err, problem_book, problem_list, book_solve, reviews} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch({ type: ACTION.LOAD_PROBLEM_BOOK, problem_book, book_solve, });
      dispatch({ type: ACTION.UPDATE_PROBLEM_LIST, problem_list, });
      dispatch({ type: ACTION.UPDATE_REVIEWS, reviews});
      dispatch({ type: ACTION.CHANGE_ROOM_TYPE, room_type, });
      dispatch({ type: ACTION.UPDATE_GO_EDIT_MODE, mode: 0 });
      dispatch(req_problem(problem_list[0], 0, false, room_type === 'make_problem'));
    }
  } catch (error) {
  }
}

export const req_problem = (problem_id, problem_index, train_mode, make_mode) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/problem', { problem_id, make_mode });
    const {err, problem} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(on_load_problem(problem, problem_index));
      dispatch(resolve_problem(problem_id, train_mode));
    }
  } catch (error) {
  }
}

export const submit_problem = (prob_index, book_data, prob_data) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/create_problem', { book_id: book_data._id });
    const {err, problem_id} = result.data;
    if (err === ErrorCode.SUCCESS) {
      const result2 = await axios.post(config.apiUrl + '/submit_problem', { problem_id, detail: prob_data });
      if (result2.data.err === ErrorCode.SUCCESS) {
        dispatch(req_problem(prob_data._id, prob_index, false, true));
      }
    }
  } catch (error) {
  }
}

