export const on_load_problem = (problem, problem_index) => dispatch => {
  GoLogic.theLogicBoard.initialize();
  var i, pos;
  for (i = 0; i < problem.black_stones.length; i ++) {
    pos = problem.black_stones[i];
    GoLogic.theLogicBoard.set_edit_stone(GoLogic.XPOS(pos), GoLogic.YPOS(pos), GoLogic.BLACK);
  }
  for (i = 0; i < problem.white_stones.length; i ++) {
    pos = problem.white_stones[i];
    GoLogic.theLogicBoard.set_edit_stone(GoLogic.XPOS(pos), GoLogic.YPOS(pos), GoLogic.WHITE);
  }
  if (problem.first_color === GoLogic.BLACK)
    GoLogic.theLogicBoard.setturn(GoLogic.BLACK);
  else
    GoLogic.theLogicBoard.setturn(GoLogic.WHITE);
  var marks = [];
  problem.marks.map((mark) => marks.push({x: mark.mark_x, y: mark.mark_y, type: mark.mark_type, text: mark.mark_text}));

  var color = problem.first_color;
  for( i in problem.answer[0]) {
    pos = problem.answer[0][i];
    GoLogic.theLogicBoard.domove(pos, color);
    color = GoLogic.OPPTURN(color);
  }
  var grcounter = GoLogic.theLogicBoard.getgrcounter();
  GoLogic.theLogicBoard.goto_idx(0);

  dispatch({ type: ACTION.LOAD_GO_PROBLEM, problem, problem_index, marks, grcounter,});
  dispatch({ type: ACTION.SET_VIEWPORT, viewport: problem.viewport});
  dispatch({ type: ACTION.SET_GO_MARKS, marks});
  dispatch({ type: ACTION.SET_EDIT_STONES, black_stones: problem.black_stones, white_stones: problem.white_stones});
  dispatch({ type: ACTION.SET_PUTABLE, putAble: true});
}

export const resolve_problem = (problem_id, train_mode) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/re_solve_problem', {problem_id, train_mode});
    const {err, retried, time, solved} = result.data;
    if (err === ErrorCode.SUCCESS) {
      GoLogic.theLogicBoard.goto_idx_undo(0);
      dispatch({ type: ACTION.RESOLVE_GO_PROBLEM, retried, time, solved });
      dispatch({ type: ACTION.SET_PUTABLE, putAble: true});
    }
  } catch (error) {
  }
}

export const on_problem_move = (move, turn, h_index, s_time) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/problem_move', {move, turn, h_index, s_time});
    const { err, response, updates } = result.data;
    if (err === ErrorCode.SUCCESS) {
      if (response === CD.PROBLEM_RESPONSE.INCORRECT) {
        dispatch(do_problem_move(move, turn, false, 'incorrect', h_index));
        dispatch({ type: ACTION.UPDATE_PROBLEM_SOLVE, retried: updates.book_solve.retried, time: updates.book_solve.time, solved: updates.book_solve.solved});
        notify_change_level(updates.reason, updates.d_level);
      } else if (response === CD.PROBLEM_RESPONSE.CORRECT) {
        dispatch(do_problem_move(move, turn, false, 'correct', h_index));
        dispatch({ type: ACTION.UPDATE_PROBLEM_SOLVE, retried: updates.book_solve.retried, time: updates.book_solve.time, solved: updates.book_solve.solved});
        notify_change_level(updates.reason, updates.d_level);
      } else if (response === CD.PROBLEM_RESPONSE.GO_ON) {
        dispatch(do_problem_move(move, turn, false, 'go on', h_index));
        dispatch(do_problem_move(updates.next_move, updates.next_turn, true, 'go on', h_index+1));
      }
    }
  } catch (error) {
  }
}

export const clear_problem_board = () => dispatch => {
  GoLogic.theLogicBoard.initialize();
  dispatch({type: ACTION.CLEAR_PROBLEM_BOARD, });
  dispatch({type: ACTION.CLEAR_GO_BOARD, });
}

export const exit_problem = () => dispatch => {
  GoLogic.theLogicBoard.initialize(GoLogic.RULE_CHINESE, GoLogic.MX_BOARD_SIZE);
  dispatch({ type: ACTION.EXIT_GO_PROBLEM, });
  dispatch({ type: ACTION.UPDATE_VIEWPORT_SELECTION, x0: 0, y0: 0, x1: 18, y1: 18});
  dispatch({ type: ACTION.UPDATE_GO_EDIT_MODE, mode: 0});
  dispatch({ type: ACTION.CLEAR_GO_BOARD, });
}

export const do_problem_move = (move, turn, putAble, result, h_index) => dispatch => {
  GoLogic.theLogicBoard.domove(move, turn, h_index);
  var next_turn = GoLogic.BLACK + GoLogic.WHITE - turn;
  dispatch({ type: ACTION.DO_GO_PROBLEM_MOVE, wpos: move, next_turn, result, });
  dispatch({ type: ACTION.SET_PUTABLE, putAble});
}

export const update_problem_history_index = (h_index, putAble) => dispatch => {
  GoLogic.theLogicBoard.goto_idx(h_index);
  dispatch({ type: ACTION.UPDATE_GO_PROBLEM_HISTORY_INDEX, h_index, });
  dispatch({ type: ACTION.SET_PUTABLE, putAble});
}

