import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = {
  language: 0,
  content: 0,
  func: 0,
  filter1: 0,
  filter2: 0,
  find: "",
  page: 0,
  rowsPerPage: 10,
  openSettingDlg: false,
  changed_list: false,
  total: 0,
  items: [],
  items2: [],
  items3: [],
  items4: [],
  path: '',
  socketLobby: null,
  side_show: {
    left:"14.5vw",
    isSideBarShow:true,
  },
  redirect_path: '',
  gr_index: 0,
  reviews: [],
  all_users: 0,
  isOpenEmoticonDlg:false,
  isShowEmoticon:false,
  emoticon_index:'',
  show_message:false,
  message_counter:0,
  emoticon_counter:0,
  isShowMesDlg:false,
  msg_index:'',
  emoticon_flag: false,
};

export default function commonReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.SET_LANGUAGE:
      return {
        ...state,
        language: action.lang,
      }
    case ACTION.CHANGE_SELECT:
      return {
        ...state,
        content: action.content != undefined? action.content : state.content,
        func: action.func != undefined? action.func : state.func,
        filter1: action.filter1 != undefined? action.filter1 : state.filter1,
        filter2: action.filter2 != undefined? action.filter2 : state.filter2,
        find: action.find != undefined? action.find : state.find,
        page: action.page != undefined? action.page : state.page,
        rowsPerPage: action.rowsPerPage != undefined? action.rowsPerPage : state.rowsPerPage,
        path: action.path != undefined? action.path : state.path,
        items: [],
      }
    case ACTION.UPDATE_LIST:
      return {
        ...state,
        total: action.total != undefined? action.total : state.total,
        items: action.items != undefined? action.items : state.items,
        items2: action.items2 != undefined? action.items2 : state.items2,
        items3: action.items3 != undefined? action.items3 : state.items3,
        items4: action.items4 != undefined? action.items4 : state.items4,
      }
    case ACTION.CHANGED_LIST:
      return {
        ...state,
        changed_list: !state.changed_list,
      }
    case ACTION.OPEN_CLOSE_SETTING_DLG:
      return {
        ...state,
        openSettingDlg: action.openSettingDlg != undefined? action.openSettingDlg : !state.openSettingDlg,
      }
    case ACTION.SET_LOBBY_SOCKET:
      return {
        ...state,
        socketLobby: action.socketLobby,
      };
    case ACTION.UPDATE_SIDEBAR:
      return {
        ...state,
        side_show: {
          left:action.left,
          isSideBarShow:action.is_show,
        }
      };
    case ACTION.REDIRECT_TO:
      return {
        ...state,
        redirect_path: action.redirect_path,
      };     
    case ACTION.UPDATE_RECORD_INDEX:
      return {
        ...state,
        gr_index: action.gr_index,
      }
    case ACTION.UPDATE_REVIEWS:
      return {
        ...state,
        reviews: action.reviews,
      };
    case ACTION.OPEN_EMOTICON_DLG:
      return {
        ...state,
        isOpenEmoticonDlg:!state.isOpenEmoticonDlg,
      }
    case ACTION.UPDATE_EMOTICON:
      return {
        ...state,      
        emoticon_index:action.emoticon_index,
        emoticon_counter:state.emoticon_counter + 1
      }

    case ACTION.SET_EMOTICON_FLAG:
      return {
        ...state,
        emoticon_flag: action.flag
      }
    case ACTION.SHOW_MESSAGE:
      return {
        ...state,
        show_message:!state.show_message,
        msg_index:action.msg_index,
        message_counter:state.message_counter + 1,
      }
    case ACTION.UPDATE_MES_DLG:
      return {
        ...state,
        isShowMesDlg:!state.isShowMesDlg,
        
      }
    case ACTION.UPDATE_ALL_USERS:
      return {
        ...state,
        all_users: action.all_users,
      }
    default:
      return state;
  }
}