import React from 'react';
import ReactDOM from 'react-dom';
import { Provider } from 'react-redux';
import { SnackbarProvider } from 'notistack';
import { ConnectedRouter } from 'connected-react-router';

import store, { history } from './store';
import App from './App';

import * as serviceWorker from './serviceWorker';
import {getCurrentUser}  from './store/actions/auth.action';
import {setTheme} from './store/actions/theme.action';
import {isEmpty} from './helper/utils';

window.i18n.init({
  resGetPath: 'assets/locales/__lng__.json',
  debug: true,
	load: 'unspecific',
	fallbackLng: false
}, function (t) {
  if (!isEmpty(localStorage.token)) {
    store.dispatch(getCurrentUser(localStorage.token));
  }
  if (localStorage.theme) {
    store.dispatch(setTheme(localStorage.theme));
  }
  
  ReactDOM.render(
    <Provider store={store}>
      <SnackbarProvider autoHideDuration={1500} anchorOrigin={{
        vertical: 'top',
        horizontal: 'right'
      }}>
        <ConnectedRouter history={history}>
          <App />
        </ConnectedRouter>
      </SnackbarProvider>
    </Provider>, 
    document.getElementById('root'),
  );
  serviceWorker.unregister();
});

