import ACTION from '../actionTypes';

const initialState = {
  piece_kind: 0,
  piece_index: 0,
  tool: 0,
  tool_property: 0,
  pen_thick: 0,
  target: '',
  complete_draw: false,
};

export default function pdesignTaskReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_PIECE_KIND:
      return {
        ...state,
        piece_kind: action.kind,
      };
    case ACTION.UPDATE_PIECE_INDEX:
      return {
        ...state,
        piece_index: action.index,
      };
    case ACTION.UPDATE_TOOL:
      return {
        ...state,
        tool: action.tool,
      };
    case ACTION.UPDATE_PEN_THICK:
      return {
        ...state,
        pen_thick: action.thick,
      };
    case ACTION.UPDATE_TOOL_PROPERTY:
      return {
        ...state,
        tool_property: action.property,
      };
    case ACTION.UPDATE_PDESIGN_TARGET:
      return {
        ...state,
        target: action.target,
        complete_draw: false,
      };
    case ACTION.COMPLETE_PDESIGN_DRAW:
      return {
        ...state,
        complete_draw: true,
      };
    default: return state;
  }
}
