import axios from "axios";
import config from '../../helper/config';
import ErrorCode from '../../helper/errorCode';
import CD from '../../helper/const';
import ACTION from '../actionTypes';
import {/*swal_s, swal_w,*/ notify_s, notify_w, /*notify_e*/} from "../../helper/alert";

import * as GoLogic from '../../components/go/logic'

var notify_change_level = (reason, d_level) => {
  if (!!d_level) {
    if (d_level > 0) 
      notify_s(window.i18n.t(`message.increase_level_reason_${reason}`).replace('{0}', d_level));
    else if (d_level < 0)
      notify_w(window.i18n.t(`message.decrease_level_reason_${reason}`).replace('{0}', -d_level));
  } 
};

export const new_game_ts = () => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/new_go_partial_game', {go_partial_type: CD.GO_PARTIAL_TYPE.GO_TS});
    const { err, boardsize, reward, init_occupy, thresholds } = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(init_train_board(boardsize, reward, init_occupy.board_str, thresholds.th_taken_count, thresholds.th_history_length));
    }
  } catch (error) {
  }
}

