export const on_train_game_move = (move, turn, go_partial_type) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/go_partial_game_move', {go_partial_type, move, color: turn});
    const { err, game_result, next_move, user_partial_game, updates } = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch(do_train_move(move, turn, updates.taken_bstones, updates.taken_wstones, false, updates.score));
      if (next_move != 0xffff) {
        var opp_turn = GoLogic.OPPTURN(turn);
        var putAble = false;
        if (game_result === CD.PARTIAL_GAME_RESULT.GO_ON)
          putAble = true;
        dispatch(do_train_move(next_move, opp_turn, updates.taken_bstones, updates.taken_wstones, putAble, go_partial_type === 3? updates.score : 0));
      }
      if (game_result > CD.PARTIAL_GAME_RESULT.GO_ON) {
        dispatch(update_train_game_result(game_result === CD.PARTIAL_GAME_RESULT.SUCCESS? 'Success !!' : 'Fail ~~', user_partial_game, updates.coin));
      }
      notify_change_level(updates.reason, updates.d_level);
    }
  } catch (error) {
  }
}

export const init_train_board = (boardsize, reward_xp, ini_board, th_taken_count, th_history_length) => dispatch => {
  var x, y, i;
  GoLogic.theLogicBoard.initialize(GoLogic.RULE_CHINESE, boardsize);
  for(y = 0; y < boardsize; y ++) {
    for(x = 0; x < boardsize; x ++) {
      i = y * boardsize + x;
      if (ini_board[i] === 'B')
        GoLogic.theLogicBoard.set_edit_stone(x, y, GoLogic.BLACK);
      else if (ini_board[i] === 'W')
        GoLogic.theLogicBoard.set_edit_stone(x, y, GoLogic.WHITE);
    }
  }
  dispatch({type: ACTION.INIT_GO_TRAIN_BOARD, th_taken_count, th_history_length, reward_xp,});
  dispatch({type: ACTION.SET_PUTABLE, putAble: true, });
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
  dispatch({type: ACTION.SET_GO_MARKS, marks: []});
}

export const init_train_board_history = (boardsize, reward_xp, ini_stones, pre_history, th_history_length, th_correct_moves) => dispatch => {
  GoLogic.theLogicBoard.initialize(GoLogic.RULE_CHINESE, boardsize);
  var color = GoLogic.BLACK;
  for (var i = 0; i < pre_history.length; i ++) {
    GoLogic.theLogicBoard.domove(pre_history[i], color);
    color = GoLogic.OPPTURN(color);
  }
  dispatch({type: ACTION.INIT_GO_TRAIN_BOARD, ini_stones, th_history_length, th_correct_moves, reward_xp, });
  dispatch({type: ACTION.SET_PUTABLE, putAble: true, });
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
  dispatch({type: ACTION.SET_GO_MARKS, marks: []});
}

export const do_train_move = (move, turn, taken_bstones, taken_wstones, putAble, score) => dispatch => {
  GoLogic.theLogicBoard.domove(move, turn);
  var h_index = GoLogic.theLogicBoard.getgridx();
  dispatch({type: ACTION.DO_GO_TRAIN_MOVE, taken_bstones, taken_wstones, h_index, score,});
  dispatch({type: ACTION.SET_PUTABLE, putAble, });
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
}

export const update_train_game_result = (result, user_partial_game, d_coin) => dispatch => {
  dispatch({type: ACTION.UPDATE_TRAIN_GAME_RESULT, result, d_coin, });
  dispatch({type: ACTION.UPDATE_GO_USER_PARTIAL_GAME}, user_partial_game, );
}

export function init_train_count() {
  return {
    type: ACTION.INIT_TRAIN_COUNT,
  }
}

