import React, {useState, useEffect} from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import moment from "moment";

import { makeStyles } from '@material-ui/core/styles';
import {
  BottomNavigation,
  BottomNavigationAction,
  Button,
} from '@material-ui/core';
import {
  MDBBtn,
  MDBRow,
  MDBCol,
  MDBScrollbar,
  MDBListGroup,
  MDBListGroupItem,
} from "mdbreact";
import CD from "../../helper/const";
import Board from "../go/board";
import * as CommonAction from "../../store/actions/common.action";
import * as GoAction from "../../store/actions/go.action";
import * as GoBoardAction from "../../store/actions/go_board.action";
import * as GoTeacherAction from "../../store/actions/go_teacher.action";
import * as GoLogic from "../go/logic";
import FileBufferReader from './FileBufferReader';
import getHTMLMediaElement from './getHTMLMediaElement';
import "./getHTMLMediaElement.css"
import ReviewAndRate from "../review/ReviewAndRate";
import Rater from 'react-rater';
import 'react-rater/lib/react-rater.css';

const useStyles = makeStyles(theme => ({
  container: {
    minHeight: '83vh',
    paddingTop: '2vh',
  },
  leftStyle: {
    paddingLeft: '2vw',
  },
  room_urls: {
    textAlign: 'center',
    display: 'none',
    background: '#F1EDED',
    marginLeft: '15px',
    border: '1px solid rgb(189, 189, 189)',
    borderLeft: '0',
    borderRight: '0',
  },
  scrollableStyle: {
    height: '20vh',
  },
  scrollItem: {
    marginBottom: 0,
    border: 0,
    borderBottom: '1px solid',
  },
  BoardToolbar: {
    paddingTop: '2vh',
    marginLeft: '8vw',
    width: '30vw',
    fontSize: '2.5vh',
  },
  BottomNavigationActionStyle1: {
    width:'2.5vw',
    minWidth: '2.5vw',
    padding:'0px',
    border:'1px solid rgb(25, 118, 208)',
    fontSize: '1.5vh',
  },
  BottomNavigationActionStyle2: {
    width:'2.5vw',
    minWidth: '2.5vw',
    padding:'0px',
    border:'1px solid rgb(25, 118, 208)',
    borderLeft:'none',
    fontSize: '1.5vh',
  },
  BottomNavigationActionStyle3: {
    width:'2.5vw',
    minWidth: '2.5vw',
    padding:'0px',
    border:'1px solid rgb(25, 118, 208)',
    borderLeft:'none',
    fontSize: '1.5vh',
  },
  navigationButton1: {
    marginLeft: '2vw',
    minWidth:'2.5vw',
    width:'2.5vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    color: "#404040",
  },
  navigationButton: {
    minWidth:'2.5vw',
    width:'2.5vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    borderLeft: 'none',
    color: "#404040",
  },
}));

var EBoardMode = {
  Move: 0,
  CountScores: 1,
  ScoreEstimate: 2,
  AddOrRemove: 3,
  AddMarkTr: 4,
  AddMarkSq: 5,
  AddMarkCr: 6,
  AddMarkX: 7,
  AddMarkTx: 8,
  AddMarkNum: 9,
  ViewPort: 10,
};

function LectureRoom(props) {
  const classes = useStyles();
  const [openReviewAndRate, setOpenReviewAndRate] = useState(false);

  const Review = ({ review: { user_id, rating, text, date } }) => (
    <MDBListGroupItem
      className={classes.scrollItem+" d-flex justify-content-between p-2 border-light text-muted"}
      // style={{ backgroundColor: active ? "#eeeeee" : "" }}
    >
      <div style={{ fontSize: "0.95rem" }}>
        <i className="la la-user la-lg pr-1" />
        <strong>{user_id}</strong>
        <span className="mb-0 mx-3" style={{ fontSize: "0.75rem" }}>
          {moment(new Date(date)).fromNow()}
        </span>
        <Rater total={5} rating={rating} interactive={false} style={{fontSize:'1rem', display:'block'}}/>      
        <p style={{ fontSize: "0.85rem" }}>{text}</p>
      </div>
    </MDBListGroupItem>
  );
  
  const {connection} = props;
  useEffect(() => {
    connection.videosContainer = document.getElementById('videos-container');
    connection.onstream = function(event) {
      var existing = document.getElementById(event.streamid);
      if(existing && existing.parentNode) {
        existing.parentNode.removeChild(existing);
      }

      event.mediaElement.removeAttribute('src');
      event.mediaElement.removeAttribute('srcObject');
  
      var video = document.createElement('video');
      video.controls = true;
      if(event.type === 'local') {
        video.muted = true;
      }
      video.srcObject = event.stream;
  
      var width = parseInt(connection.videosContainer.clientWidth / 2) - 20;
      var mediaElement = getHTMLMediaElement(video, {
        title: event.userid,
        buttons: ['full-screen'],
        width: width,
        showOnMouseEnter: false
      });
  
      connection.videosContainer.appendChild(mediaElement);
  
      setTimeout(function() {
        mediaElement.media.play();
      }, 5000);
  
      mediaElement.id = event.streamid;
    };
    
    connection.onstreamended = function(event) {
      var mediaElement = document.getElementById(event.streamid);
      if (mediaElement) {
        mediaElement.parentNode.removeChild(mediaElement);
      }
    };
    
    connection.onMediaError = function(e) {
      if (e.message === 'Concurrent mic process limit.') {
        if (window.DetectRTC.audioInputDevices.length <= 1) {
          alert('Please select external microphone. Check github issue number 483.');
          return;
        }

        var secondaryMic = window.DetectRTC.audioInputDevices[1].deviceId;
        connection.mediaConstraints.audio = {
          deviceId: secondaryMic
        };

        connection.join(connection.sessionid);
      }
    };

    connection.onmessage = appendDIV;
    connection.filesContainer = document.getElementById('file-container');
    
    connection.onopen = function() {
      if (!!document.getElementById('share-file'))
        document.getElementById('share-file').disabled = false;
      if (!!document.getElementById('input-text-chat'))
        document.getElementById('input-text-chat').disabled = false;
    };
    
    connection.onEntireSessionClosed = function(event) {
      connection.attachStreams.forEach(function(stream) {
        stream.stop();
      });
    };
    
    connection.onUserIdAlreadyTaken = function(useridAlreadyTaken, yourNewUserId) {
      // seems room is already opened
      connection.join(useridAlreadyTaken);
    };

    connection.socket.on(connection.socketCustomEvent, function(msg) {
      if (msg.type === 'initBoard') {
        props.load_board_in_lecture_room(msg.viewport, msg.ini_board, msg.marks, msg.move_history, msg.h_index);
      } else if (msg.type === 'putStone') {
        props.do_move(GoLogic.WPOS(msg.x, msg.y), msg.turn);
      } else if (msg.type === 'gotoHIndex') {
        props.update_lecture_board_history_index(msg.h_index);
      } else if (msg.type === 'updateViewport') {
        props.update_viewport(msg.x0, msg.y0, msg.x1, msg.y1);
      } else if (msg.type === 'setEditStone') {
        props.set_edit_stone(msg.x, msg.y, msg.color);
      } else if (msg.type === 'removeMark') {
        props.remove_mark(msg.mark_x, msg.mark_y, false);
      } else if (msg.type === 'addMark') {
        props.add_mark(msg.mark_x, msg.mark_y, msg.mark_type, false, msg.mark_text);
      } else if (msg.type === 'clearBoard') {
        props.clear_lecture_board();
      }
    });

    const {user, get_teacher_data, enter_lecture_room, lecture_room_list} = props;
    var room_id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    var room;
    if (props.func == CD.FUNC.FUNC_LECTURE) {
      lecture_room_list.map((r) => {
        if (r.sessionid === room_id)
          room = r;
      });
    }
    get_teacher_data(room.owner);
    enter_lecture_room(connection, room, user);

    return () => {
      connection.onbeforeunload(false, false);
    };
  }, []);

  const [mode, setMode] = useState(4);
  
  const handleToFirst = () => {
    const {lecture_room, update_lecture_board_history_index} = props;
    update_lecture_board_history_index(0);
    connection.socket.emit(connection.socketCustomEvent, {type: 'gotoHIndex', h_index: 0})
  }

  const handleToBack = () => {
    const {lecture_room, update_lecture_board_history_index} = props;
    update_lecture_board_history_index(lecture_room.h_index - 1);
    connection.socket.emit(connection.socketCustomEvent, {type: 'gotoHIndex', h_index: lecture_room.h_index - 1})
  }
 
  const handleToNext = () => {
    const {lecture_room, update_lecture_board_history_index} = props;
    update_lecture_board_history_index(lecture_room.h_index + 1);
    connection.socket.emit(connection.socketCustomEvent, {type: 'gotoHIndex', h_index: lecture_room.h_index + 1})
  }

  const handleToLast = () => {
    const {lecture_room, update_lecture_board_history_index} = props;
    update_lecture_board_history_index(lecture_room.move_history.length);
    connection.socket.emit(connection.socketCustomEvent, {type: 'gotoHIndex', h_index: lecture_room.move_history.length})
  }

  const handleEditModeChange = (mode) => {
    setMode(mode);
    var edit_mode;
    switch(mode) {
      case 0:
        edit_mode = EBoardMode.ViewPort;
        break;
      case 1:
        edit_mode = EBoardMode.AddOrRemove;
        break;
      case 2:
        edit_mode = EBoardMode.AddMarkTr;
        break;
      case 3:
        edit_mode = EBoardMode.AddMarkTx;
        break;
      case 4:
        edit_mode = EBoardMode.Move;
        break;
      default:
        break;
    }
    props.update_edit_mode(edit_mode);
  };

  const clearBoard = () => {
    const {clear_lecture_board} = props;
    clear_lecture_board();
    connection.socket.emit(connection.socketCustomEvent, {type: 'clearBoard'});
  };

  const handleClickShareFile = () => {
    var fileSelector = new window.FileSelector();
    fileSelector.selectSingleFile(function(file) {
        connection.send(file);
    });
  };

  const handleKeyUpInputTextChat = (e) => {
    if (e.keyCode != 13) return;

    // removing trailing/leading whitespace
    e.target.value = e.target.value.replace(/^\s+|\s+$/g, '');
    if (!e.target.value.length) return;

    var chat = '';
    if(!!props.user)
      chat = props.user.user_id + ': ';
    chat += e.target.value;
    connection.send(chat);
    appendDIV(chat);
    e.target.value = '';
  };

  const appendDIV = (event) => {
    var div = document.createElement('div');
    div.innerHTML = event.data || event;
    var chatContainer = document.querySelector('.chat-output');
    chatContainer.insertBefore(div, chatContainer.firstChild);
    div.tabIndex = 0;
    div.focus();

    document.getElementById('input-text-chat').focus();
  }

  const handleCloseReviewAndRateDlg = (value) => {
    if (!!value) {
      setOpenReviewAndRate(false);
      const {user, lecture_room, add_review_to_teacher} = props;
      if(!!user)
        add_review_to_teacher(lecture_room.teacher, value.msg, value.rating);
    } else {
      setOpenReviewAndRate(false);
    }
  };

  const handleOpenReviewAndRateDlg = () => {
    setOpenReviewAndRate(true);
  }

  const {user, lecture_room, reviews} = props;
  var cur_review;
  var total_rating = 0;
  for(var i in reviews) {
    total_rating += reviews[i].rating;
    if(!!user && reviews[i].user_id === user.user_id)
      cur_review = {rating: reviews[i].rating, text: reviews[i].text};
  }
  var avg_rating = reviews.length > 0? total_rating / reviews.length : 0;
  

  return (
    <div className={classes.container}>
      <ReviewAndRate open={openReviewAndRate} review={cur_review} onClose={handleCloseReviewAndRateDlg}/>
      <MDBRow className="m-0">
        <MDBCol md='2' className={classes.leftStyle}>
          <MDBRow className="py-2">
            <MDBCol>
              <h5>RoomId : {lecture_room.room_id}</h5>
              <h5>Teacher : {lecture_room.teacher}</h5>
              <h5>Title : {lecture_room.title}</h5>
              <h5>Start : {lecture_room.start}</h5>
              <h5>State : {lecture_room.status}</h5>
              <input type="text" id="input-text-chat" onKeyUp={handleKeyUpInputTextChat} placeholder="Enter Text Chat" disabled />
              <button id="share-file" onClick={handleClickShareFile} >Share File</button>
              <br></br>
              <div id="chat-container">
                <div id="file-container"></div>
                <div className="chat-output"></div>
              </div>
            </MDBCol>
          </MDBRow>
          <MDBRow className="px-lg-2 py-2">
            <MDBCol
              className={classes.scrollableStyle+" px-0 mb-4 mb-md-0"}
            >
              <span className="font-weight-bold mb-3 text-lg-left pr-5">Reviews</span>
              <Rater total={5} rating={avg_rating} interactive={false}/>
              <MDBBtn outline color="gray" className="px-2 py-1 ml-5 mt-0 my-3" onClick={handleOpenReviewAndRateDlg} disabled = {!!user && user.user_id === lecture_room.teacher}>
                rate
              </MDBBtn>
              
              <MDBScrollbar className="white z-depth-1 p-3">
                <MDBListGroup className="friend-list">
                  {reviews.map((review, index) => (
                    <Review key={index} review={review} />
                  ))}
                </MDBListGroup>
              </MDBScrollbar>
            </MDBCol>
          </MDBRow>
        </MDBCol>
        <MDBCol md='5'>
          <Board boardId = {0} readOnly = {false} putAble = {!!user && user.user_id === lecture_room.teacher} width='50' height='70'/>
          {
            (!!user && user.user_id === lecture_room.teacher) && (
              <div>
                <MDBRow className={classes.BoardToolbar}>
                  <BottomNavigation
                    value={mode}
                    onChange={(event, newMode) => {
                      handleEditModeChange(newMode);
                    }}
                    showLabels
                  >
                    <BottomNavigationAction icon={<i className="fa fa-crop fa-2x pb-2" />} className={classes.BottomNavigationActionStyle1} style={{padding:'0px'}}/>
                    <BottomNavigationAction icon={<i className="fa fa-plus-circle fa-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                    <BottomNavigationAction icon={<i className="la la-exclamation-triangle la-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                    <BottomNavigationAction icon={<i className="fa fa-font fa-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                    <BottomNavigationAction icon={<i className="fa fa-arrow-circle-down fa-2x pb-2" />} className={classes.BottomNavigationActionStyle3} style={{padding:'0px'}} />
                  </BottomNavigation>
                  <Button className={classes.navigationButton1} disabled={false} style={{padding:'0px', fontSize: 'inherit'}}  onClick={clearBoard}><i className="fa fa-trash"/></Button>
                  <Button className={classes.navigationButton} disabled={lecture_room.h_index <= 0} style={{padding:'0px', fontSize: 'inherit'}}  onClick={handleToFirst}><i className="fa fa-fast-backward"/></Button>
                  <Button className={classes.navigationButton} disabled={lecture_room.h_index <= 0} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToBack}><i className="fa fa-step-backward" /></Button>
                  <Button className={classes.navigationButton} disabled={lecture_room.h_index >= lecture_room.move_history.length} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToNext}><i className="fa fa-step-forward" /></Button>
                  <Button className={classes.navigationButton} disabled={lecture_room.h_index >= lecture_room.move_history.length} style={{padding:'0px', fontSize: 'inherit'}} onClick={handleToLast}><i className="fa fa-fast-forward" /></Button>
                </MDBRow>
              </div>
            )
          }
          
        </MDBCol>
        
        <MDBCol>
          <div id="videos-container"></div>
        </MDBCol>
      </MDBRow>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  func: store.commonReducer.func,
  connection: store.goTeacherReducer.connection,
  lecture_room_list: store.commonReducer.items,
  lecture_room: store.goTeacherReducer.lecture_room,
  reviews: store.commonReducer.reviews,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    add_review_to_teacher: CommonAction.add_review_to_teacher,
    get_teacher_data: GoTeacherAction.get_teacher_data,
    enter_lecture_room: GoTeacherAction.enter_lecture_room,
    do_move: GoAction.do_move,
    load_board_in_lecture_room: GoTeacherAction.load_board_in_lecture_room,
    update_edit_mode: GoBoardAction.update_edit_mode,
    set_edit_stone: GoBoardAction.set_edit_stone,
    remove_mark: GoBoardAction.remove_mark,
    add_mark: GoBoardAction.add_mark,
    update_lecture_board_history_index: GoTeacherAction.update_lecture_board_history_index,
    update_viewport: GoBoardAction.update_viewport_selection,
    clear_lecture_board: GoTeacherAction.clear_lecture_board,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(LectureRoom);
