import React, { useEffect, useState } from 'react';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import {
  MDBRow,
  MDBCol,
  MDBBtn,
  MDBDataTable,
  MDBContainer,
} from "mdbreact";
import CD from "../../helper/const";
import PROTOCOL from "../../helper/protocol";
import * as CommonAction from "../../store/actions/common.action";
import GoSetting from "../go/goSetting";
import FFASetting from "../ffa/ffaSetting";
import SKoniSetting from "../skpni/skpniSetting";
import OmokSetting from "../omok/omokSetting";

const btnStyle = {
  height: '2vh', 
  width: '2vw', 
  fontSize:'1.2vh', 
  padding: "0.4vh"  
};

function Bots(props) {
  const [sel_bot_id, setSelBotId] = useState("");
  const [sel_game_type, setSelGameType] = useState("");
  const columns_bot = [
    {
      label: "No",
      field: "no",
      sort: "disabled",
      width: 100
    },    
    {
      label: "BotID",
      field: "bot_id",
      sort: "disabled",
      width: 150,
    },
    {
      label: "Where",
      field: "where",
      sort: "disabled",
      width: 150,
    },
    {
      label: "State",
      field: "state",
      sort: "disabled",
      width: 150,
    },
    {
      label: "Action",
      field: "action",
      sort: "disabled",
      width: 400,
    },
  ];
  var rows_bot = [];
  useEffect(() => {
    setRowBots();
  }) 

  const handleOn = (bot_id) => {
    const {socketLobby, user} = props;
    if (!!socketLobby) {
      socketLobby.emit('admin_message', PROTOCOL.CS_BOT_ONLINE, {token: user.token, bot_id});
    }
  };
  const handleToRoom = (bot_id, game_type) => {
    setSelBotId(bot_id);
    setSelGameType(game_type);
    props.updateSettingDlg(true);
  };
  const onSettingOK = (setting, user_id, game_type) => {
    const {user, socketLobby} = props; 
    socketLobby.emit('admin_message', PROTOCOL.CS_BOT_TO_ROOM, {token: user.token, bot_id: user_id, game_type, setting});
  };
  const handleQuit = (bot_id, game_type) => {
    const {socketLobby, socketGoRoom, socketFFARoom, socketSKoniRoom, socketOmokRoom, user} = props;
    if(game_type == CD.GAME_TYPE.GO) {
      if (!!socketGoRoom)
        socketGoRoom.emit('admin_message', PROTOCOL.CS_BOT_OFFLINE, {token: user.token, bot_id});
    } else if (game_type == CD.GAME_TYPE.FFA) {
      if (!!socketFFARoom)
        socketFFARoom.emit('admin_message', PROTOCOL.CS_BOT_OFFLINE, {token: user.token, bot_id});
    } else if (game_type == CD.GAME_TYPE.SKPNI) {
      if (!!socketSKoniRoom)
        socketSKoniRoom.emit('admin_message', PROTOCOL.CS_BOT_OFFLINE, {token: user.token, bot_id});
    } else if (game_type = CD.GAME_TYPE.OMOK) {
      if (!!socketOmokRoom)
        socketOmokRoom.emit('admin_message', PROTOCOL.CS_BOT_OFFLINE, {token: user.token, bot_id});
    } else {
      if (!!socketLobby)
        socketLobby.emit('admin_message', PROTOCOL.CS_BOT_OFFLINE, {token: user.token, bot_id});
    }
  };
  const setRowBots = () => {
    let {all_bot_ids, bots_lobby, bots_go, bots_ffa, bots_skpni, bots_omok} = props;
    let bots_offline = {};
    let i, j, bot_id;
    for(i in all_bot_ids) {
      bots_offline[all_bot_ids[i]] = 1;
    }
    for(i = 0, j = 1; i < bots_lobby.length; i ++, j++) {
      bot_id = bots_lobby[i];
      delete bots_offline[bot_id];
      rows_bot.push({no: j, bot_id: bot_id, where: "lobby", State: "-", 
        action:
          <div>
            <MDBBtn style={btnStyle} onClick={handleToRoom.bind(this, bot_id, CD.GAME_TYPE.GO)}>go</MDBBtn>
            <MDBBtn style={btnStyle} onClick={handleToRoom.bind(this, bot_id, CD.GAME_TYPE.FFA)}>ffa</MDBBtn>
            <MDBBtn style={btnStyle} onClick={handleToRoom.bind(this, bot_id, CD.GAME_TYPE.SKPNI)}>skpni</MDBBtn>
            <MDBBtn style={btnStyle} onClick={handleToRoom.bind(this, bot_id, CD.GAME_TYPE.OMOK)}>omok</MDBBtn>
            <MDBBtn style={btnStyle} onClick={handleQuit.bind(this, bot_id, -1)}>quit</MDBBtn>
          </div> 
      });
    }
    for(i = 0; i < bots_go.length; i ++, j++) {
      bot_id = bots_go[i];
      delete bots_offline[bot_id];
      rows_bot.push({no: j, bot_id: bot_id, where: "go", State: bots_go[i].state, 
        action:
          <div>
            <MDBBtn style={btnStyle} onClick={handleQuit.bind(this, bot_id, CD.GAME_TYPE.GO)}>quit</MDBBtn>
          </div> 
      });
    }
    for(i = 0; i < bots_ffa.length; i ++, j++) {
      bot_id = bots_ffa[i];
      delete bots_offline[bot_id];
      rows_bot.push({no: j, bot_id: bot_id, where: "ffa", State: bots_ffa[i].state, 
        action:
          <div>
            <MDBBtn style={btnStyle} onClick={handleQuit.bind(this, bot_id, CD.GAME_TYPE.FFA)}>quit</MDBBtn>
          </div> 
      });
    }
    for(i = 0; i < bots_skpni.length; i ++, j++) {
      bot_id = bots_skpni[i];
      delete bots_offline[bot_id];
      rows_bot.push({no: j, bot_id: bot_id, where: "skpni", State: bots_skpni[i].state, 
        action:
          <div>
            <MDBBtn style={btnStyle} onClick={handleQuit.bind(this, bot_id, CD.GAME_TYPE.SKPNI)}>quit</MDBBtn>
          </div> 
      });
    }
    for(i = 0; i < bots_omok.length; i ++, j++) {
      bot_id = bots_omok[i];
      delete bots_offline[bot_id];
      rows_bot.push({no: j, bot_id: bot_id, where: "skpni", State: bots_omok[i].state, 
        action:
          <div>
            <MDBBtn style={btnStyle} onClick={handleQuit.bind(this, bot_id, CD.GAME_TYPE.OMOK)}>quit</MDBBtn>
          </div> 
      });
    }
    for(bot_id in bots_offline) {
      rows_bot.push({no: j++, bot_id: bot_id, where: "offline", State: "-", 
        action:
          <div>
            <MDBBtn style={btnStyle} onClick={handleOn.bind(this, bot_id)}>on</MDBBtn>
          </div> 
      });
    }
  }

  return (
    <div>
      <MDBContainer style = {{minWidth: '95%'}}>
        <MDBRow className="px-4 pt-2 pb-2">
          <MDBCol size="2">
            <h5 className="font-weight-bold dark-grey-text">Bots</h5>
          </MDBCol>
        </MDBRow>
        <MDBRow size = '12' className="px-4 pb-2">
          <MDBDataTable hover theadColor="cyan lighten-3" displayEntries={false} searching={false} info={false} paging={false} small={true} scrollX scrollY maxHeight="40vh" data={{columns: columns_bot, rows:rows_bot}}/>
        </MDBRow>
        {props.openSettingDlg && sel_game_type == CD.GAME_TYPE.GO && <GoSetting  onSettingOK = {onSettingOK} user_id = {sel_bot_id} />}
        {props.openSettingDlg && sel_game_type == CD.GAME_TYPE.FFA && <FFASetting  onSettingOK = {onSettingOK} user_id = {sel_bot_id} />}
        {props.openSettingDlg && sel_game_type == CD.GAME_TYPE.SKPNI && <SKoniSetting onSettingOK = {onSettingOK} user_id = {sel_bot_id} />}    
        {props.openSettingDlg && sel_game_type == CD.GAME_TYPE.OMOK && <OmokSetting onSettingOK = {onSettingOK} user_id = {sel_bot_id} />}
      </MDBContainer>
    </div>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  all_bot_ids: store.adminReducer.all_bot_ids,
  bots_lobby: store.adminReducer.bots_lobby,
  bots_go: store.adminReducer.bots_go,
  bots_ffa: store.adminReducer.bots_ffa,
  bots_skpni: store.adminReducer.bots_skpni,
  bots_omok: store.adminReducer.bots_omok,
  socketLobby: store.commonReducer.socketLobby,
  socketGoRoom: store.adminReducer.socketGoRoom,
  socketPuzzleRoom: store.adminReducer.socketPuzzleRoom,
  socketPDesignRoom: store.adminReducer.socketPDesignRoom,
  socketFFARoom: store.adminReducer.socketFFARoom,
  socketSKoniRoom: store.adminReducer.socketSKoniRoom,
  socketOmokRoom: store.adminReducer.socketOmokRoom,
  game_type: store.commonReducer.content,
  openSettingDlg: store.commonReducer.openSettingDlg,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    updateSettingDlg: CommonAction.updateSettingDlg,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Bots));
