export function updateUserList(user_count, user_list) {
  return {
    type: ACTION.UPDATE_USER_LIST,
    user_list,
    user_count,
  }
}

export function update_replay_mode(replay_mode) {
  return {
    type: ACTION.SET_PUTABLE,
    putAble: replay_mode === 1,
  }
}

export function updated_user_list() {
  return {
    type: ACTION.UPDATED_USER_LIST,
  }
}

export function update_omok_user_count(count) { 
  return {
    type: ACTION.UPDATE_OMOK_USER_COUNT,
    count   
  }
}

export function room_betted(user_id, bet_coin, bet_to_player, game_step) {
  return {
    type: ACTION.ROOM_BETTED,
    user_id,
    bet_coin,
    bet_to_player,
    game_step,
  }
}

export function update_record_play(play) {
  return {
    type: ACTION.UPDATE_RECORD_PLAY,
    play:play,
  }
}

export function init_move_history() {
  return{
    type: ACTION.INIT_OMOK_MOVE_HISTORY,
  }
}
