import React from 'react';
import {connect} from "react-redux";
import { Link, withRouter } from 'react-router-dom';
import { makeStyles } from '@material-ui/core/styles';
import * as CommonAction from "../../store/actions/common.action";
import {
  Typography,
  FormControl,
  InputLabel,
  OutlinedInput,
  Checkbox,
  FormControlLabel,
  FormLabel,
  Grid,
  Button
} from "@material-ui/core";
import {
  MDBBtn,
} from "mdbreact";
import {loginUser} from "../../store/actions/auth.action";
import * as ToastAction from "../../store/actions/toast.action";
import { SpaceBarOutlined } from '@material-ui/icons';

const useStyles = makeStyles(theme => ({
  svgStyle: {
    position: 'fixed',
    top:'12vh',
    marginBottom: '6vw',
    marginLeft: '-1vw',
    width: '1000px',
    height: '600px',
    backgroundColor: 'none',
    transform: 'scale(1, 1)',
    background: "url(/assets/img/Mark_back.svg)",
    backgroundSize: 'cover'
  },
  fontStyle: {
    color: '#616b76',
    fontSize: 30,
    paddingTop: '3vh',
    paddingBottom: '2vh',
    marginLeft: '8px',
    zIndex:1,
  },
  forgetPassFontStyle: {
    color: '#616b76',
    float: 'right',
    paddingTop: 8,
    fontSize: 16,
  },
  container: {
    display: 'inline-grid',
    position:'fixed',
    // boxShadow:'0px 0px 15px rgba(0, 0, 0, 0.2)',
    width: '40vw',
    left:'35vw',
    top:'25vh',
    padding: '2vw',
    backgroundColor: 'rgba(0, 0, 0, 0.0)',
    borderRadius: '40px',
   // paddingRight: '33vw',
    paddingBottom: '3vw',
    backgroundSize: 'contain',
  },
  formControl: {
    margin: theme.spacing(1),    
    alignSelf: 'right',
  },
  formLabelStyle: {
    color: '#616b76',
    float: 'left',
  },
  linkStyle: {
    color: '#616b76',
    textDecoration: 'none',
  },
  button: {
    width: "7vw",
    color: "white",
    alignSelf: 'center',
    textTransform: 'unset',
    // backgroundColor: '#3f1f8c',
  },
}));

function Login(props) {
  const [labelWidth, setLabelWidth] = React.useState(0);
  const [user_id, setUserid] = React.useState('');
  const [password, setPassword] = React.useState('');
  const labelRef = React.useRef(null);
  const classes = useStyles();

  React.useEffect(() => {
    setLabelWidth(labelRef.current.offsetWidth);
    props.showHiddenSideBar("14.5vw", true);
  }, []);

  const handleChangeUserid = event => {
    setUserid(event.target.value);
  };

  const handleChangePassword = event => {
    setPassword(event.target.value);
  };

  const onSubmit = event => {
    event.preventDefault();
    const {loginUser, history, returnUrl} = props;
    loginUser({user_id, password}, history, returnUrl);    
    props.showHiddenSideBar("14.5vw", true);
  };

  const onRegister = () => {
    props.history.push('/register');
  }

  return (
    <div alt ='auth' >
      <React.Fragment>
        <svg className={classes.svgStyle}>
          {/* <path d="M 188 0 4 158 C 4 158 -10 180 12 186 L 12 186 274 240 C 274 240 310 246 320 224 L 320 224 390 120 310 192 C 310 192 292 212 268 206 L268 206 74 170 C 74 170 40 164 62 138 L62 138Z" stroke="#99ccff" strokeWidth="1" fill="#99ccff" />
          <path d="M 34 240 292 327 C 292 327 334 342 352 304 L 352 304 416 170 C 416 170 417 166 418 162 L418 162 418 120 C 418 120 418 76 376 106 C 376 106 400 92 402 112 L402 112 402 146 C 402 146 401.5 154 401 162 L401 162 342 270 C 342 270 324 308 286 298 L286 298Z" stroke="#cce6ff" strokeWidth="1" fill="#cce6ff" /> */}
          {/* <path d="M100 100C100 100 200 200 300 200 S 150 250 400 400z"></path> */}
          
          Sorry, your browser does not support inline SVG.
        </svg>
        
        <div className={classes.container} >
          <Typography variant="h6" className={classes.fontStyle}>
            {window.i18n.t("login.header")}
          </Typography>
          <FormControl className={classes.formControl} variant="outlined">
            <InputLabel ref={labelRef} htmlFor="component-outlined">
              {window.i18n.t("login.user_id")}
            </InputLabel>
            <OutlinedInput
              id="component-outlined"
              value={user_id}
              onChange={handleChangeUserid}
              labelWidth={labelWidth}           
            />
          </FormControl>
          <FormControl className={classes.formControl} variant="outlined" >
            <InputLabel ref={labelRef} htmlFor="component-outlined">
              {window.i18n.t("login.password")}
            </InputLabel>
            <OutlinedInput
              id="component-outlined"
              type="password"
              value={password}
              onChange={handleChangePassword}
              labelWidth={labelWidth}                   
            />
          </FormControl>
          <FormControl className={classes.formControl} variant="outlined">
            <FormLabel component="legend"></FormLabel>
            <Grid container>
              <Grid item xs={12} sm={6}>
                <FormControlLabel
                  value="Remember"
                  control={<Checkbox color="primary" />}
                  label = {window.i18n.t("login.remember_me")}
                  labelPlacement="end"
                  className={classes.formLabelStyle}
                />
              </Grid>
              <Grid item xs={12} sm={6}>
                <Typography variant="h6" className={classes.forgetPassFontStyle}>
                  <Link className={classes.linkStyle} to="/login">{window.i18n.t("login.forget_password")}</Link>
                </Typography>
              </Grid>
            </Grid>
          </FormControl>
          <FormControl className={classes.formControl} style = {{whiteSpace: 'nowrap'}} variant="outlined">
            <span>
              <MDBBtn variant="contained" color = "cyan" style = {{marginLeft: '15vw'}} className={classes.button + " px-2 py-2"} onClick={onSubmit}>
                {window.i18n.t("button.sign_in")}
              </MDBBtn>
              <MDBBtn variant="contained" color = "cyan" className={classes.button + " float-right px-2 py-2"} onClick={onRegister}>
                {window.i18n.t("menu.register")}
              </MDBBtn>
            </span>
          </FormControl>
        </div>
      </React.Fragment>
    </div>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
    returnUrl: store.authReducer.stored_url,
  }
}

const mapDispatchToProps = {
  loginUser,
  createToast: ToastAction.createToast,
  showHiddenSideBar:CommonAction.show_hidden_sidebar,
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Login))