import React, { useState, useEffect, useRef } from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import {
  MDBRow,
  MDBCol,
} from "mdbreact";

import OmokBoard from './omokBoard';

import { makeStyles } from '@material-ui/core/styles';
import { Button } from "@material-ui/core"

const useStyles = makeStyles(theme => ({
  container: {
    position: 'fixed',
    left: "0vw", 
    top: '0vh',
    width: "100vw", 
    height:"100vh",
    zIndex: '1111',
    backgroundImage: "url(/assets/img/backg_2_2.jpg)"
  },
  board: {
    position: 'fixed',
    left: '24vw',
    top: '3vh',
    zIndex: '1112',
  },
  text: {
    fontSize: '3vh',
    fontWeight: 'bold',
    fontFamily: 'cursive',
  },
  quit: {
    position: 'fixed',
    right: '0vw',
    top: '3vh',
    zIndex: '1112',
    fontSize: '2.5vh',
  }
}));

function TryOmok(props) {
  const classes = useStyles();

  const handleExit = () => {
    props.history.goBack();
  }

  return (
    <div>
      <div className={classes.container}/>
      <div  className={classes.board}>
        <OmokBoard width="52" height="94"/>
      </div>
      <div className={classes.quit}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i class = "fa fa-home" style = {{fontSize: '2rem', color: 'white'}}/>
          </Button>
        </span>
      </div>
    </div>
  )
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(TryOmok);

