import React, {useEffect, useRef} from 'react';
import { Redirect, withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import {
  MDBBtn,
  MDBContainer,
  MDBRow,
  MDBCol,
  MDBCard,
  MDBCardBody,
} from "mdbreact";
import * as AuthAction from "../../store/actions/auth.action";
import * as CommonAction from "../../store/actions/common.action";
import * as TournamentAction from "../../store/actions/tournament.action";
import CD from "../../helper/const";
import PROTOCOL from "../../helper/protocol";
import ErrorCode from '../../helper/errorCode';

const useStyles = makeStyles(theme => ({
  avatarImg: {
    height: '4vh',
    width: '4vh',
    float: 'left',
    paddingRight: '1vh',
  },
  imgStyle: {
    height: '5vh',
    width: 'auto',
    background: 'url(assets/img/pasted.png)'
  },
  cardStyle: {
    // background:'url(assets/img/pasted.png)',
    backgroundSize: 'contain',
    backgroundRepeat: 'no-repeat',
    backgroundPosition: 'right',
    marginTop: '2vh',
    marginBottom: '2vh',
    padding: '2vw',
    backgroundColor: 'rgba(230, 230, 230, 0)',
    boxShadow: 'unset'
  },
  cardStyle2: {
    // background:'url(assets/img/holding.png)',
    backgroundSize: 'contain',
    backgroundRepeat: 'no-repeat',
    backgroundPosition: 'right',
    marginTop: '4vh',
    marginBottom: '2vh',
    padding: '2vw',
    backgroundColor: 'rgba(41, 137, 204, 0)',
    boxShadow: 'unset'
  },
  cardBodyStyle: {
    border: 'dashed',
    borderRadius: '5px',
    borderColor: 'rgb(190, 190, 190)',
    borderWidth: '2px',
    transition: '0.3s'
  },
  cardBodyStyle2: {
    border: 'dashed',
    borderRadius: '5px',
    borderColor: 'rgb(41, 137, 204)',
    borderWidth: '2px',
  }
}));

function Tournaments(props) {
  const classes = useStyles();
  const socketLobby_ref = useRef();

  useEffect(() => {
    props.req_tournament_list(props.game_type);
    props.setFunc(CD.FUNC.FUNC_TOURNAMENTS);
    props.saveTournamentId("");
  }, []);
  useEffect(() => {
    props.req_tournament_list(props.game_type);
  }, [props.game_type]);
  useEffect(() => {
    if(props.socketLobby !== null) {
      socketLobby_ref.current = props.socketLobby;   
      socketLobby_ref.current.on('sc_message', function(protocol, err, msg) {
        switch(protocol) {
          case PROTOCOL.CSC_CREATE_TOURNAMENT:
            if(err === ErrorCode.SUCCESS) {
              handleSelectTournament(false, msg.tournament_id);
            }
            break;
          default:
            break;
        }
      });
    }
  }, [props.socketLobby]);

  const handleSelectTournament = (past, tournament_id) => {
    const {history} = props;
    if (past)
      history.push('/tournament_past:' + tournament_id);
    else
      history.push('/tournament_current:' + tournament_id);
  };

  const handleCreateTournament = () => {
    const {user, game_type} = props;  
    socketLobby_ref.current.emit('admin_message', PROTOCOL.CSC_CREATE_TOURNAMENT, {token:user.token, category:game_type});
  };

  const handleHover = () => {
    classes.cardBodyStyle.backgroundColor = "rgba(0, 0, 0, 0.1)";
  }

  const prize_element = (p, i) => {
    var color = (i == 0)? '#ffe346' : (i == 1)? 'silver' : '#ff8c46';
    var medal = (i == 0)? 'fa fa-trophy' : 'la la-certificate';
    return (
      <MDBCol key={i} className="mb-md-0 px-1">
        <MDBRow>
          <MDBCol md="3" style={{fontSize:'2rem'}}>
            <i className={medal} style={{float: 'right', color: color}} />
          </MDBCol>
          <MDBCol>
            <img alt="avatar" className={classes.avatarImg} src={p.avatar} />
            <h6 className="text-left dark-grey-text mb-0">{p.user_id}</h6>
            <h6 className="text-left dark-grey-text"><small>Lv{p.level}</small></h6>
          </MDBCol>
        </MDBRow>
      </MDBCol>
    )
  };

  const { user, tournament_list } = props;

  return (
    <React.Fragment>
      <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
        <MDBContainer style = {{maxWidth: '95%'}}>
        {
          !!user && user.role === 'admin' && props.game_type == 0 && (
            <MDBRow>
              <MDBBtn color="cyan" className="float-left mt-4 px-4 py-2 ml-5" disabled={false} onClick = {handleCreateTournament}>
                {window.i18n.t("tournament.create_tournament")}
              </MDBBtn>
            </MDBRow>
          )
        }       
        {
          props.func == CD.FUNC.FUNC_TOURNAMENTS && tournament_list.map((tournament, index) => {
            if (!tournament.participants)
              return (
                <MDBCard key={index} className = {classes.cardStyle} >
                  <MDBCardBody onClick={handleSelectTournament.bind(this, true, tournament._id)} className = {classes.cardBodyStyle}>
                    <MDBRow>
                      <MDBCol md="4" className="mb-md-0 px-1">
                        <h5 className="font-weight-bold dark-grey-text pb-3">
                        { tournament.title }
                        </h5>
                      </MDBCol>
                      <MDBCol md="4" className="mb-md-0 px-1">
                        <h6 className="dark-grey-text pt-1 float-right">
                          <small>
                          {new Date(tournament.start_date).toLocaleDateString()} - {new Date(tournament.end_date).toLocaleDateString()}
                          </small>
                        </h6>
                      </MDBCol>
                      <MDBCol className="mb-md-0 px-1">
                        <h6 className="dark-grey-text pt-1 float-right">
                          <small>
                            {window.i18n.t("tournament.participate_info").replace("{0}", tournament.players).replace("{1}", parseInt(tournament.games / 2))}
                          </small>
                        </h6>
                      </MDBCol>
                    </MDBRow>
                    <MDBRow>
                      {
                        tournament.prize.map((p, i) => prize_element(p, i))
                      }
                    </MDBRow>
                  </MDBCardBody>
                </MDBCard>
              );
            else
              return (
                <MDBCard key={index} className = {classes.cardStyle2} >
                  <MDBCardBody onClick={handleSelectTournament.bind(this, false, tournament._id)} className = {classes.cardBodyStyle2}>
                    <MDBRow>
                      <MDBCol md="4" className="mb-md-0 px-1">
                        <h5 className="font-weight-bold pb-3" style = {{color: 'rgb(41, 137, 204)', fontSize: '25px',marginLeft: '1vw'}}>
                        { tournament.title }
                        </h5>
                      </MDBCol>
                      <MDBCol md="4" className="mb-md-0 px-1">
                        <h6 className="pt-1 float-right">
                          <small>
                          {new Date(tournament.start_date).toLocaleDateString()} - {new Date(tournament.end_date).toLocaleDateString()}
                          </small>
                        </h6>
                      </MDBCol>
                      <MDBCol className="mb-md-0 px-1">
                        <h6 className="pt-1 float-right">
                          <small>
                            {window.i18n.t("tournament.current_player").replace("{0}", tournament.participants.length)}
                          </small>
                        </h6>
                      </MDBCol>
                    </MDBRow>
                    <MDBRow>
                      <MDBCol md="4" className="mb-md-0 px-1">
                        <h6 className="font-weight-bold pb-3" style = {{marginLeft: '1.5vw'}}>
                        { tournament.information }
                        </h6>
                      </MDBCol>
                    </MDBRow>
                  </MDBCardBody>
                </MDBCard>
              );
          })
        }
        </MDBContainer>
      </div>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  tournament: store.tournamentReducer.go_tournament,
  tournament_list: store.commonReducer.items,
  socketLobby: store.commonReducer.socketLobby,
  game_type:store.commonReducer.content,
  func: store.commonReducer.func,
  open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    saveTournamentId: TournamentAction.saveTournamentId,
    req_tournament_list: CommonAction.req_tournament_list,
    setFunc: CommonAction.setFunc,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Tournaments));
