export const req_article = (article_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/article', {article_id});
    const {err, article} = result.data;
    if (err === ErrorCode.SUCCESS) {
      var articles = [];
      articles.push(article);
      if (article.boards.length > 0)
        GoLogic.theLogicBoard.initialize();
      if (article.boards.length > 1)
        GoLogic.theLogicBoard2.initialize();
      dispatch( { type: ACTION.SET_ARTICLES, articles, article_id});
    }
  } catch (error) {
  }
}

