import ACTION from '../actionTypes';

const initialState = {
  board: [],
  board_size: 9,
  isShowGrid: true,
  board_back: 0,
  board_updated: false,
};

export default function pdesignBoardReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.UPDATE_BOARD_SIZE:
      return {
        ...state,
        board_size: action.size,
      };
    case ACTION.UPDATE_SHOW_GRID:
      return {
        ...state,
        isShowGrid: action.isShow,
      };
    case ACTION.UPDATE_BACKGROUND:
      return {
        ...state,
        board_back: action.back,
      }
    case ACTION.INIT_BOARD:
      return {
        ...state,
        board: action.board,
        board_updated: action.board_updated
      };
    default: return state;
  }
}
