import React, {useState,useEffect, useRef} from 'react';
import io from 'socket.io-client';
import { withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import {
  Button,
} from '@material-ui/core';
import ErrorCode from "../../helper/errorCode";
import * as CommonAction from "../../store/actions/common.action";
import * as RoomAction from "../../store/actions/room.action";
import * as SKoniAction from "../../store/actions/skpni.action";
import * as ToastAction from "../../store/actions/toast.action";
import * as AuthAction from '../../store/actions/auth.action';
import  PROTOCOL  from"../../helper/protocol";
import CD from "../../helper/const";
import SKoniBoard from  './SKoniBoard';
import AvatarCom from '../control/AvatarCom';
import Clock from '../control/Clock';
import GrController from '../control/GrController';
import {swal_s, notify_s, notify_w} from "../../helper/alert";
import './star.css';

var exitReq = [false, false];
function SKoniRoom(props) { 
  const view_state = {
    view_history:1,
    view_game:0,
  };
  let w = window.innerWidth;
  let h = window.innerHeight;
  let avatarWidth = w/9*500/726;
  let avatarPosition=[[5 * w / 100, 63 * h / 100], [82 * w / 100, h / 5]]; 
  let clockPositionArray = [
    [avatarPosition[0][0] + 2 * avatarWidth, avatarPosition[0][1] + w / 25], 
    [avatarPosition[1][0] - 0.8 * avatarWidth, avatarPosition[1][1] + w / 25]
  ];
  let player1_update_coin_ref = useRef(), player2_update_coin_ref = useRef();
  let users_ref = useRef([]);
  var roomCoin_ref = useRef();
  let leftCountPosArr =[
    [avatarPosition[0][0], avatarPosition[0][1] ],
    [avatarPosition[1][0], avatarPosition[1][1] ]
  ];  
  let clockPosition_ref  = useRef();
  const [gameResult, setGameResult] = useState([]); 
  let [leftPass, setLeftPass] = useState([3, 3]);
  const [viewBtnColor, setViewBtnColor] = useState(['green', 'color']);
  const [exitRequest, setExitRequest] = useState([false, false]);
  const [isshowMessage, setIsMessage] = useState([0, 0, 0, 0]);
  const [isshowEmoticon, setIsEmoticon] = useState([0, 0, 0, 0]);
  const [emoticonIndex, setEmoticonIndex] = useState('');
  const [roomCoin, setRoomCoin] = useState(0);
  const [playersCoin, setPlayersCoin] = useState([]);
  let msg_set =  ['you are wonderful', 'you are wonderful', 'thanks for thinking', 'thanks for listening', 'thank you', 'thank you', 'thank you'];
  var socketRoom_ref = useRef();
  let spectate_mode_ref = useRef();
  let playersCoin_ref = useRef();
  const {user} = props;
  let token = !!user? user.token : null;
  let user_id = !!user? user.user_id : null;   
  let actionTime = 16;    
  let leftCount_ref = useRef();
  var handleTime, globalHandleTime;    
  const [leftTime, setLeftTime] = useState(0);
  const [displayClock, setDisplay] = useState('none');
  const [leftCountPos, setLeftCountPos] = useState(leftCountPosArr[0]);
  let mineNumber_ref = useRef();
  const removePassText = ()=>{
    document.getElementById("passText").style.display = 'none';   
  };
  const showPassText = (x, y)=>{
    document.getElementById("passText").style.left = `${x}px`;
    document.getElementById("passText").style.top = `${y}px`;
    document.getElementById("passText").style.display = 'block';
  };
  let gameCount = 0;  
  const openPrepareDlg = ()=>{
    var {user,  room_id } = props;
    var token = !!user? user.token : null;
    props.openModal({
      content: window.i18n.t("go_game.ready_sentence"),
      type: 'query',
      clickOK: () => {
        socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_CONFIRM_PREPARED, {token, room_id});
      },
      clickCancel: () => {
        handleExit();
      }
    });   
  };    
  const handleExit = () => {
    const {history} = props;
    history.push('/lobby');
  };
  const roundTimeDisplay = () =>{
    let second, minute, hour; 
    var date = new Date();
    hour = date.getHours();
    minute = date.getMinutes();
    if(minute < 10)
      minute = "0" + minute;
    second = date.getSeconds(); 
    if(second < 10)
      second = "0" + second;
    document.getElementById('timeCounter').innerHTML = hour + ':' + minute + ':' + second;     
  };
  const leftTimeDisplay = () =>{ 
    if(actionTime === 0) {
      clearInterval(handleTime);
      actionTime = 15;       
      return;
    }     
    actionTime --;
    setLeftTime(actionTime);   
  };

  const setSpectateMode = (mode)=>{
    const {update_spectate_mode, update_skpni_gr_index} = props;
    mode === 1?setDisplay('none'):setDisplay('block');
    update_spectate_mode(mode);
    if(mode == 1) update_skpni_gr_index(0);
  }; 
  let {room_no, room_coin,  player1_id, player1_avatar, player1_coin, player1_level, player2_id, player2_avatar, player2_coin, player2_level,  mineNumber} = props;
  useEffect(()=>{
    spectate_mode_ref.current = props.spectate_mode;
    if(props.spectate_mode === view_state.view_game) 
      setViewBtnColor(['white', 'black']);
    else{
      setViewBtnColor(['black', 'white']);
    }
  }, [props.spectate_mode]); 
  useEffect(()=>{
    let playersCoin = [player1_coin, player2_coin];
    setPlayersCoin(playersCoin.slice());
    playersCoin_ref.current = playersCoin.slice();
  }, [player1_coin, player2_coin]);
  useEffect(()=>{
    users_ref.current = props.users;
  },[props.users]);
  useEffect(()=>{
    let {room_coin} = props;
    roomCoin_ref.current = room_coin;
    if(room_coin !== 10)
      setRoomCoin(room_coin);
  }, [props.room_coin])
  useEffect(() => {
    const {room_id, roomURL, setSocketRoom} = props;
    var socketRoom = io(roomURL);   
    setSocketRoom(socketRoom);  
    exitReq = [false, false];
    socketRoom.on('sc_message', function(protocol, err, msg) {
      switch(protocol) {
        case PROTOCOL.SC_ROOM_INFO:
          {
            if (err === ErrorCode.SUCCESS) {   
              globalHandleTime = setInterval(roundTimeDisplay, 1000);
              let room_info = msg;           
              const users = msg.users; 
              props.load_room_info(user_id, room_info, CD.GAME_TYPE.SKPNI);           
              let turn = msg.turn;  
              gameCount ++;   
              if(users.length > 2)
                gameCount ++;
              mineNumber_ref.current = 2;        
              for(let i = 0; i < users.length;  i ++) {
                if(users[i].user_id === window.localStorage.getItem("token")) {
                  mineNumber_ref.current = i;             
                  break;
                }
              }              
              props.setMineNumber(mineNumber_ref.current); 
            }
          }
          break;          
        case PROTOCOL.SC_START_PREPARE:  
          if(err === ErrorCode.SUCCESS) {           
            document.getElementById('result').style.display = 'none';
            if(gameCount < 2 || mineNumber_ref.current < 2) {
              props.init_move_history();
              openPrepareDlg();             
            } else {
              props.init_move_history();
            }                    
          }      
          break;  
        case PROTOCOL.SC_GAME_START:
          {
            const users = msg.users;  
            let turn = msg.turn;  
            document.getElementById('leftCount').style.display = 'none';
            leftPass = [3, 3];  
            setLeftPass([leftPass[0], leftPass[1]]);        
            for(let i = 0; i < users.length;  i ++) {
              if(users[i].user_id === window.localStorage.getItem("token")) {
                mineNumber_ref.current  = i;                    
                break;
              }
            } 
            if(turn === mineNumber_ref.current  ) {
              clockPosition_ref.current = clockPositionArray[0];
            } else {
              clockPosition_ref.current = clockPositionArray[1];
            }           
            setDisplay('block');
            props.setMineNumber(mineNumber_ref.current );
            props.updateGameStart();
            actionTime = 15;
            setLeftTime(15); 
            handleTime = setInterval(leftTimeDisplay, 1000);
          }
          break; 
        case PROTOCOL.SC_GAME_MOVE:
          if (err === ErrorCode.SUCCESS) {
            setDisplay('none');
            setLeftTime(0);
            clearInterval(handleTime);                   
            let turn = msg.turn;                     
            if(turn === mineNumber_ref.current ) {
              clockPosition_ref.current = clockPositionArray[1];
              if(msg.move === 9000) {
                setLeftPass([ -- leftPass[0], leftPass[1]]);
                showPassText(avatarPosition[0][0] + 1.5 * avatarWidth, avatarPosition[0][1]);
                setTimeout(()=>{
                  removePassText();
                }, 1000)
              }
            } else if(mineNumber_ref.current  >= 2) {
              if(spectate_mode_ref.current === 0) {
                clockPosition_ref.current = clockPositionArray[turn];
                if(msg.move === 9000) {
                  if(turn === 0) {
                    setLeftPass([leftPass[0], -- leftPass[1]]);
                    showPassText(avatarPosition[1][0] - avatarWidth, avatarPosition[1][1] -  h / 10);
                    setTimeout(()=>{
                      removePassText();
                    }, 1000);
                  }
                  else {
                    setLeftPass([-- leftPass[0], leftPass[1]]);
                    setLeftPass([ -- leftPass[0], leftPass[1]]);
                    showPassText(avatarPosition[0][0] + 1.5 * avatarWidth, avatarPosition[0][1]);
                    setTimeout(()=>{
                      removePassText();
                    }, 1000);
                  }
                }
              }                
            } else {
              showPassText(avatarPosition[1][0] - avatarWidth, avatarPosition[1][1] + h / 10);
              setTimeout(()=>{
                removePassText();
              }, 1000)
              clockPosition_ref.current = clockPositionArray[0];
              if(msg.move === 9000)
                setLeftPass([leftPass[0], -- leftPass[1]]);
            }                
            actionTime = 15;
            setLeftTime(15);        
            handleTime = setInterval(leftTimeDisplay, 1000);   
            if(spectate_mode_ref.current === 0)    // don't display clock for view history
              setDisplay('block'); 
          }   
          break; 
        case PROTOCOL.SC_KICK_OUT:
          if (msg.reason == CD.REASON.ENTERED_ANOTHER_WITH_SAME_ID) {
            notify_w("Entered another user with same id. You are kicked");
            props.logoutUser('/');
            props.history.push('/');
          }
          break;
        case PROTOCOL.SC_OUT_ROOM: 
          if(err === ErrorCode.SUCCESS) {
            setTimeout(()=>{
              props.history.push("/lobby");
            }, 1500)
          }
          break;
        case PROTOCOL.SC_WILL_OUT_ROOM: 
          if(err === ErrorCode.SUCCESS) {
            let {user_id} = msg;
            if( mineNumber_ref.current  < 2) {
              for(let i = 0; i <  users_ref.current.length; i ++) {
                if( users_ref.current[i].user_id === user_id)
                  i ===  mineNumber_ref.current ?exitReq[0] = true:exitReq[1] = true;
              }
            } else {
              for(let i = 0; i <  users_ref.current.length; i ++) {
                if(users_ref.current[i].user_id === user_id)
                  i === 0 ?exitReq[1] = true:exitReq[0] = true;
              }
            }
            setExitRequest(exitReq.slice());
          }
          break;
        case PROTOCOL.SC_GAME_END:
          if(err === ErrorCode.SUCCESS) {                    
            let rewards_0, rewards_1;  
            //gameResult_ref.current = msg.game_result;
            setGameResult(msg.game_result);
            clearInterval(globalHandleTime);
            clearInterval(handleTime);
            setDisplay('none');
            let tem_players_coin = playersCoin_ref.current; 
            rewards_0 = msg.rewards[0];
            rewards_1 = msg.rewards[1];           
            if(mineNumber_ref.current !== 0) {
              player1_update_coin_ref.current = msg.rewards[1];
              player2_update_coin_ref.current = msg.rewards[0];    
              tem_players_coin[0] += msg.rewards[1];
              tem_players_coin[1] += msg.rewards[0];     
            } else {
              player1_update_coin_ref.current = msg.rewards[0];
              player2_update_coin_ref.current = msg.rewards[1];    
              tem_players_coin[0] += msg.rewards[0];
              tem_players_coin[1] += msg.rewards[1];            
            }         
            props.updateGameResult(gameResult,rewards_0, rewards_1);     
            setPlayersCoin(tem_players_coin.slice());
            if(player1_update_coin_ref.current > 0)
              player1_update_coin_ref.current = '+' + player1_update_coin_ref.current;
            if(player2_update_coin_ref.current > 0)
              player2_update_coin_ref.current = '+' + player2_update_coin_ref.current;
            document.getElementById("result").style.display = 'block'; 
          }
          break;
        case PROTOCOL.SC_UPDATED_COIN:
          if(err === ErrorCode.SUCCESS) {
            let {reason, d_coin} = msg;
            props.updateUserCoin(d_coin);
          }
          break;
        case PROTOCOL.SC_LEFT_COUNT:
          if(err === ErrorCode.SUCCESS) { 
            if(msg.left_count === undefined)   
              leftCount_ref.current = 0;
            else
              leftCount_ref.current = msg.left_count;        
            ///let turn = msg.turn;
            if(msg.turn === 0) {
              if(mineNumber_ref.current === 0) {               
                setLeftCountPos(leftCountPosArr[0]);
              } else {             
               setLeftCountPos(leftCountPosArr[1]);
              }
            } else {
              if(mineNumber_ref.current === 0) {              
                setLeftCountPos(leftCountPosArr[1]);
              } else {               
                setLeftCountPos(leftCountPosArr[0]);
              }
            }      
            document.getElementById('leftCount').style.display = 'block';
          } 
          break;         
        case PROTOCOL.SC_ROOM_CHAT:
          if(err === ErrorCode.SUCCESS) {          
            let user_id = msg.user_id;   
            let user_num ;        
            const {user} = props;   
            for(let i = 0; i < users_ref.current.length; i ++) {
              if(user_id === users_ref.current[i].user_id) {
                user_num = i;
                break;
              }
            }        
            if(user_num <= 1) {             //check observer or player
              props.room_chat(msg.user_id, msg.chat);           
              if(user.user_id === user_id) {
                isshowMessage[1] ++;               
                setIsMessage(isshowMessage.slice());
              } else {
                isshowMessage[3] ++;               
                setIsMessage(isshowMessage.slice());
              }  
            }             
          }
          break;
        case PROTOCOL.SC_UPDATED_MULTIPLIER:
          if(err === ErrorCode.SUCCESS) {
            let {multiplier} = msg;
            setRoomCoin(roomCoin_ref.current * multiplier);
            notify_s("coin X"+ multiplier);
          }
          break;
        case PROTOCOL.SC_ROOM_EMOTICON:       
          if(err === ErrorCode.SUCCESS) {          
            let user_id = msg.user_id;  
            let user_num ;        
            const {user, users} = props;        
            setEmoticonIndex(msg.emoticon);   
            for(let i = 0;i < users_ref.current.length; i ++) {
              if(user_id === users_ref.current[i].user_id) {
                user_num = i;
                break;
              }
            }
            if(user_num <= 1) {                //check observer or player
              if(mineNumber_ref.current < 2 ) {             
                user.user_id === user_id?  isshowEmoticon[1] ++: isshowEmoticon[3] ++;
                setIsEmoticon(isshowEmoticon.slice());
              }  else {
                let emoticon_sender_index;
                for(let i = 0; i < 2; i ++) {
                  if(users_ref.current[i].user_id === user_id) {
                    emoticon_sender_index = i;
                    break;
                  }              
                }            
                emoticon_sender_index === 0?  isshowEmoticon[3] ++: isshowEmoticon[3] ++;
                setIsEmoticon(isshowEmoticon.slice());
              }   
            }
          }    
          break;
        default:
          break;
      }
    });    
    socketRoom.on('connect', function() {
      socketRoom.emit('cs_message', PROTOCOL.CS_ENTERED_ROOM, {token, room_id});
      socketRoom.emit('cs_message', PROTOCOL.CS_ROOM_INFO, {room_id});
    });  
    window.addEventListener('resize', ()=>{
    })
    return ()=>{
      clearInterval(globalHandleTime);
      socketRoom_ref.current.emit('close');
      props.init_move_history();
      window.removeEventListener('resize',()=>{
      })
    }
  }, []);
  useEffect(()=>{
    const {user, emoticon_index, room_id} = props;
    if(props.emoticon_index !== '' && !!socketRoom_ref.current) {
      socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_ROOM_EMOTICON, {token:user.user_id, room_id:room_id, emoticon:emoticon_index});           
    }    
  }, [props.emoticon_index, props.emoticon_counter]);
  useEffect(()=>{
    const {user, room_id} = props;
    let chat = msg_set[props.msg_index];       
    if(props.msg_index !== '') {   
      socketRoom_ref.current.emit('cs_message', PROTOCOL.CS_ROOM_CHAT, {token:user.user_id, room_id:room_id, chat:chat});           
    }
  }, [props.message_counter, props.msg_index]); 
  useEffect(()=>{
    socketRoom_ref.current = props.socketRoom;
  }, [props.socketRoom]);
  if(user_id !== player1_id) {
    let  temp_id = player1_id;
    let  temp_avatar = player1_avatar;
    let temp_level = player1_level;
    let temp_coin = player1_coin;
    player1_id =  player2_id;
    player1_coin = player2_coin;
    player1_coin = player2_coin;
    player1_level = player2_level;
    player1_avatar = player2_avatar;
    player2_id =  temp_id;
    player2_coin = temp_coin;
    player2_level = temp_level;
    player2_avatar = temp_avatar; 
  }
  return(  
    <div >
      <div id='board' style={{backgroundImage:'url(/assets/img/KPNI_back.svg)', backgroundSize: "cover", width:`${w}px`, height: `${h}px`, position:"fixed",left:`${0}px`, top: `${0}px`, zIndex:"1112"}}>                              
        <SKoniBoard action = {'play'}/>              
        <AvatarCom roomType = {3}  exitRequest = {exitRequest[0]} emoticon_index = {emoticonIndex} Emoticon = {isshowEmoticon[1]} show_message = {isshowMessage[1]} avatarPosition = {avatarPosition[0]} playerLevel = {player1_level} playerId = {player1_id} avatar = {player1_avatar} playerCoin = {playersCoin[0]} multiplier = {1}/>
        <AvatarCom  roomType = {3} exitRequest = {exitRequest[1]} emoticon_index = {emoticonIndex} Emoticon = {isshowEmoticon[3]} show_message = {isshowMessage[3]} avatarPosition = {avatarPosition[1]} playerLevel = {player2_level} playerId = {player2_id} avatar = {player2_avatar} playerCoin = {playersCoin[1]} multiplier = {1}/>
        <div >
          <p  alt = 'leftCount' id = 'leftCount'  style = {{fontSize:'1.5vw', fontWeight: 'bold', textTransform: 'none', position:'fixed', left:`${leftCountPos[0]}px`, top:`${leftCountPos[1]}px`,marginTop:'0px', color:'#ffff60', display:'none'}}>{"Left Count " + leftCount_ref.current}        
          </p>
          <p  alt = 'leftPass_0'  id = 'leftPass_0'  style = {{fontSize:'1.2vw', fontWeight: 'bold', textTransform: 'none' ,position:'fixed', left:`${leftCountPosArr[0][0]}px`, top:`${leftCountPosArr[0][1] - 30}px`,marginTop:'0px', color:'#ffff60', display:'block'}}>{'Left Pass ' + leftPass[0]}        
          </p>
          <p  alt = 'leftPass_1'  id = ''  style = {{fontSize:'1.2vw', fontWeight: 'bold', textTransform: 'none', position:'fixed', left:`${leftCountPosArr[1][0]}px`, top:`${leftCountPosArr[1][1] - 30}px`,marginTop:'0px', color:'#ffff60', display:'block'}}>{'Left Pass ' + leftPass[1]}        
          </p>       
        
          <h6 id = 'roomNumber'  style = {{fontSize:'30px', position:'fixed', left:'20vw', top:'4vh' ,marginTop:'0px', color:'#ffff60', zIndex:'1114'}}>{room_no}        
          </h6>
          <h6 id = 'roomCoin'  style = {{fontSize:'30px',position:'fixed', marginTop:'0px', left:'27vw', top:'4vh' , color:'#ffff60', zIndex:'1114'}}><i className={" fa fa-star"}/>{" "}{roomCoin}       
          </h6>
          <h6 id = 'timeCounter'  style = {{fontSize:'30px',position:'fixed', left:'38vw', top:'4vh', marginTop:'0px', color:'#ffff60', zIndex:'1114'}}>        
          </h6>
          {/* <img id="coinImg" alt ='coinImg' src='/assets/img/coin_Img.png' style={{position:'fixed', left:'25vw', top:'2.5vh',  width:'4vh', height:'4vh', zIndex:'1114'}}></img>                   */}
             
          <img id="clockImg" alt='clockImg' src='/assets/img/clock.png' style={{position:'fixed',display:'none'}}></img>  
          <div id = "Clock">
            <p id = 'ClockText'  style = {{fontSize:'25px',position:'fixed',marginTop:'0px', color:'white', zIndex:'1113'}}>        
            </p>
          </div>     
        </div>            
        {clockPosition_ref.current === undefined ?(<Clock leftTime = {leftTime} display = {displayClock} clockPosition = {[0, 0]}/>):
        (<Clock leftTime = {leftTime} display = {displayClock} clockPosition = {clockPosition_ref.current}/>)}            
        {props.mineNumber >= 2 && 
          <div style = {{position: "absolute", bottom: '10vh', right: "2vw", width: "21vw"}}>
            <Button id = 'view_history' onClick = {setSpectateMode.bind(this, 1)} style = {{backgroundColor:"rgba(0, 0, 0, 0)", zIndex:'1113', color:`${viewBtnColor[1]}`, width:'50%', height: '8vh', borderRadius: '0px', border: '1px solid black'}}>
              {"view history"}       
            </Button>  
            <Button id = 'view_game' onClick = {setSpectateMode.bind(this, 0)} style = {{backgroundColor:"rgba(0, 0, 0, 0)", zIndex:'1113', color:`${viewBtnColor[0]}`, width:'50%', height: '8vh', borderRadius: '0px', border: '1px solid black', borderLeft: 'none'}}>
              {"view game"}       
            </Button>  
          </div>}
        {props.spectate_mode === view_state.view_history &&
          <div style = {{position: 'absolute', right: '2vw', bottom: '20vh'}}>
            <GrController/>
          </div>
        }
    </div>
    <div alt = 'result' id = 'result' style = {{width:`${w}px`, height:`${h}px`, position:"fixed",left:`${0}px`, top: `${0}px`, display:'none',  zIndex:"1113" }}>      
      <div alt = 'result_back' id = 'result_img'  style = {{position:'fixed', width:`${w}px`,marginTop:'0px',  height:`${h}px`, left :`${0}px`, top:`${0}px`, backgroundColor:'rgba(0, 224, 0, 0.1)'}}></div>     
      { 
        ( gameResult[mineNumber_ref.current] === 'W') &&
        <h1  style = {{fontSize:'6vw',  fontWeight: 'bold', position:'fixed', left:`${w / 2 - w / 100 * 4.5}px`, top:`${h / 2 - w / 100 * 3}px` ,marginTop:'0px' , color:'orange', opacity:'1'}}>WIN
        </h1>
      }
      {
        (gameResult[mineNumber_ref.current] === 'L') &&
        <h1  style = {{fontSize:'6vw',  fontWeight: 'bold', position:'fixed', left:`${w / 2 - w / 100 * 4.5}px`, top:`${h / 2 - w / 100 * 3}px` ,marginTop:'0px' , color:'black', opacity:'1'}}>LOSE
        </h1>
      }
      <p id = 'player1_update_coin'  style = {{fontSize:'3vw',  fontWeight: 'bold', position:'fixed', left:`${avatarPosition[0][0] + avatarWidth}px`, top:`${avatarPosition[0][1] + avatarWidth / 1.5}px` ,marginTop:'0px' , color:'#ffff60', opacity:'1'}}>{  player1_update_coin_ref.current }</p>
      <p id = 'player2_update_coin'  style = {{fontSize:'3vw',  fontWeight: 'bold', position:'fixed', left:`${avatarPosition[1][0] - avatarWidth / 2}px`, top:`${avatarPosition[1][1] + avatarWidth / 1.5}px`,marginTop:'0px' , color:'#ffff60', opacity:'1'}}>{  player2_update_coin_ref.current }</p>       
    </div>
    <p id = 'passText'  style = {{fontSize:'3vw',position:'fixed',marginTop:'0px', display:'none',textShadow :'2px 2px  5px green',zIndex:'1200', color:'tomato'}}>        
      Pass
    </p>    
  </div>
  );
}
const mapStateToProps = (store) => {
  let players = store.roomReducer.room.players;
  return {    
    // ream change
    users: store.roomReducer.room.users,
    move_history: store.roomReducer.room.move_history,
    mineNumber:store.skpniReducer.mineNumber, 
    room_no:store.roomReducer.room.room_no,
    room_coin:store.roomReducer.room.coin,
    player1_id:players.length > 0? players[0].user_id : '',
    player1_avatar: players.length > 0? players[0].avatar : '',
    player1_level: players.length > 0? players[0].level : 0,
    player1_coin: players.length > 0? players[0].coin : 0,
    player2_id: players.length > 1? players[1].user_id : '',
    player2_avatar: players.length > 1? players[1].avatar : '',
    player2_level: players.length > 1? players[1].level : 0,
    player2_coin: players.length > 1? players[1].coin : 0,
    gr_index: store.commonReducer.gr_index,     
    spectate_mode: store.roomReducer.room.spectate_mode,
    player1_update_coin:store.skpniReducer.room.player1_update_coin,
    player2_update_coin:store.skpniReducer.room.player2_update_coin,
    gameResult:store.roomReducer.room.result,
    board_update:store.skpniReducer.board_update,
    //
    socketRoom: store.roomReducer.socketRoom,
    room_type: store.roomReducer.room.room_type,
    room_id: store.roomReducer.room.room_id,    
    msg_index:store.commonReducer.msg_index,
    message_counter:store.commonReducer.message_counter, 
    isShowEmoticon:store.commonReducer.isShowEmoticon,
    emoticon_counter:store.commonReducer.emoticon_counter,
    emoticon_index:store.commonReducer.emoticon_index,
    ///   
    roomURL: store.roomReducer.room.room_url,    
    players: players,    
    user: store.authReducer.user,
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    logoutUser : AuthAction.logoutUser,
    openModal: ToastAction.openModal,   
    load_room_info: RoomAction.load_room_info,
    update_skpni_gr_index: CommonAction.update_gr_index,
    update_spectate_mode: RoomAction.update_spectate_mode,
    setSocketRoom: RoomAction.setSocketRoom,   
    updateGameStart: SKoniAction.update_game_start,
    setMineNumber:SKoniAction.set_mine_number,
    updateGameResult:SKoniAction.update_game_result,
    init_move_history: RoomAction.init_move_history,
    room_chat: RoomAction.room_chat,
    updateUserCoin:AuthAction.updateUserCoin,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(SKoniRoom));

