import CD from '../../helper/const';
import ACTION from '../actionTypes';

const initialState = {
  board: [],
  room: {
    countdown: 0,
    move_histories: [],
    problem: null,
  },
};

export default function puzzleReducer(state=initialState, action){
  switch (action.type) {
    case ACTION.LOAD_PUZZLE_ROOM_INFO:
      return {
        ...state,
        room: {
          ...state.room,
          countdown: action.countdown,
          problem: !!action.problem ? action.problem : state.room.problem
        },       
      };
    case ACTION.LOAD_PUZZLE_RECORD:
      return {
        ...state,
        room: {
          ...state,
          move_histories: action.game.move_histories,
          countdown: !!action.game.countdown ? action.game.countdown : state.room.countdown,
          problem: !!action.game.problem ? action.game.problem : state.room.problem
        }
      }
    default: return state;
  }
}
