import React, {useState,useEffect, useRef} from 'react';
import CD from "../../helper/const";
import { withRouter } from "react-router-dom";
import FFARoomBase from './FFARoomBase';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";

function FFAReplay(props) {
  return (
    <div>
      <div style={{backgroundColor: "rgba(0, 0, 0, 0)", position:"fixed", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "100vw", height: "100vh" , paddingTop: '90vh', paddingLeft: '78vw'}}>
        <FFARoomBase action_method = {props.game_kind == 0? CD.ACTION_METHOD.REPLAY_2 : CD.ACTION_METHOD.REPLAY_4}/>
      </div>
    </div>  
  );
}

const mapStateToProps = (store) => {
  return {     
    game_kind: store.ffaReducer.room.game_kind,
  }
};

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {   
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(FFAReplay));
