import React, {useEffect} from 'react';
import { Redirect, withRouter } from "react-router-dom";
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import Forum_compose from './Forum_compose';
import Forum_view from './Forum_view';
import Forum from './Forum';
import {
  MDBRow,
  MDBCol,

} from "mdbreact";
import {   
    Select,
    MenuItem,
    MenuList,
  } from '@material-ui/core';
import * as GoAction from "../../store/actions/go.action";


const useStyles = makeStyles(theme => ({
    container: {
      display: 'fixed',
      top:'15vh',
      left:'7.8vw',
      paddingLeft: '1vw',
      paddingRight: '1vw',
      paddingTop: '2vh',
     // minHeight: '83vh',
      maxHeight:"70vh",
      scrollBehavior: 'smooth',
    },
}));
function ForumRoom(props) { 

    const [selectedMenuKey, setMenuKey] = React.useState(1);
    const classes = useStyles();    
    const handleSelect = (key) => {   
        setMenuKey(key);
    };
    return (
    <React.Fragment >
        <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
            <div className={classes.container}>
                <MDBRow >
                    <MDBCol size="2">
                        <MenuList>
                            <MenuItem onClick={handleSelect.bind(this, 1)} key="1" style={{ border: '1px solid #f0f0f0', backgroundColor: selectedMenuKey === 1? '#e0e0e0' : 'white'}}>Forum</MenuItem>
                            <MenuItem onClick={handleSelect.bind(this, 2)} key="2" style={{ border: '1px solid #f0f0f0', backgroundColor: selectedMenuKey === 2? '#e0e0e0' : 'white'}}>Forum_Compose </MenuItem>                        
                        </MenuList>
                    </MDBCol>
                    <MDBCol>
                        {selectedMenuKey === 1 && <Forum/>}
                        {selectedMenuKey === 2 && <Forum_compose/>}                   
                    </MDBCol>
                </MDBRow>      
            </div>
        </div>
    </React.Fragment>
    );
}

const mapStateToProps = (store) => ({
    open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(ForumRoom));
