export const get_teacher_data = (teacher_id) => async dispatch => {
  try {
    const result = await axios.post(config.apiUrl + '/teacher_rating', {teacher_id});
    const {err, students, reviews} = result.data;
    if (err === ErrorCode.SUCCESS) {
      dispatch({type: ACTION.UPDATE_TEACHER_DATA, students});
      dispatch({type: ACTION.UPDATE_REVIEWS, reviews});
    }
  } catch (error) {
  }
}

