export const enter_lecture_room = (connection, room, user) => async dispatch => {
  try {
    dispatch({ 
      type: ACTION.ENTER_LECTURE_ROOM,
      room_id: room.sessionid, 
      teacher: room.owner, 
      title: room.extra.title, 
      start: new Date(room.extra.start).toLocaleTimeString('en-US', { hour12: true, hour: "numeric", minute: "numeric"}),
      status: room.extra.status
    });
    dispatch({type: ACTION.CHANGE_ROOM_TYPE, room_type: 'lecture'});
    if (room.owner === user.user_id) {
      connection.dontCaptureUserMedia = false;
      connection.captureUserMedia();
    } else {
      connection.join(room.sessionid, function() {});
    }
  } catch (error) {
  }
}

export const load_board_in_lecture_room = (viewport, ini_board, marks, move_history, h_index) => dispatch => {
  GoLogic.theLogicBoard.initialize();
  GoLogic.theLogicBoard.setboard(ini_board);
  var color = GoLogic.BLACK;
  for (var i = 0; i < move_history.length; i ++) {
    GoLogic.theLogicBoard.domove(move_history[i], color);
    color = GoLogic.BLACK + GoLogic.WHITE - color;
  }
  dispatch({type: ACTION.LOAD_BOARD_IN_LECTURE_ROOM, move_history, h_index,});
  dispatch({type: ACTION.SET_VIEWPORT, viewport});
  dispatch({type: ACTION.SET_GO_MARKS, marks});
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
}

export const update_lecture_board_history_index = (h_index) => dispatch => {
  GoLogic.theLogicBoard.goto_idx(h_index);
  dispatch({ type: ACTION.UPDATE_LECTURE_BOARD_HISTORY_INDEX,  h_index, });
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
}

export const clear_lecture_board = () => dispatch => {
  GoLogic.theLogicBoard.initialize();
  dispatch({ type: ACTION.CLEAR_LECTURE_BOARD, });
  dispatch({type: ACTION.UPDATED_GO_BOARD, });
  dispatch({type: ACTION.SET_GO_MARKS, marks: []});
}

export function reset_rtc_connection(connection) {
  return {
    type: ACTION.RESET_RTC_MULTI_CONNECTION,
    connection,
  }
}

export function do_move_in_lecture_room (x, y, turn) {
  var wpos = GoLogic.WPOS(x, y);
  GoLogic.theLogicBoard.domove(wpos, turn);
  var h_index = GoLogic.theLogicBoard.getgridx();
  return {
    type: ACTION.DO_GO_LECTURE_MOVE,
    wpos,
    h_index,
  }
}

