export const req_game_list = (game_type, category, keyword, pagesize, page) => async dispatch => {
  dispatch({type: ACTION.CHANGE_SELECT, content: game_type, filter1: category, find: keyword, page, rowsPerPage: pagesize });
  try {
    const result = await axios.post(config.apiUrl + '/record_list', {game_type, category, keyword, pagesize, page });
    const {err, total, items} = result.data;
    if (err === ErrorCode.SUCCESS)
      dispatch(updateList(items, total));
  } catch (error) {
    let errorObj = parseError(error);
    notify_w(JSON.stringify(errorObj));
  }
}

