export const req_article_list = (category, keyword, pagesize, page) => async dispatch => {
  dispatch({type: ACTION.CHANGE_SELECT, find: keyword, page, rowsPerPage: pagesize});
  try {
    const result = await axios.post(config.apiUrl + '/article_list', {category, keyword, pagesize, page});
    const {err, total, items} = result.data;
    if (err === ErrorCode.SUCCESS) {
      if (category === 0) {
        dispatch( { type: ACTION.UPDATE_LIST, items, total});
      } else if (category === 1)
        dispatch( { type: ACTION.UPDATE_LIST, items2: items });
      else if (category === 2)
        dispatch( { type: ACTION.UPDATE_LIST, items3: items });
      else if (category === 3)
        dispatch( { type: ACTION.UPDATE_LIST, items4: items });
    }
  } catch (error) {
  }
}

