import React, { useState, useEffect } from 'react';
import {bindActionCreators} from "redux";
import {connect} from "react-redux";
import { withRouter } from "react-router-dom";
import { makeStyles } from '@material-ui/core/styles';

import {
  MDBBtn,
  MDBRow,
  MDBCol,
} from "mdbreact";

import { notify_w } from "../../helper/alert";


const useStyles = makeStyles(theme => ({
  container: {
    width: "95%",
    minHeight: '83vh',
    paddingTop: '2vh',
  },
}));

function OmokTraining(props) {
  const classes = useStyles();

  const tryOmok = (id) => {
    const { history, user } = props;
    // if(!!user)
    //   history.push('/try_omok:'+id);
    // else {
    //   notify_w("First, you have to login!");
    //   props.history.push('/login');
    // }
      history.push('/try_omok:'+id);
  };

  return (
    <div className={classes.container}>
      <MDBRow className="py-2 mx-0 px-5 mt-2">
       <h4 className="pr-5"><strong>{"TryOmok"}</strong></h4>
      </MDBRow>
      <MDBRow className="py-2 mx-0 px-5 mt-2">
        <MDBCol size = '1'></MDBCol>
        <MDBCol >
          <MDBBtn style={{width:'15vh', height:'5vh'}} color="cyan" className="px-3 py-1" onClick={tryOmok}>
            {"try"}
          </MDBBtn>
        </MDBCol>
      </MDBRow>
    </div>
  );
}

function mapStateToProps(store) {
  return {
    user: store.authReducer.user,
  }
}

function mapDispatchToProps(dispatch) {
  return bindActionCreators(
    {
    },
    dispatch
  )
}

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(OmokTraining));
