import React, { useState, useEffect, useRef } from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import Rater from 'react-rater';
import PCD from './puzzleConst';
import * as PBC from './puzzleBaseClasses';
import PuzzleBoard from "./puzzleBoard";
import PPAction from './puzzleProcAction';
import * as PCBoard from './puzzleCalcBoard';
import * as PuzzleProblemAction from "../../store/actions/puzzle_problem.action";
import {
  Button,
  Checkbox,
  FormControl,
  FormControlLabel,
  Radio,
  RadioGroup,
} from "@material-ui/core";

const useStyles = makeStyles(theme => ({
  board: {
    position: 'fixed',
    left: '24vw',
    top: '3vh',
    zIndex: '1112',
  },
  description: {
    position: 'fixed',
    right: '1vw',
    top: '10vh',
    width: "24vw", 
    height:"47vh",
    zIndex: '1112',
    color: 'black',
    background: 'rgba(255,255,255,0.6)',
    paddingTop: '2vh',
    paddingLeft: '1vw',
    paddingRight: '1vw',
  },
  text: {
    paddingLeft: '1.5vw', 
    fontSize: '2.5vh',
    fontWeight: 'bold',
    fontFamily: 'cursive',
  },
  difficulty: {
    position: 'fixed',
    right: '8vw',
    top: '3vh',
    width: '15vw',
    height: '5vh',
    background: 'rgba(200,200,200,0)',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
  options: {
    position: 'fixed',
    right: '1vw',
    top: '60vh',
    width: "24vw", 
    height:"27vh",
    zIndex: '1112',
    color: 'black',
    background: 'rgba(255,255,255,0.6)',
    paddingTop: '2vh',
    paddingLeft: '1vw',
    paddingRight: '1vw',
  },
  completed: {
    position: 'fixed',
    right: '5vw',
    top: '90vh',
    width: '12vw',
    height: '7vh',
    background: 'rgba(200,200,200,0)',
    zIndex: '1112',
    fontSize: '2.5vh',
  },
}));

function PuzzleProblem(props) {
  const classes = useStyles();
  const [extra_type, setExtraType] = useState(-1);
  const [cur_extra_index, setCurExtraIndex] = useState("");
  const [extra_indices, setExtraIndices] = useState([]);
  const [btn_disabled, setBtnDisable] = useState(false);

  useEffect(() => {
    if(extra_type == 0 || extra_type == 3 ) {
      array_extra_data.map((data, i) => {
        let wBg = PCD.LOWORD(data.n_data);
        let wSymbol = PCD.HIWORD(data.n_data);
        drawBtnImage(i, wBg, wSymbol, new PBC.CSize(48, 48));
      })
    }
  });
  useEffect(() => {
    setupOptionPanel();
  }, [props.array_extra_data]);
  useEffect(() => {
    setCurExtraIndex(props.curExtraIndex);
  }, [props.curExtraIndex]);
  useEffect(() => {
    setExtraIndices(props.extraIndices);
  }, [props.extraIndices]);
  useEffect(() => {
    setBtnDisable(props.completeSolve);
  }, [props.completeSolve]);
  useEffect(() => {
    const {move_history} = props;
    if (!!move_history.arrayCandiIndexes) {
      var array = move_history.arrayCandiIndexes;
      for (let i = 0; i < array.length; i ++) {
        if (extra_type == 1) {
          handleChangeExtraSelect({target: {value: array[i]}});
        } else if (extra_type == 2) {
          handleChangeExtraCheck(array[i]);
        }
      }
    }
  }, [props.move_history]);
  const setupOptionPanel = () => {
    const {solution_type, array_extra_data} = props;
    setExtraType(-1);
    setExtraIndices(new Array(array_extra_data.length).fill(false));
    for(let nn = 0; nn < array_extra_data.length; nn ++) {
      if(solution_type == PCD.SOLUTION_TYPE.SOLUTION_SELECTONLYONE ||
      solution_type == PCD.SOLUTION_TYPE.SOLUTION_MOUSEBUTTON ||
      solution_type == PCD.SOLUTION_TYPE.SOLUTION_BUTTONMOUSE) {
        if(!array_extra_data[nn].s_data) {
          //pushButton
          setExtraType(0);
        } else {
          //radio button
          setExtraType(1);
        }
      } else if (solution_type == PCD.SOLUTION_TYPE.SOLUTION_SELECTONEMORE) {
        //checkbox
        setExtraType(2);
      } else { //PCD.SOLUTION_TYPE.SOLUTION_MOUSEACTION
        //pushButton
        setExtraType(3);
      }
    }
  }
  const drawBtnImage = (i, wBg, wSymbol, size, nBoardShape/* = SQUARE*/, nBoardShapeIdx/* = 0*/) => {
    const STICK_WIDTH = 4;
    let strFile;
    let wArray = [wBg, wSymbol];
    let nIconGroup, nIconIndex, nSymbolColorIdx = 0;

    let elem = document.getElementById("BtnImg_"+i);
    elem.setAttribute("width", size.width());
    elem.setAttribute("height", size.height());
    let image = elem.getContext("2d");

    image.clearRect(0, 0, size.width(), size.height());
    for (let nn = 0; nn < 2; nn ++)
    {
      let size1 = size;
      if (wArray[nn] == PCD.EMPTY_CELL)
          wArray[nn] = 0;

      nIconGroup = PCD.CELLTYPE(wArray[nn]);
      nIconIndex = PCD.CELLINDEX(wArray[nn]);
      if (nIconGroup == PCD.CELL_TYPE.STICK && nIconIndex == PCD.EMPTY_BORDER)
      {
          nIconGroup = 0;
          nIconIndex = 0;
      }
      if (nn == 1) {
        // Symbol
        if (PCD.CELLTYPE(wBg) == PCD.CELL_TYPE.COLOR)
          nSymbolColorIdx = (PCD.CELLINDEX(wBg) < 14) ? 14 : 0;
        else if (PCD.CELLTYPE(wBg) == PCD.CELL_TYPE.STONE)
          nSymbolColorIdx = (PCD.CELLINDEX(wBg) < 16 && PCD.CELLINDEX(wBg) != 0 && PCD.CELLINDEX(wBg) != 2) ? 14 : 0;
        else if (wBg != PCD.EMPTY_CELL)
          nSymbolColorIdx = nIconIndex % (PCD.cr.length / 2);
        else
          nSymbolColorIdx = 0;
      }

      // switch(nIconGroup)
      // {
      // case PCD.CELL_TYPE.STONE:	strFile = `:/cell/0/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.COLOR:	strFile = `:/cell/1/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.KPREAN: strFile = `:/cell/2/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.ENGLISH: strFile = `:/cell/3/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.SHAPE:	strFile = `:/cell/5/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.MARK:	strFile = `:/cell/7/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.FRUIT:	strFile = `:/cell/8/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.ANIMAL:	strFile = `:/cell/9/${nIconIndex}.png`; break;
      // case PCD.CELL_TYPE.PICTURE: strFile = `${nIconIndex}.png`; break;
      // default:			strFile = "";
      // }

      if ((nn == 1 && (nIconGroup == PCD.CELL_TYPE.DIGIT || nIconGroup == (PCD.CELL_TYPE.DIGIT | 0x40))) ||
        (nn == 0 && (nIconGroup == PCD.CELL_TYPE.TOPNUM || nIconGroup == (PCD.CELL_TYPE.TOPNUM | 0x40)) ||
        (nIconGroup == PCD.CELL_TYPE.BOTTOMNUM || nIconGroup == (PCD.CELL_TYPE.BOTTOMNUM | 0x40)) ||
        (nIconGroup == PCD.CELL_TYPE.LTOPNUM || nIconGroup == (PCD.CELL_TYPE.LTOPNUM | 0x40))))
      {
        let x = 0, y = 0;
        if ((nIconGroup & 0x40) != 0)
          nIconIndex *=-1;
        strFile = `${nIconIndex}`;
        if (nIconGroup != PCD.CELL_TYPE.DIGIT && nIconGroup != (PCD.CELL_TYPE.DIGIT | 0x40))
        {
          if ((nIconGroup == PCD.CELL_TYPE.TOPNUM || nIconGroup == (PCD.CELL_TYPE.TOPNUM | 0x40)))
          {
            x = size1.width()/2;
            y = 0;
          }
          else if (nIconGroup == PCD.CELL_TYPE.BOTTOMNUM || nIconGroup == (PCD.CELL_TYPE.BOTTOMNUM | 0x40))
          {
            x = size1.width()/2;
            y = size1.height()/2;
          }
          else if (nIconGroup == PCD.CELL_TYPE.LTOPNUM || nIconGroup == (PCD.CELL_TYPE.LTOPNUM | 0x40))
          {
            x = 0;
            y = 0;
          }
          size1.setHeight(size1.height()/3);
          size1.setWidth(size1.width()/2);
        }
        let fontsize = (nBoardShape == PCD.BSHAPE_TYPE.SQUARE)? size1.height() * 0.96 : size1.height() * 0.55;
        fontsize = fontsize*2/(strFile.length+1);
        image.font = `${parseInt(fontsize)}px Arial`;
        image.fillStyle = PCD.cr[nSymbolColorIdx];
        image.textBaseline = "top";
        image.fillText(strFile, 0, 0);
      } else if (nIconGroup == PCD.CELL_TYPE.COLOR && (nBoardShape == PCD.BSHAPE_TYPE.VER_TRIALGLE || nBoardShape == PCD.BSHAPE_TYPE.HOR_TRIALGLE)) {
        nIconIndex = PCBoard.getval(nIconIndex, 0, PCD.cr.length-1);
        image.fillStyle = PCD.cr[nIconIndex];
        let pt = [0, 0, 0];
        if(nBoardShape == PCD.BSHAPE_TYPE.VER_TRIALGLE) {
          pt[0] = new PBC.CPoint(size1.width()/2, ((nBoardShapeIdx == 0)? 0 : size1.height()));
          pt[1] = new PBC.CPoint(0, ((nBoardShapeIdx == 0)? size1.height() : 0));
          pt[2] = new PBC.CPoint(size1.width(), ((nBoardShapeIdx == 0)? size1.height() : 0));
        } else if(nBoardShape == PCD.BSHAPE_TYPE.HOR_TRIALGLE) {
          pt[0] = new PBC.CPoint(((nBoardShapeIdx == 0)? 0 : size1.width()), size1.height()/2);
          pt[1] = new PBC.CPoint(((nBoardShapeIdx == 0)? size1.width() : 0), 0);
          pt[2] = new PBC.CPoint(((nBoardShapeIdx == 0)? size1.width() : 0), size1.height());
        }
        image.beginPath();
        image.moveTo(pt[0].x, pt[0].y);
        image.lineTo(pt[1].x, pt[1].y);
        image.lineTo(pt[2].x, pt[2].y);
        image.closePath();
      } else if (nIconGroup == PCD.CELL_TYPE.STICK) {
        image.strokeStyle = PCD.cr[6];
        image.lineWidth = STICK_WIDTH;
        if(nBoardShape == PCD.BSHAPE_TYPE.SQUARE) {
          switch (nIconIndex) {
          case 1:  image.moveTo(0, STICK_WIDTH); image.lineTo(size1.width(), STICK_WIDTH); break;
          case 2:  image.moveTo(STICK_WIDTH, 0); image.lineTo(STICK_WIDTH, size1.height()); break;
          case 3:  image.moveTo(0, 0); image.lineTo(size1.width(), size1.height()); break;
          case 4:  image.moveTo(size1.width(), 0); image.lineTo(0, size1.height()); break;
          }
        } else if(nBoardShape == PCD.BSHAPE_TYPE.VER_TRIALGLE) {
          switch (nIconIndex) {
          case 1:  image.moveTo(0, STICK_WIDTH/2); image.lineTo(size1.width(), STICK_WIDTH/2); break;
          case 2:  image.moveTo(size1.width()/2, size1.height()); image.lineTo(size1.width(), 0); break;
          case 3:  image.moveTo(0, 0); image.lineTo(size1.width()/2, size1.height()); break;
          }
        } else if(nBoardShape == PCD.BSHAPE_TYPE.HOR_TRIALGLE) {
          switch (nIconIndex) {
          case 1:  image.moveTo(STICK_WIDTH/2, 0); image.lineTo(STICK_WIDTH/2, size1.height()); break;  // |
          case 2:  image.moveTo(0, size1.height()); image.lineTo(size1.width(), size1.height()/2); break; // /
          case 3:  image.moveTo(0, 0); image.lineTo(size1.width(), size1.height()/2); break;         // \ //*/
          }
        }
        image.stroke();
      } else {
        // if (!!strFile) {
          // let img = document.getElementById('cell_' + `${nIconGroup}_${nIconIndex}`);
          var img;
          if (nIconGroup == PCD.CELL_TYPE.PICTURE) {
            img = document.getElementById("picture_"+ `${nIconGroup}_${nIconIndex}`);
          } else img = document.getElementById('cell_' + `${nIconGroup}_${nIconIndex}`);
          if (!img){
            return;
          }
          image.drawImage(img, 0, 0, size1.width(), size1.height());
        // }
      }
    }
  }

  const handleComplete = () => {
    props.onCompleteSolve();
  }
  const handleExtraClick = index => {
    setCurExtraIndex(index);
    props.set_cur_extra_index(index);
  };
  const handleChangeExtraSelect = event => {
    setCurExtraIndex(event.target.value);
    props.set_cur_extra_index(event.target.value);
  };
  const handleChangeExtraCheck = index => {
    extra_indices[index] = !extra_indices[index];
    let indices = [].concat(extra_indices);
    setExtraIndices(indices);
    props.set_extra_indices(extra_indices);
  };

  const { prob_type, prob_comment, array_extra_data,  } = props;
  return (
    <div>
      <div  className={classes.board}>
        <PuzzleBoard width="52" height="94"/>
      </div>
      <div className={classes.difficulty}>
        <div className={classes.text}>
          <Rater total={5} rating={3} interactive={false} style={{fontSize:'2rem', display:'block'}}/>
        </div>
      </div>
      <div className={classes.description}>
        <span className={classes.text}>
          {"[" + prob_type + "] " + prob_comment}
        </span>
      </div>
      <div id = "options" className={classes.options}>
      {
        (extra_type == 0 || extra_type == 3 ) && (
          <div>
          {
            array_extra_data.map((data, i) => {
              return (
                <Button style={{margin: '5px', width: 64, height: 64, backgroundColor: cur_extra_index==i?'rgba(128,128,200,0.5)':'rgba(200,200,200,0.1'}} variant="outlined" onClick={handleExtraClick.bind(this, i)} ><canvas id={`BtnImg_${i}`}/></Button>
              );
            })
          }
          </div>          
        )
      }
      {
        extra_type == 1 && (
          <FormControl component="fieldset">
            <RadioGroup row value={"" + cur_extra_index} onChange={handleChangeExtraSelect}>
            {
              array_extra_data.map((data, i) => (
                <FormControlLabel value={"" + i} control={<Radio color={'primary'}/>} label={data.s_data}/>
              ))
            }
            </RadioGroup>
          </FormControl>
        )
      }
      {
        extra_type == 2 && (
          <div>
          {
            array_extra_data.map((data, i) => (
              <FormControlLabel control={<Checkbox color={'primary'} checked={extra_indices[i]} onChange={handleChangeExtraCheck.bind(this, i)}/>} label={data.s_data}/>
            ))
          }
          </div>
        )
      }
      </div>
      <div className={classes.completed} style = {{display: props.btnDisplay ? "block" : 'none'}}>
        <span className={classes.text}>
          <Button style = {{boxShadow: "none", backgroundColor: "rgba(0, 0, 0, 0.5)"}} onClick = {handleComplete} disabled = {btn_disabled}>
            <i className = "fa fa-check" style = {{fontSize: '2.5rem', color: btn_disabled ? 'rgb(150, 150, 150)' : 'rgb(0, 240, 0)'}}><span style = {{color: btn_disabled ? 'rgb(150, 150, 150)' : 'white', fontSize: '1.5rem', fontFamily: 'cursive'}}>Complete</span></i>
          </Button>
        </span>
      </div>
      <PPAction />
    </div>
  )
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  prob_type: store.puzzleProblemReducer.problem.prob_type,
  prob_comment: store.puzzleProblemReducer.problem.prob_comment,
  solution_type: store.puzzleProblemReducer.problem.solution_type,
  array_extra_data: store.puzzleProblemReducer.problem.array_extra_data,
  curExtraIndex: store.puzzleProblemReducer.cur_extra_index,
  extraIndices: store.puzzleProblemReducer.extra_indices,
  completeSolve: store.puzzleProblemReducer.complete_solve,
  room_type: store.roomReducer.room.room_type,

  move_history: store.roomReducer.room.move_history,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    onCompleteSolve: PuzzleProblemAction.on_complete_solve,
    set_cur_extra_index: PuzzleProblemAction.set_cur_extra_index,
    set_extra_indices: PuzzleProblemAction.set_extra_indices,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(PuzzleProblem);

