import React, {useState, useEffect, useRef} from "react";
import { connect } from "react-redux";
import { Redirect, withRouter } from "react-router-dom";
import {bindActionCreators} from "redux";

import {
  BottomNavigation,
  BottomNavigationAction,
  Button,
} from '@material-ui/core';

import {
  MDBBtn,
  MDBRow,
  MDBCol,
} from "mdbreact";

import { makeStyles } from '@material-ui/core/styles';
import * as GoAction from "../../store/actions/go.action";
import * as GoBoardAction from "../../store/actions/go_board.action";
import * as ArticleAction from "../../store/actions/article.action";
import Board from "../go/board";
import * as GoLogic from "../go/logic";
import {notify_w} from "../../helper/alert";

const useStyles = makeStyles(theme => ({
  container: {
    width: '100%',
    minHeight: '80vh',
    paddingTop: '2vh',
    paddingLeft: '4vw',
  },
  buttonStyle: {
    width: '80px'
  },
  root: {
    width: '16vw',
  },
  BottomNavigationActionStyle1: {
    minWidth:'40px',
    width:'40px',
    padding:'0px',
    height:'80px',
    border:'1px solid rgb(25, 118, 208)',
    borderRadius: '5px 0px 0px 5px',
  },
  BottomNavigationActionStyle2: {
    minWidth:'40px',
    width:'40px',
    padding:'0px',
    height:'80px',
    border:'1px solid rgb(25, 118, 208)',
    borderLeft:'none',
  },
  BottomNavigationActionStyle3: {
    minWidth:'40px',
    width:'40px',
    padding:'0px',
    height:'80px',
    border:'1px solid rgb(25, 118, 208)',
    borderLeft:'none',
    borderRadius: '0px 5px 5px 0px',
  },
  navigationButtons: {
    paddingTop: '5vh',
    width: '18vw',
    height: '8vh',
    background: '#ffffff',
    fontSize: '2.5vh',
  },
  navigationButton1: {
    minWidth:'3vw',
    width:'3vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    color: "#404040",
  },
  navigationButton: {
    minWidth:'3vw',
    width:'3vw',
    border:'1px solid rgb(64, 64, 64)',
    borderRadius: '0vw',
    borderLeft: 'none',
    color: "#404040",
  },
}));

var EBoardMode = {
  Move: 0,
  CountScores: 1,
  ScoreEstimate: 2,
  AddOrRemove: 3,
  AddMarkTr: 4,
  AddMarkSq: 5,
  AddMarkCr: 6,
  AddMarkX: 7,
  AddMarkTx: 8,
  AddMarkNum: 9,
  ViewPort: 10,
  ClearBoard: 11,
  Answer: 12,
};

var EDrawingMark = {
  Lm: -1,
  Tr: 0, 
  Sq: 1, 
  Cr: 2, 
  Tx: 3, 
  X: 4,
  Tb: 5, 
  Tw: 6, 
  Tb2: 7,
  Tw2: 8 
};


//////////////////
if ( window.CKEDITOR.env.ie && window.CKEDITOR.env.version < 9 )
	window.CKEDITOR.tools.enableHtml5Elements( document );

// The trick to keep the editor in the sample quite small
// unless user specified own height.
window.CKEDITOR.config.height = 150;
window.CKEDITOR.config.width = 'auto';
//////////////////

function Forum_compose(props) {
  const classes = useStyles();

  const [title, setTitle] = useState("");
  const [board_list, setBoardList] = useState([]);

  const board_list_ref = useRef();

  const [mode, setMode] = React.useState(4);

  useEffect(() => {
    board_list_ref.current = board_list;
  }, [board_list]);
  
  var initSample = ( function() {
    var wysiwygareaAvailable = isWysiwygareaAvailable(),
      isBBCodeBuiltIn = !!window.CKEDITOR.plugins.get( 'bbcode' );
  
    return function() {
      var editorElement = window.CKEDITOR.document.getById( 'editor' );
      var editor;
      // :(((
      if ( isBBCodeBuiltIn ) {
        editorElement.setHtml(
          'Hello world!\n\n' +
          'I\'m an instance of [url=http://ckeditor.com]CKEditor[/url].'
        );
      }
      var toolbarGroups = [
        { name: 'basicstyles', groups: [ 'basicstyles', 'cleanup' ] },
        { name: 'paragraph',   groups: [ 'list', 'indent', 'blocks', 'align', 'bidi' ] },
        { name: 'links', groups: [ 'links' ] },
        { name: 'styles', groups: [ 'styles' ] },
        { name: 'document',	   groups: [ 'mode', 'document', 'doctools' ] },
        { name: 'others', groups: [ 'others' ] },
        '/',
        { name: 'boards', groups: ['new_board', 'delete_board']},
      ];
  
      // Depending on the wysiwygare plugin availability initialize classic or inline editor.
      if ( wysiwygareaAvailable ) {
        editor = window.CKEDITOR.replace( 'editor', {
          toolbarGroups,
          // allowedContent: true,
          extraAllowedContent: 'div(*)'
        });
      } else {
        editorElement.setAttribute( 'contenteditable', 'true' );
        editor = window.CKEDITOR.inline( 'editor' );
  
        // TODO we can consider displaying some info box that
        // without wysiwygarea the classic editor may not work.
      }
      editor.addCommand('new_board',
      {
        modes: { wysiwyg: 1, source: 1 },
        exec: function (editor) { // Add here custom function for the save button
          var array = [];
          if (board_list_ref.current.length < 2) {
            board_list_ref.current.map((board) => array.push(board));
            array.push({});
            if (board_list_ref.current.length === 0)
              GoLogic.theLogicBoard.initialize();
            if (board_list_ref.current.length === 1)
              GoLogic.theLogicBoard2.initialize();

            setBoardList(array);
          }
          props.change_room_type("forum_compose");
        }
      });
      editor.addCommand('delete_board',
      {
        modes: { wysiwyg: 1, source: 1 },
        exec: function (editor) { 
          var array = [];
          if (board_list_ref.current.length > 0) {
            board_list_ref.current.map((board) => array.push(board));
            array.pop();
          }
          setBoardList(array);
        }
      });
      editor.ui.addButton('new_board', { label: 'new_board', command: 'new_board', icon: '/assets/img/edit_board.png' });
      editor.ui.addButton('delete_board', { label: 'delete_board', command: 'delete_board', icon: '/assets/img/delete_board.png' });
    };
  
    function isWysiwygareaAvailable() {
      // If in development mode, then the wysiwygarea must be available.
      // Split REV into two strings so builder does not replace it :D.
      if ( window.CKEDITOR.revision == ( '%RE' + 'V%' ) ) {
        return true;
      }
  
      return !!window.CKEDITOR.plugins.get( 'wysiwygarea' );
    }
  } )();
  
  useEffect(() => {
    initSample();
    const {edit_article} = props;
    if (edit_article.reply_to_article_id !== '')
      setTitle('RE: ' + edit_article.reply_to_article_title);
  }, []);

  console.log(props.edit_article)

  const handleArticleTitleChange = (event) => {
    setTitle(event.target.value);
  };

  const postArticle = () => {
    const { user, edit_article, submitArticle, replyArticle, viewport, marks, marks2, history } = props;
    let content = window.CKEDITOR.instances.editor.getData();
    if (!user) {
      notify_w("Login is required");
      return;
    }
    if (title == "" || content == ""){
      notify_w("Please enter all information");
      return;
    }
    if (board_list.length > 0) {
      board_list[0].board_str = GoLogic.theLogicBoard.getboardstr(0, 0, 18, 18);
      board_list[0].viewport = viewport;
      board_list[0].marks = [];
      marks.map((mark) => board_list[0].marks.push({mark_x: mark.x, mark_y: mark.y, mark_type: mark.type, mark_text: mark.text}));
    }
    if (board_list.length > 1) {
      board_list[1].board_str = GoLogic.theLogicBoard2.getboardstr(0, 0, 18, 18);
      board_list[1].viewport = viewport;
      board_list[1].marks = [];
      marks2.map((mark) => board_list[1].marks.push({mark_x: mark.x, mark_y: mark.y, mark_type: mark.type, mark_text: mark.text}));
    }
    if (edit_article.reply_to_article_id !== '') {
      replyArticle(edit_article.reply_to_article_id, {title, content, boards: board_list});
    }
    else {
      submitArticle({title, content, author_id: user.user_id, boards: board_list});
    }
    history.push('/forum');
  };

  const discardArticle = () => {
    props.history.push('/forum');
  };
  
  const handleEditModeChange = (mode) => {
    setMode(mode);
    var edit_mode;
    switch(mode) {
      case 0:
        edit_mode = EBoardMode.ViewPort;
        break;
      case 1:
        edit_mode = EBoardMode.AddOrRemove;
        break;
      case 2:
        edit_mode = EBoardMode.AddMarkTr;
        break;
      case 3:
        edit_mode = EBoardMode.AddMarkTx;
        break;
      case 4:
        edit_mode = EBoardMode.Move;
        break;
      default:
        break;
    }
    props.update_edit_mode(edit_mode);
  };

  const clearBoard = (what) => {
    const {remove_all_marks} = props;
    if (what === 1) {
      GoLogic.theLogicBoard.initboard(GoLogic.RULE_CHINESE, GoLogic.MX_BOARD_SIZE, 0);
      GoLogic.theLogicBoard.setgrcounter(0);
      remove_all_marks(1);
    } else {
      GoLogic.theLogicBoard2.initboard(GoLogic.RULE_CHINESE, GoLogic.MX_BOARD_SIZE, 0);
      GoLogic.theLogicBoard2.setgrcounter(0);
      remove_all_marks(2);
    }
  };

  const {edit_article} = props;
  return (
    <React.Fragment>
      <div style = {props.open_other ? {position: 'fixed', top: '16vh', height: '75vh', width: '85.5vw', overflow: 'scrollY'} : {}}>
        <MDBRow className={classes.container}>
          <MDBCol size="11">
            <MDBRow className="pt-2 pb-2">
              <MDBCol size = '6'>
                <h4><strong>{window.i18n.t("forum.new_post")}</strong></h4>
              </MDBCol>
              <MDBCol>
                <MDBBtn color="default" className={classes.buttonStyle +" float-right py-2 px-2"} onClick={discardArticle}>
                  <i className="fa fa-remove" style={{ color: "white"}} /> {window.i18n.t("forum.discard")}
                </MDBBtn>
                <MDBBtn color="success" className={classes.buttonStyle + " float-right py-2 px-2"} onClick={postArticle}>
                  <i className="fa fa-cloud-upload" style={{ color: "white"}} /> {window.i18n.t("forum.post")}
                </MDBBtn>
              </MDBCol>
            </MDBRow>
            <MDBRow className="pt-2 pb-2">
              <MDBCol size="1" className="pt-2">
                <h5><strong>Title</strong></h5>
              </MDBCol>
              <MDBCol>
                <input type="text" name="title" value={title} onChange={handleArticleTitleChange} className="form-control form-control-sm" style={{border:'none', borderBottom:'1px solid rgb(204, 204, 204)',padding:'0px'}} placeholder="title" />
              </MDBCol>
            </MDBRow>
            <MDBRow className="pt-2 pb-2">
              <MDBCol>
                <div id="editor" style={{border: '1px solid rgb(204, 204, 204)'}}>
                </div>
              </MDBCol>
            </MDBRow>
            <MDBRow className="pt-2 pb-2">
              { board_list.length > 0 && (
                <MDBCol>
                  <Board boardId = {1} readOnly = {false} putAble = {true} board_str = {board_list[0]} last_move = {0} width={15} height={100}/>
                </MDBCol>
              )}
              { board_list.length > 0 && (
                <MDBCol>
                  <MDBRow>
                    <BottomNavigation
                      value={mode}
                      onChange={(event, newMode) => {
                        handleEditModeChange(newMode);
                      }}
                      showLabels
                      className={classes.root}
                    >
                      <BottomNavigationAction label="Viewport" icon={<i className="fa fa-crop fa-2x pb-2" />} className={classes.BottomNavigationActionStyle1} style={{padding:'0px'}}/>
                      <BottomNavigationAction label="Stone" icon={<i className="fa fa-plus-circle fa-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                      <BottomNavigationAction label="Symbol" icon={<i className="la la-exclamation-triangle la-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                      <BottomNavigationAction label="Alphabet" icon={<i className="fa fa-font fa-2x pb-2" />} className={classes.BottomNavigationActionStyle2} style={{padding:'0px'}} />
                      <BottomNavigationAction label="History" icon={<i className="fa fa-arrow-circle-down fa-2x pb-2" />} className={classes.BottomNavigationActionStyle3} style={{padding:'0px'}} />
                    </BottomNavigation>
                  </MDBRow>
                  <MDBRow className={classes.navigationButtons}>
                    <Button className={classes.navigationButton1} disabled={false} style={{padding:'0px', fontSize: 'inherit'}}  onClick={clearBoard.bind(this, 1)}><i className="fa fa-trash"/>{board_list.length > 1? "1" : ""}</Button>
                    { board_list.length > 1 && (
                      <Button className={classes.navigationButton} disabled={false} style={{padding:'0px', fontSize: 'inherit'}}  onClick={clearBoard.bind(this, 2)}><i className="fa fa-trash"/>2</Button>
                    )}
                  </MDBRow>
                </MDBCol>
              )}
              { board_list.length > 1 && (
                <MDBCol>
                  <Board boardId = {2} readOnly = {false} lboard2 = {true} putAble = {true} board_str = {board_list[1]} last_move = {0} width={15} height={100}/>
                </MDBCol>
              )}
            </MDBRow>
            <MDBRow className="pt-2 pb-1">
            </MDBRow>
          </MDBCol>
        </MDBRow>
      </div>
    </React.Fragment>
  );
}

const mapStateToProps = (store) => ({
  user: store.authReducer.user,
  edit_article: store.articleReducer.edit_article,
  viewport: store.goReducer.viewport,
  marks: store.goReducer.marks,
  marks2: store.goReducer.marks2,
  open_other: store.commonReducer.content > 2,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {    
    submitArticle: ArticleAction.submitArticle,
    replyArticle: ArticleAction.replyArticle,
    req_article: ArticleAction.req_article,
    change_room_type: GoAction.change_room_type,
    update_edit_mode: GoBoardAction.update_edit_mode,
    remove_all_marks: GoBoardAction.remove_all_marks,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Forum_compose));
