import React, {useEffect} from 'react';
import { connect } from "react-redux";
import {bindActionCreators} from "redux";
import { makeStyles } from '@material-ui/core/styles';
import {
  MDBContainer,
  MDBDataTable,
  MDBRow,
  MDBCol,
} from "mdbreact";
import { Redirect, withRouter } from 'react-router-dom';
import { Link, Button } from '@material-ui/core';
import * as TournamentAction from "../../store/actions/tournament.action";
import * as CommonAction from "../../store/actions/common.action";

const useStyles = makeStyles(theme => ({
  avatarImg: {
    height: '4vh',
    width: '4vh',
    float: 'left',
    paddingRight: '1vh',
  },
}));

function Tournament(props) {
  const classes = useStyles();
  useEffect(() => {
    var id = document.URL.slice(document.URL.lastIndexOf(':') + 1);
    props.req_tournament(props.game_type, id);
    props.saveTournamentId(props.game_type, id);
  }, []);

  function handleExit(){
    props.history.push("/tournaments")
  }

  const { tournament } = props;

  var columns = [];
  var rows = [];
  
  const reloadGoTournamentData = (tournament) => {
    columns.push({ label: window.i18n.t("tournament.no"), field: "no", sort: "disabled", width: 60 });
    columns.push({ label: window.i18n.t("tournament.participant"), field: "participant", sort: "disabled", width: 180 });
    for (var i = 0; i < tournament.schedule.round_start.length; i ++) {
      columns.push({ label: i + 1, field: "rnd_" + (i + 1), sort: "disabled", width: 60 });
    }
    columns.push({ label: window.i18n.t("tournament.wins"), field: "wins", sort: "disabled", width: 70 });
    columns.push({ label: "SDS", field: "sds", sort: "disabled", width: 60 });
    columns.push({ label: "SUO", field: "suo", sort: "disabled", width: 60 });
    columns.push({ label: window.i18n.t("tournament.rank"), field: "rank", sort: "disabled", width: 60 });

    const participant = (p) => (
      <div>
        <img alt="avatar" className={classes.avatarImg} src={p.avatar} />
        <h6 className="dark-grey-text mb-0">{p.user_id + " (Lv" + p.level + ")"}</h6>
      </div>
    );

    tournament.participants.map((p, i) => {
      var row = {};
      row.no = i + 1;
      row.participant = participant(p);
      p.round_game.map((g, j) => {
        var gr;
        if(g.win == 1)  //win
          gr = "+";
        else if(g.win == 2) //lose
          gr = "-";
        else              //no finished
          gr = "";
        
        if (g.color == 1)   //black
          gr += "B";
        else if (g.color == 2)  //white
          gr += "W";
        
        if (g.opponent_num > 0)
          gr += g.opponent_num;
        row["rnd_"+(j+1)] = <Link onClick={() => handleOpenGame(g.game_id)}>{gr}</Link>;
      });
      row.wins = p.wins;
      row.sds = p.sds;
      row.suo = p.suo;
      row.rank = p.rank;
      rows.push(row);
    });
  }
  
  const handleOpenGame = (game_id) => {
    const {history} = props;
    history.push('/go_record:'+game_id);
    // props.showHiddenSideBar("0px",false );
  }

  const prize_element = (p, i) => {
    var color = (i == 0)? '#ffe346' : (i == 1)? 'silver' : '#ff8c46';
    var medal = (i == 0)? 'fa fa-trophy' : 'la la-certificate';
    return (
      <MDBRow className="py-3">
        <MDBCol md="1" style={{fontSize:'2rem'}}>
          <i className={medal} style={{float: 'right', color: color}} />
        </MDBCol>
        <MDBCol>
          <img alt="avatar" className={classes.avatarImg} src={p.avatar} />
          <h6 className="text-left dark-grey-text mb-0">{p.user_id + " "} Lv{p.level}</h6>
        </MDBCol>
      </MDBRow>
    )
  };

  reloadGoTournamentData(tournament);

  return (
    <div style={{backgroundColor: "#f9f9fc", left:`${0}px`, top: `${0}px`, zIndex:"1112", width: "100vw", height: "100vh", overflow: 'scrollY'}}> 
    
      <MDBRow className="md-12 mx-5 py-3">
        <MDBCol size = "10">
          <h3 className="font-weight-bold dark-grey-text mt-4 pb-3" style = {{textAlign: "center"}}>
          { tournament.title }
          </h3>
        </MDBCol>
        <MDBCol className = "mt-4 pb-3">
          <Button style = {{boxShadow: "none", backgroundColor: "rbga(0, 0, 0, 0)"}} onClick = {handleExit}>
            <i className = "fa fa-reply font-weight-bold dark-grey-text" style = {{fontSize: '2rem'}}/>
          </Button>
        </MDBCol>
      </MDBRow>
      <MDBRow className="md-12 mx-5 py-3">
        <MDBCol>
          <h5 className="font-weight-bold dark-grey-text pb-3">
          {window.i18n.t("tournament.information")}
          </h5>
          <h6 className="dark-grey-text pt-1 pb-3">
          { tournament.information }
          </h6>
          <h5 className="font-weight-bold dark-grey-text pb-3">
          {window.i18n.t("tournament.date")} {new Date(tournament.start_date).toLocaleDateString()} - {new Date(tournament.end_date).toLocaleDateString()}
          </h5>
          <h5 className="font-weight-bold dark-grey-text pb-1">
          {window.i18n.t("tournament.result")}
          </h5>
          {
            tournament.prize.map((p, i) => prize_element(p, i))
          }
        </MDBCol>
      </MDBRow>
      <MDBRow className="md-12 mx-5 pl-3 py-3">
        <MDBCol>
          <MDBRow>
            <h5 className="font-weight-bold dark-grey-text pb-3">
              {window.i18n.t("tournament.participants_games")}
            </h5>
          </MDBRow>
          <MDBRow className = "float-left ml-2 pl-5">
            <MDBDataTable hover  autoWidth style = {{lineHeight: 1}} theadColor = {'cyan lighten-3'} searching={false} paging={false} small={false} scrollX scrollY maxHeight="70vh" data={{columns: columns, rows: rows}} />
          </MDBRow>
        </MDBCol>
      </MDBRow>
    </div>
  );
}

const mapStateToProps = (store) => ({
  cd: store.goReducer.cd,
  tournament: store.tournamentReducer.go_tournament,
  game_type: store.commonReducer.content,
});

const mapDispatchToProps = (dispatch) => bindActionCreators(
  {
    saveTournamentId: TournamentAction.saveTournamentId,
    req_tournament: TournamentAction.req_tournament,
    showHiddenSideBar:CommonAction.show_hidden_sidebar,
  },
  dispatch,
);

export default connect(mapStateToProps, mapDispatchToProps)(withRouter(Tournament));
