import ACTION from '../actionTypes';

export const update_game_result = ( result, player1_update_coin, player2_update_coin, player3_update_coin = 0, player4_update_coin = 0) => dispatch => { 
  dispatch({
    type: ACTION.UPDATE_GAME_RESULT,
    result,
  });
  dispatch({
    type: ACTION.UPDATE_COIN_RESULT,
    player1_update_coin:player1_update_coin,
    player2_update_coin:player2_update_coin,
    player3_update_coin:player3_update_coin,
    player4_update_coin:player4_update_coin,
  });
}

export function remove_player(user_id) {
  return {
    type: ACTION.REMOVE_FFA_PLAYER,
    user_id
  }
}

export function update_last_move(last_move) {
  return {
    type: ACTION.UPDATE_LAST_MOVE,
    last_move,
  }
}

export function update_last_turn(last_turn) {
  return {
    type: ACTION.UPDATE_LAST_TURN,
    last_turn,
  }
}

export function set_game_kind(game_kind) {
  return {
    type: ACTION.SET_FFA_GAME_KIND,
    game_kind,
  }
}

export function set_open_multiple_dlg(open) {
  return {
    type: ACTION.SET_OPEN_MULTIPLE_DLG,
    open,
  }
}

export function update_ffa_user_count(count) { 
  return {
    type: ACTION.UPDATE_FFA_USER_COUNT,
    count   
  }
}

export function set_last_multiplier(multiplier) { 
  return {
    type: ACTION.SET_LAST_MULTIPLIER,
    multiplier:multiplier,
  }
}