export const RULE_JAPANESE = 0;
export const RULE_CHINESE = 1;
export const RULE_SJ = 2;

export const MX_BOARD_SIZE = 19;
export const BOARD_LEN = MX_BOARD_SIZE * MX_BOARD_SIZE;

export const OK = 0;
export const PASS = 1;
export const ATARI = 2;
export const GAME_OVER = 3;
export const PROHIBIT = -1;
export const COUNT_OVER = -2;
export const OUTBOARD = -3;
export const PRE_STONE = -4;
export const KP_POS = -5;
export const GRC_OVER = -6;

export const EMPTY = 0;
export const BLACK = 1;
export const WHITE = 2;

export const PASS_MOVE = 0x2020;
export const THROW_MOVE = 0x2121;


const MX_HISTORY_COUNT = 3000;
const MX_GR_COUNT = 500;

const HISTORY_MARK = 0xEEEE;

export function OPPTURN(color) { return BLACK + WHITE - color; }

export function XPOS(wpos) { return wpos & 0xff; }
export function YPOS(wpos) { return (wpos >> 8) & 0xff; }
export function WPOS(x, y) { return (x & 0xff) | ((y & 0xff) << 8); }
export function APOS(x, y) { return y * MX_BOARD_SIZE + x; }
export function WPOS2APOS(wpos) {
    let x = XPOS(wpos), y = YPOS(wpos);
    return APOS(x, y);
}

const SJ_IBS = [ [ 3, 9 ], [ 3, 15 ], [ 6, 3 ], [ 6, 15 ], [ 12, 3 ], [ 12, 15 ], [ 15, 3 ], [ 15, 9 ] ];
const SJ_IWS = [ [ 3, 3 ], [ 3, 6 ], [ 3, 12 ], [ 9, 3 ], [ 9, 15 ], [ 15, 6 ], [ 15, 12 ], [ 15, 15 ] ];
// const SJ_KPMI = [ 5.5, 0.0, -10.5, -20.5, -30.5, -40.5, -50.5, -60.5, -70.5, -80.5];
const SJ_HANDICAP_POS = [[9, 9], [12, 6], [6, 12], [12, 12], [6, 6], [9, 12], [9, 6], [12, 9], [6, 9]];
const HANDICAP_POS = [
    [[3, 15], [15, 3], [3, 3], [15, 15], [3, 9], [15, 9], [9, 3], [9, 15], [9, 9], [16, 2]],  // 19 x 19
    [[3, 13], [13, 3], [3, 3], [13, 13], [3, 8], [13, 8], [8, 3], [8, 13], [8, 8], [14, 2]],  //17 x 17
    [[3, 11], [11, 3], [3, 3], [11, 11], [3, 7], [11, 7], [7, 3], [7, 11], [7, 7], [12, 2]],  //15 x 15
    [[3, 9], [9, 3], [3, 3], [9, 9], [3, 6], [9, 6], [6, 3], [6, 9], [6, 6], [10, 2]],  // 13 x 13
    [[3, 7], [7, 3], [3, 3], [7, 7], [3, 5], [7, 5], [5, 3], [5, 7], [5, 5], [8, 2]],  // 11 x 11
    [[2, 6], [6, 2], [2, 2], [6, 6], [2, 4], [6, 4], [4, 2], [4, 6], [4, 4], [7, 1]]  // 9 x 9
];

function MOVE() {
    this.pos = 0;
    this.color = EMPTY;
}

class LogicBoard {
    constructor () {
        this.initialize(RULE_JAPANESE, MX_BOARD_SIZE);
    }
    initialize(rule = RULE_JAPANESE, boardsize = MX_BOARD_SIZE, handicap = 0, kpmi = 6.5) {
        this.board = [];
        this.history = [];
        this.moves = [];
        this.numboard = [];

        this.rule = rule;
        this.boardsize = (rule !== RULE_SJ) ? boardsize : 19;
        this.handicap = handicap;
        this.kpmi = kpmi;
        for (let i = 0; i < BOARD_LEN; i ++) {
            this.board.push(EMPTY);
            this.numboard.push(0);
        }
        for (let i = 0; i < MX_HISTORY_COUNT; i ++) {
            this.history[i] = HISTORY_MARK;
        }
        this.historyidx = 0;
        for (let i = 0; i < MX_GR_COUNT; i ++) {
            this.moves[i] = new MOVE();
        }
        this.grcounter = 0;
        this.gridx = 0;
        this.taken_white = 0;
        this.taken_black = 0;

        this.initboard(this.rule, this.boardsize, this.handicap);

        if (this.rule !== RULE_SJ)
            this.first = (this.handicap < 2) ? BLACK : WHITE;
        else
            this.first = (this.handicap < 1) ? BLACK : WHITE;
        this.turn = this.first;
    }
    setturn(color) {
        this.turn = color;
        if (this.gridx === 0)
            this.first = this.turn;
    }
    getturn() { return this.turn; }
    getstate(x, y) { return this.board[APOS(x,y)]; }
    getboard() { return this.board; }
    getboardstr(x0, y0, x1, y1) {
        var board_str = "";
        for (var y = y0; y <= y1; y ++) {
            for(var x = x0; x <= x1; x ++) {
                var pos = APOS(x, y);
                if (this.board[pos] === BLACK)
                    board_str += "b";
                else if (this.board[pos] === WHITE)
                    board_str += "w";
                else // (this.board[pos] === EMPTY)
                    board_str += "e";
            }
        }
        return board_str;
    }
    getstones(x0, y0, x1, y1) {
        var black_stones = [];
        var white_stones = [];
        for (var x = x0; x <= x1; x ++)
            for (var y = y0; y <= y1; y ++) {
                if (this.board[APOS(x, y)] === BLACK)
                    black_stones.push(WPOS(x, y));
                else if (this.board[APOS(x, y)] === WHITE)
                    white_stones.push(WPOS(x, y));
            }
        return { black_stones: black_stones, white_stones: white_stones };
    }
    getnumboard() { return this.numboard; }
    setboard(board) { this.board = board; }
    checkstone(wpos) {
        let ret = this.domove(wpos, this.turn);
        if (ret < 0)
            return false;
        this.undo();
        return true;
    }
    domove(wpos, color, h_index) {
        if (this.grcounter > MX_GR_COUNT)
            return GRC_OVER;
        let ret = this.putstone(wpos, color, h_index);
        if ((ret === OK) || (ret === ATARI) || (ret === PASS)) {
            this.grcounter = this.gridx;
            this.addgrmove(wpos, color);
            this.gridx = this.grcounter;
        }
        return ret;
    }
    set_edit_stone(x, y, color) {
        this.board[APOS(x, y)] = color;
    }
    undo() {
        this.goto_plus(-1);
        this.grcounter --;
        this.gridx = this.grcounter;
    }
    goto_idx_undo(idx) {
        while(this.grcounter > idx) {
            this.undo();
        }
    }
    goto_idx(idx) {
        if (idx < 0)
            idx = 0;
        if (idx > this.grcounter)
            idx = this.grcounter;
        if (idx === this.gridx)
            return this.gridx;

        if (idx < this.gridx) {
            while (idx !== this.gridx) {
                this.backstone();
                this.gridx --;
            }
        } else {
            while (idx !== this.gridx) {
                let move = this.moves[this.gridx];
                this.putstone(move.pos, move.color);
                this.gridx ++;
            }
        }
        this.turn = (this.gridx === 0) ? this.first : 3 - this.moves[this.gridx - 1].color;
        return this.gridx;
    }
    goto_plus(delta) {
        return this.goto_idx(this.gridx + delta);
    }
    getgridx() { return this.gridx; }
    getgrcounter() { return this.grcounter; }
    setgrcounter(grcounter) {
        this.goto_idx(grcounter);
        this.grcounter = grcounter;
    }
    addgrmove(wpos, color) {
        if (this.grcounter >= MX_GR_COUNT)
            return false;
        this.moves[this.grcounter].pos = wpos;
        this.moves[this.grcounter].color = color;
        this.grcounter ++;
        this.turn = 3 - color;
        return true;
    }
    getgrmove(idx) { return this.moves[idx]; }
    getcurmove() {
        var move = new MOVE();
        if (this.gridx < 1) {
            move.pos = -1;
            move.color = this.first;
            return move;
        }
        move.pos = this.moves[this.gridx - 1].pos;
        move.color = this.moves[this.gridx - 1].color;
        return move;
    }
    getlastmove() {
        return this.moves[this.grcounter - 1];
    }
    getfirstmove() {
        return this.moves[0];
    }
    getcurcolor() {
        if (this.gridx < 1)
            return this.first;
        return this.moves[this.gridx - 1].color;
    }
    gettakencount(color) {
        if (color === BLACK)
            return  this.taken_white;
        if (color === WHITE)
            return  this.taken_black;
        return  0;
    }
    getpasscount() {
        if (this.grcounter < 1)
            return  0;
        if (this.moves[this.grcounter - 1].pos !== PASS_MOVE)
            return  0;
        if (this.grcounter < 2)
            return  1;
        if (this.moves[this.grcounter - 2].pos !== PASS_MOVE)
            return  1;
        return  2;
    }
    getkppos() {
        for (let y = 0; y < this.boardsize; y ++) {
            for (let x = 0; x < this.boardsize; x ++) {
                if (this.capturedstones === 1 && this.teststonekp(x, y)) {
                    return  WPOS(x, y);
                }
            }
        }
        return  0xFFFF;
    }
    initboard(rule, boardsize, handicap) {
        let s, i, x, y;
        this.rule = rule;
        for (i = 0; i < BOARD_LEN; i ++) {
            this.board[i] = EMPTY;
        }
        if (this.rule === RULE_SJ) {
            for (i = 0; i < 8; i ++) {
                this.board[APOS(SJ_IBS[i][0], SJ_IBS[i][1])] = BLACK;
                this.board[APOS(SJ_IWS[i][0], SJ_IWS[i][1])] = WHITE;
            }
            if (handicap === 0)
                this.kpmi = 5.5;
            else {
                this.kpmi = 0;
                for (i = 0; i < handicap; i ++) {
                    this.board[APOS(SJ_HANDICAP_POS[i][0], SJ_HANDICAP_POS[i][1])] = BLACK;
                }
            }
            return;
        }

        if (handicap < 2)
            return;

        if ((handicap > 9) && (boardsize !== 19))
            handicap = 9;

        if (handicap <= 9) {
            s = Math.floor((19 - boardsize) / 2);
            if ((handicap === 5) || (handicap === 7)) {
                for (i = 0; i < handicap - 1; i ++) {
                    x = HANDICAP_POS[s][i][0];
                    y = HANDICAP_POS[s][i][1];
                    this.board[APOS(x, y)] = BLACK;
                }
                x = HANDICAP_POS[s][8][0];
                y = HANDICAP_POS[s][8][1];
                this.board[APOS(x, y)] = BLACK;
            } else {
                for (i = 0; i < handicap; i ++) {
                    x = HANDICAP_POS[s][i][0];
                    y = HANDICAP_POS[s][i][1];
                    this.board[APOS(x, y)] = BLACK;
                }
                if (handicap === 3) {
                    x = HANDICAP_POS[s][2][0];
                    y = HANDICAP_POS[s][2][1];
                    this.board[APOS(x, y)] = BLACK;

                    x = HANDICAP_POS[s][3][0];
                    y = HANDICAP_POS[s][3][1];
                    this.board[APOS(x, y)] = EMPTY;
                }
            }
        }
    }
    putstone(wpos, color, h_index) {
        if ((wpos === PASS_MOVE) || (wpos === THROW_MOVE)) {
            this.history[this.historyidx] = HISTORY_MARK;
            this.historyidx ++;
            this.history[this.historyidx] = wpos;
            this.historyidx ++;
            return PASS;
        }
        let x = XPOS(wpos);
        let y = YPOS(wpos);
        if ((x < 0) || (x >= MX_BOARD_SIZE) || (y < 0) || (y >= MX_BOARD_SIZE))
            return  OUTBOARD;
        // if (this.rule === RULE_SJ && this.grcounter === 0 && (x !== 9 || y !== 9))
        //     return  PROHIBIT;

        let ret = this.teststone(x, y, color);
        if ((ret === OK) || (ret === ATARI)) {
            this.history[this.historyidx] = HISTORY_MARK;
            this.historyidx ++;
            this.history[this.historyidx] = wpos;
            this.historyidx ++;

            this.finddeadstones(x, y, color);
        }
        if (!!h_index)
            this.numboard[APOS(x, y)] = h_index + 1;
        else
            this.numboard[APOS(x, y)] = this.gridx + 1;
        return  ret;
    }
    backstone() {
        if (this.grcounter < 1 || this.historyidx < 1)
            return  0;
        let curidx = this.historyidx;
        while (this.history[--this.historyidx] !== HISTORY_MARK)
            ;
        this.history[this.historyidx] = HISTORY_MARK;
        let wpos = this.history[this.historyidx + 1];
        if (wpos === PASS_MOVE || wpos === THROW_MOVE) {
            this.history[this.historyidx + 1] = HISTORY_MARK;
            return  1;
        }
        let x = XPOS(wpos);
        let y = YPOS(wpos);
        let color = this.board[APOS(x, y)];
        this.board[APOS(x, y)] = EMPTY;
        this.history[this.historyidx + 1] = HISTORY_MARK;

        for (let i = this.historyidx + 2; i < curidx; i ++) {
            wpos = this.history[i];
            this.history[i] = HISTORY_MARK;
            x = XPOS(wpos);
            y = YPOS(wpos);
            this.board[APOS(x, y)] = 3 - color;
            if (this.board[APOS(x, y)] === BLACK)
                this.taken_black --;
            else if (this.board[APOS(x, y)] === WHITE)
                this.taken_white --;
        }
        return  1;
    }
    finddeadstones(x, y, color) {
        color = 3 - color;
        if (y > 0 && this.board[APOS(x, y - 1)] === color)
            this.teststone2(x, y - 1);
        if (x > 0 && this.board[APOS(x - 1, y)] === color)
            this.teststone2(x - 1, y);
        if (y < this.boardsize - 1 && this.board[APOS(x, y + 1)] === color)
            this.teststone2(x, y + 1);
        if (x < this.boardsize - 1 && this.board[APOS(x + 1, y)] === color)
            this.teststone2(x + 1, y);
    }
    teststone(x, y, curstone) {
        let atari = false;
        let ret, test;
        this.capturedstones = 0;
        if (this.board[APOS(x, y)] !== EMPTY)
            return  PRE_STONE;
        this.board[APOS(x, y)] = curstone;
        ret = this.teststone1(x, y);

        let color = 3 - curstone;
        let n = 0;
        if (y > 0 && this.board[APOS(x, y - 1)] === color) {
            test = this.teststone3(x, y - 1);
            if (test === 1)
                n += 1;
            else if (test === 2)
                atari = true;
        }
        if (x > 0 && this.board[APOS(x - 1, y)] === color) {
            test = this.teststone3(x - 1, y);
            if (test === 1)
                n += 1;
            else if (test === 2)
                atari = true;
        }
        if (y < this.boardsize - 1 && this.board[APOS(x, y + 1)] === color) {
            test = this.teststone3(x, y + 1);
            if (test === 1)
                n += 1;
            else if (test === 2)
                atari = true;
        }
        if (x < this.boardsize - 1 && this.board[APOS(x + 1, y)] === color) {
            test = this.teststone3(x + 1, y);
            if (test === 1)
                n += 1;
            else if (test === 2)
                atari = true;
        }
        if (ret) {
            if (n === 0) {
                this.board[APOS(x, y)] = EMPTY;
                return  PROHIBIT;
            } else if (n === 1 && this.capturedstones === 1) {
                if (this.teststonekp(x, y)) {
                    this.board[APOS(x, y)] = EMPTY;
                    return  KP_POS;
                }
            }
        }
        if (atari)
            return  ATARI;
        return  OK;
    }
    teststone1(x, y) {
        let temp = [];
        for (let i = 0; i < BOARD_LEN; i ++)
            temp[i] = 0;
        let count, x1, y1;
        let color = this.board[APOS(x, y)];
        temp[APOS(x, y)] = 1;
        do {
            count = 0;
            for (y1 = 0; y1 < this.boardsize; y1 ++) {
                for (x1 = 0; x1 < this.boardsize; x1 ++) {
                    if (temp[APOS(x1, y1)] !== 0 || this.board[APOS(x1, y1)] !== color)
                        continue;
                    if ((x1 > 0 && temp[APOS(x1 - 1, y1)] !== 0) ||
                        (y1 > 0 && temp[APOS(x1, y1 - 1)] !== 0) ||
                        (x1 < this.boardsize - 1 && temp[APOS(x1 + 1, y1)] !== 0) ||
                        (y1 < this.boardsize - 1 && temp[APOS(x1, y1 + 1)] !== 0)) {
                        temp[APOS(x1, y1)] = 1;
                        count ++;
                    }
                }
            }
        } while (count !== 0);
        for (y1 = 0; y1 < this.boardsize; y1 ++) {
            for (x1 = 0; x1 < this.boardsize; x1 ++) {
                if (this.board[APOS(x1, y1)] !== EMPTY)
                    continue;
                if ((x1 > 0 && temp[APOS(x1 - 1, y1)] !== 0) ||
                    (y1 > 0 && temp[APOS(x1, y1 - 1)] !== 0) ||
                    (x1 < this.boardsize - 1 && temp[APOS(x1 + 1, y1)] !== 0) ||
                    (y1 < this.boardsize - 1 && temp[APOS(x1, y1 + 1)] !== 0))
                    break;
            }
            if (x1 < this.boardsize)
                break;
        }
        if (y1 < this.boardsize)
            return  false;
        return  true;
    }
    teststone2(x, y) {
        let temp = [];
        for (let i = 0; i < BOARD_LEN; i ++)
            temp[i] = 0;
        let count, x1, y1;
        let color = this.board[APOS(x, y)];
        temp[APOS(x, y)] = 1;
        do {
            count = 0;
            for (y1 = 0; y1 < this.boardsize; y1 ++) {
                for (x1 = 0; x1 < this.boardsize; x1 ++) {
                    if (temp[APOS(x1, y1)] !== 0 || this.board[APOS(x1, y1)] !== color)
                        continue;
                    if ((x1 > 0 && temp[APOS(x1 - 1, y1)] !== 0) ||
                        (y1 > 0 && temp[APOS(x1, y1 - 1)] !== 0) ||
                        (x1 < this.boardsize - 1 && temp[APOS(x1 + 1, y1)] !== 0) ||
                        (y1 < this.boardsize - 1 && temp[APOS(x1, y1 + 1)] !== 0)) {
                        temp[APOS(x1, y1)] = 1;
                        count ++;
                    }
                }
            }
        } while (count !== 0);
        for (y1 = 0; y1 < this.boardsize; y1 ++) {
            for (x1 = 0; x1 < this.boardsize; x1 ++) {
                if (this.board[APOS(x1, y1)] !== EMPTY)
                    continue;
                if ((x1 > 0 && temp[APOS(x1 - 1, y1)] !== 0) ||
                    (y1 > 0 && temp[APOS(x1, y1 - 1)] !== 0) ||
                    (x1 < this.boardsize - 1 && temp[APOS(x1 + 1, y1)] !== 0) ||
                    (y1 < this.boardsize - 1 && temp[APOS(x1, y1 + 1)] !== 0))
                    break;
            }
            if (x1 < this.boardsize)
                break;
        }
        if (y1 < this.boardsize)
            return;
        for (y1 = 0; y1 < this.boardsize; y1 ++) {
            for (x1 = 0; x1 < this.boardsize; x1 ++) {
                if (temp[APOS(x1, y1)] === 0)
                    continue;
                this.history[this.historyidx ++] = WPOS(x1, y1);
                color = this.board[APOS(x1, y1)];
                this.board[APOS(x1, y1)] = EMPTY;
                if (color === BLACK)
                    this.taken_black ++;
                else if (color === WHITE)
                    this.taken_white ++;
            }
        }
    }
    teststone3(x, y) {
        let temp = [];
        for (let i = 0; i < BOARD_LEN; i ++)
            temp[i] = 0;
        let count, x1, y1;
        let color = this.board[APOS(x, y)];
        temp[APOS(x, y)] = 1;
        do {
            count = 0;
            for (y1 = 0; y1 < this.boardsize; y1 ++) {
                for (x1 = 0; x1 < this.boardsize; x1 ++) {
                    if (temp[APOS(x1, y1)] !== 0 || this.board[APOS(x1, y1)] !== color)
                        continue;
                    if ((x1 > 0 && temp[APOS(x1 - 1, y1)] !== 0) ||
                        (y1 > 0 && temp[APOS(x1, y1 - 1)] !== 0) ||
                        (x1 < this.boardsize - 1 && temp[APOS(x1 + 1, y1)] !== 0) ||
                        (y1 < this.boardsize - 1 && temp[APOS(x1, y1 + 1)] !== 0)) {
                        temp[APOS(x1, y1)] = 1;
                        count ++;
                    }
                }
            }
        } while (count !== 0);
        count = 0;
        for (y1 = 0; y1 < this.boardsize; y1 ++) {
            for (x1 = 0; x1 < this.boardsize; x1 ++) {
                if (this.board[APOS(x1, y1)] !== EMPTY)
                    continue;
                if ((x1 > 0 && temp[APOS(x1 - 1, y1)] !== 0) ||
                    (y1 > 0 && temp[APOS(x1, y1 - 1)] !== 0) ||
                    (x1 < this.boardsize - 1 && temp[APOS(x1 + 1, y1)] !== 0) ||
                    (y1 < this.boardsize - 1 && temp[APOS(x1, y1 + 1)] !== 0)) {
                    count ++;
                    if (count >= 2)
                        break;
                    continue;
                }
            }
            if (x1 < this.boardsize)
                break;
        }
        if (count === 1)
            return  2;
        if (y1 < this.boardsize || count > 1)
            return  0;
        count = 0;
        for (y1 = 0; y1 < this.boardsize; y1 ++) {
            for (x1 = 0; x1 < this.boardsize; x1 ++) {
                if (temp[APOS(x1, y1)] !== 0)
                    count ++;
            }
        }
        this.capturedstones = count;
        return  1;
    }
    teststonekp(x, y) {
        let wpos = WPOS(x, y);
        if (this.historyidx > 2 && this.history[this.historyidx - 3] === HISTORY_MARK &&
            this.history[this.historyidx - 1] === wpos)
            return  true;
        return  false;
    }
}

export var theLogicBoard = new LogicBoard();
export var theLogicBoard2 = new LogicBoard();

